SELECT s.id AS 科目ID, s.subject_name AS 科目,
  SUM(CASE WHEN q.question_type=1 THEN 1 ELSE 0 END) AS 单选,
  SUM(CASE WHEN q.question_type=2 THEN 1 ELSE 0 END) AS 多选,
  SUM(CASE WHEN q.question_type=3 THEN 1 ELSE 0 END) AS 判断,
  SUM(CASE WHEN q.question_type=4 THEN 1 ELSE 0 END) AS 填空,
  SUM(CASE WHEN q.question_type=5 THEN 1 ELSE 0 END) AS 简答,
  COUNT(*) AS 总数 FROM edu_subject s LEFT JOIN exam_question q ON q.subject_id=s.id AND q.id>=1000
WHERE s.id >= 100 GROUP BY s.id, s.subject_name ORDER BY s.id;
