INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(1000, 100, 1, '函数f(x)=x²+2x+1的导数f''(x)等于', '{"A": "2x+2", "B": "2x+1", "C": "x²+2", "D": "2x"}', 'A', '对f(x)=x²+2x+1求导，f''(x)=2x+2', 2.00, 1, 100),
(1001, 100, 1, '∫(2x)dx的结果是', '{"A": "x²+C", "B": "2x²+C", "C": "x+C", "D": "2x+C"}', 'A', '∫(2x)dx = 2·(x²/2) + C = x²+C', 2.00, 1, 100),
(1002, 100, 1, 'lim(x→0) sin(x)/x 的值为', '{"A": "1", "B": "0", "C": "∞", "D": "不存在"}', 'A', '这是一个重要极限，lim(x→0) sin(x)/x = 1', 2.00, 1, 100),
(1003, 100, 1, '函数f(x)=e^x在x=0处的泰勒展开式的前两项是', '{"A": "1+x", "B": "1+2x", "C": "x+x²", "D": "1+x²"}', 'A', 'e^x = 1 + x + x²/2! + ...，前两项为1+x', 3.00, 2, 100),
(1004, 100, 1, '下列哪个函数在其定义域内是连续的', '{"A": "f(x)=1/x", "B": "f(x)=|x|", "C": "f(x)=tan(x)", "D": "f(x)=[x](取整)"}', 'B', '绝对值函数在整个实数域上连续', 2.00, 1, 100),
(1005, 100, 2, '下列哪些是求导法则', '{"A": "乘法法则", "B": "链式法则", "C": "洛必达法则", "D": "商法则"}', 'ABD', '乘法法则、链式法则、商法则都是求导法则，洛必达法则是求极限的方法', 3.00, 2, 100),
(1006, 100, 2, '关于定积分的性质，正确的有', '{"A": "∫(a,b)kf(x)dx=k∫(a,b)f(x)dx", "B": "∫(a,b)f(x)dx=-∫(b,a)f(x)dx", "C": "∫(a,a)f(x)dx=1", "D": "∫(a,b)[f(x)+g(x)]dx=∫(a,b)f(x)dx+∫(a,b)g(x)dx"}', 'ABD', '∫(a,a)f(x)dx=0而非1', 3.00, 2, 100),
(1007, 100, 3, '连续函数一定可导', NULL, '错误', '连续是可导的必要条件但非充分条件，如f(x)=|x|在x=0处连续但不可导', 2.00, 1, 100),
(1008, 100, 3, '可导函数一定连续', NULL, '正确', '可导是连续的充分条件，可导必连续', 2.00, 1, 100),
(1009, 100, 3, '两个无穷小量的和仍然是无穷小量', NULL, '正确', '有限个无穷小量的和仍是无穷小量', 2.00, 1, 100),
(1010, 100, 4, '函数y=ln(x)的导数y''=____', NULL, '1/x', 'ln(x)的导数为1/x', 2.00, 1, 100),
(1011, 100, 4, '∫(0,1) x²dx = ____', NULL, '1/3', '∫(0,1) x²dx = [x³/3](0,1) = 1/3', 3.00, 2, 100),
(1012, 100, 5, '请用定义证明lim(n→∞) 1/n = 0', NULL, '对任意ε>0，取N=[1/ε]+1，当n>N时，|1/n-0|=1/n<1/N<ε，故lim(n→∞)1/n=0', '用ε-N语言证明即可', 5.00, 3, 100),
(1013, 100, 5, '求函数f(x)=x³-3x+2的极值点和极值', NULL, 'f''(x)=3x²-3=0，x=±1。f''''(1)=6>0，x=1为极小值点，f(1)=0；f''''(-1)=-6<0，x=-1为极大值点，f(-1)=4', '先求一阶导数令其为零求驻点，再用二阶导数判定极值类型', 5.00, 2, 100),
(1014, 100, 1, '矩阵A的转置记为A^T，则(AB)^T等于', '{"A": "A^T·B^T", "B": "B^T·A^T", "C": "(A·B)^T", "D": "B·A"}', 'B', '矩阵乘积的转置等于各矩阵转置的逆序乘积', 2.00, 2, 100),
(1015, 100, 1, '函数f(x)=1/(x-1)的间断点x=1是', '{"A": "可去间断点", "B": "跳跃间断点", "C": "无穷间断点", "D": "振荡间断点"}', 'C', 'x→1时函数趋于无穷', 2.00, 1, 100),
(1016, 100, 1, 'lim(x→∞)(1+1/x)^x的值为', '{"A": "0", "B": "1", "C": "e", "D": "∞"}', 'C', '这是自然对数e的定义', 2.00, 1, 100),
(1017, 100, 1, '函数f(x)=|x|在x=0处', '{"A": "可导", "B": "不可导", "C": "不连续", "D": "无定义"}', 'B', '绝对值函数在0处连续但不可导', 2.00, 1, 100),
(1018, 100, 1, '不定积分∫cos(x)dx等于', '{"A": "sin(x)+C", "B": "-sin(x)+C", "C": "cos(x)+C", "D": "-cos(x)+C"}', 'A', 'cos的原函数是sin', 2.00, 1, 100),
(1019, 100, 1, '函数f(x)=x^3的拐点在', '{"A": "x=0", "B": "x=1", "C": "x=-1", "D": "无拐点"}', 'A', 'f''''(x)=6x在x=0处变号', 2.00, 2, 100),
(1020, 100, 1, '下列哪个级数是收敛的', '{"A": "∑1/n", "B": "∑1/n^2", "C": "∑n", "D": "∑(-1)^n"}', 'B', 'p级数p=2>1收敛', 2.00, 2, 100),
(1021, 100, 1, '曲线y=x^2在x=1处的切线斜率是', '{"A": "1", "B": "2", "C": "3", "D": "4"}', 'B', 'y''=2x在x=1处为2', 2.00, 1, 100),
(1022, 100, 1, '定积分∫(0,π)sin(x)dx等于', '{"A": "0", "B": "1", "C": "2", "D": "π"}', 'C', '[-cos(x)]从0到π=1+1=2', 2.00, 1, 100),
(1023, 100, 1, '下列哪个函数是奇函数', '{"A": "x^2", "B": "cos(x)", "C": "sin(x)", "D": "e^x"}', 'C', 'sin(-x)=-sin(x)是奇函数', 2.00, 1, 100),
(1024, 100, 1, '微分方程y''+2y=0的通解是', '{"A": "y=Ce^(2x)", "B": "y=Ce^(-2x)", "C": "y=C/x^2", "D": "y=Cx^2"}', 'B', '分离变量法得y=Ce^(-2x)', 3.00, 2, 100),
(1025, 100, 1, '函数f(x)=ln(x)的定义域是', '{"A": "(-∞,+∞)", "B": "(0,+∞)", "C": "[0,+∞)", "D": "(-∞,0)"}', 'B', '对数函数定义域为正实数', 2.00, 1, 100),
(1026, 100, 1, '泰勒公式中e^x在x=0处展开的一次近似为', '{"A": "1", "B": "1+x", "C": "x", "D": "1-x"}', 'B', 'e^x≈1+x(x→0)', 2.00, 2, 100),
(1027, 100, 1, '二重积分∬dxdy在区域D上的几何意义是', '{"A": "曲面面积", "B": "D的面积", "C": "体积", "D": "弧长"}', 'B', '∬1dxdy等于区域D的面积', 2.00, 2, 100),
(1028, 100, 1, '向量a=(1,2,3)和b=(2,4,6)的关系是', '{"A": "垂直", "B": "平行", "C": "既不垂直也不平行", "D": "无法判断"}', 'B', 'b=2a所以平行', 2.00, 1, 100),
(1029, 100, 2, '下列函数在其定义域内连续的有', '{"A": "多项式函数", "B": "指数函数", "C": "三角函数", "D": "对数函数"}', 'ABCD', '初等函数在定义域内都连续', 3.00, 1, 100),
(1030, 100, 2, '关于导数正确的有', '{"A": "导数表示变化率", "B": "导数为零可能是极值点", "C": "可导一定连续", "D": "连续一定可导"}', 'ABC', '连续不一定可导如|x|', 3.00, 1, 100),
(1031, 100, 2, '下列求导法则正确的有', '{"A": "(f+g)''=f''+g''", "B": "(fg)''=f''g+fg''", "C": "(f/g)''=(f''g-fg'')/g^2", "D": "(f(g(x)))''=f''(g(x))g''(x)"}', 'ABCD', '都是基本求导法则', 3.00, 1, 100),
(1032, 100, 2, '定积分的性质包括', '{"A": "线性性质", "B": "区间可加性", "C": "保号性", "D": "积分中值定理"}', 'ABCD', '都是定积分的基本性质', 3.00, 2, 100),
(1033, 100, 2, '下列级数判别法有', '{"A": "比较判别法", "B": "比值判别法", "C": "根值判别法", "D": "积分判别法"}', 'ABCD', '都是级数收敛判别法', 3.00, 2, 100),
(1034, 100, 2, '关于多元函数正确的有', '{"A": "偏导数存在不一定可微", "B": "可微一定连续", "C": "可微一定有偏导数", "D": "连续不一定可微"}', 'ABCD', '多元函数微积分的基本关系', 3.00, 3, 100),
(1035, 100, 2, '常用的积分方法有', '{"A": "换元法", "B": "分部积分法", "C": "有理函数积分", "D": "三角代换法"}', 'ABCD', '都是常用不定积分方法', 3.00, 1, 100),
(1036, 100, 2, '关于无穷级数正确的有', '{"A": "收敛级数的通项趋于0", "B": "通项趋于0的级数不一定收敛", "C": "绝对收敛则条件收敛", "D": "条件收敛不一定绝对收敛"}', 'ABD', '绝对收敛比条件收敛强C说反了', 3.00, 2, 100),
(1037, 100, 2, '关于微分方程正确的有', '{"A": "阶数由最高阶导数决定", "B": "通解含任意常数", "C": "特解由初始条件确定", "D": "线性方程有叠加原理"}', 'ABCD', '都是微分方程基本概念', 3.00, 2, 100),
(1038, 100, 2, '向量运算包括', '{"A": "数量积(点乘)", "B": "向量积(叉乘)", "C": "加法", "D": "数乘"}', 'ABCD', '都是向量基本运算', 3.00, 1, 100),
(1039, 100, 2, '关于极限正确的有', '{"A": "极限存在则唯一", "B": "有界函数不一定有极限", "C": "极限的四则运算法则", "D": "夹逼定理可以求极限"}', 'ABCD', '都是极限的性质和方法', 3.00, 1, 100),
(1040, 100, 2, '曲线的凹凸性判断方法包括', '{"A": "f''''(x)>0则凹", "B": "f''''(x)<0则凸", "C": "拐点处f''''(x)=0或不存在", "D": "拐点处凹凸性改变"}', 'ABCD', '都是判断凹凸性的方法', 3.00, 2, 100),
(1041, 100, 2, '下列属于第一类间断点的有', '{"A": "可去间断点", "B": "跳跃间断点", "C": "无穷间断点", "D": "振荡间断点"}', 'AB', '无穷和振荡是第二类间断点', 3.00, 2, 100),
(1042, 100, 2, '常微分方程的求解方法有', '{"A": "分离变量法", "B": "常数变易法", "C": "待定系数法", "D": "降阶法"}', 'ABCD', '都是常微分方程的求解方法', 3.00, 2, 100),
(1043, 100, 2, '关于行列式正确的有', '{"A": "转置行列式值不变", "B": "交换两行变号", "C": "某行乘k等于行列式乘k", "D": "两行成比例则为0"}', 'ABCD', '都是行列式的性质', 3.00, 2, 100),
(1044, 100, 2, '关于矩阵正确的有', '{"A": "矩阵乘法不满足交换律", "B": "(AB)^T=B^T·A^T", "C": "可逆矩阵的行列式不为0", "D": "单位矩阵是任何矩阵的乘法幺元"}', 'ABCD', '都是矩阵的基本性质', 3.00, 2, 100),
(1045, 100, 2, '求极限的方法有', '{"A": "洛必达法则", "B": "等价无穷小替换", "C": "泰勒展开", "D": "夹逼准则"}', 'ABCD', '都是求极限的方法', 3.00, 1, 100),
(1046, 100, 3, '极限存在则函数在该点一定有定义', NULL, '错误', '极限与函数在该点是否有定义无关', 2.00, 1, 100),
(1047, 100, 3, '闭区间上的连续函数一定有最大值和最小值', NULL, '正确', '闭区间连续函数的最值定理', 2.00, 1, 100),
(1048, 100, 3, '函数的极大值一定大于极小值', NULL, '错误', '极大值可能小于极小值', 2.00, 2, 100),
(1049, 100, 3, '收敛级数的通项极限必为零', NULL, '正确', '级数收敛的必要条件是通项趋于0', 2.00, 1, 100),
(1050, 100, 3, '原函数存在则一定可积', NULL, '正确', '有原函数则不定积分存在', 2.00, 2, 100),
(1051, 100, 3, '可微一定可导', NULL, '正确', '一元函数可微与可导等价', 2.00, 1, 100),
(1052, 100, 3, 'e^x的导数还是e^x', NULL, '正确', 'e^x是唯一导数等于自身的函数', 2.00, 1, 100),
(1053, 100, 3, '∫(0,1)1/x dx收敛', NULL, '错误', '这是瑕积分在x=0处发散', 2.00, 2, 100),
(1054, 100, 3, '齐次线性方程组一定有解', NULL, '正确', '齐次方程组至少有零解', 2.00, 1, 100),
(1055, 100, 3, '二次连续可导函数的混合偏导数与求导顺序无关', NULL, '正确', '二阶混合偏导连续时与顺序无关', 2.00, 2, 100),
(1056, 100, 3, '幂级数在收敛半径内绝对收敛', NULL, '正确', '收敛圆内绝对收敛', 2.00, 2, 100),
(1057, 100, 3, '定积分的值与被积函数的自变量字母无关', NULL, '正确', '定积分是一个数值与积分变量无关', 2.00, 1, 100),
(1058, 100, 3, 'lim(x→0)sin(x)/x=1', NULL, '正确', '这是第一个重要极限', 2.00, 1, 100),
(1059, 100, 3, '反函数的导数等于原函数导数的倒数', NULL, '正确', '反函数求导公式', 2.00, 2, 100),
(1060, 100, 3, '两个无穷大量的差一定是无穷大量', NULL, '错误', '两个无穷大相减可能有限(如∞-∞)', 2.00, 2, 100),
(1061, 100, 3, '梯度方向是函数增长最快的方向', NULL, '正确', '梯度指向函数值增大最快的方向', 2.00, 2, 100),
(1062, 100, 3, '行列式等于零的矩阵不可逆', NULL, '正确', '可逆矩阵行列式不为零', 2.00, 1, 100),
(1063, 100, 4, 'lim(x→0)(1-cos(x))/x^2=____', NULL, '1/2', '利用等价无穷小1-cosx~x^2/2', 3.00, 1, 100),
(1064, 100, 4, '函数f(x)=x^3-3x在x=____处取得极小值', NULL, '1', 'f''=3x^2-3=0得x=±1,x=1极小', 3.00, 2, 100),
(1065, 100, 4, '∫e^x dx=____+C', NULL, 'e^x', 'e^x的原函数是它自己', 3.00, 1, 100),
(1066, 100, 4, 'n阶行列式的展开需要n!个____', NULL, '项', 'n阶行列式展开有n!项', 3.00, 1, 100),
(1067, 100, 4, '函数y=sin(x)的周期为____', NULL, '2π', '正弦函数周期为2π', 3.00, 1, 100),
(1068, 100, 4, '∫(0,+∞)e^(-x)dx=____', NULL, '1', '广义积分[-e^(-x)]从0到∞=1', 3.00, 2, 100),
(1069, 100, 4, '函数f(x)=x^2·e^x的导数f''(x)=____', NULL, '(2x+x^2)e^x', '乘法求导法则', 3.00, 2, 100),
(1070, 100, 4, '微分方程y''=y的通解是y=____', NULL, 'Ce^x', '分离变量法dy/y=dx', 3.00, 1, 100),
(1071, 100, 4, '向量a=(1,0,0)和b=(0,1,0)的数量积a·b=____', NULL, '0', '垂直向量点乘为0', 3.00, 1, 100),
(1072, 100, 4, '曲线y=x^2在x=2处的曲率半径R=____', NULL, '(1+16)^(3/2)/2', 'R=(1+y''^2)^(3/2)/|y''''|', 3.00, 3, 100),
(1073, 100, 4, 'lim(n→∞)(1+1/n)^n=____', NULL, 'e', '第二个重要极限', 3.00, 1, 100),
(1074, 100, 4, '设f(x)=ln(1+x)则f''(0)=____', NULL, '1', 'f''(x)=1/(1+x)代入x=0得1', 3.00, 1, 100),
(1075, 100, 4, '∫sin^2(x)dx=____+C', NULL, 'x/2-sin(2x)/4', '利用降幂公式sin^2x=(1-cos2x)/2', 3.00, 2, 100),
(1076, 100, 4, '二元函数f(x,y)=x^2+y^2的全微分df=____', NULL, '2xdx+2ydy', 'df=∂f/∂x·dx+∂f/∂y·dy', 3.00, 2, 100),
(1077, 100, 4, '等比级数∑ar^n(|r|<1)的和为____', NULL, 'a/(1-r)', '等比级数求和公式', 3.00, 2, 100),
(1078, 100, 4, '3阶单位矩阵的行列式值为____', NULL, '1', '单位矩阵行列式为1', 3.00, 1, 100),
(1079, 100, 4, '拉格朗日中值定理的条件是闭区间连续开区间____', NULL, '可导', '拉格朗日中值定理条件', 3.00, 1, 100),
(1080, 100, 4, '曲线y=e^x在x=0处的切线方程是y=____', NULL, 'x+1', '切线y=f(0)+f''(0)(x-0)=1+x', 3.00, 1, 100),
(1081, 100, 5, '请用ε-δ语言叙述函数极限的定义并举例说明', NULL, '定义：对任意ε>0，存在δ>0，当0<|x-x0|<δ时有|f(x)-A|<ε，则称A为f(x)在x→x0时的极限。例：证明lim(x→2)(3x-1)=5。对任意ε>0取δ=ε/3，当0<|x-2|<δ时|3x-1-5|=|3x-6|=3|x-2|<3δ=ε。', '需给出定义和一个完整证明例', 5.00, 2, 100),
(1082, 100, 5, '请说明洛必达法则的条件和应用', NULL, '条件：1.lim f(x)和lim g(x)同为0或同为∞(0/0或∞/∞型)；2.f和g在某去心邻域可导且g''≠0；3.lim f''/g''存在(含∞)。结论：lim f/g=lim f''/g''。注意：不满足条件不能用；可多次使用；其他不定式(0·∞,∞-∞,0^0等)需转化。例：lim(x→0)sinx/x=lim cosx/1=1。', '需说明条件注意事项和例题', 5.00, 2, 100),
(1083, 100, 5, '请比较定积分和不定积分的区别与联系', NULL, '不定积分：求原函数F(x)+C，结果是函数族。定积分：∫(a,b)f(x)dx=F(b)-F(a)，结果是确定的数值。联系：牛顿-莱布尼茨公式将二者联系即定积分等于原函数在上下限的差。区别：不定积分是求运算定积分是求数值；不定积分有常数C定积分没有。', '需说明概念区别和牛顿莱布尼茨公式', 5.00, 1, 100),
(1084, 100, 5, '请解释多元函数的偏导数和全微分', NULL, '偏导数：多元函数对其中一个变量求导其余变量视为常数。∂f/∂x表示f对x的偏导数。全微分：df=∂f/∂x·dx+∂f/∂y·dy，反映函数在各方向的总变化量。关系：全微分存在(可微)则偏导数存在反之不然。几何意义：偏导数是曲面沿坐标轴方向的切线斜率。', '需说明偏导数全微分的概念和关系', 5.00, 2, 100),
(1085, 100, 5, '请说明矩阵的初等变换及其在解线性方程组中的应用', NULL, '初等行变换：1.交换两行；2.某行乘非零常数；3.某行加上另一行的倍数。应用：将增广矩阵化为行阶梯形或行最简形求解。高斯消元法：通过初等行变换消元化为阶梯形回代求解。若rank(A)=rank(A|b)=n则有唯一解；rank(A)=rank(A|b)<n则有无穷多解；rank(A)<rank(A|b)则无解。', '需说明三种变换和高斯消元法', 5.00, 2, 100),
(1086, 100, 5, '请解释幂级数的收敛半径和收敛域', NULL, '幂级数∑anx^n。收敛半径R：|x|<R绝对收敛|x|>R发散。求法：R=lim|an/an+1|或R=1/lim|an|^(1/n)。收敛域：在(-R,R)内收敛端点x=±R需单独检验。性质：收敛域内可逐项求导和积分且收敛半径不变。例：∑x^n/n的R=1收敛域[-1,1)。', '需说明收敛半径的求法和端点判断', 5.00, 3, 100),
(1087, 100, 5, '请说明格林公式及其应用', NULL, '格林公式：设D是平面有界闭区域边界L为正向(逆时针)，P、Q在D上有连续一阶偏导数，则∮(Pdx+Qdy)=∬(∂Q/∂x-∂P/∂y)dxdy。应用：1.将曲线积分转化为二重积分或反之；2.计算平面区域面积S=1/2∮(xdy-ydx)；3.判断曲线积分与路径无关的条件：∂P/∂y=∂Q/∂x。', '需说明公式内容和至少两个应用', 5.00, 3, 100),
(1088, 100, 5, '请解释什么是无穷小量及其比较', NULL, '无穷小量：以0为极限的变量。比较：设α和β都是无穷小。1.lim β/α=0则β是α的高阶无穷小β=o(α)；2.lim β/α=c(c≠0)则同阶无穷小c=1时等价无穷小β~α。常用等价：sinx~x,tanx~x,1-cosx~x^2/2,ln(1+x)~x,e^x-1~x(x→0)。用途：等价无穷小替换简化极限计算。', '需说明定义比较方法和常用等价', 5.00, 2, 100),
(1089, 100, 2, '关于隐函数求导正确的有', '{"A": "对方程两边同时求导", "B": "y视为x的函数", "C": "利用复合函数求导", "D": "可以求高阶导数"}', 'ABCD', '都是隐函数求导的要点', 3.00, 2, 100),
(1090, 100, 1, '函数 y=ln(x-1) 的定义域是', '{"A": "(-∞,+∞)", "B": "(0,+∞)", "C": "(1,+∞)", "D": "[1,+∞)"}', 'C', '对数函数要求真数 x-1>0,即 x>1', 2.00, 1, 100),
(1091, 100, 1, '下列函数中是奇函数的是', '{"A": "y=x^2", "B": "y=cos x", "C": "y=x*sin x", "D": "y=x*cos x"}', 'D', 'x*cos x 满足 f(-x)=-f(x)', 2.00, 2, 100),
(1092, 100, 1, '函数 f(x)=x^2 在区间 [-1,2] 上的最大值是', '{"A": "1", "B": "2", "C": "4", "D": "8"}', 'C', 'f(2)=4 大于 f(-1)=1 和 f(0)=0', 2.00, 1, 100),
(1093, 100, 1, '函数 y=1/(x-2) 的间断点是', '{"A": "x=0", "B": "x=1", "C": "x=2", "D": "x=-2"}', 'C', 'x=2 处分母为 0,函数无定义', 2.00, 1, 100),
(1094, 100, 1, 'lim(x→0) sin(3x)/x 的值是', '{"A": "0", "B": "1", "C": "3", "D": "∞"}', 'C', 'lim sin(3x)/x = 3*lim sin(3x)/(3x) = 3*1 = 3', 2.00, 2, 100),
(1095, 100, 1, 'lim(x→0) (1-cos x)/x^2 的值是', '{"A": "0", "B": "1/2", "C": "1", "D": "2"}', 'B', '利用泰勒展开 1-cos x≈x^2/2,极限为 1/2', 2.00, 2, 100),
(1096, 100, 1, 'lim(x→∞) (1+1/x)^x 的值是', '{"A": "0", "B": "1", "C": "e", "D": "∞"}', 'C', '重要极限定义', 2.00, 1, 100),
(1097, 100, 1, 'lim(x→0) (e^x-1)/x 的值是', '{"A": "0", "B": "1", "C": "e", "D": "∞"}', 'B', '等价无穷小 e^x-1~x', 2.00, 1, 100),
(1098, 100, 1, 'lim(x→0) ln(1+x)/x 的值是', '{"A": "0", "B": "1", "C": "e", "D": "∞"}', 'B', '等价无穷小 ln(1+x)~x', 2.00, 1, 100),
(1099, 100, 1, '若 f(x)=x*sin(1/x),x≠0,则 lim(x→0) f(x) 等于', '{"A": "0", "B": "1", "C": "sin1", "D": "不存在"}', 'A', '|f(x)|≤|x|→0,夹逼定理给出极限为 0', 2.00, 2, 100),
(1100, 100, 1, '函数 f(x)=|x| 在 x=0 处', '{"A": "可导", "B": "连续不可导", "C": "不连续", "D": "导数为 0"}', 'B', '|x| 在 0 处连续但左右导数不等,不可导', 2.00, 2, 100),
(1101, 100, 1, '函数 f(x) 在 x0 处可导,则 f(x) 在 x0 处', '{"A": "必连续", "B": "必可微", "C": "必有极值", "D": "必单调"}', 'A', '可导必连续(可导是连续的充分条件)', 2.00, 1, 100),
(1102, 100, 1, '若 y=x^3,则 dy/dx 等于', '{"A": "x^2", "B": "3x^2", "C": "x^3", "D": "3x"}', 'B', '幂函数求导公式 (x^n)''=nx^(n-1)', 2.00, 1, 100),
(1103, 100, 1, '若 y=sin x,则 y'' 等于', '{"A": "cos x", "B": "-cos x", "C": "sin x", "D": "-sin x"}', 'A', '正弦的导数是余弦', 2.00, 1, 100),
(1104, 100, 1, '若 y=e^(2x),则 y'' 等于', '{"A": "e^(2x)", "B": "2e^(2x)", "C": "2x*e^(2x)", "D": "e^x"}', 'B', '复合函数求导,(e^(2x))''=2*e^(2x)', 2.00, 1, 100),
(1105, 100, 1, '若 y=ln(x^2+1),则 y'' 等于', '{"A": "1/(x^2+1)", "B": "2x/(x^2+1)", "C": "x/(x^2+1)", "D": "2/(x^2+1)"}', 'B', '复合函数求导,内层 (x^2+1)''=2x', 2.00, 2, 100),
(1106, 100, 1, '设 y=x^x (x>0),则 y'' 等于', '{"A": "x^x", "B": "x*x^(x-1)", "C": "x^x*(ln x+1)", "D": "x^x*ln x"}', 'C', '对 ln y=x ln x 两边求导得到 y''/y=ln x+1', 2.00, 3, 100),
(1107, 100, 1, '函数 y=x^3-3x 的极小值点是', '{"A": "x=-1", "B": "x=0", "C": "x=1", "D": "x=2"}', 'C', 'y''=3x^2-3,在 x=±1 处导数为 0,x=1 处二阶导>0 为极小值点', 2.00, 2, 100),
(1108, 100, 1, '函数 y=x^2 在 x=1 处的微分 dy 等于', '{"A": "dx", "B": "2dx", "C": "x dx", "D": "2x dx"}', 'B', 'dy=y''(1)dx=2dx', 2.00, 2, 100),
(1109, 100, 1, '曲线 y=x^2 在点 (1,1) 处的切线斜率为', '{"A": "1", "B": "2", "C": "3", "D": "4"}', 'B', 'y''=2x,在 x=1 处 y''=2', 2.00, 1, 100),
(1110, 100, 1, '若 f(x) 在 x0 处可微,则下列错误的是', '{"A": "f 在 x0 连续", "B": "f 在 x0 可导", "C": "Δy=f''(x0)Δx+o(Δx)", "D": "Δy=f''(x0)Δx"}', 'D', 'D 缺少高阶无穷小项', 2.00, 2, 100),
(1111, 100, 1, '罗尔定理的条件不包括', '{"A": "f 在 [a,b] 连续", "B": "f 在 (a,b) 可导", "C": "f(a)=f(b)", "D": "f 单调"}', 'D', '罗尔定理三条件:闭区间连续、开区间可导、端点函数值相等', 2.00, 1, 100),
