(1120, 100, 1, '∫sin x dx 等于', '{"A": "cos x+C", "B": "-cos x+C", "C": "sin x+C", "D": "-sin x+C"}', 'B', 'sin x 的原函数是 -cos x', 2.00, 1, 100),
