(1127, 100, 1, '∫(0 到 π) sin x dx 的值是', '{"A": "0", "B": "1", "C": "2", "D": "-2"}', 'C', '-cos x 在 0 到 π:[-cos π+cos 0]=2', 2.00, 1, 100),
(1128, 100, 1, '∫(0 到 π/2) sin^2 x dx 的值是', '{"A": "π/4", "B": "π/2", "C": "1", "D": "π"}', 'A', '利用 sin^2=(1-cos 2x)/2 积分得 π/4', 2.00, 2, 100),
