(1144, 100, 1, '二元函数全微分公式是', '{"A": "dz=fx dx+fy dy", "B": "dz=(fx+fy)(dx+dy)", "C": "dz=fx*fy*dx*dy", "D": "dz=fxy dxdy"}', 'A', '全微分=各偏导乘以对应增量再相加', 2.00, 2, 100),
