(1149, 100, 1, '在极坐标下,面积元 dxdy 变为', '{"A": "r dr dθ", "B": "dr dθ", "C": "r^2 dr dθ", "D": "r dθ"}', 'A', '极坐标变换雅可比为 r,故 dxdy=r dr dθ', 2.00, 2, 100),
