(1221, 100, 3, '柯西中值定理是拉格朗日中值定理的特例', NULL, '错误', '柯西是推广,拉格朗日是 g(x)=x 的特例', 1.00, 2, 100),
(1222, 100, 3, '泰勒公式将函数展开为多项式的精确表达', NULL, '正确', '泰勒公式可精确逼近(带余项)', 1.00, 1, 100),
(1223, 100, 3, '洛必达法则可处理 0·∞ 和 ∞-∞ 型不定式', NULL, '错误', '只能直接处理 0/0 和 ∞/∞,其他需变形', 1.00, 2, 100),
(1224, 100, 3, '定积分 ∫(a→b) f(x)dx 中 dx 表示自变量增量', NULL, '正确', 'dx 是无穷小自变量增量', 1.00, 1, 100),
(1225, 100, 3, '牛顿莱布尼茨公式建立了不定积分与定积分的桥梁', NULL, '正确', '∫(a→b)f=F(b)-F(a) 是微积分基本定理', 1.00, 1, 100),
(1226, 100, 3, '定积分上下限可以相等,此时定积分为 0', NULL, '正确', '∫(a→a) f=0 是定积分性质', 1.00, 1, 100),
(1227, 100, 3, '原函数与不定积分相同', NULL, '错误', '不定积分是原函数的全体: F(x)+C', 1.00, 2, 100),
(1228, 100, 3, '分部积分法的口诀是反对幂指三', NULL, '正确', '选 u 的顺序:反三角→对数→幂→指→三角', 1.00, 2, 100),
(1229, 100, 3, '若 f 在 [a,b] 可积,则 f 在 [a,b] 必连续', NULL, '错误', '可积只要求至多有限个间断点', 1.00, 3, 100),
(1230, 100, 3, '二元函数 f(x,y) 在 (x0,y0) 偏导数存在则必连续', NULL, '错误', '偏导存在不蕴涵连续', 1.00, 3, 100),
(1231, 100, 3, '二元函数可微则必偏导存在', NULL, '正确', '可微 ⇒ 可偏导(且连续)', 1.00, 2, 100),
(1232, 100, 3, '二重积分可以化为累次积分', NULL, '正确', 'Fubini 定理: 在合理条件下二重积分=累次积分', 1.00, 2, 100),
(1233, 100, 3, '极坐标变换的雅可比行列式是 r', NULL, '正确', 'dxdy = r dr dθ 是经典结论', 1.00, 2, 100),
(1234, 100, 3, '球面坐标变换的雅可比行列式是 r^2 sinφ', NULL, '正确', '三维球坐标 dV = r^2 sinφ dr dφ dθ', 1.00, 3, 100),
(1235, 100, 3, '格林公式是高斯公式在二维平面的特殊情形', NULL, '正确', '格林是高斯定理在 2D 的特例', 1.00, 3, 100),
(1236, 100, 3, '曲线 y=x^2 的弧长公式中需用 √(1+y''^2)', NULL, '正确', '直角坐标系下弧长公式 L=∫√(1+y''^2)dx', 1.00, 2, 100),
(1237, 100, 3, '旋转体侧面积公式 S=2π∫y√(1+y''^2)dx', NULL, '正确', '绕 x 轴旋转的侧面积', 1.00, 3, 100),
(1238, 100, 3, '可分离变量微分方程必能化为 g(y)dy=f(x)dx 形式', NULL, '正确', '这是可分离变量的定义', 1.00, 1, 100),
(1239, 100, 3, '一阶线性微分方程通解=齐次通解+一个特解', NULL, '正确', '线性方程的通解结构', 1.00, 2, 100),
(1240, 100, 3, '二阶常系数齐次线性微分方程总有两个线性无关解', NULL, '正确', '由特征方程的根可写出两个基本解', 1.00, 2, 100),
(1241, 100, 3, '所有的常微分方程都能用初等函数表示通解', NULL, '错误', '并非所有 ODE 都能初等积分(如 y''=e^(x^2))', 1.00, 2, 100),
(1242, 100, 3, '调和级数 Σ 1/n 收敛', NULL, '错误', '调和级数发散,经典结果', 1.00, 1, 100),
(1243, 100, 3, '几何级数 Σ q^n 收敛当且仅当 |q|<1', NULL, '正确', '几何级数收敛性的充要条件', 1.00, 1, 100),
(1244, 100, 3, 'Σ 1/n^2 的和等于 π^2/6', NULL, '正确', '欧拉公式: Σ 1/n^2 = π^2/6', 1.00, 3, 100),
(1245, 100, 3, '幂级数在收敛域内可以逐项求导和积分', NULL, '正确', '幂级数的逐项可导可积性质', 1.00, 2, 100),
(1246, 100, 3, '若 f(x)=Σ a_n x^n 在 |x|<R 收敛,则 f(x) 在此区间连续', NULL, '正确', '幂级数和函数在收敛区间内连续', 1.00, 2, 100),
(1247, 100, 3, 'sin x 和 cos x 在整个数轴上都可展开为麦克劳林级数', NULL, '正确', '收敛半径均为 +∞', 1.00, 2, 100),
(1248, 100, 3, 'ln(1+x) 的麦克劳林展开收敛半径是 1', NULL, '正确', 'ln(1+x) 在 (-1,1] 收敛', 1.00, 2, 100),
(1249, 100, 4, 'lim(x→0) sin(2x)/x 的值是____', NULL, '2', '2*lim sin(2x)/(2x)=2', 3.00, 1, 100),
(1250, 100, 4, '函数 y=arctan x 的导数是____', NULL, '1/(1+x^2)', '反正切的导数公式', 3.00, 1, 100),
(1251, 100, 4, '函数 y=√x 在 x=4 处的导数是____', NULL, '1/4', '(√x)''=1/(2√x),代入 x=4 得 1/4', 3.00, 2, 100),
(1252, 100, 4, '若 y=x e^x,则 y''=____', NULL, 'e^x+x e^x|(1+x)e^x', '乘法法则: 1*e^x+x*e^x', 3.00, 2, 100),
(1253, 100, 4, '若 f(x)=x^3-3x+1,则 f 的极小值点是 x=____', NULL, '1', 'f''=3x^2-3,根为 ±1,二阶导 6x 在 x=1 处为正', 3.00, 2, 100),
(1254, 100, 4, '∫(0→1) e^x dx 的值是____', NULL, 'e-1', '[e^x] 从 0 到 1 = e-1', 3.00, 1, 100),
(1255, 100, 4, '∫(1→e) 1/x dx 的值是____', NULL, '1', '[ln x] 从 1 到 e = 1-0 = 1', 3.00, 1, 100),
(1256, 100, 4, '曲线 y=x^2 在 (1,1) 处的切线方程是 y=____', NULL, '2x-1', '斜率 2,过 (1,1),y-1=2(x-1)', 3.00, 2, 100),
(1257, 100, 4, '设 f(x)=x^2,则 lim(x→1) (f(x)-f(1))/(x-1) = ____', NULL, '2', '即 f''(1)=2', 3.00, 1, 100),
(1258, 100, 4, '函数 y=ln(x+1) 的麦克劳林展开式前三项是____', NULL, 'x-x^2/2+x^3/3', 'ln(1+x)=x-x^2/2+x^3/3-...', 3.00, 2, 100),
(1259, 100, 4, '几何级数 Σ(1/2)^n,n 从 0 开始的和是____', NULL, '2', 'S=1/(1-1/2)=2', 3.00, 1, 100),
(1260, 100, 4, 'p 级数 Σ 1/n^p 收敛当且仅当 p ____', NULL, '>1|大于1', 'p 级数收敛条件', 3.00, 2, 100),
(1261, 100, 4, '幂级数 Σ x^n/n 的收敛半径是____', NULL, '1', '系数比 (n+1)/n→1,半径 1', 3.00, 2, 100),
(1262, 100, 4, '二元函数 z=x^2+y^2,在 (1,2) 处的全微分 dz=____', NULL, '2dx+4dy', 'fx(1,2)=2,fy(1,2)=4,dz=2dx+4dy', 3.00, 2, 100),
(1263, 100, 4, '若 z=xy,则 ∂^2 z/∂x∂y = ____', NULL, '1', '∂z/∂x=y,∂(y)/∂y=1', 3.00, 2, 100),
(1264, 100, 4, '在极坐标系中,曲线 r=2sinθ 是____', NULL, '圆|过原点的圆', 'r=2sinθ 是以 (0,1) 为圆心半径 1 的圆', 3.00, 3, 100),
(1265, 100, 4, '格林公式 ∫∫_D (∂Q/∂x-∂P/∂y)dxdy = ____', NULL, '∮_L Pdx+Qdy', '格林公式右边是边界曲线积分', 3.00, 2, 100),
(1266, 100, 4, '微分方程 dy/dx=2y 的通解是 y=____', NULL, 'Ce^(2x)', '分离变量,y=Ce^(2x)', 3.00, 2, 100),
(1267, 100, 4, '二阶常系数齐次方程 y''''-3y''+2y=0 的特征方程是____', NULL, 'r^2-3r+2=0', '对应特征方程的根决定通解形式', 3.00, 2, 100),
(1268, 100, 4, '若 y''=y,y(0)=1,则 y=____', NULL, 'e^x', '通解 y=Ce^x,初值 y(0)=1 ⇒ C=1', 3.00, 1, 100),
(1269, 100, 4, '函数 f(x)=x^2 在区间 [0,1] 上的平均值是____', NULL, '1/3', 'f 的平均值=1/(b-a) ∫f dx=1/3', 3.00, 2, 100),
(1270, 100, 4, '曲线 y=x^2 在 [0,2] 上方与 x 轴围成区域面积是____', NULL, '8/3', '∫(0→2) x^2 dx = 8/3', 3.00, 2, 100),
(1271, 100, 4, '函数 e^x 在 0 处的 4 阶泰勒展开式包括到 ____ 项', NULL, 'x^4/24|x^4/4!', 'e^x=1+x+x^2/2+x^3/6+x^4/24+...', 3.00, 2, 100),
(1272, 100, 4, '球面坐标变换中 dV=____', NULL, 'r^2 sinφ dr dφ dθ', '三维球坐标体积元', 3.00, 3, 100),
(1273, 100, 4, '曲线 y=sin x 的弧长公式是 L=∫____', NULL, '√(1+cos^2 x) dx', '直角坐标弧长 L=∫√(1+y''^2)dx', 3.00, 3, 100),
(1274, 100, 4, '若 f(x,y)=x^2+y^2,则 f 在 (3,4) 处的方向 (1,0) 上的方向导数是____', NULL, '6', '方向 (1,0) 即 ∂f/∂x|_(3,4)=2*3=6', 3.00, 2, 100),
(1275, 100, 4, '求 lim(x→0) (1-cos x)/x^2 = ____', NULL, '1/2', '泰勒展开或洛必达均得 1/2', 3.00, 2, 100),
(1276, 100, 4, '若 f(x)=Σ a_n x^n 是 ln(1+x) 的展开,则 a_3 = ____', NULL, '1/3', 'ln(1+x) 的 x^3 项系数为 1/3', 3.00, 2, 100),
(1277, 100, 4, '∫arctan x dx 的结果是____', NULL, 'x arctan x-ln(1+x^2)/2+C|x*arctan(x)-ln(1+x^2)/2+C', '分部积分: u=arctan x,dv=dx', 3.00, 3, 100),
(1278, 100, 4, '二阶导数为 0 的点称为____', NULL, '拐点|拐点候选', '拐点是二阶导变号的点(候选)', 3.00, 2, 100),
(1279, 100, 5, '简述函数的极限与连续之间的关系', NULL, '函数 f(x) 在点 x0 处连续 ⇔ lim(x→x0) f(x)=f(x0)。三个条件: (1)f(x0) 有定义; (2)极限 lim(x→x0) f(x) 存在; (3)极限值等于 f(x0)。连续是比极限更强的概念,极限可以存在但不一定等于函数值(可去间断点),也可以不存在(跳跃间断点、无穷间断点等)', '极限与连续是微积分的基础', 10.00, 2, 100),
(1280, 100, 5, '简述导数的定义、几何意义和物理意义', NULL, '定义: f''(x0)=lim(Δx→0) [f(x0+Δx)-f(x0)]/Δx,若极限存在则称 f 在 x0 处可导。几何意义: f''(x0) 是曲线 y=f(x) 在点 (x0,f(x0)) 处切线的斜率。物理意义: 若 f(t) 是位移,f''(t) 是瞬时速度; 一般地,导数描述变量的瞬时变化率', '导数是微积分的核心概念', 10.00, 1, 100),
(1281, 100, 5, '简述拉格朗日中值定理及其几何意义', NULL, '内容: 若 f(x) 在 [a,b] 连续,在 (a,b) 可导,则至少存在一点 ξ∈(a,b) 使得 f''(ξ)=(f(b)-f(a))/(b-a)。几何意义: 在曲线 y=f(x) 上,至少存在一点 (ξ,f(ξ)) 使得该点处的切线与连接端点 A(a,f(a))、B(b,f(b)) 的弦平行。应用: 证明不等式、估计函数变化等', '拉格朗日是微分中值的核心定理', 10.00, 2, 100),
(1282, 100, 5, '简述罗尔定理、拉格朗日中值定理、柯西中值定理的关系', NULL, '三者层层递进。罗尔定理: f 在 [a,b] 连续 (a,b) 可导且 f(a)=f(b),则存在 ξ 使 f''(ξ)=0。拉格朗日中值定理: 去掉 f(a)=f(b) 条件,结论变为 f''(ξ)=(f(b)-f(a))/(b-a),罗尔是其 f(a)=f(b) 的特例。柯西中值定理: 涉及两个函数 f,g,结论 f''(ξ)/g''(ξ)=(f(b)-f(a))/(g(b)-g(a)),拉格朗日是 g(x)=x 时的特例', '三大中值定理逻辑递进', 15.00, 3, 100),
(1283, 100, 5, '简述定积分的几何应用', NULL, '主要应用: (1)平面图形面积: 由 y=f(x)、y=g(x) 在 [a,b] 围成的面积 S=∫|f-g|dx; (2)旋转体体积: 绕 x 轴 V=π∫y^2 dx,绕 y 轴 V=2π∫xy dx(壳层法); (3)曲线弧长: L=∫√(1+y''^2)dx; (4)旋转曲面侧面积: S=2π∫y√(1+y''^2)dx; (5)变力做功、流体压力、引力等物理量', '定积分广泛应用于面积、体积、弧长计算', 15.00, 2, 100),
(1284, 100, 5, '简述牛顿莱布尼茨公式的内容及其意义', NULL, '内容: 若 F(x) 是 f(x) 在 [a,b] 上的一个原函数,且 f 在 [a,b] 上可积,则 ∫(a→b) f(x)dx = F(b)-F(a)。意义: (1)将定积分计算转化为求原函数,是微积分基本定理; (2)将微分和积分两个看似无关的运算统一起来,称为微积分的桥梁; (3)极大简化了定积分的计算', '牛顿莱布尼茨公式是微积分的核心成果', 15.00, 2, 100),
(1285, 100, 5, '简述泰勒公式的内容及其作用', NULL, '内容: 若 f(x) 在 x0 的某邻域内有直到 n+1 阶导数,则 f(x)=Σ(k=0→n) f^(k)(x0)(x-x0)^k/k! + R_n(x),其中 R_n 是余项(可用拉格朗日型、皮亚诺型等)。作用: (1)用多项式逼近函数值; (2)求函数极限(尤其难处理的极限); (3)求函数极值与凹凸性; (4)证明不等式; (5)误差估计', '泰勒公式是函数局部展开的基础', 15.00, 2, 100),
(1286, 100, 5, '简述全微分与偏导数的关系', NULL, '全微分 dz = fx dx + fy dy 是函数增量的线性主部。关系: (1)可微 ⇒ 可偏导,反之不一定; (2)偏导存在且连续 ⇒ 可微; (3)可微 ⇒ 连续,偏导存在不蕴涵连续。全微分体现了多元函数中各方向变化的综合,偏导只是各坐标方向的特殊情况', '全微分是多元函数微分学的核心概念', 10.00, 2, 100),
(1287, 100, 5, '简述二重积分换元法(极坐标)的应用情形', NULL, '使用情形: (1)积分区域为圆、扇形、环形,边界用极坐标描述简单; (2)被积函数含 x^2+y^2 形式; (3)被积函数含 √(x^2+y^2)。变换公式: ∫∫_D f(x,y)dxdy=∫∫_D'' f(r cosθ,r sinθ) r dr dθ,雅可比为 r,要小心面积元乘 r', '极坐标可极大简化某些类型二重积分', 10.00, 2, 100),
(1288, 100, 5, '简述一阶线性微分方程 y''+P(x)y=Q(x) 的求解步骤', NULL, '步骤: (1)找出 P(x) 和 Q(x); (2)计算积分因子 μ(x)=e^(∫P dx); (3)将方程两边乘 μ(x),左边变为 d(μy)/dx; (4)积分: μ(x)y=∫μ(x)Q(x)dx + C; (5)解出 y=[∫μ(x)Q(x)dx + C]/μ(x)。或直接套公式: y=e^(-∫P dx)[∫Q(x)e^(∫P dx)dx + C]', '一阶线性 ODE 是 ODE 中最基础的类型', 15.00, 2, 100),
(1289, 100, 5, '简述二阶常系数齐次线性微分方程 ay''''+by''+cy=0 的解法', NULL, '步骤: (1)写出特征方程 ar^2+br+c=0; (2)解出特征根 r1,r2; (3)按三种情形写通解: 实根不等 y=C1 e^(r1 x)+C2 e^(r2 x); 实根相等 r1=r2=r,y=(C1+C2 x)e^(rx); 共轭虚根 r=α±βi,y=e^(αx)(C1 cos βx+C2 sin βx)。三种情形对应判别式 Δ>0、Δ=0、Δ<0', '二阶常系数齐次方程是 ODE 中最重要的一类', 15.00, 2, 100),
(1290, 100, 5, '简述级数收敛的几种判别法', NULL, '正项级数: (1)比较判别法; (2)比值法 lim a_(n+1)/a_n; (3)根值法 lim ^n√a_n; (4)积分判别法。任意项级数: (5)绝对收敛 ⇒ 收敛; (6)交错级数用莱布尼茨准则(单调减且→0); (7)阿贝尔/狄利克雷判别法。每种方法适用情形不同,要根据级数特征选取', '判别级数收敛性是无穷级数的基础', 15.00, 2, 100),
(1291, 100, 5, '简述幂级数的收敛半径和收敛域的求法', NULL, '幂级数 Σ a_n x^n 的收敛半径 R 求法: 计算 ρ=lim|a_(n+1)/a_n| 或 ρ=lim ^n√|a_n|,则 R=1/ρ(ρ=0 时 R=∞)。收敛域 = 开区间 (-R,R) 加上端点处分别判断收敛性。注意端点处需用其他判别法(如莱布尼茨、p 级数比较)单独验证', '幂级数是函数展开的基础工具', 10.00, 2, 100),
(1292, 100, 5, '简述函数的麦克劳林展开及其常见结果', NULL, '麦克劳林展开 = 在 x0=0 处的泰勒展开。常见结果: (1)e^x=Σ x^n/n! (R=∞); (2)sin x=Σ (-1)^n x^(2n+1)/(2n+1)! (R=∞); (3)cos x=Σ (-1)^n x^(2n)/(2n)! (R=∞); (4)ln(1+x)=Σ (-1)^(n-1) x^n/n (-1<x<=1); (5)(1+x)^α=Σ C(α,n) x^n (-1<x<1)。这些是数学分析、物理、工程中常用', '熟记基本初等函数的麦克劳林展开非常重要', 15.00, 2, 100),
(1293, 100, 5, '简述函数极值的判定方法', NULL, '必要条件: 若 f 在 x0 取得极值且 f''(x0) 存在,则 f''(x0)=0(费马定理),驻点是极值点的候选。充分条件: (1)第一充分条件: 在 x0 两侧 f''(x) 异号则有极值,具体看正负方向; (2)第二充分条件: f''(x0)=0,f''''(x0)>0 极小值; f''''(x0)<0 极大值; f''''(x0)=0 不定。不可导点也可能是极值点,需单独判断', '求极值是导数应用的核心', 10.00, 2, 100),
(1294, 100, 5, '简述梯度向量的定义和性质', NULL, '定义: 二元函数 z=f(x,y) 的梯度为 grad f=(∂f/∂x,∂f/∂y),三元类似。性质: (1)沿梯度方向函数增长最快,反方向减少最快; (2)梯度的模等于最大方向导数; (3)梯度垂直于等值线(等值面); (4)梯度为 0 处可能为极值点或鞍点。应用: 机器学习的梯度下降、物理中的力场表示', '梯度是多元函数分析的核心概念', 15.00, 2, 100),
(1295, 100, 5, '简述凹凸性与拐点的判定', NULL, '凹凸性: 若 f''''(x)>0 在区间内,f 凹(图像呈 U 型); f''''(x)<0 在区间内,f 凸(图像呈 ∩ 型)。拐点: f''''(x) 变号的点,即由凹变凸或由凸变凹的临界点。判定步骤: (1)求 f''''(x); (2)求 f''''=0 或不存在的点; (3)检查这些点两侧 f'''' 是否变号,变号则为拐点', '凹凸与拐点描述函数图像形态', 10.00, 2, 100),
(1296, 100, 5, '简述格林公式的内容、几何意义及应用', NULL, '内容: 设 D 为有界闭区域,边界 L 取正方向,P、Q 在 D 上有一阶连续偏导,则 ∮_L Pdx+Qdy=∫∫_D (∂Q/∂x-∂P/∂y)dxdy。几何意义: 将平面闭曲线上的环流与区域上的二重积分(类似旋度)联系起来。应用: (1)计算闭曲线积分时转化为更简单的二重积分; (2)判断曲线积分与路径无关; (3)求平面图形面积', '格林公式是平面向量场的基本定理', 15.00, 2, 100),
(1297, 100, 5, '简述凸函数与不等式应用', NULL, '凸函数定义: 在区间 I 上,对任意 x1,x2 和 λ∈[0,1],有 f(λx1+(1-λ)x2)<=λf(x1)+(1-λ)f(x2),即函数图像位于弦下方。判定: f''''(x)>=0 时凸。应用: (1)证明不等式如算几不等式、Jensen 不等式; (2)证明常见不等式: x>=ln(1+x)、sin x>=x-x^3/6 等。凹函数对称定义', '凸函数在不等式证明、优化中至关重要', 15.00, 3, 100),
(1298, 100, 5, '综合分析: 求 ∫(0→1) x ln x dx 并说明用什么方法', NULL, '方法: 分部积分。设 u=ln x,dv=x dx,则 du=1/x dx,v=x^2/2。原积分 = uv|(0→1) - ∫v du = [x^2 ln x / 2]_(0→1) - ∫(0→1) x^2/(2x) dx = [x^2 ln x / 2]_(0→1) - 1/2 * ∫(0→1) x dx。第一项: 在 x=1 处 1*0/2=0,在 x→0+ 处 x^2 ln x→0(用洛必达 lim x^2 ln x=lim ln x/x^(-2)=lim (1/x)/(-2x^(-3))=0)。第二项: 1/2 * 1/2 = 1/4。故原式=0-1/4=-1/4', '分部积分 + 极限分析综合应用', 20.00, 3, 100);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(1299, 101, 1, 'The book ___ on the table is mine.', '{"A": "lying", "B": "laying", "C": "lain", "D": "laid"}', 'A', 'lie(躺/位于) 的现在分词为 lying，作后置定语修饰 book', 2.00, 1, 104),
(1300, 101, 1, 'Neither he nor I ___ to blame for the accident.', '{"A": "is", "B": "are", "C": "am", "D": "have"}', 'C', 'neither...nor 连接的主语，谓语动词与最近的主语 I 一致', 2.00, 2, 104),
(1301, 101, 1, 'By the time you arrive tomorrow, I ___ the report.', '{"A": "will finish", "B": "will have finished", "C": "have finished", "D": "finish"}', 'B', 'by the time + 一般现在时从句，主句用将来完成时', 2.00, 2, 104),
(1302, 101, 1, 'It is essential that every student ___ the safety rules.', '{"A": "observes", "B": "observe", "C": "observed", "D": "will observe"}', 'B', 'It is essential that 引导虚拟语气，从句谓语用 should + 动词原形，should 可省', 2.00, 3, 104),
(1303, 101, 1, 'The professor ___ delivering the lecture when the lights suddenly went out.', '{"A": "was", "B": "is", "C": "has been", "D": "had been"}', 'A', '过去进行时表示动作正在发生时被另一动作打断', 2.00, 1, 104),
(1304, 101, 1, 'Hardly ___ home when it began to rain.', '{"A": "I had got", "B": "had I got", "C": "I got", "D": "did I get"}', 'B', 'Hardly 置于句首，主句要部分倒装；hardly...when 用过去完成时', 2.00, 2, 104),
(1305, 101, 1, 'This is the museum ___ we visited last summer.', '{"A": "where", "B": "in which", "C": "which", "D": "what"}', 'C', '先行词 museum 在从句中作 visited 的宾语，用 which 或 that，不用 where', 2.00, 2, 104),
(1306, 101, 1, '___ the rain, the football match was postponed.', '{"A": "Because", "B": "Due to", "C": "Thanks", "D": "As"}', 'B', 'due to 是介词短语后接名词；because 后接句子；thanks to 也可以但用法稍显积极', 2.00, 1, 104),
(1307, 101, 1, 'She would rather ___ at home than ___ to the party.', '{"A": "stay; go", "B": "to stay; to go", "C": "staying; going", "D": "stayed; went"}', 'A', 'would rather do A than do B 结构，两个动词都用原形', 2.00, 1, 104),
(1308, 101, 1, 'The committee ___ divided in their opinions on the new policy.', '{"A": "is", "B": "are", "C": "has", "D": "was"}', 'B', '集合名词 committee 强调成员个体时用复数', 2.00, 2, 104),
(1309, 101, 1, 'He suggested that we ___ the meeting until next week.', '{"A": "postpone", "B": "postponed", "C": "would postpone", "D": "will postpone"}', 'A', 'suggest 后宾语从句用虚拟语气 (should) + 动词原形', 2.00, 2, 104),
(1310, 101, 1, 'Not until I read the letter ___ the truth.', '{"A": "I knew", "B": "did I know", "C": "I had known", "D": "had I known"}', 'B', 'Not until 置于句首，主句部分倒装', 2.00, 3, 104),
(1311, 101, 2, 'Which of the following are countable nouns?', '{"A": "information", "B": "book", "C": "advice", "D": "student"}', 'BD', 'information 和 advice 是不可数名词，book 和 student 都是可数名词', 3.00, 2, 104),
(1312, 101, 2, 'Which of the following words can be followed by a gerund (-ing form)?', '{"A": "enjoy", "B": "want", "C": "finish", "D": "avoid"}', 'ACD', 'enjoy/finish/avoid 后接动名词；want 后接不定式', 3.00, 2, 104),
(1313, 101, 2, 'Which of the following sentences use the subjunctive mood correctly?', '{"A": "If I were you, I would accept the offer.", "B": "I wish I had studied harder last semester.", "C": "He demanded that she leaves immediately.", "D": "It is important that he be present at the meeting."}', 'ABD', 'C 应为 leave (虚拟语气原形)，其余三项均为正确虚拟语气用法', 3.00, 3, 104),
(1314, 101, 2, 'In academic English writing, which of the following are considered formal?', '{"A": "furthermore", "B": "plus", "C": "consequently", "D": "moreover"}', 'ACD', 'plus 偏口语化；其余都是学术写作常用连接词', 3.00, 2, 104),
(1315, 101, 3, 'In English, the past tense of ''go'' is ''goed''.', NULL, '错误', 'go 是不规则动词，过去式为 went', 1.00, 1, 104),
(1316, 101, 3, 'The auxiliary verb ''do'' is used to form questions and negatives in the present tense.', NULL, '正确', 'do/does 在一般现在时中用于构成疑问句和否定句', 1.00, 1, 104),
(1317, 101, 3, 'In English, adjectives must agree with the gender and number of the noun they modify.', NULL, '错误', '英语形容词没有性数变化（与法语/西班牙语不同）', 1.00, 1, 104),
(1318, 101, 3, 'The phrase ''used to do'' indicates a past habit that no longer exists.', NULL, '正确', 'used to do 表示过去的习惯而现在不再如此', 1.00, 1, 104),
(1319, 101, 3, 'In a passive voice sentence, the doer of the action must always be mentioned.', NULL, '错误', '被动语态中 by + 施动者 可以省略，特别是当施动者不明确或不重要时', 1.00, 2, 104),
(1320, 101, 3, 'The present perfect continuous tense (have/has been doing) emphasizes the duration of an action that started in the past and continues to the present.', NULL, '正确', '现在完成进行时强调动作从过去到现在的持续性', 1.00, 2, 104),
(1321, 101, 4, 'Fill in the blank: She has been studying English ___ five years.', NULL, 'for', 'for + 时间段 表示持续时间', 2.00, 1, 104),
(1322, 101, 4, 'Translate into English: 我宁愿步行也不愿乘公交车。 I would rather walk ___ take the bus.', NULL, 'than', 'would rather A than B 是固定结构', 2.00, 2, 104),
(1323, 101, 4, 'Fill in the blank with the correct preposition: The conference will be held ___ Monday morning.', NULL, 'on', 'on + 具体的某一天（包括 Monday morning）', 2.00, 1, 104),
(1324, 101, 4, 'Complete the sentence: ___ the bad weather, the flight was delayed for three hours.', NULL, 'Because of', 'because of + 名词短语，作原因状语', 2.00, 1, 104),
(1325, 101, 5, 'What is the difference between ''few'' and ''a few'' when used with countable nouns? Give an example for each.', NULL, 'few 表示否定意义，意为''几乎没有''；a few 表示肯定意义，意为''有一些''。例如: He has few friends.（他几乎没有朋友。）He has a few friends.（他有几个朋友。）', 'few/little 表示否定的''几乎没有''；a few/a little 表示肯定的''有一些''', 5.00, 2, 104),
(1326, 101, 5, 'Briefly explain the structure of the third conditional in English and give an example.', NULL, '第三条件句结构: If + 过去完成时,would have + 过去分词。表示与过去事实相反的虚拟。例: If I had studied harder,I would have passed the exam.', '第三条件句用于表达对过去情况的虚拟假设，表示与过去事实相反', 5.00, 3, 104),
(1327, 101, 5, 'What are the main differences between British English and American English in terms of vocabulary? Give at least three pairs of examples.', NULL, '主要词汇差异举例: 1) lift (BrE) vs elevator (AmE) 电梯; 2) flat (BrE) vs apartment (AmE) 公寓; 3) lorry (BrE) vs truck (AmE) 卡车; 4) holiday (BrE) vs vacation (AmE) 假期; 5) autumn (BrE) vs fall (AmE) 秋季。', 'BrE 与 AmE 在词汇、拼写（colour/color）、语法上均有差异', 5.00, 2, 104),
(1328, 101, 5, 'Write a brief paragraph (about 50 words) introducing yourself in English, including your name, major, and one hobby.', NULL, '参考答案: My name is Li Ming. I am a freshman majoring in Computer Science at USTS Tianping College. I enjoy programming in my spare time,especially developing small applications using Java. Besides studying,I also love playing basketball with my classmates.', '自我介绍开放题，重点考查基本句法和语篇连贯性', 5.00, 1, 104),
(1329, 101, 1, 'He devoted himself ___ scientific research after retirement.', '{"A": "to", "B": "for", "C": "with", "D": "on"}', 'A', 'devote oneself to + n./v-ing 是固定搭配，to 是介词', 2.00, 1, 104),
(1330, 101, 1, 'The new policy will come ___ effect next month.', '{"A": "in", "B": "into", "C": "out", "D": "of"}', 'B', 'come into effect 生效，固定搭配', 2.00, 1, 104),
(1331, 101, 1, 'I''d rather you ___ smoke in the meeting room.', '{"A": "don''t", "B": "didn''t", "C": "not", "D": "won''t"}', 'B', 'would rather + 主语 + 过去时表示对现在/将来的虚拟意愿', 2.00, 2, 104),
(1332, 101, 1, 'No sooner had he sat down ___ the phone rang.', '{"A": "when", "B": "than", "C": "as", "D": "while"}', 'B', 'no sooner...than 是固定搭配，意为''一...就...''', 2.00, 3, 104),
(1333, 101, 1, 'The reason ___ he was late was that he missed the bus.', '{"A": "why", "B": "which", "C": "as", "D": "for which"}', 'A', 'reason 作先行词，定从中作原因状语用 why 或 for which', 2.00, 2, 104),
(1334, 101, 1, 'She objected to ___ as a guinea pig.', '{"A": "treat", "B": "be treated", "C": "being treated", "D": "having treated"}', 'C', 'object to 中 to 是介词，后接动名词；又因 she 与 treat 是被动关系，用 being treated', 2.00, 3, 104),
(1335, 101, 1, 'If only I ___ harder when I was young!', '{"A": "had worked", "B": "worked", "C": "work", "D": "would work"}', 'A', 'if only 引导的虚拟语气，对过去的虚拟用过去完成时', 2.00, 2, 104),
(1336, 101, 1, 'The committee consists ___ ten members.', '{"A": "with", "B": "in", "C": "of", "D": "from"}', 'C', 'consist of 由...组成，固定搭配', 2.00, 1, 104),
(1337, 101, 1, 'Such ___ the case, we had to call off the meeting.', '{"A": "is", "B": "being", "C": "be", "D": "to be"}', 'B', 'such being the case 是独立主格结构，意为''情况如此''', 2.00, 3, 104),
(1338, 101, 1, 'The manager along with his assistants ___ to attend the conference.', '{"A": "is", "B": "are", "C": "were", "D": "have"}', 'A', 'along with 连接的主语，谓语与主语一致（manager 单数）', 2.00, 2, 104),
(1339, 101, 1, 'She is ___ a writer ___ a journalist.', '{"A": "not only; but also", "B": "both; nor", "C": "neither; or", "D": "either; nor"}', 'A', 'not only A but also B 既是...也是...', 2.00, 1, 104),
(1340, 101, 1, 'His proposal is worth ___ further.', '{"A": "discussing", "B": "to discuss", "C": "discussed", "D": "being discussed"}', 'A', 'be worth + v-ing（主动表被动）', 2.00, 2, 104),
(1341, 101, 2, 'Which of the following are linking words used to express contrast?', '{"A": "however", "B": "nevertheless", "C": "moreover", "D": "yet"}', 'ABD', 'however/nevertheless/yet 都表转折；moreover 表递进', 3.00, 2, 104),
(1342, 101, 2, 'Which sentences contain a dangling modifier (悬垂修饰)?', '{"A": "Walking down the street, the trees were beautiful.", "B": "Walking down the street, I saw beautiful trees.", "C": "Having finished homework, the TV was turned on by me.", "D": "Having finished homework, I turned on the TV."}', 'AC', 'A 和 C 的现在分词的逻辑主语与主句主语不一致，属悬垂修饰', 3.00, 3, 104),
(1343, 101, 2, 'Which of the following expressions can introduce a personal opinion in an essay?', '{"A": "In my view", "B": "It seems to me that", "C": "Without a doubt", "D": "From my perspective"}', 'ABD', 'without a doubt 表示绝对肯定，更适合陈述事实而非个人观点', 3.00, 2, 104),
(1344, 101, 2, 'Which words have an /æ/ sound (like in ''cat'')?', '{"A": "map", "B": "make", "C": "happy", "D": "bath"}', 'ACD', 'map/happy/bath 含 /æ/；make 是 /eɪ/', 3.00, 1, 104),
(1345, 101, 3, '''Less'' is used with countable nouns and ''fewer'' is used with uncountable nouns.', NULL, '错误', '正好相反：fewer 用于可数，less 用于不可数', 1.00, 2, 104),
(1346, 101, 3, 'An academic essay typically has an introduction, body, and conclusion.', NULL, '正确', '学术论文的标准结构：引言、主体、结论', 1.00, 1, 104),
(1347, 101, 3, 'The infinitive ''to'' must always be placed immediately before the verb (no split infinitive).', NULL, '错误', '现代英语接受 split infinitive，例如 to boldly go', 1.00, 2, 104),
(1348, 101, 3, 'Topic sentences are usually placed at the beginning of a paragraph in English writing.', NULL, '正确', '英语段落写作中，主题句通常居首', 1.00, 1, 104),
(1349, 101, 3, 'Synonyms always have the exact same connotation in English.', NULL, '错误', '同义词常有语义/感情色彩差异，如 thin/slim/skinny', 1.00, 2, 104),
(1350, 101, 3, 'The phrase ''on the contrary'' is used to show agreement with a previous statement.', NULL, '错误', 'on the contrary 表示相反观点', 1.00, 1, 104),
(1351, 101, 4, 'Translate: 他不仅会说英语，还会说法语。 He can speak ___ English ___ French.', NULL, 'not only;but also', 'not only...but also 不仅...而且', 2.00, 1, 104),
(1352, 101, 4, 'Fill in: It''s high time we ___ (leave) for the airport.', NULL, 'left', 'it''s high time + 过去虚拟语气', 2.00, 2, 104),
(1353, 101, 4, 'Complete: I look forward to ___ (hear) from you soon.', NULL, 'hearing', 'look forward to 中 to 是介词，后接 v-ing', 2.00, 1, 104),
(1354, 101, 4, 'Fill in the appropriate connective: ___ being tired, she continued working.', NULL, 'Despite', 'despite + n./v-ing 表让步', 2.00, 2, 104),
(1355, 101, 5, 'Explain the difference between ''specially'' and ''especially'' with one example each.', NULL, 'especially 强调''尤其、特别（在众多中突出某一项）''；specially 强调''特地、专门（为某目的）''。例：This book was specially designed for beginners.（这本书是专门为初学者设计的。）I love fruits,especially apples.（我喜欢水果，尤其是苹果。）', '两词常被混淆，关键看强调点', 5.00, 2, 104),
(1356, 101, 5, 'Write a thesis statement for an essay on ''The advantages and disadvantages of online learning'' (about 30 words).', NULL, '参考答案: While online learning offers flexibility and accessibility to a broader audience,it also presents challenges such as reduced social interaction and the requirement for strong self-discipline.', '论点句应清晰表达正反两面或主要立场', 5.00, 2, 104),
(1357, 101, 5, 'Briefly explain what ''cohesion'' and ''coherence'' mean in academic writing.', NULL, 'Cohesion (衔接) 指的是句子之间通过连接词、代词、重复等手段在表面上形成的链接；coherence (连贯) 指段落和篇章在内容、逻辑上的紧密一致。前者着眼于语言形式，后者关注思想逻辑。', '学术写作两大支柱', 5.00, 3, 104),
(1358, 101, 5, 'Explain when to use ''whose'' as a relative pronoun, with an example.', NULL, 'whose 用作关系代词，表示所属关系，可用于指代人或物，引导定语从句。例：The girl whose father is a doctor is my friend. The book whose cover is red is mine.', 'whose 是 of which/of whom 的简洁替代', 5.00, 2, 104),
(1359, 101, 1, 'I ___ TV when my mother came in.', '{"A": "watched", "B": "was watching", "C": "watch", "D": "am watching"}', 'B', '过去进行时:was/were + V-ing', 2.00, 2, 104),
(1360, 101, 1, 'She ___ to Beijing twice.', '{"A": "has been", "B": "has gone", "C": "went", "D": "goes"}', 'A', 'has been to 去过(已回);has gone to 去了(未回)', 2.00, 2, 104),
(1361, 101, 1, 'By next year, I ___ here for ten years.', '{"A": "will work", "B": "will be working", "C": "will have worked", "D": "work"}', 'C', '将来完成时 will have V-ed', 2.00, 3, 104),
(1362, 101, 1, 'If I ___ you, I would accept the offer.', '{"A": "am", "B": "were", "C": "be", "D": "was"}', 'B', '虚拟语气过去时用 were', 2.00, 3, 104),
(1363, 101, 1, 'He said he ___ to the cinema.', '{"A": "goes", "B": "went", "C": "had gone", "D": "has gone"}', 'C', '主句过去时,从句过去完成', 2.00, 2, 104),
(1364, 101, 1, 'The bus ___ at 8 every morning.', '{"A": "leave", "B": "leaves", "C": "is leaving", "D": "left"}', 'B', '一般现在时第三人称单数', 2.00, 1, 104),
(1365, 101, 1, 'She ___ her homework already.', '{"A": "finished", "B": "has finished", "C": "is finishing", "D": "finishes"}', 'B', 'already 用现在完成时', 2.00, 2, 104),
(1366, 101, 1, 'Look! It ___ outside.', '{"A": "rains", "B": "rained", "C": "is raining", "D": "has rained"}', 'C', 'Look! 用现在进行', 2.00, 1, 104),
(1367, 101, 1, 'I ___ him for ten years.', '{"A": "know", "B": "knew", "C": "have known", "D": "am knowing"}', 'C', 'for + 时段用现在完成', 2.00, 2, 104),
(1368, 101, 1, 'When I got home, my mother ___ dinner.', '{"A": "cooked", "B": "was cooking", "C": "has cooked", "D": "is cooking"}', 'B', 'when + 过去时,主句过去进行', 2.00, 2, 104),
(1369, 101, 1, 'English ___ all over the world.', '{"A": "speaks", "B": "is speaking", "C": "is spoken", "D": "spoke"}', 'C', '被动语态 is spoken', 2.00, 2, 104),
