(1599, 101, 4, 'child 复数是____', NULL, 'children', 'children', 2.00, 2, 104),
(1600, 101, 4, 'mouse 复数是____', NULL, 'mice', 'mice', 2.00, 2, 104),
(1601, 101, 5, 'Please explain what you do every day.', NULL, 'My typical day starts at 7 a.m. After getting up,I wash my face and have breakfast. Then I go to university by bus. I have classes from 8 to 12. After lunch,I study at the library or do experiments in the lab from 2 to 5 p.m. In the evening,I have dinner with my roommates. Then I review my lessons or do homework until 10 p.m. Before going to bed at 11,I read books or watch news. Weekends are different - I usually exercise,meet friends,or go shopping.', '日常生活', 5.00, 1, 104),
(1602, 101, 5, 'Please write a short text about a recent book you read.', NULL, 'I recently finished reading ''The Three-Body Problem'' by Liu Cixin. It is a science fiction novel set in a complex universe. The book tells a story about humanity''s first contact with an alien civilization. What impressed me most is the author''s grand imagination of cosmic sociology and the depth of philosophical questions raised. The characters are vivid,especially Ye Wenjie whose decisions shape humanity''s destiny. The book made me think deeply about science,civilization,and our place in the universe. I highly recommend it to anyone interested in deep science fiction.', '读后感', 5.00, 2, 104);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(1603, 102, 1, '设 A 为 3 阶方阵，|A| = 2，则 |2A| = ?', '{"A": "4", "B": "8", "C": "16", "D": "6"}', 'C', '|kA| = k^n × |A|，n=3 时 |2A| = 8 × 2 = 16', 2.00, 1, 107),
(1604, 102, 1, '若 A 是可逆矩阵，则下列说法错误的是', '{"A": "|A| ≠ 0", "B": "A 的行向量组线性无关", "C": "齐次方程 Ax=0 只有零解", "D": "A 必为对称矩阵"}', 'D', '可逆矩阵不必是对称矩阵', 2.00, 1, 107),
(1605, 102, 1, '设 n 阶矩阵 A 的秩 r(A) = r，则齐次方程 Ax=0 的基础解系含解向量个数为', '{"A": "r", "B": "n-r", "C": "n", "D": "n+r"}', 'B', '齐次方程基础解系含 n - r(A) 个线性无关解向量', 2.00, 2, 107),
(1606, 102, 1, '设 α₁, α₂, α₃ 线性相关，则下列必成立的是', '{"A": "每一个向量都可由其余向量线性表示", "B": "至少存在一个向量可由其余向量线性表示", "C": "α₁ 一定可由 α₂, α₃ 线性表示", "D": "必有 α₁ = 0"}', 'B', '线性相关定义：存在不全为零的 k₁,k₂,k₃ 使 k₁α₁+k₂α₂+k₃α₃=0，至少一个系数非零的向量可表示', 2.00, 2, 107),
(1607, 102, 1, '已知 λ=2 是矩阵 A 的特征值，则 A² 必有特征值', '{"A": "2", "B": "4", "C": "-2", "D": "1/2"}', 'B', '若 Aα=λα，则 A²α=λ²α，故 A² 有特征值 λ²=4', 2.00, 1, 107),
(1608, 102, 1, '设 3 阶矩阵 A 的特征值为 1, 2, 3，则 |A| = ?', '{"A": "3", "B": "6", "C": "5", "D": "0"}', 'B', '|A| = 全部特征值的乘积 = 1 × 2 × 3 = 6', 2.00, 1, 107),
(1609, 102, 1, '设 n 元齐次线性方程组 Ax=0 的系数矩阵秩为 r，则该方程组', '{"A": "当 r=n 时只有零解", "B": "当 r<n 时无解", "C": "当 r>n 时有无穷多解", "D": "任何情况下都有非零解"}', 'A', 'r(A)=n 时只有零解；r(A)<n 时有无穷多解', 2.00, 1, 107),
(1610, 102, 1, '二次型 f = x₁² + 2x₂² + 3x₃² 的矩阵为', '{"A": "diag(1,2,3)", "B": "diag(1,1,1)", "C": "diag(2,4,6)", "D": "上三角"}', 'A', '二次型矩阵是对角矩阵 diag(1,2,3)', 2.00, 1, 107),
(1611, 102, 1, '设 A 与 B 都是 n 阶方阵，下列等式恒成立的是', '{"A": "AB = BA", "B": "(AB)ᵀ = AᵀBᵀ", "C": "(A+B)² = A² + 2AB + B²", "D": "|AB| = |A| × |B|"}', 'D', '行列式有 |AB|=|A||B|；矩阵乘法不满足交换律和(A+B)²的展开式（含 AB+BA）', 2.00, 2, 107),
(1612, 102, 1, '若实对称矩阵 A 与 B 合同，则它们', '{"A": "必相似", "B": "特征值相同", "C": "正负惯性指数相同", "D": "一定都正定"}', 'C', '实对称矩阵合同充要条件是正、负惯性指数相同', 2.00, 3, 107),
(1613, 102, 1, '行列式 |A| = 0 当且仅当', '{"A": "A 的行向量组线性相关", "B": "A 是零矩阵", "C": "A 是上三角矩阵", "D": "A 是反对称矩阵"}', 'A', '|A|=0 的充要条件是 A 不可逆，即行（列）向量组线性相关', 2.00, 1, 107),
(1614, 102, 1, '设 A 是 m×n 矩阵，r(A)=r，则非齐次方程 Ax=b 有解的充要条件是', '{"A": "r(A) = m", "B": "r(A) = n", "C": "r(A) = r(A|b)", "D": "r(A) < r(A|b)"}', 'C', '非齐次方程有解 ⟺ 系数矩阵秩 = 增广矩阵秩', 2.00, 2, 107),
(1615, 102, 2, '下列关于行列式性质的叙述中，正确的是', '{"A": "互换两行行列式变号", "B": "某一行乘以 k，行列式变为原来的 k 倍", "C": "两行成比例则行列式为 0", "D": "任意两行交换，行列式不变"}', 'ABC', 'D 错误，互换两行行列式变号；其余均为基本性质', 3.00, 2, 107),
(1616, 102, 2, '下列关于矩阵可逆的等价条件，正确的是', '{"A": "|A| ≠ 0", "B": "A 的列向量组线性无关", "C": "齐次方程 Ax=0 只有零解", "D": "r(A) = n"}', 'ABCD', '以上均为 n 阶方阵 A 可逆的等价命题', 3.00, 2, 107),
(1617, 102, 2, '设 A 是 n 阶方阵，A 的特征值都为正，则 A 是', '{"A": "可逆的", "B": "|A| > 0", "C": "必为对称阵", "D": "非奇异的"}', 'ABD', '特征值全为正 ⟹ |A|=∏λ>0 ⟹ A 可逆/非奇异；但不一定对称', 3.00, 3, 107),
(1618, 102, 2, '实二次型 f = xᵀAx 正定的充要条件包括', '{"A": "A 的所有特征值大于 0", "B": "A 的所有顺序主子式大于 0", "C": "A 与单位矩阵合同", "D": "|A| > 0"}', 'ABC', 'D 仅是必要条件，不充分（需所有顺序主子式 > 0）', 3.00, 3, 107),
(1619, 102, 3, '任何方阵都可对角化。', NULL, '错误', '只有 n 个线性无关特征向量的方阵才可对角化', 1.00, 2, 107),
(1620, 102, 3, '实对称矩阵的不同特征值对应的特征向量正交。', NULL, '正确', '实对称矩阵的重要性质：不同特征值对应特征向量正交', 1.00, 2, 107),
(1621, 102, 3, '行列式与矩阵是同一个概念。', NULL, '错误', '行列式是一个数值，而矩阵是数表；只有方阵才有行列式', 1.00, 1, 107),
(1622, 102, 3, '对任意矩阵 A，都有 (Aᵀ)ᵀ = A。', NULL, '正确', '转置的转置等于原矩阵', 1.00, 1, 107),
(1623, 102, 3, '若 A, B 都可逆，则 (AB)⁻¹ = A⁻¹B⁻¹。', NULL, '错误', '应为 (AB)⁻¹ = B⁻¹A⁻¹（注意顺序）', 1.00, 2, 107),
(1624, 102, 3, '实对称矩阵正定 ⟺ 所有特征值都是正实数。', NULL, '正确', '实对称矩阵正定的充要条件之一', 1.00, 2, 107),
(1625, 102, 4, '3 阶单位矩阵 E 的行列式 |E| = ___。', NULL, '1', '单位矩阵行列式恒为 1', 2.00, 1, 107),
(1626, 102, 4, '若 A 是 n 阶方阵，|A|=5，则 |A*| = ___（A* 为伴随矩阵，n=3）。', NULL, '25', '|A*| = |A|^(n-1)，n=3 时 = 5² = 25', 2.00, 2, 107),
(1627, 102, 4, '二次型 x₁² + x₂² - x₃² 的正惯性指数为 ___。', NULL, '2', '正惯性指数 = 标准形中正项个数 = 2', 2.00, 2, 107),
(1628, 102, 4, '向量组 α₁=(1,0,0), α₂=(0,1,0), α₃=(1,1,0) 的秩为 ___。', NULL, '2', 'α₃ = α₁ + α₂，所以最大无关组为 α₁,α₂，秩为 2', 2.00, 2, 107),
(1629, 102, 5, '简述矩阵的初等行变换有哪三种？这些变换的几何意义或代数意义是什么？', NULL, '三种初等行变换：(1) 互换两行 (2) 某一行乘以非零常数 k (3) 某行加上另一行的 k 倍。代数意义：用初等矩阵左乘原矩阵实现，不改变矩阵的秩，可用于求逆、解方程、求秩、化阶梯形', '初等变换是线性代数的基本工具', 5.00, 2, 107),
(1630, 102, 5, '什么是矩阵 A 的特征值与特征向量？写出求解 n 阶方阵 A 全部特征值的标准步骤。', NULL, '若存在非零向量 α 和数 λ 使 Aα=λα，则 λ 是 A 的特征值，α 是对应特征向量。求解步骤：(1) 写出特征多项式 |λE-A|=0；(2) 解多项式方程得 λ₁,λ₂,...,λₙ；(3) 对每个 λᵢ 解 (λᵢE-A)x=0 得对应特征向量', '特征值/向量是矩阵对角化的核心概念', 5.00, 2, 107),
(1631, 102, 5, '判断向量组 α₁=(1,2,3), α₂=(2,4,6), α₃=(0,1,2) 是否线性相关，并说明理由。', NULL, '线性相关。因为 α₂ = 2α₁，所以这三个向量已线性相关（无需考虑 α₃）。或：将 (α₁,α₂,α₃) 拼成矩阵作初等行变换，秩 = 2 < 3，故线性相关', '线性相关的几种判定方法', 5.00, 1, 107),
(1632, 102, 5, '叙述实对称矩阵正交相似对角化的步骤。', NULL, '步骤：(1) 求 A 的特征值 λ₁,...,λₙ（实对称矩阵特征值都为实数）；(2) 对每个特征值求基础解系得特征向量；(3) 不同特征值对应的特征向量已正交，重特征值对应特征向量需 Schmidt 正交化；(4) 单位化所有特征向量得正交矩阵 Q；(5) 则 QᵀAQ = diag(λ₁,...,λₙ)', '是二次型化标准形和主轴定理的核心', 5.00, 3, 107),
(1633, 102, 1, '设 A 为 3 阶矩阵，|A|=2，则 |2A| 等于', '{"A": "4", "B": "8", "C": "16", "D": "2"}', 'C', '|kA| = k^n · |A|，n 为阶数。|2A| = 2³·2 = 16', 2.00, 2, 107),
(1634, 102, 1, '若矩阵 A 可逆，则下列说法正确的是', '{"A": "|A|=0", "B": "A 的列向量线性相关", "C": "A 的秩等于阶数", "D": "A 必为对称矩阵"}', 'C', '可逆 ⇔ 满秩 ⇔ |A|≠0 ⇔ 列向量线性无关', 2.00, 1, 107),
(1635, 102, 1, '设 A、B 为同阶可逆矩阵，则 (AB)⁻¹ 等于', '{"A": "A⁻¹B⁻¹", "B": "B⁻¹A⁻¹", "C": "(BA)⁻¹", "D": "A⁻¹+B⁻¹"}', 'B', '矩阵乘积的逆等于各自逆的逆序乘积', 2.00, 2, 107),
(1636, 102, 1, 'n 阶单位矩阵 E 的行列式 |E| 等于', '{"A": "0", "B": "n", "C": "1", "D": "n!"}', 'C', '单位矩阵主对角线全为 1，其余为 0，|E|=1', 2.00, 1, 107),
(1637, 102, 1, '设 λ 是方阵 A 的特征值，则 A² 的特征值是', '{"A": "λ", "B": "λ²", "C": "2λ", "D": "1/λ"}', 'B', '若 Ax=λx，则 A²x=A(λx)=λ²x，故 λ² 是 A² 的特征值', 2.00, 2, 107),
(1638, 102, 1, '向量组 α₁,α₂,α₃ 线性相关的充要条件是', '{"A": "其中某向量为零向量", "B": "其中至少有一向量可由其余向量线性表示", "C": "其中任意两个向量成比例", "D": "其中存在两个相等向量"}', 'B', '线性相关 ⇔ 至少有一个向量可由其余向量线性表示', 2.00, 2, 107),
(1639, 102, 1, '若 n 元齐次线性方程组 Ax=0 仅有零解，则', '{"A": "R(A)<n", "B": "R(A)=n", "C": "R(A)>n", "D": "|A|=0"}', 'B', '齐次方程组仅有零解 ⇔ 系数矩阵满秩 ⇔ R(A)=n', 2.00, 2, 107),
(1640, 102, 1, '已知 A=[[1,2],[3,4]]，则 A 的特征多项式为', '{"A": "λ²-5λ-2", "B": "λ²-5λ+2", "C": "λ²+5λ-2", "D": "λ²-4λ-1"}', 'A', '|λE-A|=(λ-1)(λ-4)-6=λ²-5λ-2', 3.00, 3, 107),
(1641, 102, 1, '下列哪个矩阵是正交矩阵', '{"A": "[[1,0],[0,1]]", "B": "[[1,1],[0,1]]", "C": "[[1,0],[1,1]]", "D": "[[2,0],[0,2]]"}', 'A', '正交矩阵满足 A^T·A=E。单位矩阵显然正交', 2.00, 2, 107),
(1642, 102, 1, '若 A、B 均为 n 阶方阵，下列等式一定成立的是', '{"A": "AB=BA", "B": "(A+B)²=A²+2AB+B²", "C": "(AB)^T=B^T·A^T", "D": "|A+B|=|A|+|B|"}', 'C', '矩阵乘积转置等于各自转置的逆序乘积，是必然成立的等式', 2.00, 2, 107),
(1643, 102, 1, '对 n 阶矩阵 A，下列等价于 A 不可逆的是', '{"A": "R(A)=n", "B": "|A|=0", "C": "A 的特征值全非零", "D": "A 的列向量线性无关"}', 'B', 'A 不可逆 ⇔ |A|=0 ⇔ R(A)<n ⇔ 列向量线性相关 ⇔ 0 是特征值', 2.00, 1, 107),
(1644, 102, 1, '向量 α=(1,2,3) 与 β=(2,4,6) 的关系是', '{"A": "正交", "B": "线性无关", "C": "线性相关", "D": "等价"}', 'C', 'β=2α，故二者线性相关', 2.00, 1, 107),
(1645, 102, 2, '下列性质属于行列式的有', '{"A": "交换两行行列式变号", "B": "某行乘以 k 行列式扩大 k 倍", "C": "某行加另一行的 k 倍行列式不变", "D": "转置后行列式取反"}', 'ABC', '前三个都是行列式基本性质；行列式转置不变号', 3.00, 2, 107),
(1646, 102, 2, '矩阵 A 的秩等于 r 的等价表述有', '{"A": "A 有 r 阶非零子式", "B": "A 的所有 (r+1) 阶子式全为 0", "C": "A 经初等变换可化为含 r 个非零行的阶梯形", "D": "A 必为方阵"}', 'ABC', '矩阵秩的定义不要求矩阵为方阵，故 D 错', 3.00, 2, 107),
(1647, 102, 2, 'n 元非齐次线性方程组 Ax=b 有解的等价条件有', '{"A": "R(A)=R(A,b)", "B": "(A,b) 经初等行变换可化为阶梯形且无 (0,…,0,c) 形式行 (c≠0)", "C": "|A|≠0", "D": "R(A,b)≤n"}', 'AB', '前两项是有解的等价条件；C 是有唯一解的条件 (限方阵)；D 永远成立', 3.00, 3, 107),
(1648, 102, 3, '若方阵 A 满足 A²=E，则 A 是可逆的', NULL, '正确', 'A²=E 说明 A 的逆为 A 本身', 1.00, 1, 107),
(1649, 102, 3, '两个 n 阶矩阵的乘法满足交换律', NULL, '错误', '矩阵乘法一般不满足交换律 AB≠BA', 1.00, 1, 107),
(1650, 102, 3, 'n 阶方阵 A 的行列式等于其特征值的乘积', NULL, '正确', '|A|=λ₁λ₂…λₙ，这是特征多项式的常数项性质', 1.00, 2, 107),
(1651, 102, 3, '矩阵的初等行变换会改变其行列式的值', NULL, '错误', '互换两行变号；倍乘一行变倍数；倍加一行行不变。会改变但不一定', 1.00, 2, 107),
(1652, 102, 3, '若 R(A)=R(A,b)<n，则线性方程组 Ax=b 有无穷多解', NULL, '正确', '有解（R(A)=R(A,b)）且自由变量数 n-R(A)>0，故有无穷多解', 1.00, 2, 107),
(1653, 102, 3, '实对称矩阵的特征值都是实数', NULL, '正确', '实对称矩阵的特征值为实数，且不同特征值对应特征向量正交', 1.00, 2, 107),
(1654, 102, 4, '若 A 是 3 阶方阵，|A|=3，则 |A⁻¹|=____', NULL, '1/3', '|A⁻¹|=1/|A|=1/3', 2.00, 1, 107),
(1655, 102, 4, '若 A 是 n 阶方阵，R(A)=r，则方程 Ax=0 的基础解系含 ____ 个向量', NULL, 'n-r', '基础解系的向量个数 = 自由未知数个数 = n - R(A)', 2.00, 2, 107),
(1656, 102, 4, '设 α=(1,2,2)，β=(3,1,2)，则 α 与 β 的内积 (α,β)=____', NULL, '9', '(α,β)=1·3+2·1+2·2=3+2+4=9', 2.00, 1, 107),
(1657, 102, 4, '若矩阵 A 的所有特征值都不为 0，则 A ____ 可逆 (填''是''或''否'')', NULL, '是', '0 不是特征值 ⇔ |A|≠0 ⇔ A 可逆', 2.00, 2, 107),
(1658, 102, 5, '简述矩阵 A 与其转置 A^T 行列式的关系，并简要证明', NULL, '|A^T|=|A|。证明：行列式按行展开等价于按列展开，转置后行变列，行列式值不变。或：行列式是关于矩阵元素的多项式，转置后所有项形式不变，故值不变。', '行列式的转置不变性', 5.00, 2, 107),
(1659, 102, 5, '求矩阵 A=[[2,1],[1,2]] 的特征值与特征向量', NULL, '特征方程 |λE-A|=(λ-2)²-1=(λ-1)(λ-3)=0，得 λ₁=1,λ₂=3。对 λ₁=1：(E-A)x=0 → [[-1,-1],[-1,-1]]x=0，得 ξ₁=(1,-1)^T；对 λ₂=3：(3E-A)x=0 → [[1,-1],[-1,1]]x=0，得 ξ₂=(1,1)^T', '求特征值步骤：解特征方程；求特征向量：解 (λE-A)x=0', 5.00, 2, 107),
(1660, 102, 5, '判断向量组 α₁=(1,2,3), α₂=(2,4,6), α₃=(1,1,1) 的线性相关性', NULL, '构造矩阵 A=[α₁,α₂,α₃]，化为阶梯形：第二列 = 2·第一列，故 R(A)≤2<3，向量组线性相关。事实上 α₂=2α₁', '线性相关 ⇔ 秩 < 向量个数', 5.00, 2, 107),
(1661, 102, 5, '什么是矩阵的相似？写出相似矩阵的主要性质（至少 3 条）', NULL, '定义：若存在可逆矩阵 P，使 P⁻¹AP=B，则称 A 与 B 相似。性质：(1) 反身性、对称性、传递性；(2) 相似矩阵有相同的特征多项式与特征值；(3) 相似矩阵的秩相等、行列式相等、迹相等；(4) 若 A 可对角化，则相似于对角矩阵。', '相似是线代核心概念，连接特征值与对角化', 5.00, 3, 107),
(1662, 102, 1, '二阶行列式 |1 2; 3 4| 等于', '{"A": "-2", "B": "2", "C": "-5", "D": "5"}', 'A', '1*4-2*3=-2', 2.00, 2, 107),
(1663, 102, 1, '二阶行列式 |a b; c d| 等于', '{"A": "ac-bd", "B": "ad-bc", "C": "ab-cd", "D": "ad+bc"}', 'B', '主对角积-副对角积', 2.00, 1, 107),
