(1860, 102, 4, '二阶行列式 |a b; c d| 等于____', NULL, 'ad-bc', '主对角积-副对角积', 2.00, 2, 107),
(1861, 102, 4, '|kA| 等于____', NULL, 'k^n|A|', '|kA|=k^n|A|', 2.00, 3, 107),
(1862, 102, 4, '|AB| 等于____', NULL, '|A||B|', '乘积行列式', 2.00, 2, 107),
(1863, 102, 4, '|A^T| 等于____', NULL, '|A|', '转置不变', 2.00, 2, 107),
(1864, 102, 4, '|A^(-1)| 等于____', NULL, '1/|A|', '逆的行列式', 2.00, 3, 107),
(1865, 102, 4, '可逆矩阵的充要条件是 |A|____0', NULL, '≠', '|A|≠0', 2.00, 2, 107),
(1866, 102, 4, '矩阵逆的公式 A^(-1) = ____ / |A|', NULL, 'A*', 'A^-1=A*/|A|', 2.00, 3, 107),
(1867, 102, 4, '(AB)^T = ____', NULL, 'B^T A^T', '转置乘积', 2.00, 3, 107),
(1868, 102, 4, '(AB)^(-1) = ____', NULL, 'B^(-1) A^(-1)', '逆乘积', 2.00, 3, 107),
(1869, 102, 4, '对称矩阵满足 A = ____', NULL, 'A^T', '对称定义', 2.00, 2, 107),
(1870, 102, 4, '正交矩阵 Q 满足 Q^T Q = ____', NULL, 'I', '正交定义', 2.00, 3, 107),
(1871, 102, 4, '正交矩阵的行列式 = ____', NULL, '±1', '|Q|=±1', 2.00, 3, 107),
(1872, 102, 4, 'Ax=0 有非零解 ⇔ r(A) ____ n', NULL, '<', '非零解条件', 2.00, 3, 107),
(1873, 102, 4, 'Ax=b 有解 ⇔ r(A) ____ r(A|b)', NULL, '=', '有解条件', 2.00, 3, 107),
(1874, 102, 4, '齐次方程基础解系含 ____ 个向量', NULL, 'n-r(A)', '基础解系数', 2.00, 3, 107),
(1875, 102, 4, '特征方程 |A - λI| = ____', NULL, '0', '特征方程', 2.00, 3, 107),
(1876, 102, 4, '特征值之和 = ____', NULL, 'tr(A)', '∑λ=tr', 2.00, 3, 107),
(1877, 102, 4, '特征值之积 = ____', NULL, '|A|', '∏λ=|A|', 2.00, 3, 107),
(1878, 102, 4, '实对称矩阵的特征值都是 ____ 数', NULL, '实', '实对称→实', 2.00, 3, 107),
(1879, 102, 4, '实对称矩阵不同特征值的特征向量 ____', NULL, '正交', '正交', 2.00, 3, 107),
(1880, 102, 4, '正定矩阵的特征值都 > ____', NULL, '0', '正定→λ>0', 2.00, 3, 107),
(1881, 102, 4, '二次型 f(x) = x^T A x 中 A 一般取 ____ 矩阵', NULL, '对称', '二次型矩阵对称', 2.00, 3, 107),
(1882, 102, 4, '秩-零度定理:r(A) + dim N(A) = ____', NULL, 'n', '秩+零空间维数=n', 2.00, 3, 107),
(1883, 102, 4, 'SVD 分解形式 A = ____', NULL, 'UΣV^T', '奇异值分解', 2.00, 3, 107),
(1884, 102, 4, 'Cholesky 分解形式 A = ____', NULL, 'LL^T', 'Cholesky', 2.00, 3, 107),
(1885, 102, 4, '施密特正交化用于构造 ____ 基', NULL, '正交', '正交基', 2.00, 3, 107),
(1886, 102, 4, 'Cayley-Hamilton 定理:矩阵满足 ____', NULL, '特征方程', 'Cayley-Hamilton', 2.00, 3, 107),
(1887, 102, 4, '矩阵的迹 tr(A) 是主对角线元素之 ____', NULL, '和', 'trace=对角和', 2.00, 2, 107),
(1888, 102, 4, 'tr(AB) ____ tr(BA)', NULL, '=', '迹性质', 2.00, 3, 107),
(1889, 102, 4, '奇异值是 A^T A 特征值的 ____ 平方根', NULL, '非负', '奇异值定义', 2.00, 3, 107),
(1890, 102, 5, '简述行列式的基本性质', NULL, '行列式 6 大基本性质:1)|A^T|=|A| 转置不变;2)互换两行(列)行列式变号;3)某行(列)全为 0,则行列式 = 0;4)某行(列)乘 k,行列式乘 k(整体|kA|=k^n|A|);5)两行(列)成比例,行列式 = 0;6)某行加上另一行的 k 倍,行列式不变。这些性质用于行列式的计算和简化。', '行列式性质', 5.00, 2, 107),
(1891, 102, 5, '简述矩阵可逆的充要条件', NULL, 'n 阶矩阵 A 可逆的等价条件(都互为充要):1)|A|≠0(行列式不为零);2)r(A)=n(满秩);3)Ax=0 只有零解;4)A 的行(列)向量线性无关;5)A 是初等矩阵的乘积;6)A 与单位矩阵 I 行(列)等价;7)A 的特征值都不为 0;8)存在矩阵 B 使 AB=BA=I。可逆矩阵又称非奇异矩阵。', '可逆条件', 5.00, 2, 107),
(1892, 102, 5, '简述高斯消元法', NULL, '高斯消元法是解线性方程组 Ax=b 的标准方法:1)写出增广矩阵 [A|b];2)用初等行变换:互换、倍乘、倍加,将其化为行阶梯形;3)从最后一个非零方程开始,逐次回代求解。Gauss-Jordan 消元法进一步把上三角化为对角(简化形式)。优点:通用、系统、可编程。复杂度 O(n^3)。可同时判断方程组解的情况(唯一/无穷/无解)。', '高斯消元', 5.00, 2, 107),
(1893, 102, 5, '简述向量组的线性相关与无关', NULL, '向量组 α₁,α₂,...,αₛ:1)线性相关:存在一组不全为零的数 k₁,k₂,...,kₛ 使 k₁α₁+...+kₛαₛ=0。等价:至少一个向量是其余的线性组合;2)线性无关:仅当 k₁=k₂=...=kₛ=0 时上式才成立。等价:每个向量都不能由其余向量表示。判定:对应向量组成的矩阵秩 = 向量个数则无关。重要结论:n+1 个 n 维向量必相关;含零向量的向量组必相关。', '线性相关', 5.00, 3, 107),
(1894, 102, 5, '简述线性方程组解的判定', NULL, '对线性方程组 Ax=b(A 为 m×n 矩阵):1)无解 ⇔ r(A) ≠ r(A|b)(系数秩 ≠ 增广秩);2)有解 ⇔ r(A) = r(A|b)。在有解的情况下:①唯一解 ⇔ r(A) = r(A|b) = n(秩 = 未知数个数);②无穷多解 ⇔ r(A) = r(A|b) < n。对齐次方程 Ax=0:必有零解,有非零解 ⇔ r(A) < n。', '解的判定', 5.00, 3, 107),
(1895, 102, 5, '简述特征值与特征向量', NULL, '对 n 阶矩阵 A,若存在数 λ 和非零向量 α 使 Aα=λα,则 λ 是 A 的特征值,α 是关于 λ 的特征向量。求法:1)由 (A-λI)α=0 知特征方程 |A-λI|=0(λ 的 n 次多项式);2)解出 n 个特征值(可重);3)对每个 λ_i,代入 (A-λ_iI)x=0 求基础解系,即特征向量。性质:不同特征值的特征向量线性无关;实对称矩阵的特征值为实数,且不同特征值的特征向量正交。', '特征值', 5.00, 3, 107),
(1896, 102, 5, '简述矩阵相似与对角化', NULL, '相似:存在可逆矩阵 P 使 P^(-1)AP=B,记 A~B。相似矩阵保持迹、行列式、秩、特征多项式不变。对角化:A 与某对角矩阵 D 相似,即存在 P 使 P^(-1)AP=D。条件:A 可对角化 ⇔ A 有 n 个线性无关的特征向量。实对称矩阵必可对角化(可正交对角化:存在正交 Q 使 Q^T AQ=D)。对角化简化矩阵幂运算:A^k = PD^k P^(-1)。', '对角化', 5.00, 3, 107),
(1897, 102, 5, '简述二次型及其标准化', NULL, '二次型:n 元二次齐次多项式 f(x₁,...,xₙ)=∑a_ij x_i x_j,可写成 f=x^T Ax,其中 A 对称。标准化方法:1)配方法:消除交叉项;2)正交变换法(实对称特有):用正交矩阵 Q,x=Qy 化为 f=∑λ_i y_i²(λ_i 是 A 的特征值);3)初等变换法:用合同变换。标准形:只含平方项。规范形:系数为 ±1 或 0(实数域唯一)。正惯性指数 + 负惯性指数 = r(A)(惯性定理)。', '二次型', 5.00, 3, 107),
(1898, 102, 5, '简述正定矩阵及其判定', NULL, '实对称矩阵 A,若对所有 x≠0,x^T Ax > 0,则称 A 正定。等价判定:1)所有特征值都 > 0;2)所有顺序主子式 > 0(西尔维斯特判别法);3)存在可逆矩阵 P 使 A=P^T P;4)存在下三角矩阵 L 使 A=LL^T(Cholesky 分解);5)正惯性指数 = n。注意 |A|>0 是必要不充分条件。半正定:x^T Ax≥0,所有特征值≥0。在最优化、统计、机器学习中应用广泛。', '正定矩阵', 5.00, 3, 107),
(1899, 102, 5, '简述向量空间与子空间', NULL, '向量空间 V:满足加法和数乘运算的集合,且满足 8 条公理(加法交换/结合、零向量、负向量、数乘单位、数乘结合、加法分配、数乘分配)。最常见 R^n。子空间 W ⊆ V:对加法和数乘封闭。等价:W 包含 V 的零向量,且对线性组合封闭。重要子空间:零空间 N(A)={x|Ax=0},列空间 C(A)={Ax|x∈R^n},行空间 R(A)。维数:基的向量个数。', '向量空间', 5.00, 3, 107),
(1900, 102, 5, '简述基与维数', NULL, '基:向量空间 V 中线性无关且能张成 V 的向量组。1)对 R^n,任意 n 个线性无关的向量组成基;2)标准基:e₁=(1,0,...,0),...,e_n=(0,...,0,1);3)同一空间的不同基有相同向量个数,称为维数 dim V。坐标:向量在某个基下的唯一表示系数。基变换:不同基之间的过渡矩阵。维数定理:子空间维数 ≤ 全空间维数。', '基与维数', 5.00, 3, 107),
(1901, 102, 5, '简述线性变换', NULL, '线性变换 T:V→W:1)保持加法 T(α+β)=T(α)+T(β);2)保持数乘 T(kα)=kT(α)。等价于保持线性组合。在选定基下,线性变换可用矩阵表示 T(x)=Ax。核(kernel):Ker(T)={x|T(x)=0},是定义域的子空间。象(image):Im(T)={T(x)|x∈V},是值域的子空间。秩-零度定理:dim Ker + dim Im = dim V。线性变换是矩阵的抽象推广。', '线性变换', 5.00, 3, 107),
(1902, 102, 5, '简述施密特正交化方法', NULL, '对线性无关的向量组 α₁,α₂,...,αₛ 进行正交化:1)β₁=α₁;2)β₂=α₂-(α₂·β₁/β₁·β₁)β₁(减去在 β₁ 上的投影);3)β_k=α_k - ∑_(i<k) (α_k·β_i/β_i·β_i)β_i;...;最后单位化 e_i=β_i/||β_i|| 得正交单位基。施密特正交化保持向量组的张成空间不变,在 QR 分解、最小二乘等应用中广泛。', 'Schmidt 正交化', 5.00, 3, 107),
(1903, 102, 5, '简述矩阵的秩', NULL, '秩 r(A):矩阵 A 的行(列)向量组的极大无关组的向量个数,即 A 中最高阶非零子式的阶数。求法:用初等变换化为行阶梯形,非零行数即为秩。性质:1)r(A^T)=r(A);2)r(A)≤min(m,n);3)r(A+B)≤r(A)+r(B);4)r(AB)≤min(r(A),r(B));5)r(AB)≥r(A)+r(B)-n(西尔维斯特不等式)。秩在矩阵理论、方程组、向量空间中至关重要。', '矩阵的秩', 5.00, 3, 107),
(1904, 102, 5, '简述行列式的计算方法', NULL, '行列式计算方法:1)定义法:n!项相加(适合 2 阶、3 阶);2)三角化法:用初等行(列)变换化为上(下)三角,行列式 = 主对角线之积;3)按行(列)展开:|A|=∑a_ij A_ij(按某行/列);4)降阶:利用 0 元素简化;5)递推法:利用矩阵结构;6)凡德蒙德、Hilbert 等特殊行列式公式;7)分块法:对分块矩阵。原则:化简为 0 元素多的行/列再展开。', '行列式计算', 5.00, 3, 107),
(1905, 102, 5, '简述线性代数在机器学习中的应用', NULL, '线性代数是机器学习的核心数学基础:1)数据表示:特征向量、矩阵存储样本;2)线性回归:y=Xβ+ε,正规方程 β=(X^T X)^(-1)X^T y;3)SVD:推荐系统(Netflix)、降维、PCA;4)PCA(主成分分析):用协方差矩阵特征值分解降维;5)矩阵分解:推荐系统(协同过滤);6)神经网络:前向传播 = 矩阵乘法,反向传播 = 链式法则;7)优化:梯度向量、Hessian 矩阵;8)谱聚类:Laplacian 矩阵特征向量。', 'LA 与 ML', 5.00, 2, 107),
(1906, 102, 5, '简述 SVD 奇异值分解', NULL, '任意 m×n 矩阵 A 可分解为 A=UΣV^T,其中:1)U 是 m×m 正交矩阵(列为左奇异向量);2)Σ 是 m×n 对角矩阵,主对角线上是奇异值 σ₁≥σ₂≥...≥σ_r>0;3)V 是 n×n 正交矩阵(列为右奇异向量)。求法:V 的列是 A^T A 的特征向量,U 的列是 AA^T 的特征向量,σ_i = √λ_i。应用:1)降维(保留前 k 大奇异值);2)图像压缩;3)推荐系统;4)伪逆 A^+=VΣ^+U^T。', 'SVD', 5.00, 3, 107),
(1907, 102, 5, '简述主成分分析(PCA)', NULL, 'PCA 是无监督降维方法,核心思想:寻找数据方差最大的方向。算法:1)数据中心化(减均值);2)计算协方差矩阵 Σ=X^T X/(n-1);3)对 Σ 特征值分解,得特征值 λ₁≥λ₂≥...≥λ_n 和特征向量 v₁,v₂,...,v_n;4)选前 k 个最大特征值对应的特征向量作为主成分;5)投影 Y=XV_k 即得降维数据。等价于 SVD:对 X 直接做 SVD,V 的列即主成分。应用:可视化、降维、特征工程、噪声过滤、人脸识别(Eigenfaces)。', 'PCA', 5.00, 3, 107),
(1908, 102, 5, '简述 Cayley-Hamilton 定理及应用', NULL, 'Cayley-Hamilton 定理:n 阶矩阵 A 满足自己的特征方程,即若特征多项式 p(λ)=det(λI-A)=λ^n+c_(n-1)λ^(n-1)+...+c_0,则 p(A)=A^n+c_(n-1)A^(n-1)+...+c_0 I=O。应用:1)求矩阵高次幂:A^n 可用 A^(n-1),...,A,I 线性表示,降阶简化;2)求矩阵逆:从 p(A)=0 推出 A 的逆表达式;3)求矩阵函数:e^A、sin A 等;4)证明矩阵方程。是矩阵理论的重要基础定理。', 'Cayley-Hamilton', 5.00, 3, 107),
(1909, 102, 5, '简述线性代数的核心思想', NULL, '线性代数的核心思想:1)抽象化:用向量、矩阵刻画线性结构;2)线性化:把复杂问题化为线性问题求解;3)矩阵思维:把数据、变换、关系都用矩阵表达;4)分解:大问题分解为简单子问题(LU/QR/SVD/Jordan/谱分解);5)空间几何观:把代数运算赋予几何意义(向量空间、变换、投影);6)对偶:行/列、原空间/对偶空间、特征值/特征向量;7)不变量:迹、行列式、秩、特征值是相似变换下的不变量。线性代数是现代数学和应用科学的根基。', 'LA 核心思想', 5.00, 2, 107),
(1910, 102, 2, '行列式的展开常用方法', '{"A": "按行展开", "B": "按列展开", "C": "Laplace 定理", "D": "降阶展开"}', 'ABCD', '展开方法', 3.00, 3, 107),
(1911, 102, 2, '矩阵相似的不变量', '{"A": "迹", "B": "行列式", "C": "秩", "D": "特征多项式"}', 'ABCD', '相似不变量', 3.00, 3, 107),
(1912, 102, 2, '下列属于矩阵分块运算', '{"A": "分块加法", "B": "分块乘法", "C": "分块求逆", "D": "分块行列式"}', 'ABCD', '分块运算', 3.00, 3, 107),
(1913, 102, 2, '下列属于实对称矩阵的应用领域', '{"A": "二次型分类", "B": "主成分分析", "C": "谱聚类", "D": "量子力学"}', 'ABCD', '实对称应用', 3.00, 3, 107),
(1914, 102, 2, '下列属于线性代数的分解技术', '{"A": "LU", "B": "QR", "C": "SVD", "D": "Jordan"}', 'ABCD', '常见分解', 3.00, 3, 107),
(1915, 102, 4, '三阶行列式按第一行展开公式 |A|=____', NULL, 'a₁₁A₁₁+a₁₂A₁₂+a₁₃A₁₃', '按行展开公式', 2.00, 3, 107),
(1916, 102, 4, '代数余子式 A_ij=(-1)^____ M_ij', NULL, 'i+j', '代数余子式', 2.00, 3, 107),
(1917, 102, 4, '范德蒙德行列式 = ____', NULL, '∏(x_i - x_j)', '范德蒙公式', 2.00, 3, 107),
(1918, 102, 4, 'r(AB) ≤ ____', NULL, 'min(r(A),r(B))', '秩不等式', 2.00, 3, 107),
(1919, 102, 4, 'Schwarz 不等式 |⟨α,β⟩| ≤ ||α||·||β||,等号成立 ⇔ α,β ____', NULL, '线性相关', 'Schwarz 等号', 2.00, 3, 107),
(1920, 102, 4, '三角不等式 ||α+β|| ≤ ||α|| + ____', NULL, '||β||', '三角不等式', 2.00, 3, 107),
(1921, 102, 4, '对角矩阵的特征值 = ____', NULL, '对角线元素', '对角矩阵特征值', 2.00, 2, 107),
(1922, 102, 4, '三角矩阵的特征值 = ____', NULL, '对角线元素', '三角矩阵特征值', 2.00, 2, 107),
(1923, 102, 4, '正交对角化:对实对称矩阵 A,存在正交阵 Q 使 Q^T AQ = ____', NULL, '对角矩阵', '正交对角化', 2.00, 3, 107),
(1924, 102, 4, 'Hermite 矩阵 H 满足 H = ____', NULL, 'H^*', 'Hermite=共轭转置等于自身', 2.00, 3, 107),
(1925, 102, 4, '酉矩阵 U 满足 U^* U = ____', NULL, 'I', '酉矩阵', 2.00, 3, 107),
(1926, 102, 4, '若 A 可对角化,则 A^k = P D^k ____', NULL, 'P^(-1)', '对角化求幂', 2.00, 3, 107),
(1927, 102, 4, 'Frobenius 范数 ||A||_F = √(____)', NULL, '∑|a_ij|^2', 'Frobenius 范数', 2.00, 3, 107),
(1928, 102, 4, '正交补空间 W^⊥ = {x | x⊥所有 W 中向量},则 dim W + dim W^⊥ = ____', NULL, 'n', '正交补维数', 2.00, 3, 107),
(1929, 102, 4, '若 P^(-1)AP = D,则 A 与 D ____', NULL, '相似', '相似定义', 2.00, 2, 107),
(1930, 102, 5, '简述矩阵的初等变换', NULL, '矩阵初等变换有三种:1)互换两行(列);2)某行(列)乘以非零常数 k;3)某行(列)加上另一行(列)的 k 倍。每个初等变换都可用一个初等矩阵左(右)乘 A 实现。性质:1)初等变换不改变矩阵的秩;2)初等行变换不改变方程组的解集;3)任何矩阵可通过有限次初等变换化为标准型。在求逆、求秩、解方程组中广泛应用。', '初等变换', 5.00, 3, 107),
(1931, 102, 5, '简述伴随矩阵及其性质', NULL, '伴随矩阵 A* (或 adj(A)):由代数余子式 A_ij 转置组成的矩阵,即 (A*)_ij = A_ji(代数余子式与下标对调)。重要性质:1)A·A* = A*·A = |A|·I;2)若 |A|≠0,则 A^(-1) = A*/|A|(求逆公式);3)|A*| = |A|^(n-1)(n 阶);4)(A*)^* = |A|^(n-2)·A (n≥2);5)伴随的伴随给出原矩阵的乘子。在求逆、推导矩阵性质中重要。', '伴随矩阵', 5.00, 3, 107),
(1932, 102, 5, '简述线性代数的抽象层次', NULL, '线性代数有多个抽象层次:1)具体计算:数字、向量、矩阵、行列式、方程组;2)空间结构:向量空间(R^n)、子空间、基、维数、线性变换;3)内积与正交:欧氏空间、正交基、施密特正交化、最小二乘;4)特征理论:特征值、特征向量、对角化、相似;5)二次型:正定、惯性、几何意义;6)矩阵分解:LU、QR、SVD、谱分解、Jordan;7)抽象代数:向量空间作为域上的模、张量代数。逐层深入,每层从前层抽象提升。', '抽象层次', 5.00, 3, 107);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(1933, 103, 1, '命题逻辑中，下列哪个公式为永真式（重言式）？', '{"A": "P∧¬P", "B": "P∨¬P", "C": "P→¬P", "D": "P↔¬P"}', 'B', 'P∨¬P 为排中律，是永真式；P∧¬P 为永假式', 2.00, 1, 109),
(1934, 103, 1, '集合 A={1,2,3}，B={2,3,4}，则 A∪B = ?', '{"A": "{2,3}", "B": "{1,2,3,4}", "C": "{1,4}", "D": "{1,2,3}"}', 'B', '并集是两集合的所有元素', 2.00, 1, 109),
(1935, 103, 1, '集合 A={1,2,3}，B={2,3,4}，则 A∩B = ?', '{"A": "{2,3}", "B": "{1,2,3,4}", "C": "{1,4}", "D": "{}"}', 'A', '交集是两集合的公共元素', 2.00, 1, 109),
(1936, 103, 1, '已知 |A|=3, |B|=4，则笛卡尔积 |A×B| = ?', '{"A": "7", "B": "12", "C": "3", "D": "4"}', 'B', '|A×B| = |A| × |B| = 3 × 4 = 12', 2.00, 1, 109),
(1937, 103, 1, '设 R 是集合 A 上的关系，若 R 既不自反也不反自反，则', '{"A": "R 不是等价关系", "B": "A 中存在元素 a 使 (a,a)∈R", "C": "A 中所有元素都不与自身相关", "D": "R 必为对称的"}', 'B', '既不自反也不反自反，意味着部分元素 (a,a)∈R 部分不属于', 2.00, 3, 109),
(1938, 103, 1, '等价关系必须满足', '{"A": "自反、对称、反对称", "B": "自反、对称、传递", "C": "自反、反对称、传递", "D": "对称、反对称、传递"}', 'B', '等价关系三性质：自反性、对称性、传递性', 2.00, 1, 109),
(1939, 103, 1, '偏序关系必须满足', '{"A": "自反、对称、传递", "B": "自反、反对称、传递", "C": "反自反、反对称、传递", "D": "对称、传递"}', 'B', '偏序关系：自反、反对称、传递', 2.00, 1, 109),
(1940, 103, 1, 'n 个顶点的简单无向图最多有多少条边？', '{"A": "n", "B": "n(n-1)", "C": "n(n-1)/2", "D": "n²"}', 'C', 'n 顶点完全图 K_n 边数为 C(n,2) = n(n-1)/2', 2.00, 1, 109),
(1941, 103, 1, '图论中，欧拉回路存在的充要条件是', '{"A": "图连通且每个顶点度为偶数", "B": "图连通且恰有两个奇度顶点", "C": "图为完全图", "D": "图无环"}', 'A', '无向连通图存在欧拉回路 ⟺ 所有顶点度均为偶数', 2.00, 2, 109),
(1942, 103, 1, 'n 个顶点的树有多少条边？', '{"A": "n-1", "B": "n", "C": "n+1", "D": "2n-1"}', 'A', '树是无环连通图，n 个顶点必有 n-1 条边', 2.00, 1, 109),
(1943, 103, 1, '群 (G, *) 必须满足', '{"A": "封闭性、结合律", "B": "封闭性、结合律、有单位元", "C": "封闭性、结合律、有单位元、每个元素有逆元", "D": "以上加交换律"}', 'C', '群的四公理；满足交换律为阿贝尔群', 2.00, 2, 109),
(1944, 103, 1, '命题 ¬(P→Q) 等价于', '{"A": "P∧¬Q", "B": "¬P∨Q", "C": "P∨Q", "D": "¬P∧¬Q"}', 'A', 'P→Q ≡ ¬P∨Q，故 ¬(P→Q) ≡ P∧¬Q', 2.00, 2, 109),
(1945, 103, 2, '下列对集合运算的描述中，正确的有', '{"A": "A∪B = B∪A", "B": "A∩(B∪C) = (A∩B)∪(A∩C)", "C": "A-B = B-A", "D": "A⊆B 时，A∪B = B"}', 'ABD', '差运算不满足交换律，A-B ≠ B-A', 3.00, 2, 109),
(1946, 103, 2, '下列哪些命题是有效的逻辑等价式？', '{"A": "P→Q ≡ ¬P∨Q", "B": "P∧Q ≡ Q∧P", "C": "¬(P∧Q) ≡ ¬P∨¬Q", "D": "P→Q ≡ Q→P"}', 'ABC', 'D 是命题逻辑中常见的错误，P→Q 与 Q→P 不等价', 3.00, 2, 109),
(1947, 103, 2, '关于二元关系 R 在 A 上的性质，下列叙述正确的是', '{"A": "自反性：∀a∈A, (a,a)∈R", "B": "对称性：(a,b)∈R ⟹ (b,a)∈R", "C": "传递性：(a,b)∈R ∧ (b,c)∈R ⟹ (a,c)∈R", "D": "反自反性：∀a∈A, (a,a)∈R"}', 'ABC', '反自反应为 ∀a∈A, (a,a)∉R', 3.00, 2, 109),
(1948, 103, 2, '下列关于图论的叙述中，正确的有', '{"A": "无向图的所有顶点度数之和为偶数", "B": "奇度顶点数必为偶数", "C": "无向连通图任意两点间至少有一条路径", "D": "任何图都有欧拉回路"}', 'ABC', 'D 错误，欧拉回路要求所有顶点度均为偶数', 3.00, 2, 109),
(1949, 103, 3, '空集是任何集合的子集。', NULL, '正确', '∅⊆A 对任意集合 A 成立', 1.00, 1, 109),
(1950, 103, 3, '集合 {1,2,3} 与集合 {3,2,1,2} 不是同一个集合。', NULL, '错误', '集合元素无序且不重复，{1,2,3}={3,2,1,2}', 1.00, 1, 109),
(1951, 103, 3, '任意自反关系的对称闭包等于该关系本身。', NULL, '错误', '对称闭包可能添加新的对偶序对（除非原本已对称）', 1.00, 2, 109),
(1952, 103, 3, '完全图 K_n 中每个顶点的度数都是 n-1。', NULL, '正确', '完全图 K_n 中每个顶点都与其余 n-1 个顶点相连', 1.00, 1, 109),
(1953, 103, 3, '二元命题逻辑中，蕴含运算 → 满足交换律。', NULL, '错误', 'P→Q 与 Q→P 不等价', 1.00, 1, 109),
(1954, 103, 3, '循环群必为阿贝尔群。', NULL, '正确', '循环群 <a> 中任意两元素 a^i 和 a^j 满足 a^i*a^j = a^(i+j) = a^j*a^i', 1.00, 2, 109),
(1955, 103, 4, '集合 {a,b,c} 的所有子集个数为 ___。', NULL, '8', 'n 元集合的子集数为 2^n = 2^3 = 8', 2.00, 1, 109),
(1956, 103, 4, '5 阶完全图 K₅ 共有 ___ 条边。', NULL, '10', 'K_n 边数为 n(n-1)/2 = 5×4/2 = 10', 2.00, 1, 109),
(1957, 103, 4, '命题公式 P∨(¬P∧Q) 化简后等价于 ___。', NULL, 'P∨Q', '分配律：P∨(¬P∧Q) = (P∨¬P)∧(P∨Q) = T∧(P∨Q) = P∨Q', 2.00, 2, 109),
(1958, 103, 4, '二叉树的前序遍历 ABDECF 后序遍历 DEBFCA，则中序遍历为 ___。', NULL, 'DBEAFC', '由前序+后序构造二叉树，再做中序遍历', 2.00, 3, 109),
(1959, 103, 5, '什么是等价关系？等价关系如何导出集合的划分？', NULL, '等价关系：自反、对称、传递的二元关系。等价关系 R 把集合 A 划分为若干互不相交的等价类，每个等价类内元素彼此等价；A 中所有元素恰属于唯一一个等价类，所有等价类之并 = A。这建立了''等价关系↔划分''的一一对应', '等价类与划分是离散数学核心概念', 5.00, 2, 109),
(1960, 103, 5, '叙述图论中欧拉回路与哈密顿回路的区别。', NULL, '欧拉回路：经过图中每条边恰好一次的回路（顶点可重复）。哈密顿回路：经过图中每个顶点恰好一次的回路（边不重复）。判定难度：欧拉回路有简单充要条件（连通+所有度偶）；哈密顿回路是 NP-完全问题，无简单判定法', '两种著名的图论遍历问题', 5.00, 2, 109),
(1961, 103, 5, '用真值表证明 P→Q ≡ ¬P∨Q。', NULL, '真值表：
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(2269, 104, 1, '在一个长度为n的顺序表中，删除第i个元素需要移动的元素个数为', '{"A": "n-i", "B": "n-i+1", "C": "n-i-1", "D": "i"}', 'A', '删除第i个元素后，第i+1到第n个元素都需要前移，共n-i个', 2.00, 1, 110),
(2270, 104, 1, '栈的特点是', '{"A": "先进先出", "B": "先进后出", "C": "随机存取", "D": "顺序存取"}', 'B', '栈是后进先出(LIFO)的数据结构', 2.00, 1, 110),
(2271, 104, 1, '二叉树的第k层最多有多少个节点', '{"A": "2^k", "B": "2^(k-1)", "C": "2k", "D": "k²"}', 'B', '二叉树第k层最多有2^(k-1)个节点', 2.00, 1, 110),
(2272, 104, 1, '快速排序的平均时间复杂度为', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n²)", "D": "O(logn)"}', 'B', '快速排序平均时间复杂度为O(nlogn)', 2.00, 1, 110),
(2273, 104, 1, '在一个具有n个顶点的无向完全图中，边的数目为', '{"A": "n(n-1)", "B": "n(n-1)/2", "C": "n²", "D": "2n"}', 'B', '无向完全图每两个顶点之间都有一条边，共n(n-1)/2条', 3.00, 2, 110),
(2274, 104, 2, '下列哪些排序算法是稳定的', '{"A": "冒泡排序", "B": "快速排序", "C": "归并排序", "D": "插入排序"}', 'ACD', '快速排序是不稳定的排序算法', 3.00, 2, 110),
(2275, 104, 2, '关于二叉搜索树，下列说法正确的是', '{"A": "左子树所有节点值小于根节点", "B": "右子树所有节点值大于根节点", "C": "中序遍历结果是有序的", "D": "查找的时间复杂度一定是O(logn)"}', 'ABC', '在最坏情况下（退化为链表），查找时间复杂度为O(n)', 3.00, 2, 110),
(2276, 104, 3, '队列是一种先进先出的线性表', NULL, '正确', '队列(Queue)的特点是先进先出(FIFO)', 2.00, 1, 110),
(2277, 104, 3, '哈夫曼树是带权路径长度最小的二叉树', NULL, '正确', '哈夫曼树(最优二叉树)的特点就是带权路径长度WPL最小', 2.00, 1, 110),
(2278, 104, 3, '图的深度优先搜索使用队列作为辅助数据结构', NULL, '错误', '深度优先搜索(DFS)使用栈，广度优先搜索(BFS)使用队列', 2.00, 1, 110),
(2279, 104, 4, '具有n个节点的完全二叉树的深度为____（向下取整用[]表示）', NULL, '[log2(n)]+1', '完全二叉树深度为⌊log₂n⌋+1', 3.00, 2, 110),
(2280, 104, 4, '对n个元素进行冒泡排序，最坏情况下的比较次数为____', NULL, 'n(n-1)/2', '最坏情况下需要n-1趟排序，比较次数为n(n-1)/2', 3.00, 2, 110),
(2281, 104, 5, '请描述二分查找算法的基本思想和时间复杂度', NULL, '二分查找针对有序数组，每次将查找区间缩小一半：比较中间元素与目标值，若相等则找到；若目标值小于中间元素，在左半区间继续查找；否则在右半区间查找。时间复杂度为O(logn)。', '需要说明前提条件（有序）、基本步骤和时间复杂度', 5.00, 2, 110),
(2282, 104, 5, '请比较链表和数组的优缺点', NULL, '数组：支持随机访问O(1)，但插入删除需要移动元素O(n)，大小固定。链表：插入删除O(1)，但只能顺序访问O(n)，额外存储指针开销，大小动态可变。', '从访问方式、插入删除效率、存储空间等方面比较', 5.00, 2, 110),
(2283, 104, 1, '堆排序的时间复杂度为', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n²)", "D": "O(logn)"}', 'B', '堆排序建堆O(n)，调整堆n-1次每次O(logn)，总体O(nlogn)', 2.00, 2, 110),
(2284, 104, 1, '线性表的顺序存储结构是一种', '{"A": "随机存取的存储结构", "B": "顺序存取的存储结构", "C": "索引存取的存储结构", "D": "散列存取的存储结构"}', 'A', '顺序存储可通过下标直接访问', 2.00, 1, 110),
(2285, 104, 1, '单链表中增加头结点的目的是', '{"A": "使单链表至少有一个结点", "B": "标识首结点位置", "C": "方便运算的实现", "D": "说明是链式存储"}', 'C', '头结点统一了空表和非空表的操作', 2.00, 1, 110),
(2286, 104, 1, '设栈输入序列为1234则不可能的输出序列是', '{"A": "1243", "B": "4321", "C": "1324", "D": "4123"}', 'D', '4先出则123已入栈只能321出', 2.00, 2, 110),
(2287, 104, 1, '循环队列队头front队尾rear最大M则长度为', '{"A": "(rear-front+M)%M", "B": "rear-front+1", "C": "rear-front", "D": "M-front+rear"}', 'A', '循环队列长度公式', 2.00, 1, 110),
(2288, 104, 1, '具有n个结点的二叉排序树最坏查找复杂度为', '{"A": "O(1)", "B": "O(logn)", "C": "O(n)", "D": "O(nlogn)"}', 'C', '退化为单链表时O(n)', 3.00, 2, 110),
(2289, 104, 1, 'n个叶子结点的哈夫曼树总结点数为', '{"A": "n", "B": "2n", "C": "2n-1", "D": "2n+1"}', 'C', '哈夫曼树总结点数2n-1', 2.00, 1, 110),
(2290, 104, 1, '图的广度优先搜索类似于树的', '{"A": "先序遍历", "B": "中序遍历", "C": "后序遍历", "D": "层次遍历"}', 'D', 'BFS按层次逐步扩展', 2.00, 1, 110),
(2291, 104, 1, '拓扑排序用来判断有向图是否存在', '{"A": "回路", "B": "连通分量", "C": "强连通分量", "D": "生成树"}', 'A', '有回路则无法完成拓扑排序', 2.00, 2, 110),
(2292, 104, 1, '折半查找要求线性表的存储结构为', '{"A": "链式存储", "B": "顺序存储", "C": "索引存储", "D": "任意存储"}', 'B', '折半查找需要随机访问能力', 2.00, 1, 110),
(2293, 104, 1, '直接插入排序最好情况时间复杂度为', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n^2)", "D": "O(logn)"}', 'A', '已有序时只需比较n-1次', 2.00, 1, 110),
(2294, 104, 1, '散列表处理冲突的方法不包括', '{"A": "开放定址法", "B": "链地址法", "C": "再哈希法", "D": "顺序查找法"}', 'D', '顺序查找不是冲突处理方法', 2.00, 1, 110),
(2295, 104, 1, 'Dijkstra算法用于求解', '{"A": "最小生成树", "B": "最短路径", "C": "拓扑排序", "D": "关键路径"}', 'B', 'Dijkstra求单源最短路径', 3.00, 2, 110),
(2296, 104, 1, '归并排序的空间复杂度为', '{"A": "O(1)", "B": "O(logn)", "C": "O(n)", "D": "O(nlogn)"}', 'C', '需要O(n)辅助空间', 2.00, 2, 110),
(2297, 104, 1, '希尔排序属于哪类排序方法', '{"A": "交换排序", "B": "插入排序", "C": "选择排序", "D": "归并排序"}', 'B', '希尔排序是改进的插入排序', 2.00, 1, 110),
(2298, 104, 2, '下列属于线性结构的有', '{"A": "栈", "B": "队列", "C": "二叉树", "D": "串"}', 'ABD', '二叉树是非线性结构', 3.00, 1, 110),
(2299, 104, 2, '时间复杂度为O(nlogn)的排序有', '{"A": "快速排序", "B": "归并排序", "C": "堆排序", "D": "冒泡排序"}', 'ABC', '冒泡排序为O(n^2)', 3.00, 2, 110),
(2300, 104, 2, '关于栈正确的有', '{"A": "后进先出", "B": "只能在栈顶操作", "C": "可用数组实现", "D": "不能用链表实现"}', 'ABC', '栈可以用链表实现', 3.00, 1, 110),
(2301, 104, 2, '树的遍历方式包括', '{"A": "先序遍历", "B": "中序遍历", "C": "后序遍历", "D": "层次遍历"}', 'ABCD', '都是树的遍历方式', 3.00, 1, 110),
(2302, 104, 2, '属于图的存储结构的有', '{"A": "邻接矩阵", "B": "邻接表", "C": "十字链表", "D": "邻接多重表"}', 'ABCD', '都是图的存储结构', 3.00, 2, 110),
(2303, 104, 2, '影响散列表查找效率的因素', '{"A": "散列函数", "B": "装填因子", "C": "冲突处理方法", "D": "初始数据顺序"}', 'ABC', '初始顺序不影响散列查找', 3.00, 2, 110),
(2304, 104, 2, '关于堆正确的有', '{"A": "大顶堆根是最大值", "B": "小顶堆根是最小值", "C": "堆是完全二叉树", "D": "堆是二叉排序树"}', 'ABC', '堆不是二叉排序树', 3.00, 2, 110),
(2305, 104, 2, '最小生成树算法有', '{"A": "Prim算法", "B": "Kruskal算法", "C": "Dijkstra算法", "D": "Floyd算法"}', 'AB', '后两个是最短路径算法', 3.00, 2, 110),
(2306, 104, 2, '队列的应用场景有', '{"A": "作业调度", "B": "打印队列", "C": "广度优先搜索", "D": "递归调用"}', 'ABC', '递归使用栈非队列', 3.00, 1, 110),
(2307, 104, 2, '不稳定的排序算法有', '{"A": "快速排序", "B": "希尔排序", "C": "堆排序", "D": "归并排序"}', 'ABC', '归并排序是稳定的', 3.00, 2, 110),
(2308, 104, 2, '二叉树的性质包括', '{"A": "第i层最多2^(i-1)个结点", "B": "深度k最多2^k-1个结点", "C": "叶子数=度2结点数+1", "D": "完全二叉树最后两层有叶子"}', 'ABCD', '都是二叉树性质', 3.00, 2, 110),
(2309, 104, 2, '关于AVL树正确的有', '{"A": "平衡二叉搜索树", "B": "左右子树高度差不超1", "C": "插入可能需旋转", "D": "查找O(logn)"}', 'ABCD', '都是AVL树特征', 3.00, 3, 110),
(2310, 104, 2, '关于链表正确的有', '{"A": "插删不需移动元素", "B": "不支持随机访问", "C": "需额外指针空间", "D": "物理存储可不连续"}', 'ABCD', '都是链表特点', 3.00, 1, 110),
(2311, 104, 2, '关于B树正确的有', '{"A": "多路平衡查找树", "B": "适用于外存查找", "C": "叶子在同一层", "D": "根至少两棵子树"}', 'ABCD', '都是B树性质', 3.00, 3, 110),
(2312, 104, 2, '最坏O(n^2)的排序有', '{"A": "冒泡排序", "B": "插入排序", "C": "快速排序", "D": "选择排序"}', 'ABCD', '最坏都是O(n^2)', 3.00, 2, 110),
(2313, 104, 2, '关于串正确的有', '{"A": "串是特殊线性表", "B": "空串长度为0", "C": "空格串不是空串", "D": "KMP用于模式匹配"}', 'ABCD', '都正确', 3.00, 1, 110),
(2314, 104, 2, '关于红黑树正确的有', '{"A": "自平衡二叉搜索树", "B": "根是黑色", "C": "红结点子结点是黑色", "D": "根到叶黑结点数相同"}', 'ABCD', '都是红黑树性质', 3.00, 3, 110),
(2315, 104, 3, '顺序存储结构优于链式存储结构', NULL, '错误', '各有优劣取决于应用场景', 2.00, 1, 110),
(2316, 104, 3, '栈和队列都是操作受限的线性表', NULL, '正确', '栈限一端队列限两端', 2.00, 1, 110),
(2317, 104, 3, '二叉树中序遍历结果一定有序', NULL, '错误', '只有BST中序才有序', 2.00, 1, 110),
(2318, 104, 3, '完全二叉树度为1的结点最多一个', NULL, '正确', '完全二叉树性质', 2.00, 2, 110),
(2319, 104, 3, '有向图邻接矩阵一定对称', NULL, '错误', '无向图才对称', 2.00, 1, 110),
(2320, 104, 3, 'Prim和Kruskal结果一定相同', NULL, '错误', '权值相同时可能不同', 2.00, 2, 110),
(2321, 104, 3, '散列表查找时间一定是O(1)', NULL, '错误', '有冲突时不一定', 2.00, 1, 110),
(2322, 104, 3, 'AOV网中不应存在环', NULL, '正确', '有环则拓扑排序无法进行', 2.00, 2, 110),
(2323, 104, 3, '任何无向连通图的最小生成树唯一', NULL, '错误', '边权有相同值时可能不唯一', 2.00, 2, 110),
(2324, 104, 3, '快速排序在任何情况下都比冒泡排序快', NULL, '错误', '最坏情况下快排退化为O(n^2)', 2.00, 1, 110),
(2325, 104, 3, '二叉排序树的查找效率与树的形态有关', NULL, '正确', '越平衡效率越高', 2.00, 2, 110),
(2326, 104, 3, '希尔排序是一种稳定的排序算法', NULL, '错误', '希尔排序是不稳定的', 2.00, 1, 110),
(2327, 104, 3, '双向链表比单链表占用更多存储空间', NULL, '正确', '每个结点多一个前驱指针', 2.00, 1, 110),
(2328, 104, 3, '深度为h的二叉树最多有2^h-1个结点', NULL, '正确', '满二叉树时达到最多', 2.00, 1, 110),
(2329, 104, 3, '邻接表适合表示稀疏图', NULL, '正确', '稀疏图用邻接表更省空间', 2.00, 1, 110),
(2330, 104, 3, '选择排序是稳定的排序算法', NULL, '错误', '选择排序是不稳定的', 2.00, 1, 110),
(2331, 104, 3, '循环链表可以从任意结点出发访问所有结点', NULL, '正确', '循环链表首尾相连', 2.00, 1, 110),
(2332, 104, 4, '在长度为n的有序表中折半查找的时间复杂度为____', NULL, 'O(log2n)', '折半查找每次缩小一半', 3.00, 1, 110),
(2333, 104, 4, 'n个顶点的连通图至少有____条边', NULL, 'n-1', '生成树有n-1条边', 3.00, 1, 110),
(2334, 104, 4, '后缀表达式也称为____表达式', NULL, '逆波兰', '后缀表达式即逆波兰表达式', 3.00, 1, 110),
(2335, 104, 4, '一棵完全二叉树有1000个结点则叶子结点有____个', NULL, '500', '完全二叉树叶子数=[n/2]', 3.00, 2, 110),
(2336, 104, 4, 'Kruskal算法的时间复杂度主要取决于____数', NULL, '边', 'Kruskal按边排序选取', 3.00, 2, 110),
(2337, 104, 4, '设散列表长度为m已存入n个元素则装填因子α=____', NULL, 'n/m', '装填因子=元素数/表长', 3.00, 1, 110),
(2338, 104, 4, '有n个结点的无向完全图有____条边', NULL, 'n(n-1)/2', '每两个顶点一条边', 3.00, 1, 110),
(2339, 104, 4, '深度优先搜索用____作为辅助数据结构', NULL, '栈', 'DFS使用栈BFS使用队列', 3.00, 1, 110),
(2340, 104, 4, 'KMP算法的核心是____数组', NULL, 'next', 'next数组记录模式串的部分匹配信息', 3.00, 2, 110),
(2341, 104, 4, 'n个元素的堆调整一次的时间复杂度为____', NULL, 'O(logn)', '堆的高度为logn', 3.00, 2, 110),
(2342, 104, 4, '有向图中顶点v的入度是指以v为____的弧的数目', NULL, '终点', '入度是指向该顶点的弧数', 3.00, 1, 110),
(2343, 104, 4, '三种基本的存储结构是顺序存储链式存储和____', NULL, '索引存储', '三种基本存储结构', 3.00, 1, 110),
(2344, 104, 4, '关键路径上的活动称为____活动', NULL, '关键', '关键路径上的活动叫关键活动', 3.00, 1, 110),
(2345, 104, 4, '用邻接矩阵表示图时查找两顶点间是否有边的时间复杂度为____', NULL, 'O(1)', '直接查矩阵元素', 3.00, 1, 110),
(2346, 104, 4, '二叉树的____遍历是唯一能确定左右子树的遍历方式', NULL, '中序', '中序遍历区分左右子树', 3.00, 2, 110),
(2347, 104, 4, '若一棵二叉树的前序和中序遍历相同则该树____', NULL, '没有左子树', '每个结点都无左孩子', 3.00, 3, 110),
(2348, 104, 4, '最小生成树的边数等于____', NULL, '顶点数-1', 'n个顶点的生成树有n-1条边', 3.00, 1, 110),
(2349, 104, 4, '基数排序属于____排序', NULL, '分配', '基数排序不基于比较', 3.00, 2, 110),
(2350, 104, 5, '请解释图的深度优先搜索和广度优先搜索的区别', NULL, 'DFS使用栈从起点出发尽可能深入每个分支再回溯适合查找路径；BFS使用队列按层次逐步扩展适合查找最短路径。DFS空间复杂度取决于图的深度BFS取决于图的宽度。', '从数据结构辅助工具和应用场景两方面比较', 5.00, 2, 110),
(2351, 104, 5, '请说明最小生成树的Prim算法和Kruskal算法的基本思想', NULL, 'Prim从某顶点出发每次选与已选顶点集合距离最近的顶点加入逐步扩展直到所有顶点加入。Kruskal将所有边按权值排序从小到大选边如果不构成回路则加入直到选够n-1条边。Prim适合稠密图O(n^2)Kruskal适合稀疏图O(eloge)。', '比较两种算法的策略和适用场景', 5.00, 2, 110),
(2352, 104, 5, '请描述快速排序的基本思想及其时间复杂度分析', NULL, '选一个基准元素将待排序列分为两部分左边都小于基准右边都大于基准然后分别递归排序。平均O(nlogn)最坏O(n^2)(有序时)空间O(logn)。是不稳定排序。', '包括基本步骤和复杂度分析', 5.00, 2, 110),
(2353, 104, 5, '请解释什么是平衡二叉树(AVL树)及其旋转操作', NULL, 'AVL树是任意结点左右子树高度差不超过1的二叉搜索树。当插入或删除破坏平衡时通过旋转恢复：LL型右旋RR型左旋LR型先左旋再右旋RL型先右旋再左旋。保证查找复杂度O(logn)。', '需说明定义和四种旋转类型', 5.00, 3, 110),
(2354, 104, 5, '请说明散列表的基本原理及常见的冲突解决方法', NULL, '散列表通过散列函数将关键字映射到存储位置实现O(1)查找。冲突解决方法：1.开放定址法(线性探测二次探测)遇冲突找下一个空位；2.链地址法将冲突元素链成链表；3.再散列法使用多个散列函数。装填因子影响性能。', '需说明原理和至少两种冲突处理方法', 5.00, 2, 110),
(2355, 104, 5, '请描述拓扑排序的算法步骤及其应用', NULL, '步骤：1.选入度为0的顶点输出；2.删除该顶点及所有出边；3.重复直到图空或无入度为0的顶点。若输出顶点数<总数则有环。应用：课程安排工程计划任务调度等有先后依赖关系的场景。时间复杂度O(n+e)。', '需说明步骤和应用场景', 5.00, 2, 110),
(2356, 104, 5, '请比较顺序查找折半查找和散列查找的特点', NULL, '顺序查找：无需有序O(n)适用任何线性表。折半查找：要求有序O(logn)只适用顺序存储。散列查找：通过散列函数直接定位平均O(1)但需处理冲突额外空间。选择取决于数据规模是否有序存储结构等。', '从适用条件效率和优缺点三方面比较', 5.00, 2, 110),
(2357, 104, 5, '请说明二叉搜索树的插入和删除操作', NULL, '插入：从根开始比较若小于当前结点往左否则往右直到空位插入新结点。删除三种情况：1.叶子结点直接删除；2.只有一个子树用子树替代；3.有两个子树用中序后继(或前驱)替代再删除后继。查找插入删除平均O(logn)。', '需说明插入和删除的完整过程', 5.00, 2, 110),
(2358, 104, 2, '关于哈希表正确的有', '{"A": "通过哈希函数映射地址", "B": "可能产生冲突", "C": "装填因子影响性能", "D": "平均查找O(1)"}', 'ABCD', '都是哈希表的特点', 3.00, 2, 110),
(2359, 104, 1, '算法分析中度量算法效率主要从哪两个方面考虑', '{"A": "时间和空间", "B": "正确性和易读性", "C": "健壮性和可读性", "D": "稳定性和通用性"}', 'A', '算法分析的两大核心指标是时间复杂度和空间复杂度', 2.00, 1, 110),
(2360, 104, 1, '下列时间复杂度中最优的是', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n^2)", "D": "O(logn)"}', 'D', 'logn 增长最慢,O(logn) 为最优', 2.00, 1, 110),
(2361, 104, 1, '程序段 for(i=0;i<n;i++) for(j=1;j<n;j*=2) x++ 的时间复杂度是', '{"A": "O(n^2)", "B": "O(nlogn)", "C": "O(n)", "D": "O(logn)"}', 'B', '外层 n 次,内层每次 j 翻倍共 logn 次,总体 O(nlogn)', 2.00, 2, 110),
(2362, 104, 1, '计算 1+2+3+...+n 的递推算法时间复杂度是', '{"A": "O(1)", "B": "O(logn)", "C": "O(n)", "D": "O(n^2)"}', 'C', '循环累加从 1 到 n 共 n 次,O(n)', 2.00, 1, 110),
(2363, 104, 1, '算法的有穷性是指', '{"A": "算法必须包含输出", "B": "算法操作步骤为有限个", "C": "算法运行时间有限", "D": "算法运算次数与输入有关"}', 'B', '有穷性指算法在有限步内终止', 2.00, 1, 110),
(2364, 104, 1, '以下不是算法基本特性的是', '{"A": "有穷性", "B": "确定性", "C": "可行性", "D": "保密性"}', 'D', '算法五特性:输入输出有穷确定可行', 2.00, 1, 110),
(2365, 104, 1, '下列算法时间复杂度最差的是', '{"A": "O(n^0.5)", "B": "O(nlogn)", "C": "O(n)", "D": "O(2^n)"}', 'D', '指数级 2^n 增长最快', 2.00, 1, 110),
(2366, 104, 1, '对于完全二叉树而言,以下哪种算法的复杂度为 O(1)', '{"A": "求根结点", "B": "求二叉树深度", "C": "计算总结点数", "D": "二叉树前序遍历"}', 'A', '数组存储的完全二叉树根结点即第 1 号位置,O(1)', 2.00, 2, 110),
(2367, 104, 1, '顺序表第 i 个元素地址为 LOC(a1)+(i-1)*L,L 表示', '{"A": "元素总数", "B": "元素序号", "C": "元素的字节数", "D": "元素类型"}', 'C', 'L 是单个元素占用的存储字节数', 2.00, 1, 110),
(2368, 104, 1, '长度为 n 的顺序表在第 i 位置(1<=i<=n+1)插入元素需移动元素个数为', '{"A": "n-i+1", "B": "n-i", "C": "i", "D": "i-1"}', 'A', '插入位置 i 需将 a_i 至 a_n 共 n-i+1 个元素后移', 2.00, 2, 110),
(2369, 104, 1, '顺序表相比链表的优点是', '{"A": "插入删除快", "B": "存储密度高", "C": "便于动态扩展", "D": "便于随机访问"}', 'D', '顺序表 O(1) 随机访问,链表只能顺序访问', 2.00, 1, 110),
(2370, 104, 1, '长度为 n 的顺序表等概率下删除一个元素平均移动元素数为', '{"A": "n/2", "B": "(n-1)/2", "C": "(n+1)/2", "D": "n"}', 'B', '平均移动 (n-1)/2,公式: 1/n * sum(n-i) for i=1..n', 2.00, 2, 110),
(2371, 104, 1, '在单链表中,在 p 后插入节点 s 的正确操作是', '{"A": "s->next=p->next; p->next=s;", "B": "p->next=s; s->next=p->next;", "C": "s->next=p; p->next=s;", "D": "p->next=s->next; s=p;"}', 'A', '必须先把 s->next 接到 p->next,再让 p->next 指 s', 2.00, 2, 110),
(2372, 104, 1, '双向链表中删除节点 p 的正确语句是', '{"A": "p->prior->next=p->next; p->next->prior=p->prior;", "B": "p->next->prior=p->prior;", "C": "p->prior->next=p->next;", "D": "p->prior=NULL; p->next=NULL;"}', 'A', '必须同时修改 p 前驱的 next 和 p 后继的 prior', 2.00, 2, 110),
(2373, 104, 1, '循环单链表的最大特点是', '{"A": "所有结点循环排列", "B": "只用尾指针即可访问任一结点", "C": "插入删除快", "D": "空间利用率高"}', 'B', '循环单链表用尾指针 r,r->next 即头结点,首尾访问都 O(1)', 2.00, 2, 110),
(2374, 104, 1, '若线性表最常用操作是存取第 i 个元素,采用哪种存储结构最节省时间', '{"A": "单链表", "B": "双链表", "C": "顺序表", "D": "循环链表"}', 'C', '顺序表随机访问 O(1)', 2.00, 1, 110),
(2375, 104, 1, '带头结点单链表 L 中,判定链表为空的条件是', '{"A": "L==NULL", "B": "L->next==NULL", "C": "L->next==L", "D": "L!=NULL"}', 'B', '头结点不存数据,L->next 为空表示链表无数据', 2.00, 2, 110),
(2376, 104, 1, '线性表是', '{"A": "可空的有限序列", "B": "不可空的有限序列", "C": "可空的无限序列", "D": "不可空的无限序列"}', 'A', '线性表定义含空表(零元素)情况', 2.00, 1, 110),
(2377, 104, 1, '下列哪种结构属于非线性结构', '{"A": "队列", "B": "栈", "C": "线性表", "D": "二叉树"}', 'D', '树和图是非线性结构', 2.00, 1, 110),
(2378, 104, 1, '单链表中 p 指针指向某结点,删除 p 后继结点的正确语句是', '{"A": "p=p->next;", "B": "p->next=p->next->next;", "C": "free(p->next); p->next=p->next->next;", "D": "q=p->next; p->next=q->next; free(q);"}', 'D', '需先保存待删指针再修改链接最后释放,顺序不能错', 2.00, 2, 110),
(2379, 104, 1, '空栈 S 经过 push(1),push(2),pop,push(3),pop,push(4) 后栈顶元素是', '{"A": "1", "B": "2", "C": "3", "D": "4"}', 'D', '入1入2出2入3出3入4 后栈中剩 1 和 4,栈顶为 4', 2.00, 2, 110),
(2380, 104, 1, '入栈序列为 1,2,3,4,5,下列哪个序列是合法的出栈序列', '{"A": "5,4,3,1,2", "B": "4,5,3,2,1", "C": "3,4,1,5,2", "D": "1,5,4,3,2"}', 'B', '按 LIFO 模拟可验证 B 项合法', 2.00, 3, 110),
(2381, 104, 1, '顺序栈 top 指向栈顶元素时,栈空条件是', '{"A": "top==-1", "B": "top==0", "C": "top==MaxSize-1", "D": "top==MaxSize"}', 'A', 'top 指栈顶元素时,空栈 top=-1', 2.00, 1, 110),
(2382, 104, 1, '用单链表实现链式队列时,队头位于', '{"A": "链表头部", "B": "链表尾部", "C": "链表中间", "D": "头尾均可"}', 'A', '队头位于链表头部便于 O(1) 出队,队尾位于链表尾部便于 O(1) 入队', 2.00, 2, 110),
(2383, 104, 1, '循环队列长 N,头指针 front 指队头前一位置,队空条件是', '{"A": "rear==front", "B": "(rear+1)%N==front", "C": "rear==N-1", "D": "rear==0"}', 'A', '该约定下 rear==front 表示队空,(rear+1)%N==front 表示队满', 2.00, 2, 110),
(2384, 104, 1, '数组 V[m] 实现的循环队列,当前 rear=0 front=m-1,队列元素个数是', '{"A": "0", "B": "1", "C": "m-1", "D": "2"}', 'B', '元素数 = (rear-front+m)%m = (0-(m-1)+m)%m = 1', 2.00, 3, 110),
(2385, 104, 1, '循环队列 Q(容量 n) 判满条件是', '{"A": "Q.rear==Q.front", "B": "(Q.rear+1)%n==Q.front", "C": "Q.rear==0", "D": "Q.front==0"}', 'B', '牺牲一个单元法判满: (rear+1)%n==front', 2.00, 2, 110),
(2386, 104, 1, '栈和队列的共同特点是', '{"A": "都是先进先出", "B": "都是先进后出", "C": "只在端点处插入和删除", "D": "没有共同点"}', 'C', '两者均只在端点操作,差别在端点选择不同', 2.00, 1, 110),
(2387, 104, 1, '以下不能用栈解决的是', '{"A": "表达式求值", "B": "函数调用", "C": "进程调度", "D": "深度优先搜索"}', 'C', '进程调度按到达顺序处理,用队列 FIFO', 2.00, 2, 110),
(2388, 104, 1, '中缀表达式 a*(b+c)-d 的后缀表达式是', '{"A": "abcd*+-", "B": "abc+*d-", "C": "abc*+d-", "D": "-+*abcd"}', 'B', '先 b+c→bc+,再 a*(...)→abc+*,最后减 d→abc+*d-', 2.00, 3, 110),
(2389, 104, 1, '卡特兰数在栈问题中代表', '{"A": "n 元素入栈所有合法出栈序列数", "B": "栈的最大长度", "C": "队列的最大长度", "D": "链表合并方式数"}', 'A', 'C(2n,n)/(n+1) 即 n 个不同元素的合法出栈序列总数', 2.00, 3, 110),
(2390, 104, 1, '最适合用队列实现的应用是', '{"A": "二叉树深度遍历", "B": "表达式求值", "C": "操作系统作业调度", "D": "函数调用"}', 'C', '作业按到达顺序处理,FIFO 用队列', 2.00, 1, 110),
(2391, 104, 1, '串是元素受限的', '{"A": "线性表", "B": "非线性表", "C": "树", "D": "图"}', 'A', '串的本质是元素必须为字符的线性表', 2.00, 1, 110),
(2392, 104, 1, '下面关于串的描述错误的是', '{"A": "空串长度为 0", "B": "空串只包含空格字符", "C": "串是字符的有限序列", "D": "串可以顺序或链式存储"}', 'B', '空串不含任何字符,空格串只是包含空格的串', 2.00, 2, 110),
(2393, 104, 1, 'KMP 算法的时间复杂度是(主串 n 模式串 m)', '{"A": "O(n+m)", "B": "O(nm)", "C": "O(n^2)", "D": "O(m^2)"}', 'A', 'KMP 主串指针不回溯,模式串按 next 数组前移,总 O(n+m)', 2.00, 2, 110),
(2394, 104, 1, '模式串 ''abaabcac'' 的 next 数组(下标 1 起,首位记 0)是', '{"A": "0,1,1,2,2,3,1,1", "B": "0,1,1,2,3,1,2,1", "C": "0,1,2,1,2,3,4,2", "D": "0,1,1,2,2,3,1,2"}', 'A', '逐位计算最长公共前后缀,得 0,1,1,2,2,3,1,1', 2.00, 3, 110),
(2395, 104, 1, '串的两个最基本运算是', '{"A": "求长度和复制", "B": "赋值和比较", "C": "赋值和连接", "D": "插入和删除"}', 'B', '赋值与比较是其他串运算的基础', 2.00, 1, 110),
(2396, 104, 1, '串 s1=''abcde'' 中 s2=''cde'' 首次出现的位置(下标从 1 计)是', '{"A": "3", "B": "4", "C": "2", "D": "1"}', 'A', '''cde'' 是 s1 的第 3 到 5 个字符', 2.00, 1, 110),
(2397, 104, 1, '字符串 ''programming'' 的长度是', '{"A": "10", "B": "11", "C": "12", "D": "13"}', 'B', 'p-r-o-g-r-a-m-m-i-n-g 共 11 个字符', 2.00, 1, 110),
(2398, 104, 1, 'KMP 与朴素模式匹配的根本不同是', '{"A": "KMP 用 next 数组让模式串智能滑动主串不回溯", "B": "主串和模式串都不回溯", "C": "KMP 比较次数多", "D": "KMP 实现简单"}', 'A', 'KMP 失配时利用 next 数组让模式串高效滑动,主串指针保持不动', 2.00, 2, 110),
(2399, 104, 1, '深度为 5 的满二叉树共有结点数', '{"A": "16", "B": "32", "C": "31", "D": "63"}', 'C', '满二叉树共 2^h-1 个结点,h=5 时 2^5-1=31', 2.00, 1, 110),
(2400, 104, 1, '具有 n 个结点的完全二叉树深度为', '{"A": "floor(log2 n)+1", "B": "ceil(log2 n)", "C": "floor(log2(n+1))", "D": "ceil(log2(n+1))"}', 'A', '完全二叉树深度为 floor(log2 n)+1', 2.00, 2, 110),
(2401, 104, 1, '二叉树第 i 层最多有', '{"A": "2i 个结点", "B": "2^(i-1) 个结点", "C": "2^i-1 个结点", "D": "2^i 个结点"}', 'B', '第 i 层(根为第 1 层)最多 2^(i-1) 个结点', 2.00, 1, 110),
(2402, 104, 1, '已知二叉树前序 ABDEC 中序 DBEAC,则后序遍历是', '{"A": "DEBCA", "B": "DBEAC", "C": "ABDEC", "D": "DEBAC"}', 'A', '前序根 A;中序左 DBE 右 C;左子树前序 BDE 中序 DBE 后序 DEB;右子树 C;合 DEBCA', 2.00, 3, 110),
(2403, 104, 1, '中序线索化二叉树中,中序遍历的第一个结点没有', '{"A": "左线索", "B": "右线索", "C": "双亲", "D": "数据"}', 'A', '第一个结点的左指针为空或作为前驱线索使用', 2.00, 2, 110),
(2404, 104, 1, '具有 n 个权值的哈夫曼树中,叶子结点数为 n,非叶子结点数为', '{"A": "n-1", "B": "n", "C": "n+1", "D": "2n-1"}', 'A', 'n 个叶子合并 n-1 次得到 n-1 个非叶子结点,总结点 2n-1', 2.00, 2, 110),
(2405, 104, 1, '具有 100 个结点的完全二叉树从 1 开始编号,编号 49 结点的左子是', '{"A": "98", "B": "99", "C": "100", "D": "不存在"}', 'A', '左子编号 = 2*49 = 98 <= 100,存在', 2.00, 2, 110),
(2406, 104, 1, '哈夫曼编码中,频率高的字符编码', '{"A": "较长", "B": "较短", "C": "等长", "D": "与频率无关"}', 'B', '哈夫曼编码:频率越高路径越短编码越短,符合最优前缀编码', 2.00, 1, 110),
(2407, 104, 1, '具有 n 个结点的二叉链表中,空指针个数为', '{"A": "n-1", "B": "n", "C": "n+1", "D": "2n"}', 'C', '共 2n 个指针,有 n-1 个指向子结点,剩 n+1 个为空', 2.00, 3, 110),
(2408, 104, 1, '二叉树前序遍历顺序为 ABCDEFG,则一定是', '{"A": "A 是根", "B": "A 是最左叶子", "C": "E 是叶子", "D": "结构唯一确定"}', 'A', '前序首先访问根', 2.00, 1, 110),
(2409, 104, 1, '关于二叉树正确的说法是', '{"A": "完全二叉树一定是满二叉树", "B": "满二叉树一定是完全二叉树", "C": "第 i 层一定有 2^(i-1) 个结点", "D": "所有二叉树都适合顺序存储"}', 'B', '满二叉树是完全二叉树的特例,反之不成立', 2.00, 2, 110),
(2410, 104, 1, '堆是一种', '{"A": "完全二叉树", "B": "满二叉树", "C": "二叉排序树", "D": "线索二叉树"}', 'A', '堆物理上基于完全二叉树,逻辑上满足堆序性', 2.00, 1, 110),
(2411, 104, 1, '二叉排序树中序遍历得到的序列特点是', '{"A": "升序", "B": "降序", "C": "随机", "D": "无序"}', 'A', 'BST 中序遍历必为递增序列', 2.00, 1, 110),
(2412, 104, 1, '平衡二叉树(AVL)的平衡因子取值范围是', '{"A": "-1,0,1", "B": "0,1", "C": "-2,-1,0,1,2", "D": "任意整数"}', 'A', 'AVL 树平衡因子 = 左子树高 - 右子树高,必须在 -1 到 1 之间', 2.00, 2, 110),
(2413, 104, 1, '若树 T 有 m 个度为 4 的结点,则 T 中边的总数为(假设全部度为 4)', '{"A": "4m", "B": "4m+1", "C": "4m-1", "D": "m+4"}', 'A', '每个度为 4 的结点对应 4 条边', 2.00, 3, 110),
(2414, 104, 1, '二叉树后序遍历的访问次序是', '{"A": "左-右-根", "B": "左-根-右", "C": "根-左-右", "D": "右-左-根"}', 'A', '后序: 左子树 右子树 根', 2.00, 1, 110),
(2415, 104, 1, '树转化为二叉树后,二叉树的根结点对应原树', '{"A": "根的最左子", "B": "根本身", "C": "根的最右子", "D": "任意结点"}', 'B', '树转二叉:根作根,孩子作左子,兄弟作右子', 2.00, 2, 110),
(2416, 104, 1, '线索二叉树将什么用作线索', '{"A": "空指针", "B": "数据域", "C": "所有指针", "D": "附加字段"}', 'A', '线索二叉树将原本为空的指针修改为指向前驱/后继', 2.00, 2, 110),
(2417, 104, 1, '满二叉树的叶子数与非叶子数关系', '{"A": "叶子=非叶子+1", "B": "叶子=非叶子-1", "C": "叶子=非叶子", "D": "叶子=2*非叶子"}', 'A', '满二叉树叶子 = 非叶 + 1,即 2^(h-1) vs 2^(h-1)-1', 2.00, 3, 110),
(2418, 104, 1, '构造哈夫曼树的算法核心步骤是', '{"A": "每次选权值最小的两棵树合并", "B": "每次选权值最大的两棵树合并", "C": "按结点排序", "D": "按层次合并"}', 'A', '哈夫曼算法贪心:总选最小两棵合并,权值相加作新根', 2.00, 2, 110),
(2419, 104, 1, '无向图中所有顶点的度数之和等于', '{"A": "边数", "B": "边数的 2 倍", "C": "边数的 1/2", "D": "顶点数"}', 'B', '每条边贡献 2 度(两个端点各 1 度)', 2.00, 1, 110),
(2420, 104, 1, '具有 n 个顶点的无向完全图边数为', '{"A": "n(n-1)", "B": "n(n-1)/2", "C": "n^2", "D": "n(n+1)/2"}', 'B', 'C(n,2) = n(n-1)/2', 2.00, 1, 110),
(2421, 104, 1, '图的深度优先搜索 DFS 的非递归实现需要', '{"A": "栈", "B": "队列", "C": "堆", "D": "哈希表"}', 'A', 'DFS 用栈模拟递归,BFS 用队列', 2.00, 1, 110),
(2422, 104, 1, 'Prim 算法求最小生成树用邻接矩阵时间复杂度', '{"A": "O(V^2)", "B": "O(VE)", "C": "O(ElogV)", "D": "O(V+E)"}', 'A', '朴素 Prim 外层 V 次,每次找最小 O(V),共 O(V^2)', 2.00, 2, 110),
(2423, 104, 1, 'Kruskal 算法求最小生成树时间复杂度', '{"A": "O(V^2)", "B": "O(VE)", "C": "O(ElogE)", "D": "O(V+E)"}', 'C', 'Kruskal 排序所有边 O(ElogE) 加并查集判环', 2.00, 2, 110),
(2424, 104, 1, 'Dijkstra 算法不能处理', '{"A": "所有最短路径问题", "B": "含负权边的图", "C": "无向连通图", "D": "稀疏图"}', 'B', 'Dijkstra 要求边权非负,负权用 Bellman-Ford', 2.00, 2, 110),
(2425, 104, 1, '拓扑排序适用于', '{"A": "有向无环图", "B": "无向连通图", "C": "有向有环图", "D": "二部图"}', 'A', '拓扑序仅对 DAG 有意义', 2.00, 1, 110),
(2426, 104, 1, 'n 个顶点的强连通有向图至少需要多少条边', '{"A": "n-1", "B": "n", "C": "n+1", "D": "2n"}', 'B', '强连通需所有点形成一个环,至少 n 条边', 2.00, 2, 110),
(2427, 104, 1, '邻接矩阵法适合存储', '{"A": "稀疏图", "B": "稠密图", "C": "完全二叉树", "D": "二部图"}', 'B', '邻接矩阵 O(V^2) 空间,边多时利用率高', 2.00, 1, 110),
(2428, 104, 1, 'AOE 网中的关键路径是', '{"A": "权值之和最大的路径", "B": "权值之和最小的路径", "C": "边数最多的路径", "D": "边数最少的路径"}', 'A', '关键路径决定整个工程最短完工时间,即最长路径', 2.00, 2, 110),
(2429, 104, 1, '下列存储方式既能反映顶点又反映边信息的是', '{"A": "邻接矩阵", "B": "邻接表", "C": "邻接多重表", "D": "以上都可以"}', 'D', '三种方式均可表示顶点和边,差别在空间和操作效率', 2.00, 2, 110),
(2430, 104, 1, '图的 BFS 遍历类似于树的', '{"A": "前序遍历", "B": "中序遍历", "C": "后序遍历", "D": "层序遍历"}', 'D', 'BFS 一层一层访问,对应树的层序遍历', 2.00, 1, 110),
(2431, 104, 1, '长度为 n 的有序顺序表折半查找,最坏比较次数约为', '{"A": "n/2", "B": "logn", "C": "n", "D": "sqrt(n)"}', 'B', '折半最坏 floor(log2 n)+1 次,即 O(logn)', 2.00, 1, 110),
(2432, 104, 1, '折半查找的前提条件是', '{"A": "表元素必须按值有序", "B": "表必须为链式存储", "C": "表元素必须为整数", "D": "表必须为递增"}', 'A', '折半查找要求顺序存储 + 元素有序', 2.00, 1, 110),
(2433, 104, 1, '平均查找长度 ASL 最小的查找方式是', '{"A": "顺序查找", "B": "折半查找", "C": "分块查找", "D": "以上一样"}', 'B', '折半查找 ASL=log(n+1)-1,远小于顺序的 (n+1)/2', 2.00, 1, 110),
(2434, 104, 1, '长度为 11 的有序顺序表折半查找成功的平均查找长度约为', '{"A": "11/4", "B": "3", "C": "11/3", "D": "3/11"}', 'B', '满二叉判定树,11 个结点的 ASL 约 3', 2.00, 3, 110),
(2435, 104, 1, '哈希表中将不同关键字映射到同一地址称为', '{"A": "冲突", "B": "重复", "C": "堆叠", "D": "碰撞"}', 'A', '哈希冲突即关键字不同但 hash 值相同', 2.00, 1, 110),
(2436, 104, 1, '处理冲突的开放定址法不包括', '{"A": "线性探测", "B": "二次探测", "C": "再哈希", "D": "链地址法"}', 'D', '链地址法是另一类冲突处理,不属于开放定址', 2.00, 2, 110),
(2437, 104, 1, 'B 树和 B+ 树主要应用于', '{"A": "内存数据", "B": "操作系统内核", "C": "数据库索引和文件系统", "D": "图形渲染"}', 'C', 'B+ 树是 MySQL、文件系统(NTFS、ext4)的核心索引结构', 2.00, 1, 110),
(2438, 104, 1, 'B+ 树相比 B 树的优势是', '{"A": "叶子结点形成有序链表便于范围查询", "B": "层数更少", "C": "非叶子结点也存数据", "D": "空间更省"}', 'A', 'B+ 树叶子用链表串联,便于高效范围查询', 2.00, 2, 110),
(2439, 104, 1, '直接插入排序的最好时间复杂度是', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n^2)", "D": "O(logn)"}', 'A', '已排序时每次仅比较一次不移动,O(n)', 2.00, 2, 110),
(2440, 104, 1, '快速排序最坏时间复杂度是', '{"A": "O(n)", "B": "O(nlogn)", "C": "O(n^2)", "D": "O(n^3)"}', 'C', '枢轴极不平衡(完全有序+取首为枢轴)时退化为 O(n^2)', 2.00, 2, 110),
(2441, 104, 1, '下列排序中稳定的是', '{"A": "快速排序", "B": "希尔排序", "C": "堆排序", "D": "归并排序"}', 'D', '归并排序保留相等元素相对次序,稳定', 2.00, 2, 110),
(2442, 104, 1, '堆排序的空间复杂度是', '{"A": "O(1)", "B": "O(n)", "C": "O(logn)", "D": "O(nlogn)"}', 'A', '堆排序原地操作,常数辅助空间', 2.00, 2, 110),
(2443, 104, 1, '下列哪种排序对几乎排好序的数据效率最高', '{"A": "直接插入", "B": "快速排序", "C": "堆排序", "D": "归并排序"}', 'A', '插入排序在近有序数据上接近 O(n)', 2.00, 2, 110),
(2444, 104, 1, '希尔排序的本质是', '{"A": "改进的插入排序", "B": "改进的冒泡排序", "C": "改进的选择排序", "D": "改进的归并排序"}', 'A', '希尔排序通过增量分组进行插入排序', 2.00, 1, 110),
(2445, 104, 1, '基数排序时间复杂度(n 元素每个 d 位 r 进制)', '{"A": "O(n)", "B": "O(n+d)", "C": "O(d(n+r))", "D": "O(nlogn)"}', 'C', 'r 个桶 d 趟分配和收集', 2.00, 3, 110),
(2446, 104, 1, '外部排序的时间主要花在', '{"A": "内部排序", "B": "归并", "C": "I/O 读写", "D": "建立索引"}', 'C', '外部排序数据在磁盘,I/O 是主要瓶颈', 2.00, 2, 110),
(2447, 104, 2, '算法必须具备以下哪些特性', '{"A": "有穷性", "B": "确定性", "C": "可行性", "D": "健壮性"}', 'ABC', '算法五大特性: 输入 输出 有穷 确定 可行,健壮性是工程评估指标', 3.00, 2, 110),
(2448, 104, 2, '关于算法时间复杂度描述正确的有', '{"A": "与机器无关", "B": "与编程语言无关", "C": "与算法本身有关", "D": "与输入数据规模有关"}', 'ABCD', '时间复杂度是算法本身效率的抽象描述', 3.00, 2, 110),
(2449, 104, 2, '下列哪些时间复杂度是同一数量级', '{"A": "O(n)", "B": "O(2n)", "C": "O(n+1000)", "D": "O(n^2)"}', 'ABC', '大 O 忽略常数和低阶项,n、2n、n+1000 都是 O(n)', 3.00, 2, 110),
(2450, 104, 2, '算法效率评估常用指标包括', '{"A": "时间复杂度", "B": "空间复杂度", "C": "可读性", "D": "正确性"}', 'ABCD', '算法评价需多维度', 3.00, 1, 110),
(2451, 104, 2, '顺序表相比链表的优势包括', '{"A": "随机访问 O(1)", "B": "存储密度高", "C": "便于二分查找", "D": "插入删除高效"}', 'ABC', '顺序表插入删除需移动元素,不高效', 3.00, 2, 110),
(2452, 104, 2, '下列关于链表的说法正确的是', '{"A": "存储不连续", "B": "插入删除不需移动元素", "C": "可以随机访问", "D": "结点含数据域和指针域"}', 'ABD', '链表只能顺序访问,不支持随机访问', 3.00, 2, 110),
(2453, 104, 2, '下列是线性结构的有', '{"A": "栈", "B": "队列", "C": "字符串", "D": "二叉树"}', 'ABC', '栈队列串都是线性结构,二叉树是非线性', 3.00, 1, 110),
(2454, 104, 2, '双向链表相比单链表的优势包括', '{"A": "可双向遍历", "B": "O(1) 删除已知结点", "C": "插入更快", "D": "空间占用更少"}', 'AB', '双向链表每个结点多一个指针,空间反而更多', 3.00, 2, 110),
(2455, 104, 2, '下列操作在循环单链表中比单链表更优的是', '{"A": "判断是否到尾部", "B": "从尾到头遍历", "C": "循环遍历多次", "D": "插入元素到表尾"}', 'CD', '循环单链表用尾指针访问表尾更快,但仍不能反向遍历', 3.00, 3, 110),
(2456, 104, 2, '栈的应用包括', '{"A": "表达式求值", "B": "函数递归", "C": "括号匹配", "D": "作业调度"}', 'ABC', '作业调度通常用队列', 3.00, 2, 110),
(2457, 104, 2, '队列的应用包括', '{"A": "BFS", "B": "操作系统消息缓冲", "C": "打印任务管理", "D": "DFS"}', 'ABC', 'DFS 用栈', 3.00, 2, 110),
(2458, 104, 2, '下列关于循环队列描述正确的是', '{"A": "解决假溢出问题", "B": "逻辑上首尾相连", "C": "判满需牺牲一个单元", "D": "头尾指针都需动态调整"}', 'ABCD', '循环队列以模运算实现首尾衔接', 3.00, 2, 110),
(2459, 104, 2, '栈和队列的共同特点是', '{"A": "线性结构", "B": "只允许端点操作", "C": "数据元素类型一致", "D": "支持随机访问"}', 'ABC', '两者都不支持随机访问', 3.00, 1, 110),
(2460, 104, 2, '用栈实现表达式求值需要', '{"A": "操作数栈", "B": "操作符栈", "C": "符号优先级表", "D": "运算结果寄存器"}', 'ABC', '双栈算法需根据优先级决定何时弹栈计算', 3.00, 2, 110),
(2461, 104, 2, '关于 KMP 算法描述正确的是', '{"A": "主串指针不回溯", "B": "利用 next 数组", "C": "时间复杂度 O(n+m)", "D": "空间复杂度 O(1)"}', 'ABC', 'KMP 需 O(m) 空间存 next 数组', 3.00, 3, 110),
(2462, 104, 2, '串的基本操作包括', '{"A": "赋值", "B": "比较", "C": "求子串", "D": "求长度"}', 'ABCD', '这些都是串的基本操作', 3.00, 1, 110),
(2463, 104, 2, '下列经典字符串匹配算法包括', '{"A": "朴素匹配", "B": "KMP", "C": "BM", "D": "Sunday"}', 'ABCD', '这些都是经典字符串匹配算法', 3.00, 2, 110),
(2464, 104, 2, '满二叉树的特点包括', '{"A": "所有叶子在同一层", "B": "每个非叶子都有两个孩子", "C": "深度 h 的满二叉树有 2^h-1 个结点", "D": "是完全二叉树的特例"}', 'ABCD', '满二叉树是完全二叉树的极端情况', 3.00, 2, 110),
(2465, 104, 2, '二叉树的遍历方式包括', '{"A": "前序", "B": "中序", "C": "后序", "D": "层序"}', 'ABCD', '四种基础遍历方式', 3.00, 1, 110),
(2466, 104, 2, '下列关于哈夫曼树正确的是', '{"A": "带权路径长度最小", "B": "非叶子结点都有两个孩子", "C": "叶子结点存权值", "D": "频率高的字符路径长"}', 'ABC', '哈夫曼编码频率高的字符路径短', 3.00, 2, 110),
(2467, 104, 2, '线索二叉树的优点包括', '{"A": "加快遍历速度", "B": "利用空指针", "C": "便于查找前驱后继", "D": "节省空间"}', 'ABC', '线索利用空指针提升遍历效率,但空间略增', 3.00, 2, 110),
(2468, 104, 2, '下列结构是二叉树特殊形态的有', '{"A": "满二叉树", "B": "完全二叉树", "C": "二叉排序树", "D": "哈夫曼树"}', 'ABCD', '这些都属于二叉树的特殊形态', 3.00, 1, 110),
(2469, 104, 2, '堆的应用包括', '{"A": "优先队列", "B": "堆排序", "C": "Top-K 问题", "D": "哈夫曼编码"}', 'ABCD', '堆是这些应用的核心数据结构', 3.00, 2, 110),
(2470, 104, 2, '二叉树的基本性质包括', '{"A": "第 i 层最多 2^(i-1) 个结点", "B": "深度 h 二叉树最多 2^h-1 个结点", "C": "完全二叉树用数组存最省空间", "D": "孩子兄弟表示法本质是二叉链表"}', 'ABCD', '这些都是二叉树的基本性质', 3.00, 2, 110),
(2471, 104, 2, '图的存储方式包括', '{"A": "邻接矩阵", "B": "邻接表", "C": "十字链表", "D": "邻接多重表"}', 'ABCD', '四种经典图存储方式', 3.00, 2, 110),
(2472, 104, 2, '图的遍历方式有', '{"A": "DFS", "B": "BFS", "C": "中序遍历", "D": "层序遍历"}', 'AB', '图没有中序、层序遍历概念,这是树的术语', 3.00, 1, 110),
(2473, 104, 2, '求最小生成树的算法有', '{"A": "Prim", "B": "Kruskal", "C": "Dijkstra", "D": "Floyd"}', 'AB', 'Dijkstra 和 Floyd 求最短路径,不是 MST', 3.00, 2, 110),
(2474, 104, 2, '求图最短路径的算法有', '{"A": "Dijkstra", "B": "Floyd", "C": "Bellman-Ford", "D": "SPFA"}', 'ABCD', '四种经典最短路径算法', 3.00, 2, 110),
(2475, 104, 2, 'DAG 的应用包括', '{"A": "拓扑排序", "B": "关键路径", "C": "课程依赖", "D": "哈夫曼编码"}', 'ABC', '哈夫曼编码基于二叉树,不基于 DAG', 3.00, 2, 110),
(2476, 104, 2, '下列哪些是图的连通性概念', '{"A": "连通图", "B": "强连通图", "C": "弱连通图", "D": "单向连通图"}', 'ABCD', '四种连通性的概念', 3.00, 3, 110),
(2477, 104, 2, '邻接表相比邻接矩阵的优势', '{"A": "空间更省(尤其稀疏图)", "B": "求所有邻接顶点更快", "C": "判断两顶点是否相邻更快", "D": "便于求度"}', 'ABD', '判断相邻邻接矩阵 O(1) 更优', 3.00, 2, 110),
(2478, 104, 2, '下列哪些查找方法时间复杂度可达 O(logn)', '{"A": "折半查找", "B": "二叉排序树查找", "C": "平衡二叉树查找", "D": "B 树查找"}', 'ACD', 'BST 退化时为 O(n),AVL/B 树保证 O(logn)', 3.00, 2, 110),
(2479, 104, 2, '哈希冲突处理方法有', '{"A": "线性探测", "B": "二次探测", "C": "再哈希", "D": "链地址法"}', 'ABCD', '四种经典冲突处理方法', 3.00, 2, 110),
(2480, 104, 2, '下列关于平衡二叉树正确的是', '{"A": "左右子树高度差不超过 1", "B": "查找复杂度 O(logn)", "C": "插入需要旋转维护平衡", "D": "所有结点平衡因子为 0"}', 'ABC', '平衡因子可为 -1,0,1 中任意值', 3.00, 2, 110),
(2481, 104, 2, 'B+ 树与 B 树的区别包括', '{"A": "B+ 树叶子结点形成有序链表", "B": "B+ 树仅叶子结点存数据", "C": "B+ 树范围查询更快", "D": "B+ 树高度更低"}', 'ABC', 'B+ 树高度未必更低,与 B 树同阶', 3.00, 3, 110),
(2482, 104, 2, '下列稳定的排序算法是', '{"A": "冒泡排序", "B": "直接插入排序", "C": "归并排序", "D": "快速排序"}', 'ABC', '快排不稳定,其余三个稳定', 3.00, 2, 110),
(2483, 104, 2, '下列原地排序算法是', '{"A": "堆排序", "B": "快速排序", "C": "归并排序", "D": "直接插入排序"}', 'ABD', '归并需 O(n) 辅助空间,非原地', 3.00, 2, 110),
(2484, 104, 2, '下列时间复杂度可达 O(nlogn) 的排序算法', '{"A": "归并排序", "B": "堆排序", "C": "快速排序(平均)", "D": "直接插入排序"}', 'ABC', '直接插入排序 O(n^2)', 3.00, 2, 110),
(2485, 104, 2, '下列适合大规模数据排序的有', '{"A": "归并排序", "B": "快速排序", "C": "堆排序", "D": "冒泡排序"}', 'ABC', '冒泡排序 O(n^2) 不适合大规模', 3.00, 2, 110),
(2486, 104, 2, '下列关于排序算法表述正确的', '{"A": "快速排序平均最快", "B": "归并排序总是 O(nlogn)", "C": "堆排序空间 O(1)", "D": "直接插入排序适合近有序数据"}', 'ABCD', '四项均为排序算法基本特性', 3.00, 2, 110),
(2487, 104, 3, '算法的时间复杂度与机器、编译器以及编程语言均无关', NULL, '正确', '时间复杂度是对算法本身的抽象描述,与运行环境无关', 1.00, 1, 110),
(2488, 104, 3, '算法可以没有输入,但必须有至少一个输出', NULL, '正确', '算法可零输入,但至少要有一个输出表示运算结果', 1.00, 2, 110),
(2489, 104, 3, '所有 O(n^2) 的算法都比 O(nlogn) 的算法慢', NULL, '错误', '大 O 仅描述增长趋势,对于小规模 n 可能 O(n^2) 更快', 1.00, 2, 110),
(2490, 104, 3, '空间复杂度只考虑算法运行过程中新申请的辅助空间', NULL, '正确', '空间复杂度通常指辅助空间,不含输入数据本身', 1.00, 1, 110),
(2491, 104, 3, '顺序表的存储密度比链表低', NULL, '错误', '顺序表只存数据,链表还需存指针,顺序表存储密度更高', 1.00, 1, 110),
(2492, 104, 3, '在单链表中,只要知道某节点指针就能 O(1) 删除该节点', NULL, '错误', '必须知道其前驱才能 O(1) 删除,否则需 O(n) 找前驱', 1.00, 2, 110),
(2493, 104, 3, '双向循环链表中,任意节点都能在 O(1) 内访问其前驱和后继', NULL, '正确', '双向链表保留前驱指针,首尾相连构成循环', 1.00, 1, 110),
(2494, 104, 3, '线性表中相邻元素在物理上一定相邻', NULL, '错误', '顺序存储时相邻,链式存储时未必', 1.00, 1, 110),
(2495, 104, 3, '顺序表的插入和删除操作平均时间复杂度为 O(1)', NULL, '错误', '平均需移动一半元素,为 O(n)', 1.00, 2, 110),
(2496, 104, 3, '栈是一种后进先出的线性表', NULL, '正确', '栈 LIFO 的定义', 1.00, 1, 110),
(2497, 104, 3, '队列是一种先进后出的线性表', NULL, '错误', '队列是先进先出 FIFO', 1.00, 1, 110),
(2498, 104, 3, '循环队列采用模运算解决假溢出问题', NULL, '正确', '循环队列通过 (rear+1)%n 等模运算实现首尾相连', 1.00, 1, 110),
(2499, 104, 3, '对于 n 个元素的入栈序列,可能的出栈序列数为 Catalan 数', NULL, '正确', '卡特兰数 C(2n,n)/(n+1) 给出合法出栈序列数', 1.00, 3, 110),
(2500, 104, 3, '表达式求值通常用栈实现', NULL, '正确', '双栈算法(操作数栈+操作符栈)是表达式求值的经典实现', 1.00, 1, 110),
(2501, 104, 3, '空串的长度等于空格串的长度', NULL, '错误', '空串长度为 0,空格串长度等于空格数', 1.00, 1, 110),
(2502, 104, 3, 'KMP 算法主串指针不回溯,模式串指针根据 next 数组前移', NULL, '正确', 'KMP 算法的核心', 1.00, 2, 110),
(2503, 104, 3, 'next 数组的本质是模式串各前缀的最长公共前后缀长度', NULL, '正确', '这是 next 数组的数学定义', 1.00, 3, 110),
(2504, 104, 3, '满二叉树一定是完全二叉树,反之未必', NULL, '正确', '满二叉树是完全二叉树的极端情况', 1.00, 1, 110),
(2505, 104, 3, '二叉树中,前序遍历和后序遍历相同则该树仅有一个结点', NULL, '正确', '前序和后序仅根结点位置一致时相同,只有单结点满足', 1.00, 3, 110),
(2506, 104, 3, '给定中序序列即可唯一确定二叉树', NULL, '错误', '至少需要中序+另一种遍历才能唯一确定', 1.00, 2, 110),
(2507, 104, 3, '完全二叉树的最后一个非叶子结点编号为 floor(n/2)', NULL, '正确', '数组存储完全二叉树时,该公式给出最后非叶位置', 1.00, 2, 110),
(2508, 104, 3, '哈夫曼树中频率最大的字符编码最短', NULL, '正确', '哈夫曼编码的核心思想:频率高的字符路径短编码短', 1.00, 1, 110),
(2509, 104, 3, '二叉排序树的中序遍历必为升序', NULL, '正确', 'BST 的核心性质', 1.00, 1, 110),
(2510, 104, 3, 'AVL 树是一种自平衡的二叉排序树', NULL, '正确', 'AVL 通过旋转维持每个结点平衡因子在 [-1,1]', 1.00, 1, 110),
(2511, 104, 3, '红黑树是严格平衡的二叉树', NULL, '错误', '红黑树是近似平衡,允许左右子树高度差最多 2 倍', 1.00, 2, 110),
(2512, 104, 3, '无向图中所有顶点度数之和等于边数', NULL, '错误', '等于边数的 2 倍,因每条边贡献两个端点的度', 1.00, 1, 110),
(2513, 104, 3, '图的 DFS 遍历不唯一,与起点和邻接顺序有关', NULL, '正确', '遍历结果依赖起点选择和邻接表中顶点顺序', 1.00, 2, 110),
(2514, 104, 3, 'Dijkstra 算法可以处理带负权边的有向图', NULL, '错误', 'Dijkstra 要求所有边权非负,负权用 Bellman-Ford', 1.00, 2, 110),
(2515, 104, 3, '拓扑排序的结果可能不唯一', NULL, '正确', '当多个入度为 0 的顶点时,选择顺序可不同,结果非唯一', 1.00, 2, 110),
(2516, 104, 3, '图的最小生成树必须含所有顶点和恰好 n-1 条边', NULL, '正确', 'MST 是 n 顶点连通图的生成子树,n-1 条边', 1.00, 2, 110),
(2517, 104, 3, '邻接矩阵存储图所需空间与边数无关', NULL, '正确', '邻接矩阵 O(V^2),只与顶点数有关', 1.00, 2, 110),
(2518, 104, 3, '折半查找适用于链式存储', NULL, '错误', '折半查找需 O(1) 访问中间元素,链表不支持随机访问', 1.00, 1, 110),
(2519, 104, 3, '哈希表的查找时间复杂度在最优情况下是 O(1)', NULL, '正确', '无冲突时 hash 直接定位,O(1)', 1.00, 1, 110),
(2520, 104, 3, '二叉排序树的查找性能与树的形态有关', NULL, '正确', 'BST 不平衡时退化为链表,查找 O(n)', 1.00, 2, 110),
(2521, 104, 3, 'B+ 树的所有叶子结点位于同一层', NULL, '正确', 'B+ 树性质:所有叶子结点深度相同', 1.00, 2, 110),
(2522, 104, 3, '快速排序在最坏情况下时间复杂度为 O(nlogn)', NULL, '错误', '最坏 O(n^2),平均 O(nlogn)', 1.00, 1, 110),
(2523, 104, 3, '堆排序是稳定的排序算法', NULL, '错误', '堆排序在调整堆时可能交换相等元素的相对位置,不稳定', 1.00, 2, 110),
(2524, 104, 3, '归并排序总能保证 O(nlogn) 时间复杂度', NULL, '正确', '归并排序与输入无关,始终 O(nlogn)', 1.00, 1, 110),
(2525, 104, 3, '希尔排序是稳定的排序算法', NULL, '错误', '希尔排序在不同增量分组时可能改变相等元素位置,不稳定', 1.00, 2, 110),
(2526, 104, 3, '直接插入排序对几乎有序的数据效率接近 O(n)', NULL, '正确', '近有序时每次插入只比较 1-2 次,接近 O(n)', 1.00, 1, 110),
(2527, 104, 4, '对长度为 n 的有序顺序表进行折半查找,查找成功的平均查找长度数量级是____', NULL, 'O(logn)|logn', '折半查找 ASL 渐进 O(logn)', 3.00, 2, 110),
(2528, 104, 4, '算法五大基本特性: 有穷性、确定性、可行性、____ 和输出', NULL, '输入', '算法五特性: 输入 输出 有穷 确定 可行', 3.00, 1, 110),
(2529, 104, 4, '程序段 for(i=1;i<=n;i*=2) x++ 的时间复杂度是____', NULL, 'O(logn)|logn', '每次 i 翻倍,循环约 log2 n 次', 3.00, 2, 110),
(2530, 104, 4, '长度为 n 的顺序表在第 i 位置插入元素需移动____个元素', NULL, 'n-i+1', '需将 a_i 至 a_n 共 n-i+1 个元素后移', 3.00, 2, 110),
(2531, 104, 4, '双向链表每个结点比单链表多____个指针', NULL, '1|一', '双向链表多一个 prior 指针', 3.00, 1, 110),
(2532, 104, 4, '带头结点单链表判空条件是 head->next == ____', NULL, 'NULL|null|空', '头结点 next 为空即链表无数据', 3.00, 1, 110),
(2533, 104, 4, '栈是限定仅在____进行插入和删除的线性表', NULL, '栈顶|表尾|一端', '栈只在栈顶/表尾操作', 3.00, 1, 110),
(2534, 104, 4, '队列的特性是____先出', NULL, '先进|FIFO', '队列先进先出', 3.00, 1, 110),
(2535, 104, 4, '循环队列长 N 头指针指队头前一位置,队满条件是____', NULL, '(rear+1)%N==front', '牺牲一个单元法判满', 3.00, 3, 110),
(2536, 104, 4, '中缀表达式 (a+b)*c 的后缀表达式是____', NULL, 'ab+c*', '先 a+b→ab+,再乘 c→ab+c*', 3.00, 2, 110),
(2537, 104, 4, 'KMP 算法时间复杂度是____(主串 n 模式 m)', NULL, 'O(n+m)|O(m+n)', 'KMP 不回溯主串,总复杂度 O(n+m)', 3.00, 2, 110),
(2538, 104, 4, '深度为 h 的满二叉树共有____个结点', NULL, '2^h-1|2的h次方减一', '满二叉树结点数公式', 3.00, 1, 110),
(2539, 104, 4, '具有 n 个权值叶子的哈夫曼树非叶子结点共____个', NULL, 'n-1', '哈夫曼树由 n 个叶子和 n-1 个非叶子结点组成', 3.00, 2, 110),
(2540, 104, 4, '二叉树第 i 层最多有____个结点', NULL, '2^(i-1)|2的i-1次方', '二叉树基本性质', 3.00, 1, 110),
(2541, 104, 4, '二叉排序树中序遍历得到的序列是____序列', NULL, '升序|有序|递增', 'BST 中序遍历必为升序', 3.00, 1, 110),
(2542, 104, 4, 'AVL 树平衡因子的取值范围是____', NULL, '-1,0,1|[-1,1]', 'AVL 平衡因子=左高-右高 必在 -1 至 1 间', 3.00, 2, 110),
(2543, 104, 4, '具有 n 个顶点的无向完全图共有____条边', NULL, 'n(n-1)/2', 'C(n,2)=n(n-1)/2', 3.00, 1, 110),
(2544, 104, 4, '图的深度优先搜索 DFS 非递归实现需借助____', NULL, '栈', 'DFS 用栈模拟递归', 3.00, 1, 110),
(2545, 104, 4, 'Prim 算法用邻接矩阵存储图时时间复杂度是____', NULL, 'O(V^2)|O(n^2)', 'Prim 朴素实现 O(V^2)', 3.00, 2, 110),
(2546, 104, 4, '拓扑排序适用于____图', NULL, '有向无环|DAG', '拓扑序仅对 DAG 有意义', 3.00, 1, 110),
(2547, 104, 4, 'AOE 网中关键路径是从源点到汇点路径长度____的路径', NULL, '最大|最长', '关键路径决定工程最短完工时间,为最长路径', 3.00, 2, 110),
(2548, 104, 4, '图的 BFS 遍历类似于树的____遍历', NULL, '层序', 'BFS 一层一层访问对应树的层序', 3.00, 1, 110),
(2549, 104, 4, '哈希冲突的处理方法主要有开放定址法和____', NULL, '链地址法|拉链法', '两类经典冲突处理方法', 3.00, 2, 110),
(2550, 104, 4, 'B+ 树主要应用于____和文件系统的索引', NULL, '数据库', 'MySQL 等数据库索引核心使用 B+ 树', 3.00, 1, 110),
(2551, 104, 4, '快速排序的最坏时间复杂度是____', NULL, 'O(n^2)|O(n*n)', '完全有序+取首为枢轴时退化', 3.00, 2, 110),
(2552, 104, 4, '归并排序的空间复杂度是____', NULL, 'O(n)', '归并需 O(n) 辅助空间', 3.00, 2, 110),
(2553, 104, 4, '堆排序的时间复杂度是____', NULL, 'O(nlogn)', '建堆 O(n) + n 次调整 O(nlogn) = O(nlogn)', 3.00, 2, 110),
(2554, 104, 4, '直接插入排序最好时间复杂度是____', NULL, 'O(n)', '已排序时仅 n-1 次比较', 3.00, 2, 110),
(2555, 104, 4, '希尔排序是基于____排序的改进算法', NULL, '直接插入|插入', '希尔排序通过分组进行插入排序', 3.00, 1, 110),
(2556, 104, 5, '简述算法的五大基本特性', NULL, '算法五大基本特性: (1)输入: 有零个或多个输入; (2)输出: 至少有一个输出; (3)有穷性: 在有限步骤内终止; (4)确定性: 每一步操作都明确无歧义; (5)可行性: 每一步操作都能由计算机实际执行', '算法五特性是衡量算法基本要求的核心准则', 10.00, 1, 110),
(2557, 104, 5, '简述时间复杂度和空间复杂度的概念及其衡量意义', NULL, '时间复杂度: 算法运行时间随输入规模增长的渐进表达,常用大 O 记号; 空间复杂度: 算法运行所需辅助存储空间随输入规模的渐进表达。两者用于在不依赖具体机器的条件下评价算法效率,时间复杂度反映效率,空间复杂度反映存储开销', '复杂度是评估算法的两大维度,影响算法选型', 10.00, 1, 110),
(2558, 104, 5, '简述顺序存储与链式存储的优缺点对比', NULL, '顺序存储优点: 随机访问 O(1)、存储密度高、便于实现折半查找等; 缺点: 插入删除需移动大量元素、空间利用率取决于预估容量; 链式存储优点: 插入删除高效不需要移动元素、空间动态分配; 缺点: 只能顺序访问、存储密度低(需指针开销)、不支持折半查找', '两种存储是数据结构基础,各有适用场景', 10.00, 2, 110),
(2559, 104, 5, '简述单链表的插入操作步骤及其时间复杂度', NULL, '在 p 节点后插入新结点 s 的步骤: (1)申请新结点 s,赋数据; (2)s->next = p->next (新结点指向 p 的后继); (3)p->next = s (p 指向新结点)。注意顺序不可颠倒。本身插入操作 O(1),但若需查找插入位置则总时间 O(n)', '单链表插入是链表基础操作,顺序与时间复杂度需牢记', 10.00, 2, 110),
(2560, 104, 5, '简述栈与队列的区别', NULL, '栈和队列均为操作受限的线性表,区别在于: 栈 LIFO 后进先出,只允许在栈顶进行插入和删除; 队列 FIFO 先进先出,只允许在队尾插入、队头删除。栈应用包括函数调用、表达式求值、括号匹配; 队列应用包括消息缓冲、BFS、作业调度等', '栈队列是常用的两种线性结构,理解差异有助于选择', 10.00, 1, 110),
(2561, 104, 5, '简述循环队列产生的原因及其设计要点', NULL, '原因: 顺序队列因 front 和 rear 单向移动会产生''假溢出''现象(队尾已到数组末端但前部仍有空间)。设计要点: (1)将数组首尾相连形成逻辑循环结构; (2)使用模运算 (rear+1)%n 实现指针绕回; (3)为区分队空和队满,采用牺牲一个存储单元法,约定 rear==front 为空、(rear+1)%n==front 为满', '循环队列是顺序队列的优化,空间利用率高', 10.00, 2, 110),
(2562, 104, 5, '简述 KMP 算法相对朴素模式匹配的改进及其核心思想', NULL, '改进核心: 朴素匹配在失配时主串和模式串都要回溯,效率 O(nm); KMP 利用模式串自身的最长公共前后缀信息(next 数组),失配时主串指针保持不动,模式串指针根据 next 数组智能滑动到合适位置继续比较,避免了主串回溯。时间复杂度由 O(nm) 优化到 O(n+m),空间 O(m)', 'KMP 是字符串匹配的经典优化', 10.00, 2, 110),
(2563, 104, 5, '简述二叉树的三种基本遍历方式', NULL, '前序遍历: 根-左-右,先访问根结点,再前序遍历左子树,后前序遍历右子树; 中序遍历: 左-根-右,先中序遍历左子树,再访问根结点,后中序遍历右子树; 后序遍历: 左-右-根,先后序遍历左子树,再后序遍历右子树,后访问根结点。三种遍历的实现都可递归或借助栈非递归实现', '三种遍历是二叉树操作的基础', 10.00, 1, 110),
(2564, 104, 5, '简述哈夫曼树的构造过程及哈夫曼编码的特点', NULL, '构造过程: (1)将 n 个权值视为 n 棵独立树组成森林; (2)每次从森林中选两棵权值最小的树合并,合并后的根权值=两子权之和; (3)新树加入森林,重复直到森林只剩一棵树即哈夫曼树。哈夫曼编码特点: 频率高的字符路径短编码短;是前缀编码,无歧义解码;带权路径长度 WPL 最小,达到最优压缩', '哈夫曼是压缩编码的基础', 10.00, 2, 110),
(2565, 104, 5, '简述二叉排序树 BST 的定义、性质和查找过程', NULL, '定义: 空树或满足以下性质的二叉树: 左子树所有结点 < 根 < 右子树所有结点,且左右子树都是 BST。性质: 中序遍历必为升序。查找过程: 从根开始,目标 < 当前则进入左子树、> 当前则进入右子树、=则查找成功。平均查找复杂度 O(logn),最坏(退化为链)时 O(n)', 'BST 是查找树的基础,实际中常用平衡 BST 如 AVL/红黑树', 10.00, 2, 110),
(2566, 104, 5, '简述图的两种遍历方式 DFS 和 BFS 的特点与实现', NULL, 'DFS 深度优先搜索: 从起点出发尽可能向深处探索,直到无未访问邻居才回溯,实现借助栈(递归或显式栈),类似树的前序遍历。BFS 广度优先搜索: 从起点出发逐层访问邻居,实现借助队列,类似树的层序遍历。两者均需访问标记数组防止重复访问。时间复杂度均为 O(V+E)(邻接表)或 O(V^2)(邻接矩阵)', 'DFS/BFS 是图遍历的两种基本算法', 10.00, 2, 110),
(2567, 104, 5, '简述 Prim 与 Kruskal 算法的思想及适用场景', NULL, 'Prim 思想: 从任一顶点出发,每次将与当前生成树相邻边权最小的顶点加入,直到 V-1 条边。适合稠密图,邻接矩阵 O(V^2)。Kruskal 思想: 将所有边按权值升序排序,依次选取不构成环的边加入,直到 V-1 条边,用并查集判环。适合稀疏图,O(ElogE)', '两者是最小生成树的经典算法,选择取决于图的稀疏程度', 15.00, 2, 110),
(2568, 104, 5, '简述 Dijkstra 算法求单源最短路径的思想与限制', NULL, '思想: 从起点 s 开始,每次从未确定结点中选取距离 s 最近的结点 u,将 u 加入已确定集合,并松弛 u 的邻居距离。重复直到所有结点确定。基于贪心 + 动态规划。复杂度 O(V^2)(朴素)或 O((V+E)logV)(堆优化)。限制: 不能处理带负权边的图,负权情况下需用 Bellman-Ford 或 SPFA', 'Dijkstra 是单源最短路径的经典算法', 15.00, 2, 110),
(2569, 104, 5, '简述折半查找的过程及其适用条件和效率', NULL, '过程: 在有序顺序表上,每次取中间元素与目标比较,目标小则在左半部继续折半,大则在右半部继续,直到找到或区间为空。适用条件: (1)顺序存储(支持 O(1) 随机访问); (2)关键字必须有序。效率: 时间复杂度 O(logn),平均查找长度 ASL=log(n+1)-1,远优于顺序查找的 O(n)', '折半查找是高效的查找方法,但要求有序', 10.00, 1, 110),
(2570, 104, 5, '简述哈希表的工作原理、冲突原因及解决方法', NULL, '工作原理: 通过哈希函数 h(key) 将关键字映射到表中地址,理想情况 O(1) 直接定位。冲突原因: 哈希函数将不同关键字映射到同一地址(碰撞)。解决方法主要两类: (1)开放定址法: 发生冲突时按一定探测序列(线性探测、二次探测、双散列等)寻找下一个空位; (2)链地址法(拉链法): 每个地址挂一个链表存所有同义词,冲突时插入链表', '哈希表是高效数据结构,但需妥善处理冲突', 15.00, 2, 110),
(2571, 104, 5, '简述快速排序的思想、过程及效率分析', NULL, '思想: 分治法。过程: (1)从数组选一个枢轴(pivot); (2)将数组分两部分: 小于 pivot 的放左,大于 pivot 的放右; (3)递归对左右部分继续排序。效率: 平均时间 O(nlogn),最坏 O(n^2)(枢轴极不平衡时,如已有序+取首为枢轴),空间 O(logn)(递归栈)。原地排序但不稳定。优化方法: 三数取中、随机化枢轴、小规模切换插入排序', '快排是工程中最常用的内部排序', 15.00, 2, 110),
(2572, 104, 5, '简述归并排序的思想、过程及与快速排序的对比', NULL, '思想: 分治法。过程: (1)分: 将数组对半分; (2)治: 递归排序左右两部分; (3)合: 将两个有序部分归并为一个有序部分(双指针合并)。对比快排: 归并稳定、时间始终 O(nlogn) 不受输入影响,但需 O(n) 辅助空间; 快排平均更快、原地排序,但最坏 O(n^2) 且不稳定。归并适合大数据外部排序、链表排序;快排适合内存数组排序', '归并和快排是分治排序的两大代表', 15.00, 2, 110),
(2573, 104, 5, '简述堆与堆排序的原理及堆的应用', NULL, '堆原理: 完全二叉树,满足堆序性(大顶堆: 父>=子; 小顶堆: 父<=子)。物理上用数组存储,父结点 i 的孩子在 2i+1 和 2i+2。堆排序: (1)将数组建大顶堆 O(n); (2)反复将堆顶与末尾交换,重新调整堆,O(nlogn)。总时间 O(nlogn),原地排序,不稳定。应用: 优先队列、Top-K 问题、堆排序、Dijkstra/Prim 算法的优化', '堆是计算机科学中应用极广的数据结构', 15.00, 2, 110),
(2574, 104, 5, '综合分析: 给定百万级数据需要排序,应选择哪种算法?', NULL, '分析: 百万级数据内存可容纳,但常数因子和稳定性需关注。推荐: (1)若强调平均效率,选快速排序(三数取中优化版),C++ std::sort、Java Arrays.sort 即基于快排; (2)若要求稳定,选归并排序; (3)若数据近有序,直接插入或 Timsort(归并+插入混合) 更佳。不推荐: 冒泡/简单选择 O(n^2) 太慢; 基数排序仅适用于位数有限的整数。生产环境通常使用语言标准库提供的混合排序算法,综合了多种算法优势', '实际排序选型需考虑数据特性', 20.00, 3, 110),
(2575, 104, 4, '哈希表中关键字与存储地址之间的对应关系称为____函数', NULL, '哈希|散列', '哈希函数 h(key) 决定关键字的存储地址', 3.00, 1, 110),
(2576, 104, 5, '简述邻接矩阵与邻接表的比较', NULL, '邻接矩阵: 用二维数组存储图,A[i][j]=1 表示存在边。空间 O(V^2),不受边数影响;判断两点是否相邻 O(1);适合稠密图。邻接表: 每个顶点维护一个邻接顶点链表。空间 O(V+E),与边数相关;求一个点的所有邻居 O(d);适合稀疏图。一般选择: 稠密图用邻接矩阵,稀疏图用邻接表', '图存储方式的选择取决于图的稀疏程度', 15.00, 2, 110);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(2577, 105, 1, '操作系统的主要功能不包括', '{"A": "处理机管理", "B": "存储器管理", "C": "文件管理", "D": "程序设计"}', 'D', 'OS 主要功能：处理机/存储器/设备/文件管理及作业管理；程序设计是用户行为', 2.00, 1, 112),
(2578, 105, 1, '进程与程序的本质区别是', '{"A": "程序是动态的，进程是静态的", "B": "进程是动态的，程序是静态的", "C": "两者完全相同", "D": "程序占用内存，进程不占用"}', 'B', '进程是程序的执行实例，是动态的；程序是磁盘上的代码，是静态的', 2.00, 1, 112),
(2579, 105, 1, '下列哪种调度算法可能导致饥饿现象？', '{"A": "FCFS", "B": "SJF", "C": "轮转法", "D": "先来先服务"}', 'B', '短作业优先 SJF 可能让长作业一直得不到执行', 2.00, 2, 112),
(2580, 105, 1, '产生死锁的四个必要条件不包括', '{"A": "互斥使用", "B": "占有并等待", "C": "非剥夺", "D": "循环让出"}', 'D', '四个必要条件：互斥、占有并等待、非剥夺、循环等待（不是让出）', 2.00, 1, 112),
(2581, 105, 1, '在分页存储管理中，地址结构包括', '{"A": "段号 + 段内偏移", "B": "页号 + 页内偏移", "C": "块号 + 块内偏移", "D": "段号 + 页号 + 偏移"}', 'B', '分页系统逻辑地址 = 页号 + 页内偏移；段页式才同时含段号', 2.00, 1, 112),
(2582, 105, 1, '虚拟存储器的最大容量取决于', '{"A": "内存的大小", "B": "外存的大小", "C": "计算机系统的地址结构", "D": "页面大小"}', 'C', '虚存最大容量由 CPU 地址位数决定（如 32 位即 4GB）', 2.00, 2, 112),
(2583, 105, 1, '以下哪种是页面置换算法？', '{"A": "FCFS", "B": "LRU", "C": "SJF", "D": "轮转"}', 'B', 'LRU = 最近最少使用，是页面置换算法；FCFS/SJF/轮转是进程调度', 2.00, 1, 112),
(2584, 105, 1, '信号量 S 的初值为 5，经过 P(S) 操作和 V(S) 操作各两次后，S 的值为', '{"A": "3", "B": "5", "C": "7", "D": "9"}', 'B', 'P 操作 S--，V 操作 S++；2P+2V 净变化 0，S 仍为 5', 2.00, 1, 112),
(2585, 105, 1, '文件系统中 i 节点（inode）通常存储', '{"A": "文件名", "B": "文件元数据（大小/权限/磁盘块指针等）", "C": "目录名", "D": "用户密码"}', 'B', 'inode 存储文件元信息但不存文件名（文件名在目录项中）', 2.00, 2, 112),
(2586, 105, 1, '用户态和内核态切换的常见触发原因不包括', '{"A": "系统调用", "B": "中断", "C": "异常", "D": "普通函数调用"}', 'D', '用户/内核态切换由系统调用、中断、异常引起；普通函数调用在同一态', 2.00, 2, 112),
(2587, 105, 1, '操作系统中实现互斥的硬件指令是', '{"A": "加法指令", "B": "TestAndSet（TAS）", "C": "跳转指令", "D": "赋值指令"}', 'B', 'TAS、CAS 等原子指令是硬件互斥的基础', 2.00, 2, 112),
(2588, 105, 1, '分时系统的主要设计目标是', '{"A": "高吞吐量", "B": "快速响应交互用户", "C": "实时性", "D": "批处理效率"}', 'B', '分时系统强调多用户公平共享 CPU，快速响应交互', 2.00, 1, 112),
(2589, 105, 2, '下列哪些属于进程间通信（IPC）方式？', '{"A": "管道", "B": "消息队列", "C": "共享内存", "D": "信号量"}', 'ABCD', '管道、消息队列、共享内存、信号量、信号、Socket 都是 IPC 方式', 3.00, 2, 112),
(2590, 105, 2, '以下哪些会引起进程从运行态进入阻塞态？', '{"A": "等待 I/O 完成", "B": "时间片用完", "C": "申请系统资源未得到", "D": "等待信号量"}', 'ACD', '时间片用完是进入就绪态，不是阻塞态', 3.00, 2, 112),
(2591, 105, 2, '下列关于线程的叙述中，正确的有', '{"A": "同一进程的线程共享地址空间", "B": "线程是 CPU 调度的基本单位", "C": "线程切换比进程切换开销小", "D": "每个线程独立拥有一份代码段副本"}', 'ABC', 'D 错误，同一进程线程共享代码段', 3.00, 2, 112),
(2592, 105, 2, '虚拟存储管理中，常见的页面置换算法包括', '{"A": "FIFO", "B": "LRU", "C": "OPT（最佳）", "D": "SJF"}', 'ABC', 'SJF 是进程调度算法，不是页面置换', 3.00, 2, 112),
(2593, 105, 3, '操作系统是计算机硬件与用户之间的接口。', NULL, '正确', 'OS 屏蔽硬件细节，向上为用户提供方便的接口', 1.00, 1, 112),
(2594, 105, 3, '进程是程序运行的实例，进程一旦创建就一直处于运行态。', NULL, '错误', '进程在生命周期中会经历就绪、运行、阻塞等多种状态', 1.00, 1, 112),
(2595, 105, 3, '轮转调度（Round-Robin）算法时间片越大，对短作业越有利。', NULL, '错误', '时间片越大，越接近 FCFS，对短作业不利；越小，则上下文开销越大', 1.00, 2, 112),
(2596, 105, 3, 'LRU 页面置换算法在实际系统中比 OPT 更常用，因为 OPT 不可实现。', NULL, '正确', 'OPT 需要预知未来，是理论最优但不可实现；LRU 是常用近似', 1.00, 2, 112),
(2597, 105, 3, '死锁与饥饿是同一个概念。', NULL, '错误', '死锁是循环等待无法继续；饥饿是某进程长期得不到资源但系统仍在运行', 1.00, 2, 112),
(2598, 105, 3, '在多道程序系统中，CPU 利用率随并发进程数增加而单调递增。', NULL, '错误', '过多进程会因为颠簸（thrashing）反而降低 CPU 利用率', 1.00, 2, 112),
(2599, 105, 4, '操作系统中实现进程同步的最经典工具是 ___（由 Dijkstra 提出）。', NULL, '信号量', 'Dijkstra 提出的信号量(semaphore)是同步互斥的经典工具', 2.00, 1, 112),
(2600, 105, 4, '假设系统采用 LRU 算法，分配 3 个物理块，访问页面序列为 1,2,3,1,2,4，则缺页次数为 ___。', NULL, '4', '逐步模拟：1(缺) 2(缺) 3(缺) 1(命中) 2(命中) 4(缺，淘汰3) 共 4 次缺页', 2.00, 2, 112),
(2601, 105, 4, '在 32 位地址结构、页面大小 4KB 的分页系统中，页号占 ___ 位。', NULL, '20', '页内偏移 4KB = 12 位；页号 = 32 - 12 = 20 位', 2.00, 2, 112),
(2602, 105, 4, '产生死锁的四个必要条件中，与资源分配策略最相关的是 ___（写中文条件名）。', NULL, '循环等待', '通过破坏循环等待（资源有序分配）是预防死锁的常用方法', 2.00, 2, 112),
(2603, 105, 5, '简述进程的三种基本状态及其转换条件。', NULL, '三态：就绪（等待 CPU）、运行（占有 CPU）、阻塞（等待事件）。转换：(1) 就绪→运行：被调度程序选中；(2) 运行→就绪：时间片用完或被高优先级进程抢占；(3) 运行→阻塞：申请资源未得到或等待 I/O；(4) 阻塞→就绪：等待事件完成', '进程三态模型是操作系统经典内容', 5.00, 2, 112),
(2604, 105, 5, '什么是死锁？产生死锁的四个必要条件是什么？', NULL, '死锁：两个或多个进程因竞争资源而陷入相互等待对方释放资源的僵局，无外力干预无法继续。四个必要条件：(1) 互斥使用 (2) 占有并等待 (3) 非剥夺 (4) 循环等待。这四个条件同时成立才会发生死锁', '经典死锁理论', 5.00, 2, 112),
(2605, 105, 5, '简述 LRU 页面置换算法的基本思想，并讨论其实现方式。', NULL, 'LRU(Least Recently Used)：当需要淘汰页面时，选择最近最长时间未被访问的页面。基本思想：基于程序的局部性原理，最近未访问的将来也可能不被访问。实现方式：(1) 计数器：每次访问记录时间戳；(2) 栈：每次访问把页移到栈顶，淘汰栈底；(3) 硬件支持的位图。纯 LRU 开销大，实际系统多用 Clock 或 NRU 近似算法', 'LRU 是页面置换的核心算法之一', 5.00, 2, 112),
(2606, 105, 5, '什么是虚拟存储器？它解决了什么问题？', NULL, '虚拟存储器：操作系统将主存与外存（磁盘）相结合，给用户提供一个比物理内存大得多的逻辑地址空间，由 OS 自动在内外存间换入换出页面。解决的问题：(1) 程序大小不再受物理内存限制；(2) 多个进程可同时运行而不需全部装入内存；(3) 提供地址保护与隔离。代价：可能发生缺页中断和颠簸现象', '虚拟存储是现代 OS 关键技术之一', 5.00, 3, 112),
(2607, 105, 1, '下列哪个不是操作系统的功能', '{"A": "进程管理", "B": "存储管理", "C": "编译程序", "D": "文件系统"}', 'C', '编译程序是系统软件但不属操作系统核心功能；OS 主要管理 CPU、内存、I/O、文件', 2.00, 1, 112),
(2608, 105, 1, '进程与线程的本质区别在于', '{"A": "进程占用更多资源", "B": "线程是 CPU 调度单位，进程是资源拥有单位", "C": "进程间不共享内存，线程间共享", "D": "以上都对"}', 'D', '三者皆为本质区别：进程是资源拥有单位，线程是调度单位；进程内存独立，线程共享进程地址空间', 2.00, 2, 112),
(2609, 105, 1, '下列哪种调度算法可能产生饥饿现象', '{"A": "FCFS（先来先服务）", "B": "短作业优先（SJF）", "C": "时间片轮转（RR）", "D": "多级反馈队列首层"}', 'B', 'SJF 优先短作业，长作业可能永远得不到调度', 2.00, 2, 112),
(2610, 105, 1, '页表的作用是', '{"A": "存储进程代码", "B": "实现虚地址到物理地址映射", "C": "记录文件位置", "D": "缓存指令"}', 'B', '页表记录虚拟页号到物理页框号的映射，是分页内存管理核心', 2.00, 1, 112),
(2611, 105, 1, '产生死锁的四个必要条件中不包含', '{"A": "互斥", "B": "请求并保持", "C": "不剥夺", "D": "饥饿"}', 'D', '死锁四条件：互斥、请求并保持、不剥夺、循环等待；饥饿是另一类问题', 2.00, 2, 112),
(2612, 105, 1, '在分页系统中，逻辑地址由几部分组成', '{"A": "段号+段内偏移", "B": "页号+页内偏移", "C": "段号+页号", "D": "块号+偏移"}', 'B', '分页：逻辑地址 = 页号 + 页内偏移；分段：段号 + 段内偏移', 2.00, 1, 112),
(2613, 105, 1, '下列哪种文件分配方式不需要文件分配表（FAT）', '{"A": "连续分配", "B": "链接分配（隐式）", "C": "链接分配（显式 FAT）", "D": "索引分配"}', 'A', '连续分配只需起始块号和长度；链接分配需指针链；索引分配需索引块', 2.00, 2, 112),
(2614, 105, 1, '银行家算法属于死锁的', '{"A": "预防策略", "B": "避免策略", "C": "检测策略", "D": "解除策略"}', 'B', '银行家算法是 Dijkstra 提出的死锁避免算法，运行时判断是否进入安全状态', 2.00, 2, 112),
(2615, 105, 1, '下列设备中属于字符设备的是', '{"A": "磁盘", "B": "网卡", "C": "键盘", "D": "USB 闪存"}', 'C', '字符设备按字节流操作（如键盘、串口）；块设备按块操作（磁盘、USB）', 2.00, 1, 112),
(2616, 105, 1, '在 LRU 页面置换算法中，被替换的页是', '{"A": "最近最少使用的页", "B": "最先进入内存的页", "C": "使用次数最少的页", "D": "随机的页"}', 'A', 'LRU = Least Recently Used，替换最久未被访问的页', 2.00, 1, 112),
(2617, 105, 1, 'Linux 中查看进程的命令是', '{"A": "ls", "B": "ps", "C": "cd", "D": "rm"}', 'B', 'ps（process status）查看进程；ls 列出文件；cd 切换目录；rm 删除', 2.00, 1, 112),
(2618, 105, 1, 'RAID 0 的特点是', '{"A": "提高可靠性", "B": "提高读写性能但无冗余", "C": "镜像备份", "D": "奇偶校验"}', 'B', 'RAID 0 是条带化（striping），无冗余；RAID 1 镜像；RAID 5 分布式奇偶', 2.00, 2, 112),
(2619, 105, 2, '操作系统的主要特性包括', '{"A": "并发", "B": "共享", "C": "虚拟", "D": "异步"}', 'ABCD', '操作系统四大特性：并发、共享、虚拟、异步（不确定性）', 3.00, 2, 112),
(2620, 105, 2, '下列哪些是进程的状态', '{"A": "运行", "B": "就绪", "C": "阻塞", "D": "终止"}', 'ABCD', '进程基本状态：新建、就绪、运行、阻塞、终止（五态模型）', 3.00, 1, 112),
(2621, 105, 2, '内存管理中下列属于动态内存分配策略的有', '{"A": "首次适应（First Fit）", "B": "循环首次适应", "C": "最佳适应（Best Fit）", "D": "最坏适应（Worst Fit）"}', 'ABCD', '四种均为常见动态分区分配策略，区别在于搜索起点与目标', 3.00, 2, 112),
(2622, 105, 2, '用于进程间通信（IPC）的机制有', '{"A": "管道", "B": "信号量", "C": "共享内存", "D": "消息队列"}', 'ABCD', 'IPC 主要机制：管道、命名管道、信号量、共享内存、消息队列、socket 等', 3.00, 2, 112),
(2623, 105, 3, '用户态和内核态的切换是通过系统调用实现的', NULL, '正确', '用户程序通过系统调用陷入内核态，执行特权指令', 1.00, 1, 112),
(2624, 105, 3, '线程切换比进程切换的开销更小', NULL, '正确', '线程共享地址空间，切换无需切换页表，开销远小于进程切换', 1.00, 1, 112),
(2625, 105, 3, '操作系统的中断处理总是发生在用户态', NULL, '错误', '中断处理在内核态进行，必要时切换上下文', 1.00, 2, 112),
(2626, 105, 3, '虚拟内存技术允许程序大于物理内存运行', NULL, '正确', '通过页面置换将不活跃页换出到磁盘，实现大于物理内存的程序运行', 1.00, 1, 112),
(2627, 105, 3, '若 P 操作和 V 操作不成对出现，则可能死锁', NULL, '正确', '信号量 P/V 操作必须成对使用，否则可能死锁或资源泄漏', 1.00, 2, 112),
(2628, 105, 3, 'Linux 一切皆文件，包括设备和管道', NULL, '正确', 'Linux 设计哲学：一切都通过文件系统接口访问（包括 /dev、/proc）', 1.00, 1, 112),
(2629, 105, 4, '把作业 J1 (4 秒)、J2 (1 秒)、J3 (2 秒) 按 SJF 调度，平均等待时间为 ____ 秒', NULL, '1.67', 'SJF 顺序：J2(1)→J3(2)→J1(4)。等待时间：0,1,3，平均 (0+1+3)/3≈1.33。或问总周转时间', 3.00, 3, 112),
(2630, 105, 4, '操作系统中，PCB 的中文全称是 ____', NULL, '进程控制块', 'PCB = Process Control Block，包含进程标识、状态、调度信息、内存信息等', 2.00, 1, 112),
(2631, 105, 4, '在分页系统中，若页大小为 4KB，则页内偏移占 ____ 位', NULL, '12', '4KB=2^12 字节，页内偏移地址占 12 位', 2.00, 2, 112),
(2632, 105, 4, 'Linux 中常用的文件系统类型有 ext4、xfs、btrfs 等，请写出查看磁盘分区的命令 ____', NULL, 'fdisk -l', 'fdisk -l 或 lsblk 都可查看分区；df -h 查看挂载情况', 2.00, 2, 112),
(2633, 105, 5, '简述进程的三种基本状态及其转换条件', NULL, '三种基本状态：(1) 就绪：已具备执行条件等待 CPU；(2) 运行：正在 CPU 上执行；(3) 阻塞：等待某事件发生（如 I/O 完成）。转换：就绪→运行（被调度）；运行→就绪（时间片用完或被抢占）；运行→阻塞（请求等待事件）；阻塞→就绪（等待事件完成）', '三态模型是进程管理基础，五态模型还包括创建和终止', 5.00, 2, 112),
(2634, 105, 5, '解释什么是死锁，并简述死锁产生的四个必要条件', NULL, '死锁：两个或多个进程因竞争资源而互相等待对方释放资源，永远无法继续执行的状态。四必要条件：(1) 互斥：资源同一时刻只能被一个进程占用；(2) 请求并保持：进程持有部分资源同时请求新资源；(3) 不剥夺：资源只能由持有者主动释放；(4) 循环等待：存在进程循环链相互等待。打破任一条件即可解除死锁', 'Coffman 条件，死锁四必要条件缺一不可', 5.00, 2, 112),
(2635, 105, 5, '解释虚拟内存的工作原理和优势', NULL, '工作原理：将进程虚拟地址空间划分为页，物理内存划分为页框。仅活跃页加载到内存，不活跃页存放在磁盘交换区。访问时若缺页则触发缺页中断，由操作系统从磁盘调入。优势：(1) 程序可以大于物理内存；(2) 多个进程共享物理内存提高利用率；(3) 进程间内存隔离更安全；(4) 简化内存管理', '虚拟内存是现代 OS 核心技术，依赖 MMU 硬件支持', 5.00, 2, 112),
(2636, 105, 5, '比较 SJF、FCFS、RR 三种调度算法的优缺点', NULL, 'FCFS（先来先服务）：简单公平，但平均周转时间长，长作业阻塞短作业；SJF（短作业优先）：平均周转时间最短，但长作业可能饥饿，需预知运行时间；RR（时间片轮转）：响应时间公平，适合交互式系统，但时间片选择敏感（太大退化为 FCFS，太小切换开销大）。实际系统常用多级反馈队列结合各家优点', '三种基本调度算法对比', 5.00, 3, 112),
(2637, 105, 1, '操作系统是介于硬件和用户之间的一层软件,其主要目标是', '{"A": "提高资源利用率", "B": "方便用户使用", "C": "提高效率与方便性", "D": "提供编程环境"}', 'C', '操作系统两大目标:资源利用率和方便用户', 2.00, 1, 112),
(2638, 105, 1, '下列不属于操作系统基本特征的是', '{"A": "并发", "B": "共享", "C": "虚拟", "D": "开源"}', 'D', 'OS 四大特征:并发、共享、虚拟、异步', 2.00, 1, 112),
(2639, 105, 1, '下列不属于操作系统功能的是', '{"A": "进程管理", "B": "存储管理", "C": "设备管理", "D": "数据库管理"}', 'D', 'OS 五大管理:进程、存储、设备、文件、用户接口', 2.00, 1, 112),
(2640, 105, 1, '操作系统中,从用户态切换到内核态的途径不包括', '{"A": "系统调用", "B": "外部中断", "C": "程序异常", "D": "用户主动切换"}', 'D', '用户不能主动切换到内核态,只能通过系统调用、中断、异常', 2.00, 2, 112),
(2641, 105, 1, '操作系统的发展历程从早到晚正确顺序是', '{"A": "批处理→分时→多道→实时", "B": "批处理→多道→分时→实时", "C": "多道→批处理→分时→实时", "D": "分时→批处理→多道→实时"}', 'B', '历史顺序:单道批→多道批→分时→实时→网络', 2.00, 1, 112),
(2642, 105, 1, '下列哪个不是现代操作系统的特征', '{"A": "并发", "B": "共享", "C": "虚拟", "D": "顺序"}', 'D', 'OS 是并发处理的,不是顺序', 2.00, 1, 112),
(2643, 105, 1, 'Linux 是一种', '{"A": "批处理操作系统", "B": "分时操作系统", "C": "实时操作系统", "D": "嵌入式操作系统"}', 'B', 'Linux 桌面/服务器版本本质是分时多任务', 2.00, 1, 112),
(2644, 105, 1, '以下属于系统调用的是', '{"A": "fork()", "B": "printf()", "C": "strcpy()", "D": "main()"}', 'A', 'fork() 是 Unix/Linux 进程创建的系统调用', 2.00, 2, 112),
(2645, 105, 1, '进程是', '{"A": "程序的执行实例", "B": "程序代码", "C": "程序的数据", "D": "程序文件"}', 'A', '进程是资源分配的基本单位,即程序的一次执行', 2.00, 1, 112),
(2646, 105, 1, '进程与程序的区别在于', '{"A": "程序静态进程动态", "B": "程序动态进程静态", "C": "二者无差别", "D": "程序占内存进程占外存"}', 'A', '进程是程序的一次执行,具有动态性', 2.00, 1, 112),
(2647, 105, 1, '进程的三种基本状态是', '{"A": "就绪、运行、阻塞", "B": "创建、执行、终止", "C": "新建、运行、终止", "D": "就绪、运行、新建"}', 'A', '进程基本三态:就绪、运行、阻塞(等待)', 2.00, 1, 112),
(2648, 105, 1, '进程从就绪态变为运行态的原因是', '{"A": "时间片用完", "B": "等待 I/O", "C": "被调度选中", "D": "I/O 完成"}', 'C', '调度程序选中后才能从就绪进入运行态', 2.00, 2, 112),
(2649, 105, 1, '进程从运行态变为阻塞态的原因是', '{"A": "时间片用完", "B": "调度选中", "C": "等待事件(如 I/O)", "D": "程序结束"}', 'C', '主动等待事件(如 I/O、信号量)进入阻塞态', 2.00, 2, 112),
(2650, 105, 1, '线程是', '{"A": "CPU 调度的基本单位", "B": "资源分配的基本单位", "C": "内存分配的基本单位", "D": "I/O 控制单位"}', 'A', '进程是资源分配单位,线程是 CPU 调度单位', 2.00, 1, 112),
(2651, 105, 1, '与进程相比,线程的优点是', '{"A": "切换开销小", "B": "隔离性好", "C": "独立地址空间", "D": "数据共享困难"}', 'A', '同进程内线程共享地址空间,切换开销小', 2.00, 2, 112),
(2652, 105, 1, '下列哪种线程实现方式由内核管理', '{"A": "用户级线程 ULT", "B": "内核级线程 KLT", "C": "纤程", "D": "协程"}', 'B', 'KLT 由内核管理,ULT 由用户库管理', 2.00, 2, 112),
(2653, 105, 1, '进程控制块 PCB 是', '{"A": "进程存在的唯一标志", "B": "操作系统的标志", "C": "CPU 内部寄存器", "D": "程序的代码段"}', 'A', 'PCB 是 OS 维护进程的核心数据结构,无 PCB 则进程不存在', 2.00, 2, 112),
(2654, 105, 1, '下列不在 PCB 中的信息是', '{"A": "进程标识符", "B": "进程状态", "C": "CPU 上下文", "D": "用户密码"}', 'D', 'PCB 含进程标识、状态、上下文、调度信息等,与密码无关', 2.00, 2, 112),
(2655, 105, 1, '下列调度算法中,平均周转时间最短的是', '{"A": "FCFS", "B": "SJF", "C": "时间片轮转", "D": "优先级调度"}', 'B', 'SJF 短作业优先理论上平均周转时间最短', 2.00, 2, 112),
(2656, 105, 1, 'FCFS 调度算法的缺点是', '{"A": "不利于短作业", "B": "难以实现", "C": "开销大", "D": "响应慢"}', 'A', 'FCFS 容易导致护航效应,长作业先到时短作业等待长', 2.00, 2, 112),
(2657, 105, 1, 'SJF 调度算法的最大缺点是', '{"A": "开销大", "B": "可能饥饿", "C": "实现困难", "D": "利用率低"}', 'B', 'SJF 长作业可能因总有短作业到达而饿死', 2.00, 2, 112),
(2658, 105, 1, '时间片轮转调度的优点是', '{"A": "吞吐量最大", "B": "响应时间短", "C": "平均周转时间短", "D": "开销最小"}', 'B', 'RR 适合分时系统,响应时间相对均匀', 2.00, 2, 112),
(2659, 105, 1, '实时系统对调度算法的核心要求是', '{"A": "公平性", "B": "响应及时", "C": "吞吐量大", "D": "简单"}', 'B', '实时调度首要保证截止期,响应必须及时', 2.00, 2, 112),
(2660, 105, 1, '下列哪种调度方式可能导致饥饿', '{"A": "FCFS", "B": "RR", "C": "优先级调度", "D": "SJF"}', 'C', '低优先级进程可能永远排在高优先级后面', 2.00, 2, 112),
(2661, 105, 1, '多级反馈队列的核心思想是', '{"A": "所有队列时间片相同", "B": "低优先级队列时间片长", "C": "所有队列优先级相同", "D": "只有一个队列"}', 'B', '低优先级队列时间片长,适合长作业', 2.00, 3, 112),
(2662, 105, 1, '设有 3 个进程到达时间均为 0,运行时间分别为 2、4、6,使用 SJF 调度的平均周转时间是', '{"A": "4", "B": "20/3", "C": "6", "D": "8"}', 'B', 'SJF 顺序 2,4,6;完成时间 2,6,12;平均周转=(2+6+12)/3=20/3', 2.00, 3, 112),
(2663, 105, 1, '下列哪种是抢占式调度算法', '{"A": "FCFS", "B": "SJF", "C": "SRTF", "D": "优先级(非抢占)"}', 'C', 'SRTF 最短剩余时间优先是抢占式 SJF', 2.00, 2, 112),
(2664, 105, 1, 'CPU 利用率的计算公式是', '{"A": "CPU 工作时间/总时间", "B": "CPU 空闲时间/总时间", "C": "总时间/CPU 工作时间", "D": "CPU 等待时间/总时间"}', 'A', 'CPU 利用率=工作时间/总时间', 2.00, 1, 112),
(2665, 105, 1, '系统的吞吐量是指', '{"A": "CPU 工作时间", "B": "单位时间内完成的作业数", "C": "作业的平均响应时间", "D": "系统空闲率"}', 'B', '吞吐量=单位时间完成作业数', 2.00, 1, 112),
(2666, 105, 1, '平均周转时间是指', '{"A": "作业从提交到完成的平均时间", "B": "等待时间", "C": "CPU 工作时间", "D": "响应时间"}', 'A', '周转时间=完成时间-提交时间,平均即所有作业的平均', 2.00, 1, 112),
(2667, 105, 1, '临界区指', '{"A": "互斥访问临界资源的代码段", "B": "进程睡眠的代码段", "C": "系统调用的代码段", "D": "内核空间代码段"}', 'A', '临界区是访问临界资源(必须互斥)的代码段', 2.00, 2, 112),
(2668, 105, 1, '互斥锁与信号量的主要区别是', '{"A": "互斥锁只能 0/1 信号量可任意值", "B": "信号量更慢", "C": "互斥锁不能用于线程", "D": "信号量必须有顺序"}', 'A', '互斥锁本质是二元信号量(0/1),计数信号量可表示多个资源', 2.00, 2, 112),
(2669, 105, 1, 'P 操作的本质是', '{"A": "申请资源", "B": "释放资源", "C": "创建进程", "D": "销毁进程"}', 'A', 'P (wait) = 申请资源,V (signal) = 释放资源', 2.00, 1, 112),
(2670, 105, 1, 'V 操作的本质是', '{"A": "申请资源", "B": "释放资源", "C": "创建进程", "D": "销毁进程"}', 'B', 'V 操作等价于 signal,释放资源/唤醒等待者', 2.00, 1, 112),
(2671, 105, 1, '信号量初值为 1 时,实现的是', '{"A": "互斥", "B": "同步", "C": "无关", "D": "死锁"}', 'A', '信号量 S=1 实现互斥访问', 2.00, 1, 112),
(2672, 105, 1, '信号量初值为 0 时,通常用于', '{"A": "互斥", "B": "同步", "C": "线程创建", "D": "死锁"}', 'B', 'S=0 用于同步等待,等待 V 操作触发', 2.00, 2, 112),
(2673, 105, 1, '生产者消费者问题至少需要几个信号量', '{"A": "1", "B": "2", "C": "3", "D": "4"}', 'C', 'empty(空槽)、full(满槽)、mutex(互斥)三个信号量', 2.00, 2, 112),
(2674, 105, 1, '管程是', '{"A": "进程的高级同步机制", "B": "内核空间", "C": "用户态资源池", "D": "调度算法"}', 'A', '管程封装共享资源和操作,提供互斥访问', 2.00, 2, 112),
(2675, 105, 1, '管程相对信号量的优点是', '{"A": "更快", "B": "更易使用与调试", "C": "开销更小", "D": "支持更多线程"}', 'B', '管程把同步逻辑封装在内,使用更简单', 2.00, 2, 112),
(2676, 105, 1, '哲学家就餐问题的本质是', '{"A": "死锁", "B": "同步", "C": "死锁与饥饿", "D": "调度"}', 'C', '哲学家就餐展示死锁和饥饿可能', 2.00, 3, 112),
(2677, 105, 1, '下列哪个不是产生死锁的必要条件', '{"A": "互斥", "B": "请求保持", "C": "不可剥夺", "D": "可抢占"}', 'D', '死锁四必要条件:互斥、占有等待、不可剥夺、循环等待;可抢占恰相反', 2.00, 2, 112),
