(2680, 105, 1, '下列说法正确的是', '{"A": "预防死锁通常牺牲并发性", "B": "避免死锁不需要安全性检查", "C": "检测后总能恢复", "D": "死锁不可避免"}', 'A', '预防方法相对粗暴,可能降低并发利用率', 2.00, 2, 112),
(2681, 105, 1, '下列哪个最容易产生死锁', '{"A": "共享资源", "B": "可抢占资源", "C": "不可抢占资源", "D": "用户资源"}', 'C', '不可抢占资源结合循环等待最易死锁', 2.00, 2, 112),
(2682, 105, 1, '解除死锁的方法不包括', '{"A": "资源剥夺", "B": "进程撤销", "C": "等待忽略", "D": "回滚"}', 'C', '等待忽略相当于不处理,实际生产不可取', 2.00, 2, 112),
