(2686, 105, 1, '进程 P1 持有 R1 申请 R2,P2 持有 R2 申请 R1,这是', '{"A": "死锁", "B": "活锁", "C": "饥饿", "D": "正常等待"}', 'A', '循环等待形成死锁', 2.00, 2, 112),
(2687, 105, 1, '下列哪个不是内存管理方式', '{"A": "连续分配", "B": "分页", "C": "分段", "D": "分时"}', 'D', '分时是 CPU 调度方式,不是内存管理', 2.00, 1, 112),
