(2691, 105, 1, '下列分配算法可能加剧外碎片的是', '{"A": "First Fit", "B": "Best Fit", "C": "Worst Fit", "D": "Next Fit"}', 'B', 'Best Fit 留下小碎片,反而加剧外碎片', 2.00, 3, 112),
(2692, 105, 1, '分页存储管理中,逻辑地址由两部分组成', '{"A": "段号+段内地址", "B": "页号+页内偏移", "C": "物理页号+偏移", "D": "虚拟地址+物理地址"}', 'B', '分页系统逻辑地址=页号+页内偏移', 2.00, 2, 112),
