(2695, 105, 1, '快表 TLB 的作用是', '{"A": "加速地址转换", "B": "存储数据", "C": "管理外存", "D": "调度进程"}', 'A', 'TLB 缓存最近使用的页表项,加速地址转换', 2.00, 2, 112),
(2696, 105, 1, '虚拟内存的核心思想是', '{"A": "用磁盘扩展物理内存", "B": "用 CPU 缓存", "C": "用快表", "D": "用堆"}', 'A', '虚存通过磁盘交换,使逻辑地址空间大于物理内存', 2.00, 2, 112),
(2697, 105, 1, '虚存中的页面置换算法,FIFO 的缺点是', '{"A": "实现复杂", "B": "可能 Belady 异常", "C": "开销大", "D": "总是最差"}', 'B', 'FIFO 在某些情形下页框增多反而缺页率增加(Belady)', 2.00, 3, 112),
(2698, 105, 1, '下列页面置换算法理论上最优的是', '{"A": "FIFO", "B": "LRU", "C": "OPT", "D": "Clock"}', 'C', 'OPT 选择未来最长时间不用的页面,理论最优(无法实现)', 2.00, 2, 112),
(2699, 105, 1, 'LRU 算法基于的局部性原理是', '{"A": "时间局部性", "B": "空间局部性", "C": "随机", "D": "一致性"}', 'A', 'LRU 假设最近使用过的页面将来也会被使用,即时间局部性', 2.00, 2, 112),
(2700, 105, 1, '在分页系统中,若页号占 20 位偏移占 12 位,则页面大小是', '{"A": "2KB", "B": "4KB", "C": "8KB", "D": "16KB"}', 'B', '页面大小=2^12=4096B=4KB', 2.00, 2, 112),
(2701, 105, 1, '文件的物理结构不包括', '{"A": "连续分配", "B": "链式分配", "C": "索引分配", "D": "树形分配"}', 'D', '文件物理结构主要 3 种:连续、链式、索引', 2.00, 2, 112),
(2702, 105, 1, '下列文件物理结构中,适合顺序访问的是', '{"A": "连续分配", "B": "链式分配", "C": "索引分配", "D": "哈希"}', 'A', '连续分配文件块物理连续,顺序访问最快', 2.00, 2, 112),
(2703, 105, 1, 'UNIX 文件系统采用的物理结构是', '{"A": "连续", "B": "链式", "C": "索引", "D": "混合(混合索引)"}', 'D', 'UNIX 用混合索引: 直接块+一级间址+二级间址+三级间址', 2.00, 3, 112),
(2704, 105, 1, '下列哪个不属于目录管理方式', '{"A": "单级目录", "B": "二级目录", "C": "树形目录", "D": "环形目录"}', 'D', '目录结构无环形,主要单级、二级、树形、图形', 2.00, 2, 112),
(2705, 105, 1, '文件控制块 FCB 的作用是', '{"A": "描述文件属性", "B": "存储文件内容", "C": "调度进程", "D": "管理设备"}', 'A', 'FCB 存储文件名、大小、位置、权限等元数据', 2.00, 2, 112),
(2706, 105, 1, '文件存储空间管理方法不包括', '{"A": "空闲表", "B": "空闲链表", "C": "位示图", "D": "位映射树"}', 'D', '主要方法:空闲表、空闲链表、位示图、成组链接', 2.00, 2, 112),
(2707, 105, 1, '下列哪种 I/O 控制方式 CPU 干预最少', '{"A": "程序直接控制", "B": "中断驱动", "C": "DMA", "D": "通道"}', 'D', '通道方式由通道独立完成 I/O,CPU 几乎不干预', 2.00, 2, 112),
(2708, 105, 1, 'SPOOLing 技术的目的是', '{"A": "将独占设备虚拟化为共享设备", "B": "加快 CPU", "C": "管理内存", "D": "调度进程"}', 'A', 'SPOOLing 把打印机等独占设备改造成多用户共享', 2.00, 2, 112),
