(2803, 105, 3, 'fork() 后父进程和子进程共享内存', NULL, '错误', 'fork 后地址空间逻辑隔离(写时复制)', 1.00, 2, 112),
(2804, 105, 3, 'exec() 替换进程映像', NULL, '正确', 'exec 加载新程序到当前进程', 1.00, 2, 112),
(2805, 105, 3, 'wait() 系统调用使父进程等待子进程结束', NULL, '正确', '防止子进程僵尸', 1.00, 2, 112),
(2806, 105, 3, '僵尸进程是已结束但 PCB 未回收的进程', NULL, '正确', '僵尸进程定义', 1.00, 2, 112),
(2807, 105, 3, '孤儿进程是父进程已退出但子进程仍存在的进程', NULL, '正确', '孤儿进程会被 init 收养', 1.00, 2, 112),
(2808, 105, 3, 'Banker 算法只要资源充足总能找到安全序列', NULL, '正确', 'Banker 算法的核心', 1.00, 3, 112),
(2809, 105, 3, '操作系统中的中断分为外中断和内中断(异常)', NULL, '正确', '常见分类', 1.00, 2, 112),
(2810, 105, 3, '系统调用属于异步事件', NULL, '错误', '系统调用是同步事件,由用户主动触发', 1.00, 3, 112),
(2811, 105, 3, 'Cache 不属于内存管理范畴', NULL, '错误', 'Cache 是内存层次的一部分', 1.00, 2, 112),
(2812, 105, 3, '操作系统启动后内核常驻内存', NULL, '正确', '内核必须驻留以处理中断和系统调用', 1.00, 2, 112),
(2813, 105, 4, '操作系统的四大特征是并发、共享、虚拟和____', NULL, '异步', 'OS 四大特征', 3.00, 1, 112),
(2814, 105, 4, '进程的三种基本状态是就绪态、运行态和____', NULL, '阻塞态|等待态', '进程基本三态', 3.00, 1, 112),
(2815, 105, 4, 'CPU 调度的基本单位是____', NULL, '线程', '线程是 CPU 调度单位', 3.00, 1, 112),
(2816, 105, 4, '资源分配的基本单位是____', NULL, '进程', '进程是资源分配单位', 3.00, 1, 112),
(2817, 105, 4, '进程控制块的英文缩写是____', NULL, 'PCB', 'Process Control Block', 3.00, 1, 112),
(2818, 105, 4, '在 Linux 中,创建子进程的系统调用是____', NULL, 'fork|fork()', 'fork 创建子进程', 3.00, 1, 112),
(2819, 105, 4, '死锁产生的四个必要条件包括互斥、请求与保持、不可剥夺和____', NULL, '循环等待', 'Coffman 第四条件', 3.00, 2, 112),
(2820, 105, 4, '死锁避免的经典算法是____算法', NULL, '银行家|Banker', '银行家算法', 3.00, 2, 112),
(2821, 105, 4, '信号量的两个基本操作是____和 V', NULL, 'P|wait', 'P 即 wait,V 即 signal', 3.00, 1, 112),
(2822, 105, 4, '管程是高级的进程同步机制,由共享数据结构和过程组成,提供____访问', NULL, '互斥', '管程保证互斥', 3.00, 2, 112),
(2823, 105, 4, 'FCFS 调度算法又叫____调度', NULL, '先来先服务|先到先服务', 'FCFS = First Come First Served', 3.00, 1, 112),
(2824, 105, 4, '时间片轮转的英文缩写是____', NULL, 'RR', 'Round Robin', 3.00, 1, 112),
(2825, 105, 4, 'SJF 全称是____', NULL, 'Shortest Job First|短作业优先', 'Shortest Job First', 3.00, 1, 112),
(2826, 105, 4, '在分页系统中,逻辑地址=页号+____', NULL, '页内偏移|页内地址', '分页地址结构', 3.00, 2, 112),
(2827, 105, 4, '在分段系统中,逻辑地址=段号+____', NULL, '段内偏移|段内地址', '分段地址结构', 3.00, 2, 112),
(2828, 105, 4, '加速分页地址转换的硬件称为____', NULL, '快表|TLB|Translation Lookaside Buffer', 'TLB 缓存最近的页表项', 3.00, 2, 112),
(2829, 105, 4, '虚拟内存技术依赖于____原理(页面短期内重复访问)', NULL, '局部性|时间局部性', '时间局部性是基础', 3.00, 2, 112),
(2830, 105, 4, '在固定页面大小为 4KB 的系统中,页内偏移的位数是____', NULL, '12', '2^12=4096B=4KB', 3.00, 2, 112),
(2831, 105, 4, 'FIFO 页面置换算法可能出现____异常', NULL, 'Belady', 'Belady 异常: 页框增多缺页率反而增大', 3.00, 3, 112),
(2832, 105, 4, '理论上最优的页面置换算法是____', NULL, 'OPT|最佳置换算法', 'OPT 选未来最长不用的页面', 3.00, 2, 112),
(2833, 105, 4, 'UNIX 文件系统中的索引节点称为____', NULL, 'inode', 'UNIX inode 含元数据', 3.00, 2, 112),
(2834, 105, 4, '目录通常由若干文件控制块组成,每个文件控制块用 ____ 表示', NULL, 'FCB', 'File Control Block', 3.00, 1, 112),
(2835, 105, 4, '文件的物理结构主要有连续分配、链式分配和____分配', NULL, '索引', '三大物理结构', 3.00, 2, 112),
(2836, 105, 4, 'I/O 控制方式中,CPU 干预最少的是____方式', NULL, '通道', '通道方式 CPU 几乎不干预', 3.00, 2, 112),
(2837, 105, 4, '____是连接独占设备的虚拟化技术,可将独占改造为共享', NULL, 'SPOOLing', 'SPOOLing 经典应用打印机', 3.00, 2, 112),
(2838, 105, 4, 'DMA 全称是____', NULL, 'Direct Memory Access|直接存储器访问', 'DMA = Direct Memory Access', 3.00, 2, 112),
(2839, 105, 4, 'Linux 内核遵循的开源协议是____', NULL, 'GPL', 'GNU 通用公共许可证', 3.00, 2, 112),
(2840, 105, 4, '死锁的四个必要条件中,最难破坏的是____', NULL, '互斥', '互斥涉及资源本质,通常不可破', 3.00, 2, 112),
(2841, 105, 4, '活锁与死锁的相似之处是都无法继续执行,不同的是 ____ 中进程仍在运行', NULL, '活锁', '活锁进程未阻塞但无进展', 3.00, 3, 112),
(2842, 105, 4, '为防止僵尸进程产生,父进程应在子进程结束后调用 ____', NULL, 'wait|waitpid', 'wait 收集子进程退出码', 3.00, 2, 112),
(2843, 105, 4, '如果父进程先于子进程退出,子进程会被 ____ 进程接管', NULL, 'init|systemd|1号', 'init/systemd 接管孤儿进程', 3.00, 2, 112),
(2844, 105, 4, '操作系统中,处于就绪队列中的进程争用的是____', NULL, 'CPU', '就绪队列等待 CPU 时间', 3.00, 2, 112),
(2845, 105, 4, '在虚拟存储中,缺页中断属于____中断(类型)', NULL, '内|内部中断|异常', '缺页是 CPU 内部异常', 3.00, 3, 112),
(2846, 105, 4, '操作系统中,实时调度算法 EDF 的全称是____', NULL, 'Earliest Deadline First|最早截止期优先', 'EDF 是动态优先级实时调度', 3.00, 3, 112),
(2847, 105, 4, 'SJF 调度算法的核心思想是先执行运行时间最____的作业', NULL, '短', 'Shortest Job First', 3.00, 1, 112),
(2848, 105, 4, '进程间共享内存通信的最大优点是____', NULL, '速度快|无内核拷贝|高效', '共享内存避免内核态拷贝', 3.00, 2, 112),
(2849, 105, 4, 'Linux 中查看进程的常用命令是____', NULL, 'ps|top', 'ps 静态查看,top 动态', 3.00, 1, 112),
(2850, 105, 4, '在 Linux 中,kill -9 用于发送____信号', NULL, 'SIGKILL|9|强制终止', 'SIGKILL 不可被捕获', 3.00, 2, 112),
(2851, 105, 4, '当多个进程都希望访问某资源但每次只允许一个时,这类资源称为____资源', NULL, '临界', '临界资源需互斥访问', 3.00, 2, 112),
(2852, 105, 4, 'Bank 算法中,资源向量 Available[m] 表示____', NULL, '系统当前可用资源数|可用资源向量', 'Available 向量是系统空闲资源', 3.00, 3, 112),
(2853, 105, 4, '操作系统接口的常见表现形式包括 Shell、命令行和____', NULL, '图形界面|GUI', '用户接口的多样化', 3.00, 1, 112),
(2854, 105, 4, '在内核态可以执行的指令称为____指令', NULL, '特权|内核态', '特权指令只能在内核态执行', 3.00, 2, 112),
(2855, 105, 5, '简述操作系统的主要功能', NULL, '操作系统的主要功能包括: (1)处理机管理(进程管理): 进程控制、同步、通信、调度; (2)存储管理: 内存分配与回收、地址变换、内存保护、内存扩充(虚存); (3)设备管理: 缓冲管理、设备分配、设备处理、虚拟设备; (4)文件管理: 文件存储空间管理、目录管理、文件读写; (5)用户接口: 命令接口、程序接口、图形接口', 'OS 五大管理模块', 10.00, 1, 112),
(2856, 105, 5, '简述进程与线程的区别', NULL, '主要区别: (1)定义: 进程是资源分配单位,线程是 CPU 调度单位; (2)资源: 进程拥有独立资源(地址空间、文件等),线程仅有少量私有资源(寄存器、栈),共享所属进程的资源; (3)开销: 创建、撤销、切换进程开销大,线程开销小; (4)并发性: 进程间并发隔离性好,线程间并发更高效; (5)通信: 进程间需 IPC,线程间可直接共享内存; (6)健壮性: 一个线程崩溃可能导致进程崩溃,而一个进程崩溃通常不影响其他进程', '进程与线程的对比', 15.00, 2, 112),
(2857, 105, 5, '简述进程的三种基本状态及其转换', NULL, '三种基本状态: 就绪态(等待 CPU)、运行态(占有 CPU 执行)、阻塞态(等待事件)。状态转换: (1)就绪→运行: 调度程序选中; (2)运行→就绪: 时间片到或被高优先级抢占; (3)运行→阻塞: 主动等待事件(如 I/O); (4)阻塞→就绪: 等待的事件发生。注意: 阻塞态不能直接转运行态,必须经过就绪态。在五态模型中还有创建态和终止态', '进程基本三态及转换', 15.00, 2, 112),
(2858, 105, 5, '简述常用的进程调度算法', NULL, '常用进程调度算法: (1)FCFS(先来先服务): 按到达顺序执行,实现简单但对短作业不利; (2)SJF(短作业优先): 选最短的作业,平均周转最短但可能饥饿; (3)RR(时间片轮转): 每个进程分时间片,适合分时系统; (4)优先级调度: 按优先级排序,可能饥饿; (5)多级反馈队列(MLFQ): 多个队列不同优先级和时间片,综合考虑短作业和长作业。每种算法侧重不同指标(吞吐量、周转、响应、公平)', '常用 CPU 调度算法', 15.00, 2, 112),
(2859, 105, 5, '简述死锁产生的四个必要条件及预防方法', NULL, '四个必要条件(Coffman): (1)互斥: 资源不能共享; (2)请求与保持: 进程持有资源同时请求新资源; (3)不可剥夺: 资源不能强制收回; (4)循环等待: 存在进程和资源的循环链。预防方法(破坏条件): (1)互斥通常不可破; (2)破坏请求保持: 一次申请所有资源; (3)破坏不可剥夺: 允许操作系统剥夺资源; (4)破坏循环等待: 给资源编号,按顺序申请', '死锁四条件与预防', 20.00, 2, 112),
(2860, 105, 5, '简述银行家算法的工作原理', NULL, '银行家算法用于死锁避免。核心数据结构: Available(可用资源)、Max(最大需求矩阵)、Allocation(已分配)、Need=Max-Allocation。工作过程: (1)进程请求资源 Request[i]; (2)检查 Request<=Need 和 Available; (3)假设分配,更新数据; (4)进行安全性检查: 寻找进程序列使每个进程的 Need<=可用资源(执行后释放); (5)若存在安全序列,真分配; 否则进程等待。安全性检查保证系统始终处于安全状态', 'Banker 算法的关键步骤', 20.00, 3, 112),
(2861, 105, 5, '简述生产者-消费者问题及其解决方案', NULL, '问题描述: 生产者和消费者共享有限缓冲区,生产者放入,消费者取出。需要解决: (1)互斥访问缓冲; (2)缓冲满时生产者等; (3)缓冲空时消费者等。解决方案: 使用三个信号量: empty=N(空闲槽),full=0(满槽),mutex=1(互斥)。生产者: P(empty); P(mutex); 放入; V(mutex); V(full)。消费者: P(full); P(mutex); 取出; V(mutex); V(empty)。要点: PV 顺序不能颠倒(否则死锁)', '生产者消费者经典模型', 20.00, 2, 112),
(2862, 105, 5, '简述读者-写者问题', NULL, '问题描述: 多读者多写者共享数据,读读可并发,但写时排他。要点: (1)允许多个读者同时读; (2)只允许一个写者写; (3)读写互斥; (4)读者优先(可能写者饥饿)、写者优先或公平。解法(读者优先): 信号量 wmutex=1(写互斥),rmutex=1(读者计数互斥),readcount=0(读者数)。读者进入: P(rmutex); readcount++; if(readcount==1)P(wmutex); V(rmutex); 读; P(rmutex); readcount--; if(readcount==0)V(wmutex); V(rmutex)', '读者写者同步问题', 20.00, 3, 112),
(2863, 105, 5, '简述虚拟存储管理的工作原理', NULL, '虚拟存储利用磁盘扩展物理内存。原理: (1)程序的逻辑地址空间可大于物理内存; (2)按需调入: 只把当前需要的页调入内存; (3)缺页中断: 访问不在内存的页,触发中断; (4)页面置换: 内存满时,选择页面换出到磁盘。基础: 局部性原理(时间和空间)。关键技术: 页表(含存在位、修改位、访问位)、TLB 加速、置换算法(FIFO/LRU/OPT/Clock)、写时复制等。优点: 用户感知大内存; 缺点: 缺页带来 I/O 开销', '虚存的核心机制', 20.00, 2, 112),
(2864, 105, 5, '简述 LRU 页面置换算法及其实现', NULL, 'LRU(Least Recently Used) 选择最久未使用的页面置换。原理: 基于时间局部性,假设最近使用的页面将来还会被使用。实现: (1)栈实现: 每次访问页将页移到栈顶,被替换时弹栈底; (2)双向链表: 类似栈,O(1) 操作; (3)硬件计数器: 每个页表项维护时间戳,代价大; (4)位移寄存器: 周期性右移,记录访问。实际操作系统(Linux)用近似 LRU(如 Clock 算法 + 多级 LRU 链表),严格 LRU 维护代价过大', 'LRU 算法', 20.00, 2, 112),
(2865, 105, 5, '简述分页与分段的区别', NULL, '主要区别: (1)出发点: 分页是物理划分(简化内存管理),分段是逻辑划分(满足程序员需要); (2)大小: 页大小固定由硬件决定,段大小变化由程序决定; (3)地址空间: 分页是一维,分段是二维(段+段内偏移); (4)碎片: 分页只有内碎片,分段有外碎片; (5)对程序员: 分页透明,分段可见; (6)共享与保护: 分段更易实现共享和按段保护。现代系统常用段页式结合', '分页与分段对比', 15.00, 2, 112),
(2866, 105, 5, '简述常见的 I/O 控制方式', NULL, '四种 I/O 控制方式: (1)程序直接控制方式: CPU 不断轮询设备状态,效率最低; (2)中断驱动方式: 设备完成后通过中断通知 CPU,CPU 利用率提高; (3)DMA 方式: DMA 控制器直接在设备和内存之间传输,CPU 仅在开始和结束时介入; (4)通道方式: 引入通道处理器,可独立执行通道程序,CPU 干预最少。演化趋势: CPU 干预递减,设备并发度提高', 'I/O 控制方式的演化', 15.00, 2, 112),
(2867, 105, 5, '简述文件的物理结构', NULL, '三种主要物理结构: (1)连续分配: 文件占连续磁盘块,顺序访问快但难扩展、易外碎片; (2)链式分配: 每块含下一块指针,扩展容易但随机访问慢、指针占空间; (3)索引分配: 用索引块记录所有数据块地址,支持随机访问、便于扩展,但索引块本身占空间。UNIX 用混合索引: 直接块、一级间接块、二级间接、三级间接组合,既适合小文件又适合大文件', '文件的物理组织', 15.00, 2, 112),
(2868, 105, 5, '简述 SPOOLing 技术', NULL, 'SPOOLing(同时联机外围操作)将独占设备改造为共享设备的虚拟化技术。组成: (1)输入井: 磁盘上模拟输入设备的存储区; (2)输出井: 磁盘上模拟输出设备的存储区; (3)输入进程: 把输入数据从设备到输入井; (4)输出进程: 把输出井数据传到设备。例: 多用户共享打印机,各用户先把打印任务存到输出井,再依次打印。优点: 提高 I/O 速度,把独占改为共享,实现虚拟设备', 'SPOOLing 经典技术', 15.00, 2, 112),
(2869, 105, 5, '简述操作系统中的中断机制', NULL, '中断是 OS 实现并发与 I/O 的核心机制。分类: (1)外中断(异步): 由设备/外部事件触发,如时钟中断、I/O 中断; (2)内中断(同步异常): CPU 自身产生,如缺页、除零、断点。处理过程: (1)中断源发起请求; (2)CPU 响应,保存上下文; (3)查中断向量表; (4)执行中断处理程序; (5)恢复现场返回。意义: (1)实现 I/O 异步; (2)系统调用通过中断进入内核; (3)异常处理; (4)进程切换', '中断机制', 15.00, 2, 112),
(2870, 105, 5, '简述系统调用与库函数的区别', NULL, '主要区别: (1)系统调用是 OS 提供给用户的接口,运行在内核态,通过 trap/中断进入内核; (2)库函数是用户态函数,可能封装系统调用,也可能不调用; (3)系统调用涉及态切换开销大,库函数较快; (4)系统调用提供的是基础功能(I/O、进程控制等); 库函数提供的是高级抽象。例: printf() 库函数最终调用 write() 系统调用; strlen() 完全在用户态', '系统调用 vs 库函数', 15.00, 2, 112),
(2871, 105, 5, '简述操作系统的发展历程', NULL, 'OS 发展阶段: (1)无操作系统(手工操作 1950 前); (2)单道批处理(1955+); (3)多道批处理(1960+,提高 CPU 利用率); (4)分时系统(1965+,如 Multics、UNIX,响应快); (5)实时系统(航空航天、工业控制); (6)个人计算机 OS(MS-DOS、Mac OS); (7)网络与分布式 OS(NFS、Plan9); (8)现代多核与移动 OS(Windows、Linux、Android、iOS)。趋势: 多核并行、虚拟化、容器化、云原生', 'OS 的演化历程', 15.00, 2, 112),
(2872, 105, 5, '简述 Linux 进程间通信(IPC)的常见方式', NULL, 'Linux IPC 方式: (1)管道 pipe: 半双工,有亲缘关系进程间; (2)命名管道 FIFO: 任意进程间,基于文件; (3)信号 signal: 异步通知; (4)消息队列 msgqueue: 内核维护的消息链表; (5)共享内存 shm: 速度最快,需要额外同步; (6)信号量 semaphore: 进程同步; (7)Socket: 网络 IPC,可跨主机; (8)文件: 通过文件读写。选择依据: 数据量、速度、是否跨主机、是否需要同步', 'Linux IPC 多种机制', 15.00, 2, 112),
(2873, 105, 5, '简述线程的两种实现方式', NULL, '两种实现: (1)用户级线程(ULT): 在用户空间用线程库实现,内核不感知线程。优点: 切换快、可在不支持线程的 OS 上运行、调度灵活; 缺点: 一线程系统调用阻塞整个进程,无法利用多核。(2)内核级线程(KLT): 内核直接管理线程。优点: 一线程阻塞不影响其他、可利用多核; 缺点: 切换需进入内核、开销较大。混合模式: M:N 线程(多用户线程映射到少量内核线程),如 Solaris、Go 协程', '线程的两种实现', 15.00, 2, 112),
(2874, 105, 5, '简述操作系统的内核态与用户态', NULL, '两种 CPU 工作模式: (1)用户态: 运行普通程序,只能执行非特权指令,访问受限; (2)内核态: 运行 OS 内核,可执行所有指令,访问硬件。切换时机: 用户态→内核态: 系统调用、中断、异常(只能被动); 内核态→用户态: 中断处理完返回。意义: 保护操作系统,防止恶意或错误程序破坏系统; 隔离用户与内核; 提供安全的系统调用接口', '用户态与内核态', 15.00, 2, 112),
(2875, 105, 5, '简述磁盘调度算法及其特点', NULL, '常见磁盘调度算法: (1)FCFS: 按请求顺序处理,公平但寻道时间长; (2)SSTF(最短寻道): 选最近的请求,寻道短但可能饥饿; (3)SCAN(电梯): 单方向扫描到尽头,再反向,公平; (4)C-SCAN: 单向扫描,到尾部直接回头,响应均匀; (5)LOOK/C-LOOK: 在最末请求处折返,优于 SCAN/C-SCAN。指标: 平均寻道时间、吞吐量、公平性', '磁盘调度算法', 15.00, 2, 112),
(2876, 105, 5, '综合分析: 在 4 个进程到达时间均为 0,运行时间分别为 8、4、9、5 的情况下,分别用 FCFS、SJF 计算平均周转时间', NULL, 'FCFS: 按到达顺序 P1(8)、P2(4)、P3(9)、P4(5)。完成时间 8、12、21、26;周转时间 8、12、21、26;平均=(8+12+21+26)/4=67/4=16.75。SJF: 按运行时间排序 P2(4)、P4(5)、P1(8)、P3(9)。完成时间 4、9、17、26;周转时间 4、9、17、26;平均=(4+9+17+26)/4=56/4=14。结论: SJF 平均周转(14) < FCFS(16.75),SJF 更优', '调度算法的实战计算', 25.00, 3, 112);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(2877, 106, 1, '计算机中最基本的存储单位是', '{"A": "位(bit)", "B": "字节(Byte)", "C": "字(Word)", "D": "千字节(KB)"}', 'A', '位(bit)是计算机中最小的数据单位，0或1', 2.00, 1, 112),
(2878, 106, 1, '冯·诺依曼计算机的核心思想是', '{"A": "面向对象", "B": "存储程序", "C": "并行计算", "D": "分布式计算"}', 'B', '冯·诺依曼体系的核心是存储程序的概念', 2.00, 1, 112),
(2879, 106, 1, 'CPU中用于存储当前执行指令地址的寄存器是', '{"A": "通用寄存器", "B": "程序计数器(PC)", "C": "指令寄存器(IR)", "D": "地址寄存器(MAR)"}', 'B', 'PC(程序计数器)保存下一条要执行的指令地址', 2.00, 1, 112),
(2880, 106, 1, '8位二进制补码能表示的数值范围是', '{"A": "-127~127", "B": "-128~127", "C": "-128~128", "D": "0~255"}', 'B', '8位补码范围：-2^7 ~ 2^7-1 即 -128~127', 3.00, 2, 112),
(2881, 106, 1, 'Cache的作用是', '{"A": "扩大内存容量", "B": "提高CPU访问内存的速度", "C": "代替主存储器", "D": "永久存储数据"}', 'B', 'Cache利用局部性原理，弥补CPU与主存之间的速度差距', 2.00, 1, 112),
(2882, 106, 2, '冯·诺依曼计算机由以下哪些部分组成', '{"A": "运算器", "B": "控制器", "C": "存储器", "D": "输入/输出设备"}', 'ABCD', '冯·诺依曼计算机五大部件：运算器、控制器、存储器、输入设备、输出设备', 3.00, 1, 112),
(2883, 106, 2, '以下属于计算机总线的有', '{"A": "数据总线", "B": "地址总线", "C": "控制总线", "D": "网络总线"}', 'ABC', '计算机系统总线包括数据总线、地址总线和控制总线', 3.00, 2, 112),
(2884, 106, 3, 'RAM是易失性存储器，断电后数据丢失', NULL, '正确', 'RAM(随机存取存储器)是易失性的，断电数据消失；ROM是非易失性的', 2.00, 1, 112),
(2885, 106, 3, '指令周期等于时钟周期', NULL, '错误', '一个指令周期通常包含多个机器周期，每个机器周期包含多个时钟周期', 2.00, 2, 112),
(2886, 106, 3, 'RISC指令集的特点是指令数量多、功能复杂', NULL, '错误', 'RISC(精简指令集)特点是指令少、格式统一、执行速度快；CISC才是指令多而复杂', 2.00, 2, 112),
(2887, 106, 4, '1KB = ____字节', NULL, '1024', '1KB = 2^10 = 1024 Bytes', 2.00, 1, 112),
(2888, 106, 4, 'CPU主要由____和控制器两部分组成', NULL, '运算器', 'CPU = 运算器(ALU) + 控制器(CU)', 2.00, 1, 112),
(2889, 106, 5, '请说明计算机中原码、反码和补码的关系', NULL, '正数：原码=反码=补码。负数：反码是原码符号位不变其余位取反；补码是反码+1。使用补码的好处：统一了加减运算，0的表示唯一。例如-5：原码10000101，反码11111010，补码11111011。', '需要分别说明正数和负数的三种编码规则及补码的优势', 5.00, 2, 112),
(2890, 106, 5, '请解释Cache的工作原理及局部性原理', NULL, 'Cache是高速缓冲存储器，位于CPU和主存之间。工作原理：CPU先访问Cache，命中则直接读取（快），未命中则从主存取数据并复制到Cache。局部性原理：时间局部性（最近访问的数据可能再次被访问）和空间局部性（访问某地址后可能访问相邻地址）。', '需要说明Cache的位置、工作流程和局部性原理的两个方面', 5.00, 2, 112),
(2891, 106, 1, '十进制数25转换为二进制是', '{"A": "10011", "B": "11001", "C": "11010", "D": "10101"}', 'B', '25=16+8+1=2^4+2^3+2^0=11001', 2.00, 1, 112),
(2892, 106, 1, '计算机中数据的最小存储单位是', '{"A": "位", "B": "字节", "C": "字", "D": "双字"}', 'A', '位(bit)是最小存储单位', 2.00, 1, 112),
(2893, 106, 1, '下列哪种存储器速度最快', '{"A": "硬盘", "B": "内存", "C": "Cache", "D": "寄存器"}', 'D', '寄存器速度最快但容量最小', 2.00, 1, 112),
(2894, 106, 1, '浮点数的表示范围主要取决于', '{"A": "阶码位数", "B": "尾数位数", "C": "符号位", "D": "基数"}', 'A', '阶码决定表示范围尾数决定精度', 2.00, 2, 112),
(2895, 106, 1, 'CPU执行一条指令的过程不包括', '{"A": "取指", "B": "译码", "C": "执行", "D": "编译"}', 'D', '编译是高级语言翻译不是CPU执行步骤', 2.00, 1, 112),
(2896, 106, 1, '下列哪种总线用于连接CPU和主存', '{"A": "数据总线", "B": "地址总线", "C": "控制总线", "D": "系统总线"}', 'D', '系统总线连接CPU主存和I/O', 2.00, 1, 112),
(2897, 106, 1, 'SRAM和DRAM相比SRAM的特点是', '{"A": "需要刷新", "B": "速度慢", "C": "速度快不需刷新", "D": "容量大"}', 'C', 'SRAM速度快不需刷新用于Cache', 2.00, 1, 112),
(2898, 106, 1, '补码表示法中-128的8位补码是', '{"A": "10000000", "B": "11111111", "C": "01111111", "D": "00000000"}', 'A', '8位补码范围-128到127', 3.00, 2, 112),
(2899, 106, 1, 'DMA方式传送数据时CPU', '{"A": "完全不工作", "B": "需要执行程序", "C": "可以执行其他程序", "D": "处于等待状态"}', 'C', 'DMA不需CPU干预CPU可执行其他任务', 2.00, 2, 112),
(2900, 106, 1, '微程序控制器中微指令存储在', '{"A": "主存", "B": "Cache", "C": "控制存储器", "D": "硬盘"}', 'C', '微指令存储在控制存储器(CM)中', 2.00, 2, 112),
(2901, 106, 1, '虚拟存储器将主存和什么结合使用', '{"A": "Cache", "B": "寄存器", "C": "辅存", "D": "ROM"}', 'C', '虚拟存储器=主存+辅存', 2.00, 1, 112),
(2902, 106, 1, '计算机总线中地址总线的宽度决定了', '{"A": "数据传输速率", "B": "最大寻址空间", "C": "指令类型数", "D": "时钟频率"}', 'B', '地址总线宽度决定寻址范围', 2.00, 1, 112),
(2903, 106, 1, '中断处理过程中保护现场是保存', '{"A": "中断向量", "B": "程序状态字和寄存器内容", "C": "中断屏蔽字", "D": "设备状态"}', 'B', '保护现场即保存CPU寄存器和状态字', 2.00, 2, 112),
(2904, 106, 1, 'IEEE754标准中32位浮点数的阶码占', '{"A": "1位", "B": "8位", "C": "23位", "D": "32位"}', 'B', '32位浮点数1位符号8位阶码23位尾数', 3.00, 2, 112),
(2905, 106, 1, '流水线技术主要用于提高', '{"A": "单条指令执行速度", "B": "指令吞吐率", "C": "存储容量", "D": "总线带宽"}', 'B', '流水线提高指令吞吐率而非单条速度', 2.00, 2, 112),
(2906, 106, 2, '冯诺依曼计算机的五大部件包括', '{"A": "运算器", "B": "控制器", "C": "存储器", "D": "输入设备和输出设备"}', 'ABCD', '五大部件构成冯诺依曼体系结构', 3.00, 1, 112),
(2907, 106, 2, 'CPU的主要组成部分包括', '{"A": "运算器", "B": "控制器", "C": "寄存器组", "D": "Cache"}', 'ABC', 'Cache不是CPU的组成部分是独立的', 3.00, 1, 112),
(2908, 106, 2, '下列属于输入设备的有', '{"A": "键盘", "B": "鼠标", "C": "扫描仪", "D": "打印机"}', 'ABC', '打印机是输出设备', 3.00, 1, 112),
(2909, 106, 2, '关于Cache正确的有', '{"A": "利用局部性原理", "B": "速度介于CPU和主存之间", "C": "对程序员透明", "D": "容量比主存小"}', 'ABCD', '都是Cache的特点', 3.00, 1, 112),
(2910, 106, 2, '计算机总线按功能分为', '{"A": "数据总线", "B": "地址总线", "C": "控制总线", "D": "I/O总线"}', 'ABC', 'I/O总线按连接对象分不是按功能', 3.00, 1, 112),
(2911, 106, 2, '影响流水线性能的因素有', '{"A": "数据冒险", "B": "控制冒险", "C": "结构冒险", "D": "时钟频率"}', 'ABCD', '都影响流水线性能', 3.00, 3, 112),
(2912, 106, 2, '关于中断正确的有', '{"A": "是一种异步事件处理机制", "B": "需要保护和恢复现场", "C": "有优先级之分", "D": "可以被屏蔽"}', 'ABCD', '都是中断的特点', 3.00, 2, 112),
(2913, 106, 2, '主存的技术指标包括', '{"A": "存储容量", "B": "存取时间", "C": "存储周期", "D": "带宽"}', 'ABCD', '都是主存的性能指标', 3.00, 1, 112),
(2914, 106, 2, 'I/O设备与主机的连接方式有', '{"A": "程序直接控制", "B": "中断方式", "C": "DMA方式", "D": "通道方式"}', 'ABCD', '都是I/O设备连接方式', 3.00, 2, 112),
(2915, 106, 2, '关于指令系统正确的有', '{"A": "指令由操作码和操作数组成", "B": "CISC指令数量多", "C": "RISC指令数量少", "D": "指令格式分固定和可变"}', 'ABCD', '都是指令系统的知识点', 3.00, 2, 112),
(2916, 106, 2, '关于寻址方式正确的有', '{"A": "立即寻址操作数在指令中", "B": "直接寻址给出操作数地址", "C": "间接寻址给出地址的地址", "D": "寄存器寻址操作数在寄存器"}', 'ABCD', '四种基本寻址方式', 3.00, 2, 112),
(2917, 106, 2, '关于补码运算正确的有', '{"A": "可以用加法实现减法", "B": "符号位参与运算", "C": "溢出需要判断", "D": "简化了硬件设计"}', 'ABCD', '都是补码运算的特点', 3.00, 2, 112),
(2918, 106, 2, '存储器的层次结构从快到慢依次是', '{"A": "寄存器", "B": "Cache", "C": "主存", "D": "辅存"}', 'ABCD', '速度递减容量递增', 3.00, 1, 112),
(2919, 106, 2, '关于虚拟存储器正确的有', '{"A": "扩大了程序的地址空间", "B": "利用了局部性原理", "C": "需要页表进行地址转换", "D": "可能产生缺页中断"}', 'ABCD', '都是虚拟存储器的特点', 3.00, 2, 112),
(2920, 106, 2, '下列属于RISC特点的有', '{"A": "指令数量少", "B": "定长指令格式", "C": "硬布线控制器", "D": "Load/Store结构"}', 'ABCD', '都是RISC的特点', 3.00, 3, 112),
(2921, 106, 2, '关于总线仲裁正确的有', '{"A": "集中式仲裁有链式查询", "B": "分布式仲裁无中央仲裁器", "C": "解决多设备争用总线问题", "D": "影响总线传输效率"}', 'ABCD', '都是总线仲裁的特点', 3.00, 3, 112),
(2922, 106, 2, '关于磁盘存储器正确的有', '{"A": "非易失性存储", "B": "存取时间包括寻道时间", "C": "旋转等待时间影响速度", "D": "可以随机访问"}', 'ABCD', '都是磁盘的特点', 3.00, 1, 112),
(2923, 106, 2, '计算机中的校验方法有', '{"A": "奇偶校验", "B": "海明校验", "C": "CRC循环冗余校验", "D": "模2运算"}', 'ABC', '模2运算是CRC的基础运算不是校验方法', 3.00, 2, 112),
(2924, 106, 3, 'ROM中的内容断电后不会丢失', NULL, '正确', 'ROM是非易失性存储器', 2.00, 1, 112),
(2925, 106, 3, '计算机的运算速度只取决于CPU主频', NULL, '错误', '还取决于指令集架构流水线等多因素', 2.00, 1, 112),
(2926, 106, 3, '补码的加法运算可能产生溢出', NULL, '正确', '两个同号数相加可能溢出', 2.00, 2, 112),
(2927, 106, 3, 'DMA方式比中断方式数据传输效率高', NULL, '正确', 'DMA不需CPU干预效率更高', 2.00, 1, 112),
(2928, 106, 3, '寄存器和主存都是易失性存储器', NULL, '正确', '都是RAM类型断电后数据丢失', 2.00, 1, 112),
(2929, 106, 3, '机器字长就是数据总线的宽度', NULL, '错误', '机器字长是CPU一次处理的数据位数不一定等于总线宽度', 2.00, 2, 112),
(2930, 106, 3, '流水线越多处理器性能一定越高', NULL, '错误', '流水线过深会带来更多冒险和开销', 2.00, 2, 112),
(2931, 106, 3, 'Cache和主存之间的数据交换以块为单位', NULL, '正确', 'Cache按块进行数据交换', 2.00, 1, 112),
(2932, 106, 3, '中断嵌套是指高优先级中断可以打断低优先级中断', NULL, '正确', '高优先级可以嵌套打断低优先级中断处理', 2.00, 2, 112),
(2933, 106, 3, '移码常用于表示浮点数的阶码', NULL, '正确', '移码便于比较浮点数大小', 2.00, 2, 112),
(2934, 106, 3, '通道是一种特殊的处理器专门负责I/O操作', NULL, '正确', '通道独立于CPU管理I/O传输', 2.00, 2, 112),
(2935, 106, 3, '程序计数器PC存放的是当前正在执行的指令', NULL, '错误', 'PC存放的是下一条要执行的指令地址', 2.00, 1, 112),
(2936, 106, 3, 'DRAM比SRAM便宜但速度慢', NULL, '正确', 'DRAM密度高便宜但需刷新速度慢', 2.00, 1, 112),
