(3124, 106, 3, 'UTF-8 是变长编码', NULL, '正确', 'UTF-8 变长 1-4 字节', 1.00, 3, 112),
(3125, 106, 3, 'GPU 适合并行计算', NULL, '正确', 'GPU 多核并行', 1.00, 2, 112),
(3126, 106, 3, '摩尔定律预言集成度每 18 个月翻倍', NULL, '正确', '摩尔定律', 1.00, 2, 112),
(3127, 106, 4, '计算机内部数据采用____进制', NULL, '二', '二进制', 2.00, 1, 112),
(3128, 106, 4, '1 字节等于____位', NULL, '8', '1B=8b', 2.00, 1, 112),
(3129, 106, 4, 'CPU 全称是____', NULL, 'Central Processing Unit', 'CPU 全称', 2.00, 1, 112),
(3130, 106, 4, 'ALU 全称是____', NULL, 'Arithmetic Logic Unit', 'ALU 全称', 2.00, 2, 112),
(3131, 106, 4, 'CU 全称是____', NULL, 'Control Unit', 'CU 全称', 2.00, 2, 112),
(3132, 106, 4, '32 位地址总线最多寻址____字节', NULL, '4G', '2^32=4G', 2.00, 2, 112),
(3133, 106, 4, 'CPU 与内存之间的高速缓冲存储器是____', NULL, 'Cache', 'Cache 缓存', 2.00, 1, 112),
(3134, 106, 4, 'Cache 命中率高的根本原理是____原理', NULL, '局部性', '局部性原理', 2.00, 2, 112),
(3135, 106, 4, 'DMA 全称是____', NULL, 'Direct Memory Access', 'DMA 直接内存访问', 2.00, 2, 112),
(3136, 106, 4, '程序计数器的英文缩写是____', NULL, 'PC', 'PC: Program Counter', 2.00, 2, 112),
(3137, 106, 4, '指令寄存器的英文缩写是____', NULL, 'IR', 'IR: Instruction Register', 2.00, 2, 112),
(3138, 106, 4, 'CPU 主频和时钟周期成____', NULL, '反比', 'f=1/T', 2.00, 2, 112),
(3139, 106, 4, 'RISC 全称是____', NULL, 'Reduced Instruction Set Computer', '精简指令集', 2.00, 2, 112),
(3140, 106, 4, 'CISC 全称是____', NULL, 'Complex Instruction Set Computer', '复杂指令集', 2.00, 2, 112),
(3141, 106, 4, 'CPI 全称是____', NULL, 'Cycles Per Instruction', '每条指令时钟数', 2.00, 3, 112),
(3142, 106, 4, 'MIPS 全称是____', NULL, 'Million Instructions Per Second', '每秒百万指令', 2.00, 2, 112),
(3143, 106, 4, 'FLOPS 全称是____', NULL, 'Floating Point Operations Per Second', '每秒浮点运算', 2.00, 2, 112),
(3144, 106, 4, 'IEEE 754 单精度浮点数总位数是____', NULL, '32', '单精度 32 位', 2.00, 2, 112),
(3145, 106, 4, 'IEEE 754 双精度浮点数总位数是____', NULL, '64', '双精度 64 位', 2.00, 2, 112),
(3146, 106, 4, 'ASCII 是____位编码', NULL, '7', '标准 ASCII 7 位', 2.00, 2, 112),
(3147, 106, 4, '流水线提高的是 CPU 的____', NULL, '吞吐量', '流水线提升吞吐', 2.00, 2, 112),
(3148, 106, 4, '流水线冲突类型有结构相关、数据相关和____', NULL, '控制相关', '三类冲突', 2.00, 3, 112),
(3149, 106, 4, '内存层次由快到慢:寄存器、Cache、主存、____', NULL, '外存', '存储层次', 2.00, 2, 112),
(3150, 106, 4, 'DRAM 需要____', NULL, '刷新', 'DRAM 必须定时刷新', 2.00, 2, 112),
(3151, 106, 4, 'SRAM 不需要____', NULL, '刷新', 'SRAM 触发器不需刷新', 2.00, 2, 112),
(3152, 106, 4, 'Cache 三种映射方式包括直接映射、全相联映射和____', NULL, '组相联', '三种 Cache 映射', 2.00, 3, 112),
(3153, 106, 4, 'CPU 通过____寻址主存', NULL, '地址总线', '地址线寻址', 2.00, 2, 112),
(3154, 106, 4, 'I/O 控制方式中,CPU 利用率最高的是____', NULL, '通道', '通道方式', 2.00, 3, 112),
(3155, 106, 4, '计算机性能公式 T = N × CPI × T_c 中 T_c 表示____', NULL, '时钟周期', '时钟周期', 2.00, 3, 112),
(3156, 106, 4, '计算机硬件五大部件:运算器、控制器、存储器、输入设备、____', NULL, '输出设备', '五大部件', 2.00, 1, 112),
(3157, 106, 5, '简述冯诺依曼计算机的核心思想', NULL, '1)存储程序原理:程序和数据都存储在同一存储器中;2)由五大部件组成:运算器、控制器、存储器、输入设备、输出设备;3)程序由指令序列组成,顺序执行,可由跳转指令改变控制流;4)采用二进制表示数据和指令。这一思想奠定了现代计算机的基础。', '冯诺依曼基本原理', 5.00, 2, 112),
(3158, 106, 5, '简述 CPU 的内部组成', NULL, 'CPU 主要由三部分组成:1)运算器(ALU):执行算术和逻辑运算;2)控制器(CU):取指、译码、产生控制信号,协调各部件;3)寄存器组:包括程序计数器 PC、指令寄存器 IR、累加器 ACC、通用寄存器、栈指针 SP 等。现代 CPU 还集成 Cache(L1/L2/L3)。', 'CPU 组成', 5.00, 2, 112),
(3159, 106, 5, '简述 RISC 和 CISC 的主要区别', NULL, '1)指令数量:RISC 指令少且简单,CISC 指令多且复杂;2)指令格式:RISC 固定长度,CISC 可变长度;3)寻址方式:RISC 简单(主要 Load/Store),CISC 多样;4)执行速度:RISC 快(单周期),CISC 慢(多周期);5)编译器:RISC 复杂,CISC 简单;6)代表:RISC 有 ARM、MIPS,CISC 有 x86。', 'RISC vs CISC', 5.00, 3, 112),
(3160, 106, 5, '简述程序的局部性原理及其意义', NULL, '程序的局部性包括:1)时间局部性:被访问的数据/指令在不远的将来仍可能被访问(如循环);2)空间局部性:相邻地址的数据/指令可能很快被访问(如顺序执行、数组遍历)。意义:1)是 Cache 设计的理论基础,使 Cache 命中率高;2)是虚拟内存有效的基础;3)指导编译优化(如循环展开、数据预取)。', '局部性原理', 5.00, 2, 112),
(3161, 106, 5, '简述 Cache 的三种映射方式', NULL, '1)直接映射:主存块映射到 Cache 唯一行,简单快速但冲突率高;2)全相联映射:主存块可映射到 Cache 任意行,冲突最少但查找开销大;3)组相联映射:Cache 分组,组内全相联,组间直接映射(常见 2 路、4 路、8 路),折中方案,实际使用最多。三种映射方式各有优劣,组相联是主流选择。', 'Cache 映射', 5.00, 3, 112),
(3162, 106, 5, '简述 Cache 的替换策略', NULL, '当 Cache 满需要替换时:1)FIFO(先进先出):简单,但不考虑访问频率,可能替换热点;2)LRU(最近最少使用):替换最久未访问的,效果好但实现复杂(需记录访问顺序);3)LFU(最少使用频率):替换访问次数最少的,适合稳定访问模式;4)随机:简单,实际效果还可以,常用于硬件实现。LRU 是最常用的高效策略。', '替换策略', 5.00, 3, 112),
(3163, 106, 5, '简述存储器的层次结构及其原因', NULL, '存储层次(由快到慢、由小到大):寄存器→Cache(L1/L2/L3)→主存(DRAM)→外存(SSD/HDD)→远程存储。原因:1)速度与容量的平衡:快的贵小,慢的便宜大;2)局部性使分层有效:大部分访问在快层即可命中;3)成本约束:每层各自优化。结果是用合理成本接近最快层速度,享受最慢层容量。', '存储层次', 5.00, 2, 112),
(3164, 106, 5, '简述总线的分类及作用', NULL, '总线按功能分三类:1)数据总线:双向,传送数据,宽度决定字长;2)地址总线:单向(CPU→内存),传送地址,宽度决定寻址范围;3)控制总线:双向,传送控制信号(如读/写、中断、就绪等)。按位置分:片内总线、系统总线、I/O 总线。总线性能指标:总线宽度、总线频率、总线带宽=宽度×频率。', '总线', 5.00, 2, 112),
(3165, 106, 5, '简述 I/O 控制方式及其特点', NULL, '四种 I/O 控制方式:1)程序查询:CPU 主动轮询 I/O 状态,CPU 利用率最低;2)中断方式:I/O 完成后中断 CPU,CPU 处理中断,提高利用率;3)DMA:I/O 设备直接与内存传输,不需 CPU 干预,CPU 仅在开始和结束参与;4)通道方式:专用 I/O 处理器(通道)管理 I/O,CPU 利用率最高,适合高速 I/O。', 'I/O 控制方式', 5.00, 3, 112),
(3166, 106, 5, '简述中断的处理过程', NULL, '中断处理 5 步:1)中断请求:外设或异常向 CPU 发请求;2)中断响应:CPU 在指令边界检查中断,响应优先级最高的;3)保护现场:把 PC、PSW 等压栈,保存寄存器;4)中断处理:执行中断服务程序(ISR);5)恢复现场:出栈恢复寄存器,返回原程序。期间会自动关中断防止嵌套覆盖,可在 ISR 中重新开中断允许嵌套。', '中断处理', 5.00, 3, 112),
(3167, 106, 5, '简述指令周期、机器周期和时钟周期的关系', NULL, '三者关系:指令周期 ≥ 机器周期 ≥ 时钟周期。1)时钟周期(T):CPU 时钟脉冲一周期,T=1/主频,最小时间单位;2)机器周期(M):CPU 完成一个基本操作的时间(如取指、读内存),由若干时钟周期组成;3)指令周期(I):取指+译码+执行一条指令的总时间,由若干机器周期组成。一条指令通常需要多个机器周期。', '三周期关系', 5.00, 3, 112),
(3168, 106, 5, '简述流水线技术及其冲突', NULL, '流水线把指令分阶段(如取指 IF、译码 ID、执行 EX、访存 MEM、写回 WB),多条指令并行处理,提高吞吐量。三类冲突:1)结构相关:硬件资源冲突(如同时访存);2)数据相关:后指令依赖前指令结果;3)控制相关:跳转改变控制流。解决方法:转发、停顿、分支预测、乱序执行、超标量等。', '流水线及冲突', 5.00, 3, 112),
(3169, 106, 5, '简述补码的优点', NULL, '补码相对原码反码的优点:1)0 的表示唯一(原码反码有 +0/-0);2)符号位可参与运算,简化加法器电路;3)减法可转换为加法(A-B=A+(-B)的补码),只需一套加法器即可处理加减;4)表示范围更大(8 位补码 -128~127,原码只 -127~127);5)位数易扩展。这些优点使补码成为现代计算机的标准表示方式。', '补码优点', 5.00, 3, 112),
(3170, 106, 5, '简述 IEEE 754 浮点数表示', NULL, 'IEEE 754 标准把浮点数分三部分:1)符号位(S):1 位,0 正 1 负;2)阶码(E):有偏移(单精度偏移 127,双精度 1023);3)尾数(M):规格化为 1.xxx,省略隐含的 1,只存小数部分。单精度 32 位:1+8+23;双精度 64 位:1+11+52。值=(-1)^S × 1.M × 2^(E-bias)。特殊值:0、NaN、±∞ 等。', 'IEEE 754', 5.00, 3, 112),
(3171, 106, 5, '简述 DMA 的工作过程', NULL, 'DMA(直接内存访问)工作过程:1)CPU 向 DMA 控制器发命令,提供:数据源地址、目的地址、传输长度、传输方向;2)DMA 控制器接管总线,直接在 I/O 设备和内存之间传输数据;3)传输过程中 CPU 可继续执行其他任务(也可能因总线占用而暂停);4)传输完成后,DMA 通过中断通知 CPU。DMA 优势:减少 CPU 干预,适合大块数据高速传输(如硬盘到内存)。', 'DMA 工作过程', 5.00, 3, 112),
(3172, 106, 5, '简述虚拟存储器原理', NULL, '虚拟存储器把内存和外存(硬盘)统一管理,给程序提供一个比实际内存大得多的逻辑地址空间。原理:1)程序使用逻辑地址,MMU 通过页表(或段表)转换为物理地址;2)当访问的页不在内存时,触发缺页中断,从外存调入(可能换出已有页);3)替换策略:LRU、CLOCK 等;4)优势:扩展逻辑空间、隔离进程、按需加载、节省内存。基础是局部性原理。', '虚拟存储器', 5.00, 3, 112),
(3173, 106, 5, '简述 CPU 性能提升的主要途径', NULL, '1)提高主频:直接缩短时钟周期(受功耗墙限制);2)降低 CPI:流水线、超标量、乱序执行、分支预测等;3)增加 IPC:多发射、超线程;4)多核并行:增加核心数;5)Cache 优化:增大容量、改善命中率;6)指令集优化:RISC 思想、SIMD 指令(如 SSE/AVX);7)制造工艺:更小的晶体管、更低功耗。现代 CPU 主要靠多核+IPC+Cache 平衡。', 'CPU 性能提升', 5.00, 3, 112),
(3174, 106, 5, '简述指令的取指执行过程', NULL, '取指执行过程(冯诺依曼):1)取指阶段(Fetch):从 PC 指向的内存地址取指令到 IR,PC++;2)译码阶段(Decode):CU 解析 IR 中的操作码,确定指令类型和操作数;3)取操作数(Operand):根据寻址方式从寄存器或内存取操作数;4)执行阶段(Execute):ALU 完成运算或控制操作;5)写回阶段(Write Back):结果写回寄存器或内存;6)修改 PC:顺序+1 或跳转。循环往复直到程序结束。', '取指执行', 5.00, 3, 112),
(3175, 106, 5, '简述并行处理的层次', NULL, '并行处理多层次:1)指令级并行(ILP):流水线、超标量、乱序执行,单核内多条指令并行;2)数据级并行(DLP):SIMD 指令(如 AVX),一条指令处理多个数据,适合向量计算;3)线程级并行(TLP):多核处理器,多线程同时执行;4)请求级并行(RLP):分布式系统多机器协作。每个层次都有相应的硬件支持和编程模型。', '并行层次', 5.00, 3, 112),
(3176, 106, 5, '简述 GPU 与 CPU 的区别', NULL, '1)设计目标:CPU 通用计算,GPU 图形/数据并行;2)核心数:CPU 少(几到几十)而强,GPU 多(几千)而弱;3)控制单元:CPU 复杂(分支预测、乱序),GPU 简单;4)Cache:CPU 大(L1/L2/L3),GPU 小;5)适用场景:CPU 适合复杂逻辑、低延迟,GPU 适合并行计算、高吞吐(图形渲染、深度学习训练、科学计算);6)编程模型:CPU 多线程,GPU 用 CUDA/OpenCL 大规模并行。', 'CPU vs GPU', 5.00, 2, 112);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(3177, 107, 1, 'TCP/IP参考模型共分为几层', '{"A": "4层", "B": "5层", "C": "6层", "D": "7层"}', 'A', 'TCP/IP模型分为4层：应用层、传输层、网际层、网络接口层', 2.00, 1, 114),
(3178, 107, 1, 'HTTP协议默认使用的端口号是', '{"A": "21", "B": "25", "C": "80", "D": "443"}', 'C', 'HTTP默认端口80，HTTPS默认443，FTP默认21，SMTP默认25', 2.00, 1, 114),
(3179, 107, 1, 'IP地址192.168.1.1属于哪类地址', '{"A": "A类", "B": "B类", "C": "C类", "D": "D类"}', 'C', '192.168.x.x属于C类私有地址', 2.00, 1, 114),
(3180, 107, 1, '以下哪个协议属于传输层', '{"A": "HTTP", "B": "TCP", "C": "IP", "D": "ARP"}', 'B', 'TCP和UDP属于传输层协议', 2.00, 1, 114),
(3181, 107, 1, '子网掩码255.255.255.0对应的CIDR表示法是', '{"A": "/8", "B": "/16", "C": "/24", "D": "/32"}', 'C', '255.255.255.0有24个1，对应/24', 2.00, 1, 114),
(3182, 107, 2, 'TCP协议的特点包括', '{"A": "面向连接", "B": "可靠传输", "C": "无连接", "D": "全双工通信"}', 'ABD', 'TCP是面向连接的、可靠的、全双工的传输层协议，UDP才是无连接的', 3.00, 2, 114),
(3183, 107, 2, '以下属于应用层协议的有', '{"A": "HTTP", "B": "FTP", "C": "TCP", "D": "DNS"}', 'ABD', 'TCP属于传输层协议，HTTP、FTP、DNS属于应用层', 3.00, 2, 114),
(3184, 107, 3, 'UDP协议提供可靠的数据传输服务', NULL, '错误', 'UDP是不可靠的传输协议，不保证数据的可靠到达', 2.00, 1, 114),
(3185, 107, 3, '交换机工作在数据链路层', NULL, '正确', '交换机根据MAC地址转发数据帧，工作在数据链路层', 2.00, 1, 114),
(3186, 107, 3, 'DNS的主要功能是将域名解析为IP地址', NULL, '正确', 'DNS(域名系统)的核心功能就是域名到IP地址的映射', 2.00, 1, 114),
(3187, 107, 4, 'TCP建立连接需要____次握手', NULL, '三', 'TCP通过三次握手建立连接', 2.00, 1, 114),
(3188, 107, 4, 'OSI参考模型共有____层', NULL, '七', 'OSI七层模型：物理层、数据链路层、网络层、传输层、会话层、表示层、应用层', 2.00, 1, 114),
(3189, 107, 5, '请简述TCP三次握手的过程', NULL, '1.客户端发送SYN报文(SYN=1,seq=x)到服务端；2.服务端收到后回复SYN+ACK报文(SYN=1,ACK=1,seq=y,ack=x+1)；3.客户端收到后发送ACK报文(ACK=1,seq=x+1,ack=y+1)，连接建立。', '需要描述三次握手的每一步及其携带的标志位', 5.00, 2, 114),
(3190, 107, 5, '请比较TCP和UDP协议的区别', NULL, 'TCP：面向连接、可靠传输、有流量控制和拥塞控制、传输效率较低、适用于文件传输等。UDP：无连接、不可靠传输、没有流量控制、传输效率高、适用于视频流等实时应用。', '从连接方式、可靠性、效率、应用场景等方面比较', 5.00, 2, 114),
(3191, 107, 1, 'ARP协议的作用是', '{"A": "IP地址到MAC地址的映射", "B": "MAC地址到IP地址的映射", "C": "域名到IP地址的映射", "D": "IP地址到域名的映射"}', 'A', 'ARP(地址解析协议)将IP地址解析为MAC地址', 2.00, 2, 114),
(3192, 107, 1, 'OSI参考模型中负责数据加密的是', '{"A": "网络层", "B": "传输层", "C": "表示层", "D": "应用层"}', 'C', '表示层负责数据加密压缩和格式转换', 2.00, 2, 114),
