(3520, 108, 2, '关于触发器正确的有', '{"A": "自动执行", "B": "可在INSERT时触发", "C": "可在UPDATE时触发", "D": "可在DELETE时触发"}', 'ABCD', '触发器在指定事件时自动执行', 3.00, 2, 116),
