(3524, 108, 3, '数据库管理系统是位于用户和操作系统之间的数据管理软件', NULL, '正确', 'DBMS介于用户和OS之间', 2.00, 1, 116),
(3525, 108, 3, '关系中的元组可以重复', NULL, '错误', '关系中不允许有重复元组', 2.00, 1, 116),
