(3528, 108, 3, '数据库的概念模型独立于具体的DBMS', NULL, '正确', '概念模型如E-R模型独立于DBMS', 2.00, 1, 116),
(3529, 108, 3, '候选键可以有多个但主键只能有一个', NULL, '正确', '从候选键中选一个作为主键', 2.00, 2, 116),
(3530, 108, 3, '两段锁协议可以保证不发生死锁', NULL, '错误', '两段锁保证可串行化但不能防止死锁', 2.00, 3, 116),
(3531, 108, 3, 'DROP TABLE语句会删除表结构和数据', NULL, '正确', 'DROP删除整个表DELETE只删数据', 2.00, 1, 116),
(3532, 108, 3, '内连接只返回两个表中匹配的行', NULL, '正确', '内连接只返回满足连接条件的行', 2.00, 1, 116),
(3533, 108, 3, 'NULL值参与任何运算结果都是NULL', NULL, '正确', 'NULL与任何值运算结果为NULL', 2.00, 2, 116),
(3534, 108, 3, '数据库的物理独立性是指修改内模式不影响概念模式', NULL, '正确', '物理独立性通过概念/内模式映像保证', 2.00, 2, 116),
(3535, 108, 3, 'B+树索引中所有数据都存储在叶子结点', NULL, '正确', 'B+树叶子结点存储所有数据并链接', 2.00, 2, 116),
(3536, 108, 3, '事务的原子性要求事务中的操作要么全做要么全不做', NULL, '正确', '原子性保证事务不可分割', 2.00, 1, 116),
(3537, 108, 3, '关系代数中的投影运算可能会减少元组数量', NULL, '正确', '投影后可能有重复元组需去重', 2.00, 2, 116),
(3538, 108, 3, '第三范式一定满足第二范式', NULL, '正确', '范式之间逐级满足', 2.00, 1, 116),
(3539, 108, 3, '索引越多查询越快', NULL, '错误', '过多索引会降低写操作性能', 2.00, 1, 116),
(3540, 108, 3, 'GRANT语句用于授予用户权限', NULL, '正确', 'GRANT授权REVOKE收回权限', 2.00, 1, 116),
(3541, 108, 4, 'SQL中用于去除重复记录的关键字是____', NULL, 'DISTINCT', 'DISTINCT去除查询结果中的重复行', 3.00, 1, 116),
(3542, 108, 4, '数据库中用____来保证事务的原子性', NULL, '日志', '通过undo日志回滚未完成事务', 3.00, 2, 116),
(3543, 108, 4, 'E-R图中用____形状表示联系', NULL, '菱形', '菱形表示联系矩形表示实体', 3.00, 1, 116),
(3544, 108, 4, 'SQL中用____子句对查询结果排序', NULL, 'ORDER BY', 'ORDER BY指定排序字段和方式', 3.00, 1, 116),
(3545, 108, 4, '在关系R中能唯一标识元组的属性集称为____', NULL, '候选键', '候选键唯一标识元组', 3.00, 1, 116),
(3546, 108, 4, '数据库的____独立性是指修改外模式不影响应用程序', NULL, '逻辑', '逻辑独立性通过外模式/概念模式映像保证', 3.00, 2, 116),
(3547, 108, 4, 'SQL中____语句用于修改表中的数据', NULL, 'UPDATE', 'UPDATE SET WHERE修改数据', 3.00, 1, 116),
(3548, 108, 4, '并发控制中____锁允许其他事务读但不允许写', NULL, '共享', '共享锁S锁允许并发读', 3.00, 2, 116),
(3549, 108, 4, '关系代数中从关系中选取若干列的操作叫____', NULL, '投影', '投影是垂直方向选取属性', 3.00, 1, 116),
(3550, 108, 4, '数据库设计的第一步是____分析', NULL, '需求', '需求分析是数据库设计的起点', 3.00, 1, 116),
(3551, 108, 4, 'SQL中____函数用于统计记录的数目', NULL, 'COUNT', 'COUNT统计行数', 3.00, 1, 116),
(3552, 108, 4, '事务的____特性保证多个事务并发执行互不干扰', NULL, '隔离性', '隔离性即Isolation', 3.00, 2, 116),
(3553, 108, 4, '数据库中____用于加速数据检索', NULL, '索引', '索引提高查询效率', 3.00, 1, 116),
(3554, 108, 4, 'SQL中用____语句删除表中满足条件的记录', NULL, 'DELETE', 'DELETE FROM WHERE删除记录', 3.00, 1, 116),
(3555, 108, 4, '关系模式规范化中将一个关系分解为多个关系的过程叫____', NULL, '分解', '模式分解是规范化的基本手段', 3.00, 2, 116),
(3556, 108, 4, '数据库中____约束要求外键值必须在被参照表中存在', NULL, '参照完整性', '外键引用必须有效', 3.00, 2, 116),
(3557, 108, 4, 'SQL中____关键字用于连接两个查询结果并去重', NULL, 'UNION', 'UNION合并去重UNION ALL不去重', 3.00, 1, 116),
(3558, 108, 4, '关系中属性的取值范围称为____', NULL, '域', '域是属性值的集合', 3.00, 1, 116),
(3559, 108, 5, '请解释数据库的三级模式结构及其优点', NULL, '三级模式：外模式(用户视图)、概念模式(全局逻辑结构)、内模式(物理存储)。两层映像：外模式/概念模式映像提供逻辑独立性；概念模式/内模式映像提供物理独立性。优点：数据独立性高，多用户使用方便，安全性好。', '需说明三级模式和两层映像', 5.00, 2, 116),
(3560, 108, 5, '请解释关系数据库中的函数依赖和范式', NULL, '函数依赖：X→Y表示X的值能唯一确定Y的值。1NF：属性不可再分。2NF：消除非主属性对码的部分函数依赖。3NF：消除非主属性对码的传递函数依赖。BCNF：每个决定因素都包含码。规范化目的是减少数据冗余和操作异常。', '需说明函数依赖概念和各范式定义', 5.00, 2, 116),
(3561, 108, 5, '请说明数据库事务的并发问题及解决方法', NULL, '并发问题：1.丢失修改两个事务同时修改同一数据；2.读脏数据读到未提交的数据；3.不可重复读两次读结果不同。解决：封锁机制(共享锁排他锁)、两段锁协议、隔离级别(读未提交/读已提交/可重复读/串行化)。', '需说明三种并发问题和解决方案', 5.00, 3, 116),
(3562, 108, 5, '请比较数据库中的聚簇索引和非聚簇索引', NULL, '聚簇索引：数据按索引顺序物理排列一个表只能有一个查找快。非聚簇索引：索引和数据分开存储一个表可有多个通过指针访问数据。聚簇索引适合范围查询非聚簇索引适合精确查询。主键默认创建聚簇索引。', '需比较两种索引的特点和适用场景', 5.00, 2, 116),
(3563, 108, 5, '请说明SQL注入的原理和防范措施', NULL, '原理：攻击者在输入中插入恶意SQL代码如在登录表单输入or 1=1导致查询条件永真绕过验证。防范：1.参数化查询/预处理语句；2.输入验证和过滤；3.最小权限原则；4.使用ORM框架；5.转义特殊字符。', '需说明原理和至少三种防范措施', 5.00, 2, 116),
(3564, 108, 5, '请解释数据库中视图的概念及其作用', NULL, '视图是从基表导出的虚拟表不存储数据查询时动态生成。作用：1.简化复杂查询将常用查询封装为视图；2.安全性控制限制用户只能看到部分数据；3.逻辑独立性修改基表结构时通过视图保持接口不变；4.不同用户看到不同数据。', '需说明概念和至少三个作用', 5.00, 1, 116),
(3565, 108, 5, '请说明数据库恢复的基本策略', NULL, '恢复策略基于数据冗余。1.数据转储：定期备份完整数据库(完全转储)或只备份修改部分(增量转储)。2.日志文件：记录所有事务操作用于redo(重做已提交)和undo(撤销未提交)。3.检查点：定期将缓冲区数据写入磁盘减少恢复时间。恢复过程：装入最近备份+利用日志前滚或回滚。', '需说明转储日志和恢复过程', 5.00, 2, 116),
(3566, 108, 5, '请比较关系数据库和NoSQL数据库的特点', NULL, '关系型：结构化数据表格形式ACID事务SQL查询适合结构化场景如MySQL。NoSQL：非结构化灵活模式高扩展性最终一致性。类型：键值(Redis)文档(MongoDB)列族(HBase)图(Neo4j)。选择：数据一致性要求高选关系型大数据量高并发选NoSQL。', '需比较两类数据库的特点和适用场景', 5.00, 2, 116),
(3567, 108, 1, '下列不属于数据库系统组成的是', '{"A": "数据库", "B": "DBMS", "C": "操作系统", "D": "用户"}', 'C', '数据库系统由 DB、DBMS、用户、应用组成', 2.00, 2, 116),
(3568, 108, 1, '数据库系统的三级模式结构是', '{"A": "外模式、模式、内模式", "B": "逻辑、物理、视图", "C": "用户、应用、系统", "D": "表、视图、索引"}', 'A', '三级模式: 外模式(用户视图)、模式(逻辑)、内模式(物理)', 2.00, 2, 116),
(3569, 108, 1, '数据独立性包括', '{"A": "物理独立性", "B": "逻辑独立性", "C": "物理和逻辑独立性", "D": "结构独立性"}', 'C', '数据独立性=逻辑独立性+物理独立性', 2.00, 2, 116),
(3570, 108, 1, '下列哪种数据模型最常用', '{"A": "层次模型", "B": "网状模型", "C": "关系模型", "D": "对象模型"}', 'C', '关系模型是当前主流', 2.00, 1, 116),
(3571, 108, 1, '数据库系统与文件系统的主要区别在于', '{"A": "数据共享性", "B": "数据结构", "C": "数据冗余", "D": "以上都对"}', 'D', 'DB 系统具备数据共享、结构化、低冗余等优势', 2.00, 2, 116),
(3572, 108, 1, 'DBA 的全称是', '{"A": "数据库管理员", "B": "数据库管理者", "C": "数据库管理者-管理员", "D": "数据库分析员"}', 'A', 'DBA: Database Administrator', 2.00, 1, 116),
(3573, 108, 1, '数据库的三个数据模型不包括', '{"A": "概念模型", "B": "逻辑模型", "C": "物理模型", "D": "应用模型"}', 'D', '数据库设计有概念-逻辑-物理三个层次', 2.00, 2, 116),
(3574, 108, 1, 'E-R 模型属于', '{"A": "概念模型", "B": "逻辑模型", "C": "物理模型", "D": "数据模型"}', 'A', 'E-R 是概念模型(实体-联系)', 2.00, 2, 116),
(3575, 108, 1, 'E-R 图中的菱形表示', '{"A": "实体", "B": "属性", "C": "联系", "D": "主键"}', 'C', 'E-R 图: 矩形=实体,椭圆=属性,菱形=联系', 2.00, 2, 116),
(3576, 108, 1, '关系模型中,二维表的行称为', '{"A": "记录", "B": "元组", "C": "字段", "D": "属性"}', 'B', '关系模型中行=元组', 2.00, 2, 116),
(3577, 108, 1, '关系模型中,二维表的列称为', '{"A": "记录", "B": "元组", "C": "属性", "D": "主键"}', 'C', '关系模型中列=属性', 2.00, 2, 116),
(3578, 108, 1, '下列哪个是关系模型必须满足的', '{"A": "表中不能有重复行", "B": "行序无关", "C": "列序无关", "D": "以上都对"}', 'D', '关系: 不重复元组,行列序均无关', 2.00, 2, 116),
(3579, 108, 1, '关系模式 R(A,B,C) 的属性数称为', '{"A": "元数", "B": "度数", "C": "基数", "D": "阶数"}', 'B', '属性数称为度(degree)', 2.00, 3, 116),
(3580, 108, 1, '关系中能唯一标识元组的属性集称为', '{"A": "候选键", "B": "主键", "C": "外键", "D": "超键"}', 'A', '候选键: 能唯一标识的最小属性集', 2.00, 2, 116),
(3581, 108, 1, '下列说法不正确的是', '{"A": "主键必须唯一", "B": "主键不能为 NULL", "C": "主键可以由多个属性组成", "D": "外键不能为 NULL"}', 'D', '外键可以为 NULL', 2.00, 2, 116),
(3582, 108, 1, '参照完整性约束是指', '{"A": "主键不能为空", "B": "外键值必须是被参照表主键值或 NULL", "C": "属性值在域中", "D": "以上都不"}', 'B', '外键值必须存在或 NULL', 2.00, 2, 116),
(3583, 108, 1, '实体完整性约束是指', '{"A": "主键非空且唯一", "B": "外键约束", "C": "域约束", "D": "用户自定义"}', 'A', '实体完整性:主键非空+唯一', 2.00, 2, 116),
(3584, 108, 1, '下列不属于完整性约束的是', '{"A": "实体完整性", "B": "参照完整性", "C": "用户自定义完整性", "D": "索引完整性"}', 'D', '三类:实体、参照、用户自定义', 2.00, 2, 116),
(3585, 108, 1, '关系代数中,基本运算包括', '{"A": "并、差、笛卡尔积、选择、投影", "B": "并、交、差、连接", "C": "选择、投影、连接、并", "D": "并、交、笛卡尔积、连接"}', 'A', '5 个基本运算:∪、-、×、σ、π', 2.00, 3, 116),
