(3676, 108, 2, '下列属于索引类型', '{"A": "B+ 树", "B": "哈希", "C": "全文", "D": "位图"}', 'ABCD', '常见索引', 3.00, 2, 116),
(3677, 108, 2, '下列哪种情况适合建索引', '{"A": "查询频繁的列", "B": "WHERE 子句中的列", "C": "JOIN 关联列", "D": "ORDER BY 列"}', 'ABCD', '常见索引候选', 3.00, 2, 116),
