(3679, 108, 2, '数据库恢复的技术包括', '{"A": "数据备份", "B": "日志", "C": "检查点", "D": "镜像"}', 'ABCD', '恢复技术多种', 3.00, 2, 116),
(3680, 108, 2, '数据库故障类型包括', '{"A": "事务故障", "B": "系统故障", "C": "介质故障", "D": "程序错误"}', 'ABC', '三类典型故障', 3.00, 2, 116),
