(3683, 108, 2, '下列哪些是 SQL 注入的防御方式', '{"A": "参数化查询", "B": "存储过程", "C": "ORM 框架", "D": "白名单校验"}', 'ABCD', 'SQL 注入防御', 3.00, 3, 116),
