(3692, 108, 3, '关系中允许属性出现重复值', NULL, '正确', '属性值可重复(行不重复)', 1.00, 2, 116),
(3693, 108, 3, '主键不允许为 NULL', NULL, '正确', '主键非空且唯一', 1.00, 1, 116),
(3694, 108, 3, '外键可以为 NULL', NULL, '正确', '外键允许 NULL', 1.00, 2, 116),
(3695, 108, 3, 'SQL 中 NULL 与 NULL 比较的结果是 TRUE', NULL, '错误', 'NULL 比较返回 UNKNOWN', 1.00, 3, 116),
(3696, 108, 3, 'SELECT * FROM 表名 等价于 SELECT 所有列 FROM 表名', NULL, '正确', '* 代表所有列', 1.00, 1, 116),
(3697, 108, 3, 'WHERE 子句可以使用聚合函数', NULL, '错误', '聚合函数应使用在 HAVING 子句', 1.00, 2, 116),
(3698, 108, 3, 'HAVING 子句必须与 GROUP BY 一起使用', NULL, '错误', 'HAVING 可以单独使用(虽不常见)', 1.00, 3, 116),
(3699, 108, 3, 'UNION 默认会去除重复行', NULL, '正确', 'UNION 默认去重,UNION ALL 不去重', 1.00, 2, 116),
