(3702, 108, 3, '所有视图都可以执行 INSERT/UPDATE', NULL, '错误', '含聚合/连接等的视图不可更新', 1.00, 3, 116),
(3703, 108, 3, '索引可以无限制建立,数量越多查询越快', NULL, '错误', '过多索引增加维护成本', 1.00, 2, 116),
(3704, 108, 3, 'B+ 树索引在范围查询时性能优于哈希索引', NULL, '正确', '哈希不支持范围', 1.00, 2, 116),
(3705, 108, 3, '聚集索引每张表只能有一个', NULL, '正确', '聚集索引决定物理顺序', 1.00, 2, 116),
(3706, 108, 3, '2NF 一定满足 1NF', NULL, '正确', '范式之间是包含关系', 1.00, 2, 116),
(3707, 108, 3, '3NF 一定满足 2NF', NULL, '正确', '范式包含关系', 1.00, 2, 116),
(3708, 108, 3, 'BCNF 严格于 3NF', NULL, '正确', 'BCNF 是更严格的形式', 1.00, 3, 116),
(3709, 108, 3, '所有关系模式都可分解到 BCNF 且保持函数依赖', NULL, '错误', 'BCNF 不一定保持依赖,3NF 可保持', 1.00, 3, 116),
(3710, 108, 3, '事务的原子性指事务要么全部完成,要么全部回滚', NULL, '正确', '原子性 atomicity', 1.00, 2, 116),
(3711, 108, 3, 'SERIALIZABLE 是最低的隔离级别', NULL, '错误', 'SERIALIZABLE 最高,READ UNCOMMITTED 最低', 1.00, 2, 116),
(3712, 108, 3, '脏读发生在 READ UNCOMMITTED 隔离级别', NULL, '正确', '只有 READ UNCOMMITTED 允许脏读', 1.00, 2, 116),
(3713, 108, 3, 'REPEATABLE READ 可以避免幻读', NULL, '错误', 'RR 不能完全避免幻读(MySQL InnoDB 例外通过 next-key lock)', 1.00, 3, 116),
(3714, 108, 3, '共享锁 S 锁与共享锁兼容', NULL, '正确', 'S 锁可并发', 1.00, 2, 116),
(3715, 108, 3, '排他锁 X 锁与任何锁都不兼容', NULL, '正确', 'X 锁互斥', 1.00, 2, 116),
(3716, 108, 3, '死锁可以通过超时检测自动解除', NULL, '正确', '超时是常见死锁处理方式', 1.00, 2, 116),
(3717, 108, 3, 'COMMIT 后事务不可以回滚', NULL, '正确', 'COMMIT 持久化', 1.00, 2, 116),
(3718, 108, 3, 'SAVEPOINT 可以让事务回滚到指定点', NULL, '正确', 'SAVEPOINT 实现部分回滚', 1.00, 3, 116),
(3719, 108, 3, 'UNDO 日志用于重做已提交事务', NULL, '错误', 'UNDO 撤销未提交;REDO 重做已提交', 1.00, 2, 116),
(3720, 108, 3, '数据库恢复的关键技术是日志和备份', NULL, '正确', '日志+备份是恢复基础', 1.00, 2, 116),
(3721, 108, 3, 'SQL 注入的根本原因是字符串拼接', NULL, '正确', '参数化查询根治', 1.00, 2, 116),
(3722, 108, 3, 'MongoDB 是关系数据库', NULL, '错误', 'MongoDB 是文档型 NoSQL', 1.00, 1, 116),
(3723, 108, 3, 'Redis 是内存型键值数据库', NULL, '正确', 'Redis 是 KV 内存数据库', 1.00, 1, 116),
(3724, 108, 3, '数据库的三级模式与二级映射保证数据独立性', NULL, '正确', '三级模式两层映射保证独立性', 1.00, 2, 116),
(3725, 108, 3, '存储过程可以减少网络流量', NULL, '正确', '只发调用语句,不发完整 SQL', 1.00, 2, 116),
(3726, 108, 3, '触发器可以修改其触发的表', NULL, '正确', '但需注意避免递归调用', 1.00, 3, 116),
(3727, 108, 4, '数据库管理系统的英文缩写是____', NULL, 'DBMS', 'DBMS=Database Management System', 2.00, 1, 116),
(3728, 108, 4, '数据库系统的三级模式是____、模式、内模式', NULL, '外模式', '三级模式中,外模式是用户视图', 2.00, 2, 116),
(3729, 108, 4, '数据独立性包括物理独立性和____', NULL, '逻辑独立性', '逻辑独立性指逻辑结构变化不影响用户', 2.00, 2, 116),
(3730, 108, 4, 'E-R 图中,矩形表示____', NULL, '实体', 'E-R 图: 矩形=实体,椭圆=属性,菱形=联系', 2.00, 2, 116),
(3731, 108, 4, '关系模型中,二维表的行称为____', NULL, '元组', '行=元组(tuple)', 2.00, 2, 116),
(3732, 108, 4, 'SQL 中创建表的语句是____', NULL, 'CREATE TABLE', 'DDL 中 CREATE TABLE', 2.00, 1, 116),
(3733, 108, 4, 'SQL 中删除表的语句是____', NULL, 'DROP TABLE', 'DROP TABLE 表名', 2.00, 1, 116),
(3734, 108, 4, 'SQL 中修改表结构的语句是____', NULL, 'ALTER TABLE', 'ALTER TABLE 表名 ADD/DROP/MODIFY', 2.00, 1, 116),
(3735, 108, 4, 'SQL 中查询数据的语句是____', NULL, 'SELECT', 'SELECT 是 DQL 的核心', 2.00, 1, 116),
(3736, 108, 4, 'SQL 中插入数据的语句是____', NULL, 'INSERT', 'INSERT INTO 表 VALUES', 2.00, 1, 116),
(3737, 108, 4, 'SQL 中修改数据的语句是____', NULL, 'UPDATE', 'UPDATE 表 SET 列=值 WHERE 条件', 2.00, 1, 116),
(3738, 108, 4, 'SQL 中删除数据的语句是____', NULL, 'DELETE', 'DELETE FROM 表 WHERE 条件', 2.00, 1, 116),
(3739, 108, 4, '聚合函数中计算行数的是____', NULL, 'COUNT', 'COUNT(*) 或 COUNT(列名)', 2.00, 1, 116),
(3740, 108, 4, '按列分组使用____子句', NULL, 'GROUP BY', 'GROUP BY 列名', 2.00, 1, 116),
(3741, 108, 4, '对分组结果进行过滤使用____子句', NULL, 'HAVING', 'HAVING 接聚合函数', 2.00, 2, 116),
(3742, 108, 4, '关系代数中选择运算符号是____', NULL, 'σ', 'σ表示选择 selection', 2.00, 3, 116),
(3743, 108, 4, '关系代数中投影运算符号是____', NULL, 'π', 'π表示投影 projection', 2.00, 3, 116),
(3744, 108, 4, '关系代数中连接运算符号是____', NULL, '⋈', '⋈表示连接 join', 2.00, 3, 116),
(3745, 108, 4, '属性不可再分的范式是____', NULL, '1NF', '1NF: 原子性', 2.00, 2, 116),
(3746, 108, 4, '消除非主属性对码的部分依赖的范式是____', NULL, '2NF', '2NF', 2.00, 3, 116),
(3747, 108, 4, '消除传递依赖的范式是____', NULL, '3NF', '3NF', 2.00, 3, 116),
(3748, 108, 4, '事务的 4 个特性是 ACID,即原子性、____、隔离性、持久性', NULL, '一致性', 'ACID: Consistency', 2.00, 2, 116),
(3749, 108, 4, 'SQL 标准的 4 种事务隔离级别中最高级是____', NULL, 'SERIALIZABLE', 'SERIALIZABLE 串行化', 2.00, 2, 116),
(3750, 108, 4, '解决脏读最简单的方式是设置隔离级别为____或更高', NULL, 'READ COMMITTED', 'RC 不允许读未提交', 2.00, 2, 116),
(3751, 108, 4, 'B+ 树索引的高度通常为____层', NULL, '3', 'B+ 树高度通常 3-4 层', 2.00, 2, 116),
(3752, 108, 4, '并发控制的主要技术是____', NULL, '封锁', '封锁(locking)是主要并发控制', 2.00, 2, 116),
(3753, 108, 4, '死锁的四个必要条件:互斥、占有等待、非抢占、____', NULL, '循环等待', '死锁四条件', 2.00, 3, 116),
(3754, 108, 4, '数据库的故障类型有事务故障、系统故障和____', NULL, '介质故障', '三类故障', 2.00, 2, 116),
(3755, 108, 4, '用于撤销未提交事务的日志称为____日志', NULL, 'UNDO', 'UNDO 日志', 2.00, 2, 116),
(3756, 108, 4, '用于重做已提交事务的日志称为____日志', NULL, 'REDO', 'REDO 日志', 2.00, 2, 116),
(3757, 108, 5, '简述数据库系统的三级模式结构', NULL, '三级模式由外模式、模式、内模式构成:1)外模式即用户视图,描述用户能看到的数据子集;2)模式即逻辑模式,描述整个数据库的逻辑结构;3)内模式描述数据在物理介质上的存储方式。三级模式之间通过外模式-模式映射和模式-内模式映射保证数据独立性。', '数据库教材标准题', 5.00, 2, 116),
(3758, 108, 5, '简述数据独立性的含义', NULL, '数据独立性是指应用程序与数据库结构之间相互独立的能力,包括:1)逻辑独立性:数据库逻辑结构变化时不需修改应用程序,由外模式-模式映射保证;2)物理独立性:数据库物理存储变化时不需修改逻辑结构,由模式-内模式映射保证。', '核心概念', 5.00, 2, 116),
(3759, 108, 5, '简述关系模型的三类完整性约束', NULL, '1)实体完整性:主键非空且唯一,保证元组唯一可标识;2)参照完整性:外键值必须是被参照表主键值或 NULL,保证表间引用一致;3)用户自定义完整性:满足业务规则的约束,如年龄>0、性别只能为男/女等。', '三类完整性', 5.00, 2, 116),
(3760, 108, 5, '简述 1NF、2NF、3NF、BCNF 的关系和要求', NULL, '1NF:属性不可再分(原子性);2NF:在 1NF 基础上,消除非主属性对码的部分函数依赖;3NF:在 2NF 基础上,消除非主属性对码的传递函数依赖;BCNF:在 3NF 基础上,要求所有函数依赖的左部都包含候选键。包含关系:BCNF⊂3NF⊂2NF⊂1NF。', '范式核心题', 5.00, 3, 116),
(3761, 108, 5, '简述事务的 ACID 特性', NULL, '事务的 4 个特性:1)Atomicity 原子性:事务要么全部完成,要么全部回滚;2)Consistency 一致性:事务执行前后数据库保持一致状态;3)Isolation 隔离性:并发事务之间相互不可见;4)Durability 持久性:事务提交后修改永久保存。', 'ACID 必背', 5.00, 2, 116),
(3762, 108, 5, '简述事务的 4 个隔离级别及对应的并发问题', NULL, '1)READ UNCOMMITTED:可能脏读、不可重复读、幻读;2)READ COMMITTED:解决脏读,仍可能不可重复读、幻读;3)REPEATABLE READ:解决脏读和不可重复读,仍可能幻读;4)SERIALIZABLE:全部解决,串行执行,性能最低。', '并发控制经典题', 5.00, 3, 116),
(3763, 108, 5, '简述脏读、不可重复读和幻读的区别', NULL, '1)脏读:事务读到另一未提交事务的修改;2)不可重复读:同一事务两次读同一行结果不同(其他事务 UPDATE 了);3)幻读:同一事务用相同条件多次查询,行数发生变化(其他事务 INSERT/DELETE 了)。三者层次递进,根本区别在于操作类型(脏数据 vs 修改 vs 新增)。', '并发问题对比', 5.00, 3, 116),
(3764, 108, 5, '简述死锁产生的 4 个必要条件', NULL, '1)互斥:资源不能同时被多个事务使用;2)占有等待:事务持有资源同时等待另一资源;3)非抢占:资源不能被强制剥夺;4)循环等待:存在事务等待环路 T1→T2→...→Tn→T1。四条件同时满足才会死锁。', '死锁四条件', 5.00, 3, 116),
(3765, 108, 5, '简述两阶段封锁协议 2PL', NULL, '2PL 把事务分为两个阶段:1)加锁阶段(Growing Phase):事务可以申请任何锁,但不能释放任何锁;2)解锁阶段(Shrinking Phase):事务释放锁后,不能再申请任何锁。遵守 2PL 保证可串行化调度,是并发控制的基础。', '2PL 经典题', 5.00, 3, 116),
(3766, 108, 5, '简述 B+ 树索引和哈希索引的区别', NULL, '1)结构:B+ 树是平衡多叉树,哈希是哈希表;2)查询:B+ 树支持范围+点查询,哈希仅支持等值;3)排序:B+ 树有序遍历,哈希无序;4)冲突:B+ 树无冲突,哈希需处理冲突;5)应用:大多数关系型 DB 默认 B+ 树,Memcached/MongoDB 用哈希。', '两类索引对比', 5.00, 2, 116),
(3767, 108, 5, '简述聚集索引和非聚集索引的区别', NULL, '1)聚集索引:索引的叶子节点是数据本身,数据按索引顺序物理存储,每表只能有 1 个;2)非聚集索引:索引的叶子节点是数据指针,可以建多个;3)查询:聚集索引点查询快,非聚集索引需回表;4)更新代价:聚集索引更新成本高(数据移动)。', '索引核心', 5.00, 3, 116),
(3768, 108, 5, '简述视图的优缺点', NULL, '优点:1)简化复杂查询;2)隐藏数据,提高安全性(只暴露需要列);3)逻辑独立性,基表变化视图可不变;4)多角度展示同一数据。缺点:1)性能可能下降(每次查询都执行底层 SQL);2)更新受限(含聚合/连接的视图不能更新);3)维护复杂。', '视图优缺点', 5.00, 2, 116),
(3769, 108, 5, '简述存储过程的优缺点', NULL, '优点:1)预编译执行效率高;2)可重用,减少代码冗余;3)减少网络流量,只传调用语句;4)封装业务逻辑,便于维护;5)安全性高,可控制权限。缺点:1)调试困难;2)不易移植(各 DB 语法不同);3)版本控制弱;4)性能调优受限。', '存储过程优缺点', 5.00, 2, 116),
(3770, 108, 5, '简述数据库恢复的基本技术', NULL, '数据库恢复主要靠 1)数据备份:定期完全/增量/差异备份,故障后从备份恢复;2)日志记录:记录事务的 redo/undo 信息,故障后通过日志重做或撤销;3)检查点机制:周期性写入检查点,加快恢复速度;4)镜像/复制:实时同步副本,故障时切换。', '数据库恢复', 5.00, 3, 116),
(3771, 108, 5, '简述关系代数中的连接运算', NULL, '连接运算从两关系的笛卡尔积中选取属性间满足条件的元组:1)θ-连接:满足条件 θ 的元组(σ(R×S));2)等值连接:θ 为等值 (=);3)自然连接:在同名属性上等值连接并去重;4)外连接:左外、右外、全外,保留不匹配元组并填 NULL。', '连接运算', 5.00, 3, 116),
(3772, 108, 5, '简述 SQL 注入的原理与防御', NULL, '原理:应用拼接用户输入到 SQL 字符串中,攻击者构造特殊输入修改 SQL 语义,例如 '' OR 1=1 --。防御:1)参数化查询(PreparedStatement),根治;2)ORM 框架(MyBatis #{}/JPA);3)严格输入校验+白名单;4)最小权限原则(应用 DB 用户只授必要权限);5)避免反馈详细 SQL 错误。', 'SQL 注入防御', 5.00, 2, 116),
(3773, 108, 5, '简述关系数据库与 NoSQL 数据库的区别', NULL, '关系数据库:1)结构化二维表;2)ACID 强一致;3)SQL 标准查询;4)适合事务、复杂查询;5)代表:MySQL、Oracle。NoSQL:1)灵活数据结构(KV/文档/列/图);2)BASE 弱一致;3)无统一查询语言;4)适合海量数据、高并发、灵活模式;5)代表:Redis、MongoDB、HBase、Neo4j。', 'RDBMS vs NoSQL', 5.00, 2, 116),
(3774, 108, 5, '简述 E-R 图到关系模型的转换规则', NULL, '1)每个实体集对应一个关系,实体属性=关系属性,实体码=关系主键;2)1:1 联系:可合并到任一端实体,或单独建关系;3)1:n 联系:n 端加上 1 端的主键作为外键;4)m:n 联系:必须单独建关系,主键由两端主键组成,加上联系属性;5)弱实体:用强实体主键+部分主键作为联合主键。', 'E-R 转换', 5.00, 3, 116),
(3775, 108, 5, '简述数据库设计的步骤', NULL, '数据库设计的 6 阶段:1)需求分析:调研用户需求,数据流图、数据字典;2)概念结构设计:用 E-R 图建立独立于 DBMS 的概念模型;3)逻辑结构设计:转换为具体 DBMS 支持的逻辑模型(如关系模型),规范化;4)物理结构设计:索引、分区、存储路径;5)数据库实施:建库、加载数据、编写应用;6)运行维护。', 'DB 设计 6 步', 5.00, 2, 116),
(3776, 108, 5, '简述索引使用的场景与代价', NULL, '适合建索引:1)频繁查询的列;2)WHERE/JOIN/ORDER BY/GROUP BY 中的列;3)高基数(选择性好)的列;4)外键列。不适合:1)低基数列(性别等);2)频繁更新列;3)小表;4)很少查询的列。代价:1)占空间;2)增删改维护成本;3)优化器选错可能反而慢。要综合 cost-benefit 评估。', '索引使用', 5.00, 2, 116);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(3777, 109, 1, 'Java中，所有类的根类是', '{"A": "Object", "B": "Class", "C": "String", "D": "System"}', 'A', 'java.lang.Object是所有Java类的基类', 2.00, 1, 117),
(3778, 109, 1, '以下哪个关键字用于实现接口', '{"A": "extends", "B": "implements", "C": "abstract", "D": "interface"}', 'B', 'implements用于类实现接口', 2.00, 1, 117),
(3779, 109, 1, 'Java中String类是', '{"A": "可变的", "B": "不可变的", "C": "基本类型", "D": "抽象类"}', 'B', 'String是不可变类，一旦创建不可修改', 2.00, 1, 117),
(3780, 109, 1, '以下哪种集合是线程安全的', '{"A": "ArrayList", "B": "HashMap", "C": "Vector", "D": "LinkedList"}', 'C', 'Vector是线程安全的，ArrayList不是', 3.00, 2, 117),
(3781, 109, 1, 'Java异常处理中，finally块的作用是', '{"A": "捕获异常", "B": "抛出异常", "C": "无论是否异常都执行", "D": "定义异常类"}', 'C', 'finally块中的代码无论是否发生异常都会执行', 2.00, 1, 117),
(3782, 109, 2, 'Java中面向对象的三大特性包括', '{"A": "封装", "B": "继承", "C": "多态", "D": "抽象"}', 'ABC', '面向对象三大特性是封装、继承、多态。抽象是重要概念但不属于三大特性', 3.00, 2, 117),
(3783, 109, 2, '以下关于Java接口的说法正确的有', '{"A": "接口中的方法默认是public abstract", "B": "接口可以包含常量", "C": "一个类可以实现多个接口", "D": "接口可以实例化"}', 'ABC', '接口不能直接实例化', 3.00, 2, 117),
(3784, 109, 3, 'Java支持多重继承', NULL, '错误', 'Java不支持多重继承(一个类只能有一个父类)，但支持多接口实现', 2.00, 1, 117),
(3785, 109, 3, '抽象类可以有构造方法', NULL, '正确', '抽象类可以有构造方法，供子类调用', 2.00, 2, 117),
(3786, 109, 4, 'Java中用于定义常量的关键字是____', NULL, 'final', 'final修饰变量使其成为常量', 2.00, 1, 117),
(3787, 109, 4, 'Java集合框架中，List接口的两个常用实现类是ArrayList和____', NULL, 'LinkedList', 'ArrayList基于数组，LinkedList基于链表', 2.00, 1, 117),
(3788, 109, 5, '请解释Java中重载(Overload)和重写(Override)的区别', NULL, '重载：同一个类中方法名相同但参数列表不同（参数类型、个数或顺序不同），返回类型可以不同。重写：子类重新定义父类中已有的方法，方法名、参数列表、返回类型必须相同，访问权限不能更严格。', '需要从定义位置、参数要求、返回类型等方面说明', 5.00, 2, 117),
(3789, 109, 5, '请说明ArrayList和LinkedList的区别及各自适用场景', NULL, 'ArrayList基于动态数组，随机访问快O(1)，插入删除慢O(n)，适合频繁查询的场景。LinkedList基于双向链表，随机访问慢O(n)，插入删除快O(1)，适合频繁增删的场景。', '从底层实现、性能特点和适用场景三个方面比较', 5.00, 2, 117),
(3790, 109, 1, 'Java中的垃圾回收机制由谁负责', '{"A": "程序员手动释放", "B": "JVM自动管理", "C": "操作系统管理", "D": "编译器管理"}', 'B', 'Java的垃圾回收(GC)由JVM自动管理', 2.00, 1, 117),
(3791, 109, 1, '下列哪项不是Java的基本数据类型', '{"A": "int", "B": "char", "C": "String", "D": "boolean"}', 'C', 'String是引用类型不是基本类型', 2.00, 1, 117),
(3792, 109, 1, 'Java中数组的长度通过什么获取', '{"A": "array.size()", "B": "array.length()", "C": "array.length", "D": "array.getLength()"}', 'C', '数组长度通过length属性获取', 2.00, 1, 117),
(3793, 109, 1, '下列哪个修饰符表示只能在本类中访问', '{"A": "public", "B": "protected", "C": "default", "D": "private"}', 'D', 'private限制为本类访问', 2.00, 1, 117),
(3794, 109, 1, 'Java中所有异常的父类是', '{"A": "Error", "B": "Exception", "C": "Throwable", "D": "RuntimeException"}', 'C', 'Throwable是所有异常和错误的父类', 2.00, 2, 117),
(3795, 109, 1, '下列哪个集合是有序且不可重复的', '{"A": "ArrayList", "B": "HashSet", "C": "TreeSet", "D": "HashMap"}', 'C', 'TreeSet有序且不重复', 2.00, 2, 117),
(3796, 109, 1, 'Java中创建线程的方式不包括', '{"A": "继承Thread类", "B": "实现Runnable接口", "C": "实现Callable接口", "D": "继承Process类"}', 'D', '没有继承Process类创建线程的方式', 2.00, 2, 117),
(3797, 109, 1, '下列哪个关键字用于定义接口', '{"A": "class", "B": "abstract", "C": "interface", "D": "implements"}', 'C', 'interface定义接口', 2.00, 1, 117),
(3798, 109, 1, 'Java中String对象一旦创建就不能修改这体现了String的', '{"A": "封装性", "B": "不可变性", "C": "多态性", "D": "继承性"}', 'B', 'String是不可变类', 2.00, 1, 117),
(3799, 109, 1, '下列哪个方法可以启动一个线程', '{"A": "run()", "B": "start()", "C": "execute()", "D": "init()"}', 'B', 'start()启动线程会自动调用run()', 2.00, 1, 117),
