(3801, 109, 1, '下列哪个不是Java的访问修饰符', '{"A": "public", "B": "private", "C": "protected", "D": "static"}', 'D', 'static是静态修饰符不是访问修饰符', 2.00, 1, 117),
(3802, 109, 1, 'HashMap和Hashtable的主要区别是', '{"A": "HashMap线程安全", "B": "Hashtable允许null键", "C": "HashMap允许null键Hashtable不允许", "D": "两者完全相同"}', 'C', 'HashMap允许null键值Hashtable不允许', 3.00, 2, 117),
