(3871, 109, 1, 'JDK、JRE、JVM 三者的关系正确的是', '{"A": "JDK ⊇ JRE ⊇ JVM", "B": "JRE ⊇ JDK ⊇ JVM", "C": "JVM ⊇ JRE ⊇ JDK", "D": "三者独立"}', 'A', 'JDK 包含 JRE,JRE 包含 JVM', 2.00, 2, 117),
