(4056, 109, 5, '简述 JDK、JRE、JVM 的区别和联系', NULL, '1)JVM 是 Java 虚拟机,负责执行字节码;2)JRE=JVM+核心类库,Java 程序运行所需的环境;3)JDK=JRE+开发工具(javac、jar、jdb 等),开发 Java 程序所需。包含关系:JDK ⊇ JRE ⊇ JVM。', '三者关系是高频题', 5.00, 2, 117),
(4057, 109, 5, '简述 Java 面向对象的三大特性', NULL, '1)封装:把数据和操作封装在类中,通过访问修饰符控制可见性,提高安全性和复用性;2)继承:子类继承父类的属性和方法,并可以重写,实现代码复用和扩展;3)多态:同一行为有不同实现,通过父类引用指向子类对象,实现运行时绑定。', 'OOP 三大特性', 5.00, 2, 117),
(4058, 109, 5, '简述方法重载和方法重写的区别', NULL, '重载(Overload):1)同一类中;2)方法名相同,参数列表不同(类型/个数/顺序);3)与返回值无关;4)编译时多态。重写(Override):1)子类与父类之间;2)方法签名(名+参)完全相同;3)返回类型可协变(子类型);4)访问修饰符不能更严格;5)运行时多态。', '重载 vs 重写', 5.00, 2, 117),
(4059, 109, 5, '简述抽象类和接口的区别', NULL, '1)关键字:abstract class vs interface;2)继承:类只能单继承抽象类,可以多实现接口;3)成员:抽象类可有普通方法和字段,接口默认 public abstract(Java8+ 可有 default/static);4)字段:接口字段默认 public static final;5)构造器:抽象类可有,接口不能;6)用途:抽象类表示 is-a,接口表示 has-a/can-do。', 'abstract vs interface', 5.00, 3, 117),
(4060, 109, 5, '简述 String、StringBuilder 和 StringBuffer 的区别', NULL, '1)String:不可变(final char[]),修改会创建新对象,大量拼接性能差;2)StringBuilder:可变,非线程安全,单线程性能最优;3)StringBuffer:可变,线程安全(synchronized 修饰),性能稍差。选用建议:1)少量拼接用 +/String;2)单线程大量拼接用 StringBuilder;3)多线程拼接用 StringBuffer。', '三者对比', 5.00, 2, 117),
(4061, 109, 5, '简述 == 和 equals 的区别', NULL, '1)==:基本类型比较值,引用类型比较地址(内存中是否同一对象);2)equals:Object 默认实现是 ==,但通常被重写为比较内容(如 String.equals 比较字符序列);3)使用建议:基本类型用 ==,对象用 equals 比较内容。注意 NPE:obj.equals 可能 NPE,Objects.equals 安全。', '来源：Java程序设计.xlsx', 5.00, 2, 117),
(4062, 109, 5, '简述 Java 集合框架的体系结构', NULL, 'Java 集合分两大体系:1)Collection(单列):①List(有序可重复)→ArrayList、LinkedList、Vector;②Set(无序不重复)→HashSet、TreeSet、LinkedHashSet;③Queue(队列)→ArrayDeque、LinkedList。2)Map(双列):HashMap、TreeMap、LinkedHashMap、ConcurrentHashMap、Hashtable。Iterator 用于遍历集合。', '集合体系', 5.00, 2, 117),
(4063, 109, 5, '简述 ArrayList 和 LinkedList 的区别', NULL, '1)底层结构:ArrayList=动态数组,LinkedList=双向链表;2)随机访问:ArrayList O(1),LinkedList O(n);3)插入删除:中间位置 ArrayList O(n)需移动元素,LinkedList O(1)只需改指针;4)内存:ArrayList 紧凑,LinkedList 每节点额外存指针;5)使用:多读取用 ArrayList,频繁中部插入用 LinkedList。', 'ArrayList vs LinkedList', 5.00, 2, 117),
(4064, 109, 5, '简述 HashMap 的实现原理', NULL, '1)JDK 7:数组+链表,通过 hash(key)%length 定位桶,冲突时链表;2)JDK 8 优化:数组+链表+红黑树,链表长度>8 转红黑树,降低查询时间到 O(logn);3)默认容量 16,负载因子 0.75,达到阈值扩容(2 倍);4)非线程安全,并发用 ConcurrentHashMap;5)允许 null 键值(各 1)。', 'HashMap 实现', 5.00, 3, 117),
(4065, 109, 5, '简述 HashMap 和 ConcurrentHashMap 的区别', NULL, '1)线程安全:HashMap 不安全,CHM 安全;2)实现:HashMap=数组+链表+红黑树,CHM=同结构+CAS+synchronized(JDK7 是 Segment 分段锁);3)性能:CHM 在并发下性能更好;4)null 键值:HashMap 允许 null,CHM 不允许;5)使用场景:单线程用 HashMap,多线程用 CHM。', 'HashMap vs CHM', 5.00, 3, 117),
(4066, 109, 5, '简述 Java 异常体系', NULL, 'Java 异常体系顶层是 Throwable,分两大类:1)Error:严重错误,如 OutOfMemoryError、StackOverflowError,程序无法处理;2)Exception:可处理异常,分两类:①受检异常(checked):IOException、SQLException 等,必须捕获或抛出;②运行时异常(unchecked,RuntimeException):NPE、ArrayIndexOutOfBounds 等,无需显式声明。', '异常体系', 5.00, 2, 117),
(4067, 109, 5, '简述创建线程的几种方式及优缺点', NULL, '1)继承 Thread:简单,但 Java 单继承,资源共享不方便;2)实现 Runnable:推荐,可避免单继承限制,易共享资源,但无返回值无异常;3)实现 Callable:有返回值,可抛异常,配合 FutureTask 使用;4)线程池(Executors/ThreadPoolExecutor):推荐生产使用,可复用、控制并发数。', '创建线程方式', 5.00, 2, 117),
(4068, 109, 5, '简述 synchronized 和 Lock 的区别', NULL, '1)实现:synchronized 是 JVM 关键字,Lock 是 JUC 接口;2)释放:synchronized 自动释放(异常/方法结束),Lock 必须 finally 显式 unlock;3)中断:synchronized 不可中断,Lock.lockInterruptibly 可中断;4)公平性:synchronized 非公平,Lock 可指定公平/非公平;5)条件:Lock 可有多个 Condition,synchronized 只有一个等待队列。', 'sync vs Lock', 5.00, 3, 117),
(4069, 109, 5, '简述 volatile 关键字的作用', NULL, 'volatile 提供两点保证:1)可见性:写入立即刷新到主内存,读取直接从主内存读,避免线程缓存导致的脏读;2)有序性:禁止指令重排序(通过内存屏障)。但注意:volatile 不保证原子性(如 i++ 不安全)。典型场景:状态标志、双重检查锁(DCL)中的 instance 字段。', 'volatile 三特性', 5.00, 3, 117),
(4070, 109, 5, '简述 ThreadLocal 的原理和应用场景', NULL, '原理:每个 Thread 有一个 ThreadLocalMap,key 是 ThreadLocal 对象,value 是数据。每个线程独立访问自己的副本,实现线程隔离。应用:1)用户上下文(UserContext);2)数据库连接;3)事务管理;4)SimpleDateFormat 线程安全使用。注意:必须 remove() 防止内存泄漏(尤其在线程池中)。', 'ThreadLocal 高频题', 5.00, 3, 117),
(4071, 109, 5, '简述 JVM 内存结构', NULL, 'JVM 五大内存区域:1)程序计数器(PC):线程私有,记录当前字节码地址;2)虚拟机栈:线程私有,存方法栈帧(局部变量、操作数栈、动态链接、返回地址);3)本地方法栈:线程私有,native 方法用;4)堆:线程共享,对象实例,GC 主要区域;5)方法区(JDK 8+ 元空间):线程共享,类元数据、常量池、静态变量。', 'JVM 内存', 5.00, 3, 117),
(4072, 109, 5, '简述 GC 算法', NULL, '1)标记-清除:标记后清除,缺点是产生碎片;2)复制算法:把存活对象复制到另一区域,无碎片但浪费空间,新生代用;3)标记-整理:标记后将存活对象向一端移动,无碎片不浪费,老年代用;4)分代收集:基于''对象朝生夕灭''假说,新生代用复制,老年代用标记-整理。GC 收集器:Serial、Parallel、CMS、G1、ZGC 等。', 'GC 算法', 5.00, 3, 117),
(4073, 109, 5, '简述 JVM 类加载过程', NULL, '类加载 7 阶段:1)加载(Loading):查找并读取 .class 文件到内存,生成 Class 对象;2)验证(Verification):校验字节码格式合法;3)准备(Preparation):为静态变量分配内存,赋默认值;4)解析(Resolution):符号引用转直接引用;5)初始化(Initialization):执行 <clinit>,真正赋值;6)使用;7)卸载。其中验证、准备、解析合称连接。', '类加载过程', 5.00, 3, 117),
(4074, 109, 5, '简述双亲委派模型及其作用', NULL, '双亲委派:类加载请求先委派给父类加载器,父类无法加载才由自己加载。三层结构:Bootstrap(根)→Extension(扩展)→Application(应用)。作用:1)避免类重复加载;2)防止核心类被篡改(如自定义 java.lang.String 不会生效);3)保证类的唯一性。打破双亲委派的场景:JDBC 驱动、JNDI、Tomcat WebappClassLoader。', '双亲委派', 5.00, 3, 117),
(4075, 109, 5, '简述 Java 8 的主要新特性', NULL, '1)Lambda 表达式:简化函数式接口实例化;2)Stream API:集合的函数式操作(filter/map/reduce);3)接口默认方法和静态方法:接口可有方法体;4)Optional:防 NPE;5)新日期时间 API(java.time):替换 Date/Calendar;6)函数式接口(Function/Predicate/Consumer/Supplier);7)方法引用 Class::method;8)Nashorn JS 引擎(JDK 11 移除)。', 'Java 8 新特性', 5.00, 2, 117);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(4076, 110, 1, '软件开发生命周期中，需求分析阶段的主要任务是', '{"A": "编写代码", "B": "确定用户需求", "C": "系统测试", "D": "系统部署"}', 'B', '需求分析阶段的核心任务是明确用户需要什么', 2.00, 1, 118),
(4077, 110, 1, '瀑布模型的特点是', '{"A": "迭代开发", "B": "阶段顺序执行", "C": "快速原型", "D": "并行开发"}', 'B', '瀑布模型是线性顺序的开发模型，各阶段依次执行', 2.00, 1, 118),
(4078, 110, 1, 'UML中用于描述系统功能的图是', '{"A": "类图", "B": "用例图", "C": "时序图", "D": "部署图"}', 'B', '用例图用于描述系统的功能需求和参与者', 2.00, 1, 118),
(4079, 110, 1, '黑盒测试关注的是', '{"A": "代码逻辑", "B": "程序内部结构", "C": "输入输出", "D": "代码覆盖率"}', 'C', '黑盒测试只关注输入输出，不考虑内部实现', 2.00, 1, 118),
(4080, 110, 1, '软件维护中，占工作量最大的是', '{"A": "纠错性维护", "B": "适应性维护", "C": "完善性维护", "D": "预防性维护"}', 'C', '完善性维护(扩充功能、提高性能)通常占60%以上', 3.00, 2, 118),
(4081, 110, 2, '敏捷开发的核心价值观包括', '{"A": "个体和互动高于流程和工具", "B": "工作的软件高于详尽的文档", "C": "客户合作高于合同谈判", "D": "遵循严格的计划"}', 'ABC', '敏捷开发强调响应变化而非遵循计划', 3.00, 2, 118),
(4082, 110, 2, '软件测试的方法包括', '{"A": "单元测试", "B": "集成测试", "C": "系统测试", "D": "验收测试"}', 'ABCD', '这四种都是软件测试的常见方法，按测试范围从小到大排列', 3.00, 2, 118),
(4083, 110, 3, '软件工程的目标是以较低的成本开发出高质量的软件', NULL, '正确', '软件工程追求在有限资源下开发高质量、可维护的软件', 2.00, 1, 118),
(4084, 110, 3, '白盒测试不需要了解程序内部结构', NULL, '错误', '白盒测试需要了解程序内部逻辑结构，根据代码进行测试', 2.00, 1, 118),
(4085, 110, 3, '面向对象设计中，高内聚低耦合是良好设计的标准', NULL, '正确', '高内聚低耦合可以提高模块的独立性和可维护性', 2.00, 1, 118),
(4086, 110, 4, '软件开发过程中，____文档是需求分析阶段的输出', NULL, '需求规格说明书', 'SRS(Software Requirements Specification)是需求分析的主要产物', 3.00, 2, 118),
(4087, 110, 4, 'UML中，用____图描述对象之间的交互顺序', NULL, '时序', '时序图(Sequence Diagram)描述对象间消息交互的时间顺序', 2.00, 1, 118),
(4088, 110, 5, '请比较瀑布模型和敏捷开发模型的优缺点', NULL, '瀑布模型：优点是文档完整、阶段清晰、易于管理；缺点是不适应需求变更、用户反馈滞后。敏捷开发：优点是快速响应变化、用户参与度高、交付频繁；缺点是文档不够完善、对团队能力要求高。', '需要分别说明两种模型的优缺点', 5.00, 2, 118),
(4089, 110, 5, '请解释什么是设计模式中的单例模式，并说明其应用场景', NULL, '单例模式确保一个类只有一个实例，并提供全局访问点。实现方式：私有构造方法+静态方法获取实例。应用场景：数据库连接池、线程池、配置文件管理、日志系统等。', '需要说明定义、实现要点和典型应用场景', 5.00, 3, 118),
(4090, 110, 1, '内聚度最高的是', '{"A": "偶然内聚", "B": "逻辑内聚", "C": "功能内聚", "D": "通信内聚"}', 'C', '功能内聚是最高级别的内聚，模块内所有元素共同完成一个功能', 3.00, 2, 118),
(4091, 110, 1, '软件工程的三要素是', '{"A": "方法、工具和过程", "B": "人员、工具和文档", "C": "需求、设计和测试", "D": "编码、调试和维护"}', 'A', '软件工程三要素方法工具过程', 2.00, 1, 118),
(4092, 110, 1, '需求分析阶段产生的主要文档是', '{"A": "概要设计说明书", "B": "详细设计说明书", "C": "软件需求规格说明书", "D": "测试计划"}', 'C', '需求分析输出SRS需求规格说明书', 2.00, 1, 118),
(4093, 110, 1, '结构化分析方法中数据流图的基本元素不包括', '{"A": "数据流", "B": "加工", "C": "数据存储", "D": "控制流"}', 'D', 'DFD基本元素为数据流加工数据存储外部实体', 2.00, 1, 118),
(4094, 110, 1, '耦合度最低的是', '{"A": "内容耦合", "B": "公共耦合", "C": "数据耦合", "D": "控制耦合"}', 'C', '数据耦合只传递数据耦合度最低', 2.00, 2, 118),
(4095, 110, 1, '下列哪种测试不属于黑盒测试', '{"A": "等价类划分", "B": "边界值分析", "C": "因果图", "D": "语句覆盖"}', 'D', '语句覆盖属于白盒测试', 2.00, 1, 118),
(4096, 110, 1, '软件维护中最常见的类型是', '{"A": "改正性维护", "B": "适应性维护", "C": "完善性维护", "D": "预防性维护"}', 'C', '完善性维护占比最大约50-60%', 2.00, 2, 118),
(4097, 110, 1, '面向对象设计中开闭原则是指', '{"A": "对扩展开放对修改关闭", "B": "对修改开放对扩展关闭", "C": "对继承开放对组合关闭", "D": "对抽象开放对具体关闭"}', 'A', 'OCP对扩展开放对修改关闭', 2.00, 2, 118),
(4098, 110, 1, '下列哪种模型适合需求不明确的项目', '{"A": "瀑布模型", "B": "原型模型", "C": "V模型", "D": "喷泉模型"}', 'B', '原型模型适合需求不明确的项目', 2.00, 1, 118),
(4099, 110, 1, 'McCabe复杂度度量的计算公式为V(G)=', '{"A": "E-N+1", "B": "E-N+2", "C": "N-E+1", "D": "N-E+2"}', 'B', 'V(G)=E-N+2 E边数N节点数', 3.00, 2, 118),
(4100, 110, 1, '统一建模语言UML中类图属于', '{"A": "结构图", "B": "行为图", "C": "交互图", "D": "实现图"}', 'A', '类图是UML的静态结构图', 2.00, 1, 118),
(4101, 110, 1, '软件项目管理中关键路径是指', '{"A": "最短路径", "B": "最长路径", "C": "最优路径", "D": "最简路径"}', 'B', '关键路径是项目中最长的路径', 2.00, 2, 118),
(4102, 110, 1, '下列哪个不是软件测试的原则', '{"A": "尽早测试", "B": "穷尽测试", "C": "独立测试", "D": "回归测试"}', 'B', '完全穷尽测试是不可能的', 2.00, 1, 118),
(4103, 110, 1, '敏捷开发中Scrum的迭代周期称为', '{"A": "Sprint", "B": "Release", "C": "Iteration", "D": "Phase"}', 'A', 'Scrum中的迭代叫Sprint冲刺', 2.00, 1, 118),
(4104, 110, 1, '软件配置管理的核心功能是', '{"A": "版本控制", "B": "需求管理", "C": "项目管理", "D": "质量管理"}', 'A', '配置管理核心是版本控制和变更控制', 2.00, 2, 118),
(4105, 110, 2, '软件开发生命周期的阶段包括', '{"A": "需求分析", "B": "系统设计", "C": "编码实现", "D": "测试维护"}', 'ABCD', '都是SDLC的阶段', 3.00, 1, 118),
(4106, 110, 2, '瀑布模型的特点有', '{"A": "阶段间有严格顺序", "B": "每个阶段有文档产出", "C": "不适合需求变化大的项目", "D": "支持迭代开发"}', 'ABC', '瀑布模型不支持迭代', 3.00, 1, 118),
(4107, 110, 2, '面向对象的基本特征包括', '{"A": "封装", "B": "继承", "C": "多态", "D": "抽象"}', 'ABCD', '面向对象四大特征', 3.00, 1, 118),
(4108, 110, 2, 'UML中的行为图包括', '{"A": "用例图", "B": "活动图", "C": "状态图", "D": "序列图"}', 'ABCD', '都属于UML行为图', 3.00, 2, 118),
(4109, 110, 2, '软件测试的方法有', '{"A": "单元测试", "B": "集成测试", "C": "系统测试", "D": "验收测试"}', 'ABCD', '都是软件测试的层次', 3.00, 1, 118),
(4110, 110, 2, '关于敏捷开发正确的有', '{"A": "强调个体和交互", "B": "可工作的软件优于文档", "C": "响应变化优于遵循计划", "D": "客户参与开发过程"}', 'ABCD', '都是敏捷宣言的核心价值', 3.00, 1, 118),
(4111, 110, 2, '软件设计的基本原则有', '{"A": "模块化", "B": "信息隐藏", "C": "高内聚低耦合", "D": "抽象"}', 'ABCD', '都是软件设计基本原则', 3.00, 1, 118),
(4112, 110, 2, '白盒测试的覆盖标准有', '{"A": "语句覆盖", "B": "判定覆盖", "C": "条件覆盖", "D": "路径覆盖"}', 'ABCD', '都是白盒测试覆盖标准', 3.00, 2, 118),
