(4356, 110, 5, '简述软件工程的定义和目标', NULL, '软件工程是应用计算机科学、数学和管理学等原理,以工程化的方法开发和维护软件的学科。三大目标:1)质量(Quality):满足功能和非功能需求,缺陷少;2)进度(Schedule):按时交付;3)成本(Cost):控制在预算内。三要素:方法、工具、过程。', 'SE 定义和目标', 5.00, 2, 118),
(4357, 110, 5, '简述软件危机及其表现', NULL, '软件危机指 1960s 末软件开发中遇到的一系列问题,1968 年 NATO 会议提出。表现:1)开发延期、成本超支;2)软件质量低下、缺陷多;3)需求变更难以响应;4)文档不完善、维护困难;5)项目失败率高。原因:软件复杂度增加、缺乏方法论、传统手工方式不适应。软件工程因此而诞生。', '软件危机', 5.00, 2, 118),
(4358, 110, 5, '简述瀑布模型及其优缺点', NULL, '瀑布模型把软件开发分为顺序的阶段:需求→分析→设计→编码→测试→维护,每个阶段完成后才进入下一阶段。优点:1)阶段清晰,文档完善;2)易于管理和监控;3)适合需求稳定的大型项目。缺点:1)线性、不适应变化;2)风险后置(测试在后);3)用户反馈晚;4)文档负担重。适合需求稳定、技术成熟的项目。', '瀑布模型', 5.00, 2, 118),
(4359, 110, 5, '简述敏捷开发的核心思想', NULL, '敏捷开发强调拥抱变化、快速反馈、客户协作。敏捷宣言四大价值观:1)个体和互动 高于 流程和工具;2)可工作的软件 高于 详尽的文档;3)客户协作 高于 合同谈判;4)响应变化 高于 遵循计划。核心实践:迭代式开发、持续反馈、自组织团队、可工作的软件、增量交付。代表方法:Scrum、XP、Kanban。', '敏捷开发', 5.00, 2, 118),
(4360, 110, 5, '简述 Scrum 框架', NULL, 'Scrum 是敏捷的轻量框架。1)三角色:Product Owner(产品负责人,管理 backlog)、Scrum Master(教练,移除障碍)、Development Team(开发团队);2)三工件:Product Backlog(产品列表)、Sprint Backlog(迭代列表)、Increment(增量产品);3)五事件:Sprint(迭代,2-4 周)、Sprint Planning、Daily Standup(每日站会)、Sprint Review、Sprint Retrospective(回顾)。', 'Scrum', 5.00, 3, 118),
(4361, 110, 5, '简述结构化设计的核心思想', NULL, '结构化设计(SD)以模块化为核心,把系统分解为相对独立的模块。设计目标:1)高内聚:模块内部紧密协作;2)低耦合:模块间松散关联。常用工具:结构图(SC)、HIPO 图。模块独立性是衡量设计质量的关键。结构化方法适合数据流明确、需求稳定的系统。OOP 出现后地位降低,但思想仍重要。', '结构化设计', 5.00, 2, 118),
(4362, 110, 5, '简述模块的内聚和耦合', NULL, '内聚:模块内部各成分关联程度,从弱到强:1)巧合内聚;2)逻辑内聚;3)时间内聚;4)过程内聚;5)通信内聚;6)顺序内聚;7)功能内聚(最强)。耦合:模块间联系程度,从弱到强:1)数据耦合(最好);2)标记耦合;3)控制耦合;4)外部耦合;5)公共耦合;6)内容耦合(最差)。设计目标:高内聚、低耦合。', '内聚耦合', 5.00, 3, 118),
(4363, 110, 5, '简述面向对象的三大特性', NULL, '1)封装(Encapsulation):把数据和操作封装在类中,通过访问修饰符隐藏内部实现,只提供公共接口。优点:安全性、易维护;2)继承(Inheritance):子类继承父类属性和方法,实现代码复用,可重写父类方法;3)多态(Polymorphism):同一接口有不同实现,通过父类引用指向子类对象,运行时动态绑定。三大特性使 OOP 具有更好的复用性、扩展性。', 'OOP 三特性', 5.00, 2, 118),
(4364, 110, 5, '简述 SOLID 设计原则', NULL, 'SOLID 是 5 条 OOP 设计原则:1)单一职责(SRP):一个类只有一个变化的原因;2)开闭原则(OCP):对扩展开放,对修改关闭;3)里氏替换(LSP):子类必须能替换父类而不影响程序正确性;4)接口隔离(ISP):不应强迫客户依赖不需要的接口,接口要小;5)依赖倒置(DIP):高层模块不应依赖低层模块,都应依赖抽象。提高代码的可维护性、可扩展性。', 'SOLID', 5.00, 3, 118),
(4365, 110, 5, '简述 UML 主要图形分类', NULL, 'UML 图分两类:1)静态图(描述结构):①类图:描述类、属性、方法、关系;②对象图:类的实例;③组件图:软件组件及关系;④部署图:运行时硬件结构。2)动态图(描述行为):①用例图:系统功能视图;②时序图:对象间消息时间顺序;③活动图:工作流;④状态图:对象状态变化;⑤通信图:对象间协作。共 13 种图(UML 2)。', 'UML 图', 5.00, 3, 118),
(4366, 110, 5, '简述软件测试的分类', NULL, '按阶段:1)单元测试(UT):测试单个模块;2)集成测试:模块间接口;3)系统测试:整体功能、性能;4)验收测试:用户参与的最终测试。按方法:1)白盒测试:基于代码内部逻辑;2)黑盒测试:基于功能规格;3)灰盒测试:介于两者之间。按目的:功能测试、性能测试、安全测试、回归测试等。', '测试分类', 5.00, 2, 118),
(4367, 110, 5, '简述白盒测试方法', NULL, '白盒测试基于代码内部结构,关注路径覆盖。覆盖标准(由弱到强):1)语句覆盖:每条语句至少执行一次;2)判定覆盖:每个判定的真假分支都被执行;3)条件覆盖:每个条件的真假取值都被测试;4)判定/条件覆盖:同时满足判定和条件覆盖;5)条件组合覆盖:每种条件组合都被测试;6)路径覆盖(最强):每条独立路径都被测试。常用方法:基本路径测试、循环测试。', '白盒测试', 5.00, 3, 118),
(4368, 110, 5, '简述黑盒测试方法', NULL, '黑盒测试不关心内部实现,基于规格说明:1)等价类划分:将输入域划分为等价类,从每类选代表;2)边界值分析:针对边界值设计测试用例,易出 bug 处;3)因果图:分析输入和输出的因果关系;4)判定表:列出所有条件组合及对应动作;5)错误推测:基于经验推测错误所在。常用于功能测试、验收测试。', '黑盒测试', 5.00, 3, 118),
(4369, 110, 5, '简述软件维护类型', NULL, '软件维护四类:1)改正性维护:修复已发现的错误,占 20%;2)适应性维护:适应环境变化(OS 升级、硬件更换),占 25%;3)完善性维护:增加功能、改善性能,占 50%(最多);4)预防性维护:为防止未来问题而进行的改进,占 5%。维护成本约占软件生命周期总成本的 60%~80%。', '维护类型', 5.00, 2, 118),
(4370, 110, 5, '简述软件配置管理(SCM)', NULL, '软件配置管理保证软件演化的可控性和可追溯。核心活动:1)版本控制:管理代码、文档的不同版本(Git/SVN);2)变更控制:控制变更请求的审批、实施;3)配置审计:验证配置项的完整性;4)状态报告:记录配置项状态变化。配置项包括:程序、文档、数据、工具、环境。重要工具:Git、SVN、Jenkins、JIRA 等。', 'SCM', 5.00, 3, 118),
(4371, 110, 5, '简述 CMM/CMMI 五级', NULL, 'CMM(能力成熟度模型)分 5 级:1)初始级(Initial):过程不可预测,英雄主义;2)可重复级(Repeatable):有基本项目管理;3)已定义级(Defined):过程标准化、文档化;4)已管理级(Managed):用度量数据控制过程;5)优化级(Optimizing):持续改进。CMMI 是 CMM 的进化,整合多模型。提升组织的软件开发成熟度。', 'CMM', 5.00, 3, 118),
(4372, 110, 5, '简述软件质量属性', NULL, 'ISO 25010 定义软件质量属性:1)功能性:正确性、合规性;2)可靠性:成熟性、容错性、可恢复;3)效率/性能:时间、资源利用;4)可用性:易学、易用、用户体验;5)可维护性:易分析、易修改、易测试;6)可移植性:适应性、易安装;7)安全性:保密、完整、不可否认;8)兼容性:互操作。这些是非功能需求的核心。', '质量属性', 5.00, 3, 118),
(4373, 110, 5, '简述项目管理三角形', NULL, '项目铁三角(范围、时间、成本)+ 质量,任一边变化都会影响其他边:1)范围(Scope):项目工作内容,扩大需要更多时间或成本;2)时间(Time):进度,缩短需增加资源或减小范围;3)成本(Cost):预算,降低则可能影响范围或质量;4)质量(Quality):受三者制约。项目经理需平衡四者,在变化时与利益相关者协商权衡。', '项目铁三角', 5.00, 2, 118),
(4374, 110, 5, '简述敏捷与瀑布的区别', NULL, '1)需求:瀑布要求需求稳定且前期定义清楚;敏捷拥抱变化,逐步细化;2)迭代:瀑布单次大瀑布;敏捷小迭代(2-4 周);3)交付:瀑布一次性交付;敏捷增量交付;4)文档:瀑布重文档;敏捷重可工作软件;5)反馈:瀑布晚反馈;敏捷持续反馈;6)适用:瀑布适合大型稳定项目(政府、军工);敏捷适合互联网、多变需求。', '敏捷 vs 瀑布', 5.00, 2, 118),
(4375, 110, 5, '简述软件工程的最佳实践', NULL, '现代软件工程最佳实践:1)版本控制(Git):全员使用、分支策略;2)代码评审(Code Review):提升质量、知识共享;3)持续集成(CI):自动构建、测试;4)持续部署(CD):自动化部署;5)测试驱动(TDD):先写测试再写代码;6)结对编程:实时审查;7)自动化测试:单元、集成、UI;8)敏捷迭代:小步快跑;9)DevOps:开发运维一体;10)监控告警:生产环境可观测。', '最佳实践', 5.00, 2, 118);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(4376, 111, 1, '编译过程的第一阶段是', '{"A": "词法分析", "B": "语法分析", "C": "语义分析", "D": "代码生成"}', 'A', '标准编译流程：词法→语法→语义→中间代码→优化→目标代码', 2.00, 1, 109),
(4377, 111, 1, '词法分析的输出是', '{"A": "语法树", "B": "Token 序列", "C": "三地址码", "D": "目标代码"}', 'B', '词法分析器把字符流转换为 Token（记号）序列', 2.00, 1, 109),
(4378, 111, 1, '用于描述程序设计语言词法规则的形式工具是', '{"A": "正则表达式", "B": "上下文无关文法", "C": "图灵机", "D": "上下文有关文法"}', 'A', '正则表达式/有限自动机描述词法；上下文无关文法描述语法', 2.00, 1, 109),
(4379, 111, 1, '用于描述程序设计语言语法结构的形式工具是', '{"A": "正则表达式", "B": "上下文无关文法（CFG）", "C": "递归函数", "D": "图灵机"}', 'B', 'BNF 形式的上下文无关文法是描述程序语法的标准', 2.00, 1, 109),
(4380, 111, 1, '自顶向下分析的代表方法是', '{"A": "LR(1) 分析", "B": "递归下降", "C": "算符优先", "D": "SLR 分析"}', 'B', '递归下降、LL(1) 是自顶向下；LR、SLR、算符优先是自底向上', 2.00, 2, 109),
(4381, 111, 1, 'LL(1) 文法不允许包含', '{"A": "右递归", "B": "左递归", "C": "终结符", "D": "非终结符"}', 'B', 'LL(1) 不能处理左递归，需要消除左递归', 2.00, 2, 109),
(4382, 111, 1, '自底向上分析中常见的两种动作是', '{"A": "移进与归约", "B": "展开与匹配", "C": "压栈与回溯", "D": "分析与综合"}', 'A', 'LR 类分析器基于''移进-归约''动作', 2.00, 2, 109),
(4383, 111, 1, '语法制导翻译技术中的属性分为', '{"A": "继承属性和综合属性", "B": "输入属性和输出属性", "C": "静态属性和动态属性", "D": "全局属性和局部属性"}', 'A', '综合属性 (synthesized) 由子节点向上传；继承属性 (inherited) 由父/兄向下传', 2.00, 2, 109),
(4384, 111, 1, '常见的中间代码表示形式不包括', '{"A": "四元式", "B": "三地址码", "C": "逆波兰式", "D": "宏指令"}', 'D', '四元式/三地址码/逆波兰/抽象语法树 都是常见中间代码', 2.00, 1, 109),
(4385, 111, 1, '为了便于循环优化，编译器通常需要识别', '{"A": "基本块和控制流图", "B": "符号表", "C": "错误信息", "D": "用户接口"}', 'A', '基本块和控制流图是数据流分析与循环优化的基础', 2.00, 2, 109),
(4386, 111, 1, '常量折叠（constant folding）属于', '{"A": "机器无关优化", "B": "机器相关优化", "C": "代码生成", "D": "语义分析"}', 'A', '常量折叠/公共子表达式消除/死代码删除等都是机器无关优化', 2.00, 2, 109),
(4387, 111, 1, 'DAG（有向无环图）在编译中主要用于', '{"A": "消除公共子表达式", "B": "分析语义错误", "C": "生成 Token", "D": "消除左递归"}', 'A', '基本块的 DAG 表示可用于消除公共子表达式和复制传播', 2.00, 3, 109),
(4388, 111, 2, '编译器的前端通常包括', '{"A": "词法分析", "B": "语法分析", "C": "语义分析", "D": "目标代码生成"}', 'ABC', '前端：词法/语法/语义分析+中间代码生成；后端：优化+目标代码生成', 3.00, 2, 109),
(4389, 111, 2, '下列哪些方法可以消除文法的左递归？', '{"A": "提取左因子", "B": "直接改写为右递归", "C": "引入新的非终结符", "D": "使用 LR 分析"}', 'BC', 'A 是消除回溯的；D 是另一种分析方法不消除左递归本身', 3.00, 3, 109),
(4390, 111, 2, '下列属于代码优化技术的有', '{"A": "公共子表达式消除", "B": "死代码消除", "C": "循环不变量外提", "D": "语法错误检测"}', 'ABC', 'D 属于语法分析', 3.00, 2, 109),
(4391, 111, 2, '运行时存储分配方式包括', '{"A": "静态分配", "B": "栈式分配", "C": "堆式分配", "D": "链式分配"}', 'ABC', '运行时存储分为静态区、栈区、堆区', 3.00, 2, 109),
(4392, 111, 3, '正则文法可以描述大多数程序设计语言的语法。', NULL, '错误', '正则文法只能描述词法；语法需要上下文无关文法（如嵌套括号匹配）', 1.00, 2, 109),
(4393, 111, 3, 'NFA 与 DFA 在能识别的语言集合上等价。', NULL, '正确', '任意 NFA 都可以转换为等价的 DFA（子集构造法）', 1.00, 2, 109),
(4394, 111, 3, 'LR(1) 文法是所有上下文无关文法中最大的可分析子集。', NULL, '错误', 'LR(1) 是所有 LR 文法的子集；LR(k) 比 LR(1) 更广', 1.00, 3, 109),
(4395, 111, 3, '任何上下文无关文法都可以转换为 Chomsky 范式。', NULL, '正确', 'CFG 可以转换为 Chomsky 范式或 Greibach 范式', 1.00, 2, 109),
(4396, 111, 3, '语义分析阶段会进行类型检查。', NULL, '正确', '类型检查是语义分析的核心任务之一', 1.00, 1, 109),
(4397, 111, 3, '目标代码生成必须依赖具体的硬件体系结构。', NULL, '正确', '目标代码与具体 CPU 指令集相关，是机器相关阶段', 1.00, 1, 109),
(4398, 111, 4, '编译过程通常分为词法分析、语法分析、语义分析、中间代码生成、___ 和目标代码生成六个阶段。', NULL, '代码优化', '经典编译流程六阶段', 2.00, 1, 109),
(4399, 111, 4, '自底向上分析过程中，分析栈与输入串的关系是：栈中是已归约的部分，输入串是 ___ 的部分。', NULL, '待分析', '自底向上：栈顶向左累积，待分析输入在右', 2.00, 2, 109),
(4400, 111, 4, '识别表达式 a+b*c 时，乘法优先于加法，这是通过 ___ 来体现的（在文法层面）。', NULL, '文法的层次结构（产生式的优先级）', '经典做法是把表达式分层 E→E+T | T，T→T*F | F', 2.00, 2, 109),
(4401, 111, 4, '三地址码语句 ''x := a + b'' 转换为四元式表示为 ___。', NULL, '(+, a, b, x)', '四元式格式 (op, arg1, arg2, result)', 2.00, 2, 109),
(4402, 111, 5, '什么是编译程序？编译程序与解释程序的主要区别？', NULL, '编译程序：把高级语言源程序翻译成等价的目标语言（汇编/机器码）程序。区别：编译程序一次性翻译生成目标代码后再执行，运行速度快；解释程序逐句解释执行，无目标代码，灵活但慢。代表：编译 - C/C++；解释 - Python/JavaScript（部分）', '两种程序翻译执行方式', 5.00, 2, 109),
(4403, 111, 5, '叙述 LL(1) 分析法的基本思想及构造分析表的步骤。', NULL, 'LL(1)：自顶向下，每步只看下一个 token 即可决定选哪条产生式。构造步骤：(1) 计算每个非终结符的 FIRST 集；(2) 计算每个非终结符的 FOLLOW 集；(3) 构造预测分析表 M[A,a]：若 A→α，对 a∈FIRST(α) 填入 α；若 ε∈FIRST(α)，对 a∈FOLLOW(A) 也填入 α。要求文法不冲突（即 M 表每格至多一项）', 'LL(1) 分析的标准构造', 5.00, 3, 109),
(4404, 111, 5, '什么是基本块？基本块的入口与出口指令分别是什么？', NULL, '基本块：连续顺序执行的三地址语句序列，控制流只能从开始进入、从结尾离开，中间没有跳入跳出。入口指令：(1) 程序首条；(2) 跳转的目标；(3) 跳转指令的下一条。出口指令：(1) 跳转/返回；(2) 下一条是入口的前一条；(3) 程序末尾', '基本块是流图与优化的基础单元', 5.00, 2, 109),
(4405, 111, 5, '举例说明三种常见的代码优化技术及其作用。', NULL, '(1) 公共子表达式消除：t1=a+b; t2=a+b → t2=t1，减少计算；(2) 常量折叠：x=3*4 → x=12，编译期算出；(3) 死代码消除：if(false){...} → 删除整段，减小代码量；(4) 循环不变量外提：for(i){x=a*b; ...} 中 a,b 不变则把 x=a*b 提到循环外；(5) 强度削弱：i*2 → i<<1', '常见优化技术', 5.00, 2, 109),
(4406, 111, 1, '编译程序的五大基本组成不包括下列哪项', '{"A": "词法分析器", "B": "语法分析器", "C": "操作系统接口", "D": "语义分析器"}', 'C', '编译器主要五阶段：词法、语法、语义分析、中间代码生成、目标代码生成；不含 OS 接口', 2.00, 1, 109),
(4407, 111, 1, '词法分析阶段产生的输出是', '{"A": "语法分析树", "B": "中间代码", "C": "记号（Token）序列", "D": "目标代码"}', 'C', '词法分析将源代码字符流转换为记号序列，供语法分析使用', 2.00, 1, 109),
(4408, 111, 1, '下列哪种文法不属于乔姆斯基文法分类的 4 种类型', '{"A": "正则文法", "B": "上下文无关文法", "C": "上下文有关文法", "D": "BNF 文法"}', 'D', '乔姆斯基 4 类文法：0 型（短语）、1 型（上下文有关）、2 型（上下文无关）、3 型（正则）；BNF 是表示法，不是文法类', 2.00, 2, 109),
(4409, 111, 1, 'LL(1) 文法中 LL(1) 的含义是', '{"A": "从左到右扫描，最左推导，向前看 1 个符号", "B": "从左到右扫描，最右推导，向前看 1 个符号", "C": "从右到左扫描，最左推导，向前看 1 个符号", "D": "线性文法"}', 'A', 'LL(1)：Left-to-right scan, Leftmost derivation, 1 lookahead', 2.00, 2, 109),
(4410, 111, 1, '下列哪个是自下而上分析法', '{"A": "递归下降", "B": "预测分析", "C": "LR 分析", "D": "LL 分析"}', 'C', 'LR 分析是自下而上（从输入串归约到开始符）；LL、递归下降、预测分析都是自上而下', 2.00, 2, 109),
(4411, 111, 1, '正则表达式 (a|b)*abb 不能识别下列哪个串', '{"A": "abb", "B": "aabb", "C": "bbabb", "D": "ab"}', 'D', '(a|b)*abb 要求以 abb 结尾，''ab'' 不以 abb 结尾', 2.00, 2, 109),
(4412, 111, 1, '下列哪种中间代码表示方式最接近源程序', '{"A": "三地址码", "B": "P-代码", "C": "抽象语法树（AST）", "D": "波兰式"}', 'C', 'AST 与源程序结构最接近；三地址码、P-代码已转换为低级表示', 2.00, 2, 109),
(4413, 111, 1, '符号表的主要作用是', '{"A": "记录运行时数据", "B": "存储源代码", "C": "登记标识符信息（类型、作用域等）", "D": "存储中间代码"}', 'C', '符号表登记每个标识符的名称、类型、地址、作用域等编译时信息', 2.00, 1, 109),
(4414, 111, 1, '三地址码 ''x := y op z'' 中的 op 是', '{"A": "一元运算符", "B": "二元运算符", "C": "三元运算符", "D": "赋值运算符"}', 'B', '三地址码的形式为 x := y op z，op 是二元运算符（+ - * /）', 2.00, 1, 109),
(4415, 111, 1, '代码优化中，循环不变量外提属于', '{"A": "局部优化", "B": "循环优化", "C": "窥孔优化", "D": "数据流优化"}', 'B', '循环不变量外提（Loop Invariant Code Motion）是循环优化的关键技术', 2.00, 2, 109),
(4416, 111, 1, '活动记录（Activation Record）通常存放在', '{"A": "代码区", "B": "栈", "C": "堆", "D": "全局数据区"}', 'B', '函数调用时活动记录入栈，包含参数、返回地址、局部变量等', 2.00, 2, 109),
(4417, 111, 1, 'DFA 与 NFA 在识别能力上的关系是', '{"A": "DFA 强", "B": "NFA 强", "C": "等价", "D": "无法比较"}', 'C', 'DFA 与 NFA 识别同一类语言（正则语言），任意 NFA 可转化为等价 DFA', 2.00, 2, 109),
(4418, 111, 2, '编译器的前端通常负责', '{"A": "词法分析", "B": "语法分析", "C": "语义分析", "D": "目标代码生成"}', 'ABC', '前端：词法、语法、语义分析、中间代码生成；后端：代码优化、目标代码生成', 3.00, 2, 109),
(4419, 111, 2, '下列哪些技术属于代码优化', '{"A": "公共子表达式消除", "B": "常量折叠", "C": "死代码消除", "D": "符号表查找"}', 'ABC', '前三个都是经典代码优化技术；符号表查找是编译时操作', 3.00, 2, 109),
(4420, 111, 2, '下列哪些工具与编译原理有关', '{"A": "Lex/Flex", "B": "Yacc/Bison", "C": "ANTLR", "D": "GDB"}', 'ABC', 'Lex/Flex 词法分析器生成器；Yacc/Bison 语法分析器生成器；ANTLR 是综合分析工具。GDB 是调试器', 3.00, 2, 109),
(4421, 111, 2, '下列文法属于二义性文法的特征', '{"A": "存在两棵不同的语法树推导同一句子", "B": "存在两种最左推导推导同一句子", "C": "存在两种最右推导推导同一句子", "D": "句子的语义不确定"}', 'ABC', '二义性文法特征：同一句子有两棵不同的语法树（即两种最左/最右推导）。语义不确定是结果不是特征', 3.00, 3, 109),
(4422, 111, 3, '正则表达式可以描述所有的程序设计语言的语法', NULL, '错误', '正则表达式描述的是 3 型语言，无法描述嵌套结构（如平衡括号），程序语言需 2 型文法', 1.00, 2, 109),
(4423, 111, 3, '自顶向下分析法不能处理左递归文法', NULL, '正确', '自顶向下（LL）分析遇左递归会陷入无限循环，需要消除左递归', 1.00, 2, 109),
(4424, 111, 3, 'LR 分析器自带一个用于状态管理的栈', NULL, '正确', 'LR 分析器用栈保存状态和符号，通过移进/归约操作处理输入', 1.00, 1, 109),
(4425, 111, 3, '中间代码的引入是为了便于不同源语言/目标机器的编译器组合', NULL, '正确', '中间代码（IR）解耦前端与后端，便于多语言、多平台的编译器组合', 1.00, 2, 109),
(4426, 111, 3, 'DFA 的最小化是为了提高识别效率', NULL, '正确', 'DFA 最小化产生等价但状态数最少的 DFA，存储和运行更高效', 1.00, 2, 109),
(4427, 111, 3, 'JIT (即时编译) 编译器与传统编译器没有本质区别', NULL, '错误', 'JIT 在运行时动态编译热点代码，结合解释和编译优点，与传统 AOT 编译不同', 1.00, 2, 109),
(4428, 111, 4, '正则表达式 a*b* 识别的语言是 ____', NULL, 'a 的任意个后跟 b 的任意个（包括空串）', 'a* 表示零或多个 a；b* 表示零或多个 b；可识别 ε, a, ab, aabbb 等', 3.00, 2, 109),
(4429, 111, 4, '上下文无关文法生成的语言称为 ____', NULL, '上下文无关语言', 'CFG 生成 CFL，是 2 型语言，可由下推自动机识别', 2.00, 1, 109),
(4430, 111, 4, '三地址码 a:=b+c*d 拆分为三地址码序列：t1:=c*d; a:=____', NULL, 'b+t1', '先算 c*d 存入 t1，再计算 b+t1 赋给 a', 3.00, 2, 109),
(4431, 111, 4, '编译过程中的''语法分析''阶段输入是 ____，输出是 ____', NULL, '记号序列；语法树', '语法分析以词法分析的记号序列为输入，生成语法树或推导序列', 3.00, 2, 109),
(4432, 111, 5, '简述编译过程的主要阶段', NULL, '编译过程主要分 6 阶段：(1) 词法分析：源程序→记号序列；(2) 语法分析：记号序列→语法树；(3) 语义分析：检查类型、作用域等；(4) 中间代码生成：→IR（如三地址码）；(5) 代码优化：对 IR 进行各种优化变换；(6) 目标代码生成：IR→机器码或汇编。其中前 4 个属前端，后 2 个属后端', '编译器经典阶段划分，理解每阶段的输入输出', 5.00, 2, 109),
(4433, 111, 5, '用例子说明上下文无关文法二义性', NULL, '经典例子：算术表达式文法 E→E+E | E*E | (E) | id 是二义的。如 ''id+id*id'' 有两棵不同的语法树：(1) ((id+id)*id) 先加后乘；(2) (id+(id*id)) 先乘后加。消除二义性的方法：引入优先级（E→E+T | T,T→T*F | F,F→(E) | id）', '经典例题，二义性影响语义', 5.00, 3, 109),
(4434, 111, 5, '什么是 LL(1) 文法？写出 LL(1) 文法必须满足的条件', NULL, 'LL(1) 文法：可用 LL(1) 分析法（自顶向下，向前看 1 个符号）分析的文法。条件：对任一非终结符 A 的两个不同产生式 A→α 和 A→β，必须满足：(1) FIRST(α) ∩ FIRST(β) = ∅；(2) 若 β 可推出 ε，则 FIRST(α) ∩ FOLLOW(A) = ∅。简言之：分析器在向前看 1 个符号后能唯一确定使用哪个产生式', 'LL(1) 是预测分析的核心要求', 5.00, 3, 109),
(4435, 111, 5, '简述代码优化的基本目标和常见技术', NULL, '基本目标：在保持语义不变的前提下，提高目标代码的执行效率或减少代码体积。常见技术：(1) 局部优化：常量折叠（3+5→8）、常量传播、复写传播；(2) 公共子表达式消除（CSE）；(3) 死代码消除（DCE）；(4) 循环优化：循环不变量外提、强度削弱（x*2→x<<1）、归纳变量替换；(5) 全局优化：基于数据流分析的活跃变量、到达定义分析', '代码优化是编译器后端核心，分局部、循环、全局三类', 5.00, 3, 109),
(4436, 111, 1, '编译器与解释器的区别是', '{"A": "编译器一次性翻译整个程序生成可执行文件", "B": "解释器逐句执行", "C": "以上都是", "D": "以上都不"}', 'C', '编译/解释', 2.00, 2, 109),
(4437, 111, 1, '编译过程不包括', '{"A": "词法分析", "B": "语法分析", "C": "执行", "D": "语义分析"}', 'C', '编译不包括执行', 2.00, 2, 109),
