(4630, 111, 3, 'CFG 等价于下推自动机', NULL, '正确', 'CFG=PDA', 1.00, 3, 109),
(4631, 111, 3, '正则文法等价于有限自动机', NULL, '正确', '正则=FA', 1.00, 3, 109),
