(4635, 111, 3, 'Python 是解释型语言', NULL, '正确', 'Python 解释', 1.00, 2, 109),
(4636, 111, 4, '编译过程的第一阶段是 ____', NULL, '词法分析', '词法分析', 2.00, 2, 109),
(4637, 111, 4, '词法分析的输出是 ____', NULL, 'Token 序列', '词法输出', 2.00, 2, 109),
(4638, 111, 4, 'DFA 是 ____ 自动机', NULL, '确定有限', 'DFA', 2.00, 2, 109),
(4639, 111, 4, 'NFA 是 ____ 自动机', NULL, '非确定有限', 'NFA', 2.00, 2, 109),
(4640, 111, 4, '正则表达式转 NFA 用 ____ 算法', NULL, 'Thompson', 'Thompson 构造', 2.00, 3, 109),
(4641, 111, 4, 'NFA 转 DFA 用 ____ 算法', NULL, '子集构造', '子集构造', 2.00, 3, 109),
(4642, 111, 4, '词法分析常用工具是 ____', NULL, 'Lex/Flex', 'Lex 工具', 2.00, 2, 109),
(4643, 111, 4, '上下文无关文法的层次是乔姆斯基 ____ 型', NULL, '2', 'CFG=2型', 2.00, 3, 109),
(4644, 111, 4, '正则文法的层次是乔姆斯基 ____ 型', NULL, '3', '正则=3型', 2.00, 3, 109),
(4645, 111, 4, 'LL(1) 分析是 ____ 向下分析', NULL, '自顶', 'LL(1)', 2.00, 3, 109),
(4646, 111, 4, 'LR 分析是 ____ 向上分析', NULL, '自底', 'LR', 2.00, 3, 109),
(4647, 111, 4, 'Yacc/Bison 默认使用 ____ 分析', NULL, 'LALR(1)', 'Yacc', 2.00, 3, 109),
(4648, 111, 4, 'First 集是 ____ 字符集合', NULL, '首', 'First 集', 2.00, 3, 109),
(4649, 111, 4, 'Follow 集是 ____ 集合', NULL, '后继', 'Follow 集', 2.00, 3, 109),
(4650, 111, 4, 'S 属性文法只有 ____ 属性', NULL, '综合', 'S 属性', 2.00, 3, 109),
(4651, 111, 4, '符号表存储 ____ 的属性', NULL, '标识符', '符号表', 2.00, 2, 109),
(4652, 111, 4, '三地址码每条指令最多 ____ 个操作数', NULL, '3', '三地址', 2.00, 2, 109),
(4653, 111, 4, '四元式 (op,arg1,arg2, ____)', NULL, 'result', '四元式', 2.00, 3, 109),
(4654, 111, 4, 'DAG 在编译器中用于 ____ 消除', NULL, '公共子表达式', 'DAG', 2.00, 3, 109),
(4655, 111, 4, 'SSA 的全称是 ____', NULL, '静态单赋值', 'SSA', 2.00, 3, 109),
(4656, 111, 4, '____ 优化是把循环不变代码移到循环外', NULL, '代码移动', '循环不变代码外提', 2.00, 3, 109),
(4657, 111, 4, '____ 是删除不会执行的代码', NULL, '死代码消除', '死代码', 2.00, 3, 109),
(4658, 111, 4, '图染色法用于 ____ 分配', NULL, '寄存器', '图染色寄存器', 2.00, 3, 109),
(4659, 111, 4, '内存分配区域包括栈、堆、代码段、 ____ 段', NULL, '数据', '内存区域', 2.00, 2, 109),
(4660, 111, 4, '活动记录用于支持 ____ 调用', NULL, '函数', '活动记录', 2.00, 3, 109),
(4661, 111, 4, 'C 语言采用 ____ 作用域', NULL, '词法', 'C 作用域', 2.00, 2, 109),
(4662, 111, 4, 'Java 编译为 ____,由 JVM 执行', NULL, '字节码', 'Java 字节码', 2.00, 2, 109),
(4663, 111, 4, 'JIT 是 ____ 时编译', NULL, '运行', 'JIT', 2.00, 3, 109),
(4664, 111, 4, 'gcc 优化级别 ____ 表示不优化', NULL, '-O0', '-O0', 2.00, 2, 109),
(4665, 111, 4, 'gcc 优化级别 ____ 表示激进优化', NULL, '-O3', '-O3', 2.00, 2, 109),
(4666, 111, 4, '龙书的作者之一是 ____', NULL, 'Aho', '龙书', 2.00, 3, 109),
(4667, 111, 4, '形式语言层次由 ____ 提出', NULL, '乔姆斯基', 'Chomsky', 2.00, 2, 109),
(4668, 111, 4, 'CFG 等价于 ____ 自动机', NULL, '下推', 'CFG=PDA', 2.00, 3, 109),
(4669, 111, 4, '递归可枚举文法等价于 ____ 机', NULL, '图灵', 'RE=TM', 2.00, 3, 109),
(4670, 111, 4, 'LLVM 的中间表示称为 ____', NULL, 'LLVM IR', 'LLVM IR', 2.00, 3, 109),
(4671, 111, 5, '简述编译器与解释器的区别', NULL, '编译器:把整个源程序一次性翻译为目标代码(可执行文件),编译期与运行期分离。优点:执行快、代码不易被篡改。缺点:跨平台需要多份编译。例:C/C++、Go、Rust。解释器:逐句翻译并执行,无独立目标代码。优点:跨平台、调试方便。缺点:执行慢。例:Python、JavaScript、Lua。混合(JIT):Java、C# 编译为字节码,JVM/CLR 解释执行,热点代码 JIT 编译为本地码。', '编译/解释', 5.00, 2, 109),
(4672, 111, 5, '简述词法分析的原理', NULL, '词法分析(Lexer/Scanner)把源代码字符流转为 Token 序列。1)Token 由类别和属性值组成,如 (ID,''foo'')、(NUM,''42'');2)正则表达式描述每种 Token 模式;3)正则表达式 → NFA(Thompson 构造)→ DFA(子集构造)→ 最小化 DFA;4)用 DFA 扫描输入,采用最长匹配规则;5)忽略空白和注释。工具:Lex/Flex 自动生成词法分析器。', '词法分析', 5.00, 2, 109),
(4673, 111, 5, '简述正则表达式与 DFA/NFA 的关系', NULL, '正则表达式、NFA、DFA 三者等价(描述能力相同),都对应正则语言。转换:1)正则表达式 → NFA:Thompson 构造,递归处理 *、|、连接,可有 ε 转移;2)NFA → DFA:子集构造法,DFA 状态是 NFA 状态的集合,使用 ε-闭包消除空转移;3)DFA 最小化:Hopcroft 算法或等价类划分法。每种正则语言都有唯一最小 DFA(同构意义)。', '正则与自动机', 5.00, 3, 109),
(4674, 111, 5, '简述语法分析的两种方法', NULL, '自顶向下:1)从开始符号推导,匹配输入串;2)递归下降:每个非终结符对应函数;3)LL(1):预测分析表,需 First/Follow 集;要求文法无左递归、无公共前缀。优点:实现简单。自底向上:1)从输入串归约到开始符号;2)LR(0)、SLR、LALR、LR(1):用项集和分析表,功能依次增强;3)移进-归约动作。优点:能处理更广泛的文法。Yacc/Bison 用 LALR(1)。', '语法分析', 5.00, 3, 109),
(4675, 111, 5, '简述上下文无关文法 (CFG)', NULL, 'CFG G=(V_T,V_N,P,S):1)V_T 终结符;2)V_N 非终结符;3)P 产生式 A→α(A∈V_N,α∈(V_T∪V_N)*);4)S 开始符号。表示能力:可描述大多数程序语言的语法,如算术表达式、控制流。乔姆斯基层次中属 2 型,等价于下推自动机(PDA)。BNF/EBNF 是 CFG 的常见表示。例:E→E+T|T,T→T*F|F,F→(E)|id 描述算术表达式。', 'CFG', 5.00, 3, 109),
(4676, 111, 5, '简述 LL(1) 文法的条件', NULL, 'LL(1) 文法:从左到右扫描,产生最左推导,1 个 lookahead。条件:1)无左递归:A→Aα 改为 A→βA'',A''→αA''|ε;2)无公共前缀:A→αβ|αγ 改为 A→αA'',A''→β|γ(提取左公因子);3)对每个 A→α|β,First(α)∩First(β)=∅;4)若 ε∈First(α),则 First(β)∩Follow(A)=∅。构造预测分析表 M[A,a],分析过程使用栈和分析表。', 'LL(1)', 5.00, 3, 109),
(4677, 111, 5, '简述 LR 分析的原理', NULL, 'LR 分析(Left-to-right scan,Rightmost derivation):自底向上,产生最右推导。基本原理:1)状态栈和符号栈维护当前分析过程;2)分析表 ACTION 表(移进/归约/接受/报错)和 GOTO 表;3)项集族(LR(0)/LR(1) 项)。变种:1)LR(0):无 lookahead;2)SLR:用 Follow 集解决冲突;3)LALR(1):合并同心项集;4)LR(1):完整 lookahead,功能最强。能力:LR(1) > LALR > SLR > LR(0)。Yacc/Bison 用 LALR(1)。', 'LR 分析', 5.00, 3, 109),
(4678, 111, 5, '简述语义分析的任务', NULL, '语义分析检查程序的意义(语法之外的约束):1)类型检查:算术运算两侧类型相容、赋值兼容、函数调用参数匹配;2)作用域检查:变量先声明后使用,作用域规则;3)常量检查;4)函数原型检查;5)错误检测和报告。实现方式:1)属性文法:综合属性(自下向上)、继承属性(自上向下);2)语法制导翻译;3)符号表查询。语义分析后产生注释的语法树或中间代码。', '语义分析', 5.00, 3, 109),
(4679, 111, 5, '简述符号表的作用', NULL, '符号表是编译器内部数据结构,存储标识符的属性。属性包括:名称、类型、作用域、内存地址、大小、初始值等。功能:1)标识符的查找、插入、删除;2)管理作用域(块结构语言用栈);3)支持类型检查、代码生成;4)运行时还可生成调试信息。实现:常用散列表(O(1) 查找)、二叉搜索树。块结构作用域用符号表栈或链表。符号表贯穿编译全过程。', '符号表', 5.00, 2, 109),
(4680, 111, 5, '简述中间代码的形式与作用', NULL, '中间代码:介于源代码和目标代码之间的表示。作用:1)前后端解耦,便于多源语言/多目标平台;2)便于优化(机器无关优化);3)简化编译器实现。常见形式:1)三地址码:x = y op z(每条最多 3 个操作数);2)四元式 (op,arg1,arg2,result);3)三元式 (op,arg1,arg2),用编号引用结果;4)间接三元式;5)抽象语法树 (AST);6)有向无环图 (DAG);7)静态单赋值 (SSA),如 LLVM IR。', 'IR', 5.00, 3, 109),
(4681, 111, 5, '简述 SSA 形式及其优势', NULL, 'SSA(静态单赋值):每个变量在程序中只赋值一次。多分支汇合点用 φ 函数选择不同前驱的值。例:x = a; x = b; → x1 = a; x2 = b; x3 = φ(x1,x2)。优势:1)定义和使用关系明确,简化数据流分析;2)便于实现各种优化:常量传播、死代码消除、值编号、寄存器分配;3)优化效果好。应用:LLVM IR、GCC GIMPLE、Java HotSpot 等现代编译器都采用 SSA。', 'SSA', 5.00, 3, 109),
(4682, 111, 5, '简述代码优化的层次', NULL, '代码优化按作用范围:1)局部优化:在单个基本块内,如公共子表达式消除、常量折叠、代数化简、死代码消除;2)循环优化:循环不变代码外提、归纳变量替换、循环展开、循环融合/分裂;3)全局优化:跨基本块的过程内优化,需数据流分析;4)过程间优化:跨函数,内联展开、克隆。按层次:1)源代码级;2)中间代码级(机器无关);3)目标代码级(机器相关:寄存器分配、指令调度)。优化原则:必须保持程序语义不变。', '代码优化', 5.00, 3, 109),
(4683, 111, 5, '简述数据流分析', NULL, '数据流分析:在程序控制流图(CFG)上,沿基本块传播信息以推导程序性质。常见分析:1)到达定值(Reaching Definitions):用于常量传播;2)活跃变量(Live Variables):用于寄存器分配、死代码消除;3)可用表达式(Available Expressions):用于公共子表达式消除;4)非常忙表达式(Very Busy);5)常量传播。框架:用半格(meet 运算)描述,迭代求解直到不动点。方向:正向(到达定值、可用表达式)、反向(活跃变量)。', '数据流分析', 5.00, 3, 109),
(4684, 111, 5, '简述寄存器分配算法', NULL, '寄存器分配把无限多虚拟寄存器映射到有限物理寄存器。核心问题:同时活跃的变量数 > 寄存器数 → 溢出(spill)。常见算法:1)图染色法:构造冲突图(节点=变量,边=同时活跃),染色 ≤ k 颜色(寄存器数);Chaitin、Briggs 算法。2)线性扫描:按变量活跃区间排序、贪心分配,适合 JIT。3)整数线性规划:理论最优但慢。指标:溢出代码数、性能。LLVM 用基于贪心的算法和图染色变体。', '寄存器分配', 5.00, 3, 109),
(4685, 111, 5, '简述基本块和控制流图', NULL, '基本块(Basic Block):一段连续的指令序列,只能从开头进入、从末尾退出,中间无跳转。识别:1)第一条指令是入口;2)跳转目标的指令;3)跳转/调用/返回指令的下一条。控制流图(CFG):节点是基本块,边表示控制流(顺序、分支、循环)。性质:1)入口节点和出口节点;2)支配关系(Dominator):每条到 v 的路径都经过 u,则 u 支配 v。CFG 是数据流分析、优化的基础。', '基本块/CFG', 5.00, 3, 109),
(4686, 111, 5, '简述运行时存储管理', NULL, '运行时存储区域:1)代码段(Code/Text):机器指令,只读;2)数据段(Data/BSS):全局/静态变量,初始化数据/未初始化数据;3)堆(Heap):动态分配,malloc/new,程序员管理或 GC;4)栈(Stack):函数调用、局部变量、参数、返回地址,LIFO,自动管理。栈帧/活动记录(Activation Record):每次函数调用对应一个栈帧,包括局部变量、参数、保存寄存器、返回地址。栈指针 SP/帧指针 FP 标识当前栈帧。', '运行时存储', 5.00, 3, 109),
(4687, 111, 5, '简述参数传递的几种方式', NULL, '参数传递方式:1)值传递(Pass by Value):传递实参的副本,被调函数修改不影响实参。例:C/C++ 默认。2)引用传递(Pass by Reference):传递实参的别名,可修改实参。例:C++ 引用、Pascal var 参数。3)指针传递:传递地址(实质值传递的一种),通过指针修改实参。例:C 中模拟引用。4)名传递(Pass by Name):每次使用形参时重新求值实参。例:Algol 60。5)写回传递(Copy-restore):入口复制、出口写回。各方式在效率、语义、安全性上有不同权衡。', '参数传递', 5.00, 3, 109),
(4688, 111, 5, '简述作用域规则', NULL, '作用域:标识符可见的程序范围。1)词法作用域(Static/Lexical):由源代码块结构决定,编译期确定。例:C、C++、Java、Python。访问外层变量按词法嵌套。2)动态作用域(Dynamic):由运行时调用链决定。例:早期 Lisp、Bash、Perl(local)。优:灵活;缺:难以理解、易出错。3)块作用域、函数作用域、文件作用域、全局作用域。实现:符号表栈、嵌套作用域、闭包(捕获环境)。', '作用域', 5.00, 3, 109),
(4689, 111, 5, '简述垃圾回收机制', NULL, 'GC(垃圾回收):自动管理动态内存,识别和回收不再使用的对象。常见算法:1)引用计数(Reference Counting):每对象维护引用数,降至 0 即回收。优:实时、增量。缺:循环引用问题。例:Python(辅以分代)、Swift。2)标记-清除(Mark-Sweep):标记可达对象,清除未标记。缺:碎片。3)复制(Copying):活跃对象复制到新区,旧区一次性清空。优:无碎片。缺:浪费空间。4)分代收集(Generational):新生代/老年代分别处理,大多数对象短命。例:Java、.NET。5)三色标记法、并发 GC。', 'GC', 5.00, 3, 109),
(4690, 111, 5, '简述 JIT 编译技术', NULL, 'JIT(Just-In-Time)编译:在程序运行时把字节码或源码动态编译为本地机器码。流程:1)初始解释执行;2)统计热点(热点方法、热点循环);3)对热点 JIT 编译为优化的本地码;4)替换执行。优化:基于运行时信息,如类型反馈、内联缓存、推测优化。优点:1)结合编译和解释优势;2)运行时信息支持激进优化;3)跨平台。缺点:启动慢、内存占用。代表:Java HotSpot、V8(JavaScript)、.NET CLR、PyPy。', 'JIT', 5.00, 3, 109),
(4691, 111, 5, '简述 LLVM 编译框架', NULL, 'LLVM(Low Level Virtual Machine):模块化、可重用的编译器基础设施。架构:1)前端 → LLVM IR → 后端。前端:clang(C/C++/ObjC)、Swift、Rust 等。LLVM IR:SSA 形式的中间表示,有文本(.ll)和二进制(.bc)两种格式;独立于源语言和目标平台。中端优化:Pass 系统,各种优化 Pass(常量传播、内联、循环优化等)。后端:针对各 ISA 生成代码(x86、ARM、RISC-V 等)。优势:模块化、Pass 化、易扩展。应用:Apple 工具链、Rust、Swift、CUDA、ML 编译器。', 'LLVM', 5.00, 3, 109),
(4692, 111, 5, '简述类型系统', NULL, '类型系统是程序语言的一组规则,用于赋予各种构造类型并防止类型错误。分类:1)静态类型/动态类型:编译期/运行期检查。例:C++/Python。2)强类型/弱类型:类型转换严格度。例:Python/C。3)类型推断:Hindley-Milner(ML、Haskell)、TypeScript、Rust。4)多态:参数化(泛型)、子类型、ad-hoc(重载)。5)代数数据类型(ADT)、类型类。理论基础:类型论、λ 演算、Curry-Howard 同构。', '类型系统', 5.00, 3, 109),
(4693, 111, 5, '简述类型检查与类型推断', NULL, '类型检查:验证程序中各表达式的类型是否符合语言规则。形式:1)显式类型注解(C、Java);2)隐式类型(Python、Lisp,运行时);3)混合(Scala、TypeScript)。类型推断:编译器自动推导未注解变量的类型。算法:Hindley-Milner(HM)算法,通过类型变量和约束求解;时间复杂度近线性。例:1)let f x = x + 1 推断 f: int → int;2)Rust 局部类型推断。优势:减少冗余、保留类型安全。', '类型推断', 5.00, 3, 109),
(4694, 111, 5, '简述错误处理与恢复策略', NULL, '编译器错误分类:1)词法错误(非法字符);2)语法错误(语法不匹配);3)语义错误(类型不匹配、未声明);4)运行时错误(由编译器无法检测,需运行时检查或异常机制)。错误恢复策略:1)紧急方式(Panic Mode):跳过 token 直到同步符号(如 ;、});2)短语级:做局部修改尝试继续;3)错误产生式:在文法中加入常见错误模式;4)全局校正:用最少修改使程序合法。目标:发现尽可能多的错误,但避免错误信息洪流。', '错误恢复', 5.00, 3, 109),
(4695, 111, 5, '简述编译原理与计算理论的关系', NULL, '编译原理与计算理论紧密相关:1)形式语言层次(乔姆斯基):正则文法 ↔ 词法分析(DFA/NFA);CFG ↔ 语法分析(下推自动机);CSG;RE。2)自动机:DFA、NFA 用于词法;PDA 用于语法;图灵机是计算模型上限。3)可计算性:Halting Problem 不可判定,影响编译器设计的局限。4)复杂度:NP 问题在编译优化中常见(如最优指令选择、寄存器分配为 NPC),用启发式或近似。5)Church-Turing 论题:任何可计算函数都可由图灵机计算。计算理论是编译原理的数学基础。', '编译/计算理论', 5.00, 3, 109),
(4696, 111, 5, '简述领域特定语言 (DSL)', NULL, 'DSL(Domain-Specific Language):为特定领域设计的小型语言。分类:1)外部 DSL(Standalone):独立语法和工具,如 SQL、CSS、正则表达式;需自定义词法/语法分析。2)内部 DSL(Embedded):宿主语言中嵌入,如 Ruby on Rails、Lisp 宏、Scala DSL;用宿主语言的语法。优势:领域抽象、表达力强、易学。挑战:维护成本、工具支持。常用工具:ANTLR、Xtext、Racket、Roslyn。', 'DSL', 5.00, 3, 109),
(4697, 111, 5, '简述编译器在现代软件开发中的地位', NULL, '编译器是软件开发的基础设施:1)语言实现:每种编程语言都需要编译器或解释器,如 gcc、clang、Python、Java;2)程序优化:不断改进的优化技术显著提升程序性能;3)程序分析:静态分析、漏洞检测、形式验证;4)代码安全:Sanitizers(ASan、UBSan)、控制流完整性 CFI;5)跨平台:LLVM 等支持多源语言多目标;6)新硬件支持:GPU(CUDA、OpenCL)、TPU、FPGA、量子;7)AI 编译器:TVM、Glow、MLIR 加速 ML 推理。编译技术持续发展,是 CS 核心研究方向之一。', '编译器地位', 5.00, 2, 109),
(4698, 111, 5, '简述编译原理课程的学习路径', NULL, '编译原理学习推荐路径:1)基础:形式语言与自动机理论(正则、CFG、DFA、PDA);2)前端:词法分析(Lex/Flex)、语法分析(LL/LR、Yacc/Bison)、AST、语义分析、符号表;3)中端:中间代码、SSA、数据流分析、各种优化技术;4)后端:指令选择、寄存器分配、指令调度、目标代码生成;5)运行时:存储管理、GC、虚拟机、JIT。教材:龙书(Dragon Book)、虎书(Tiger Book)、鲸书(Whale Book)。实践:实现小语言 mini compiler,或贡献开源编译器(LLVM、GCC、V8)。', '学习路径', 5.00, 2, 109),
(4699, 111, 2, '下列是 First 集计算规则', '{"A": "终结符的 First 集是它本身", "B": "ε 产生式贡献 ε", "C": "X→Y1Y2... 时贡献 First(Y1)", "D": "以上都是"}', 'ABCD', 'First 集计算', 3.00, 3, 109),
(4700, 111, 2, '下列是 Follow 集计算规则', '{"A": "开始符号的 Follow 包含 $", "B": "A→αBβ 时 First(β) 入 Follow(B)", "C": "β 可推 ε 时 Follow(A) 入 Follow(B)", "D": "以上都是"}', 'ABCD', 'Follow 集计算', 3.00, 3, 109),
(4701, 111, 2, '下列哪些是抽象语法树(AST)的特点', '{"A": "保留结构信息", "B": "去除括号等冗余", "C": "便于遍历", "D": "以上都是"}', 'ABCD', 'AST 特点', 3.00, 3, 109),
(4702, 111, 2, '下列是函数调用相关概念', '{"A": "活动记录", "B": "调用约定", "C": "返回地址", "D": "堆栈帧"}', 'ABCD', '函数调用', 3.00, 3, 109),
(4703, 111, 2, '下列是优化的基本原则', '{"A": "保持语义不变", "B": "提升性能", "C": "减少代码体积", "D": "降低能耗"}', 'ABCD', '优化原则', 3.00, 3, 109),
(4704, 111, 4, '乔姆斯基文法层次共有 ____ 类', NULL, '4', 'Chomsky 4层', 2.00, 3, 109),
(4705, 111, 4, '下推自动机简称 ____', NULL, 'PDA', 'PDA', 2.00, 3, 109),
(4706, 111, 4, '线性有界自动机简称 ____', NULL, 'LBA', 'LBA', 2.00, 3, 109),
(4707, 111, 4, 'BNF 是描述 ____ 的常见表示', NULL, '上下文无关文法', 'BNF', 2.00, 3, 109),
(4708, 111, 4, 'EBNF 是 ____ 的扩展', NULL, 'BNF', 'EBNF', 2.00, 3, 109),
(4709, 111, 4, 'φ 函数用于 SSA 在 ____ 处选择', NULL, '分支汇合', 'φ 函数', 2.00, 3, 109),
(4710, 111, 4, 'Halting Problem 即 ____ 问题', NULL, '停机', 'Halting', 2.00, 3, 109),
(4711, 111, 4, 'clang 是 ____ 的 C/C++ 前端', NULL, 'LLVM', 'clang', 2.00, 3, 109),
(4712, 111, 4, 'Hindley-Milner 算法用于 ____ 推断', NULL, '类型', 'HM 类型推断', 2.00, 3, 109),
(4713, 111, 4, 'Sanitizer 用于检测 ____ 错误', NULL, '运行时', 'Sanitizer', 2.00, 3, 109),
(4714, 111, 4, 'CPM 是 ____ 路径法', NULL, '关键', 'CPM', 2.00, 2, 109),
(4715, 111, 4, 'DSL 全称是 ____', NULL, '领域特定语言', 'DSL', 2.00, 3, 109);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(4716, 112, 1, '人工智能的英文缩写是', '{"A": "AI", "B": "BI", "C": "CI", "D": "DI"}', 'A', 'Artificial Intelligence的缩写是AI', 2.00, 1, 114),
(4717, 112, 1, '被称为''人工智能之父''的科学家是', '{"A": "图灵", "B": "冯·诺依曼", "C": "香农", "D": "麦卡锡"}', 'A', '艾伦·图灵被广泛认为是人工智能之父，提出了图灵测试', 2.00, 1, 114),
(4718, 112, 1, '图灵测试的目的是', '{"A": "测试计算机运算速度", "B": "判断机器是否具有智能", "C": "测试网络连接速度", "D": "检测软件漏洞"}', 'B', '图灵测试通过人机对话来判断机器是否具有智能', 2.00, 1, 114),
(4719, 112, 1, '以下哪个属于监督学习算法', '{"A": "K-Means", "B": "决策树", "C": "PCA", "D": "Apriori"}', 'B', '决策树是典型的监督学习算法，需要标注数据进行训练', 2.00, 1, 114),
(4720, 112, 1, '神经网络中，将输入信号转换为输出信号的函数称为', '{"A": "损失函数", "B": "激活函数", "C": "目标函数", "D": "代价函数"}', 'B', '激活函数（Activation Function）用于对神经元的输入进行非线性变换', 2.00, 1, 114),
(4721, 112, 1, '深度学习是机器学习的一个分支，其核心模型是', '{"A": "决策树", "B": "支持向量机", "C": "深度神经网络", "D": "朴素贝叶斯"}', 'C', '深度学习的核心是多层深度神经网络', 2.00, 1, 114),
(4722, 112, 1, '以下哪种算法常用于图像识别任务', '{"A": "RNN", "B": "CNN", "C": "KNN", "D": "SVM"}', 'B', '卷积神经网络（CNN）擅长处理图像数据，是图像识别的主流模型', 2.00, 1, 114),
(4723, 112, 1, '在机器学习中，将数据分为训练集和测试集的目的是', '{"A": "减少数据量", "B": "评估模型泛化能力", "C": "加快训练速度", "D": "增加数据维度"}', 'B', '划分训练集和测试集是为了评估模型在未见数据上的泛化能力', 2.00, 1, 114),
(4724, 112, 1, '以下哪个不是常见的激活函数', '{"A": "ReLU", "B": "Sigmoid", "C": "Softmax", "D": "Dropout"}', 'D', 'Dropout是正则化技术而非激活函数，ReLU、Sigmoid、Softmax都是激活函数', 2.00, 1, 114),
(4725, 112, 1, '强化学习中，智能体与什么进行交互来学习', '{"A": "数据库", "B": "环境", "C": "用户", "D": "服务器"}', 'B', '强化学习中智能体通过与环境交互，根据奖励信号学习最优策略', 2.00, 1, 114),
(4726, 112, 1, '自然语言处理的英文缩写是', '{"A": "NPC", "B": "NLP", "C": "NPL", "D": "NLR"}', 'B', 'Natural Language Processing缩写为NLP', 2.00, 1, 114),
(4727, 112, 1, '过拟合是指模型', '{"A": "在训练集上表现差", "B": "在训练集和测试集上都表现差", "C": "在训练集上表现好但测试集上表现差", "D": "在测试集上表现好但训练集上表现差"}', 'C', '过拟合指模型过度学习训练数据的噪声，导致在新数据上泛化能力差', 2.00, 1, 114),
(4728, 112, 1, '梯度下降法是一种常用的', '{"A": "分类算法", "B": "聚类算法", "C": "优化算法", "D": "搜索算法"}', 'C', '梯度下降法是一种迭代优化算法，用于最小化损失函数', 2.00, 1, 114),
(4729, 112, 1, 'K-Means算法属于', '{"A": "监督学习", "B": "无监督学习", "C": "强化学习", "D": "半监督学习"}', 'B', 'K-Means是典型的无监督聚类算法，不需要标签数据', 2.00, 1, 114),
(4730, 112, 1, '以下哪个是生成式AI模型', '{"A": "SVM", "B": "KNN", "C": "GPT", "D": "Random Forest"}', 'C', 'GPT（Generative Pre-trained Transformer）是典型的生成式AI模型', 2.00, 1, 114),
(4731, 112, 1, '反向传播算法主要用于', '{"A": "数据预处理", "B": "特征提取", "C": "神经网络权重更新", "D": "模型部署"}', 'C', '反向传播（Backpropagation）通过链式法则计算梯度来更新神经网络权重', 2.00, 2, 114),
(4732, 112, 1, '在卷积神经网络中，池化层的主要作用是', '{"A": "增加参数数量", "B": "降低特征维度", "C": "增加非线性", "D": "数据增强"}', 'B', '池化层通过下采样操作降低特征图维度，减少计算量并防止过拟合', 2.00, 2, 114),
(4733, 112, 1, 'Transformer模型的核心机制是', '{"A": "卷积操作", "B": "循环连接", "C": "自注意力机制", "D": "池化操作"}', 'C', 'Transformer的核心创新是Self-Attention（自注意力）机制', 2.00, 2, 114),
(4734, 112, 1, '在贝叶斯分类中，''朴素''的含义是', '{"A": "算法简单", "B": "假设特征之间相互独立", "C": "只适用于小数据集", "D": "不需要训练过程"}', 'B', '朴素贝叶斯中的''朴素''指假设所有特征之间条件独立', 3.00, 2, 114),
(4735, 112, 1, 'LSTM网络相比普通RNN的主要优势是', '{"A": "训练速度更快", "B": "参数更少", "C": "能更好地处理长距离依赖问题", "D": "不需要激活函数"}', 'C', 'LSTM通过门控机制（遗忘门、输入门、输出门）解决了RNN的梯度消失问题，能捕获长距离依赖', 3.00, 2, 114),
(4736, 112, 2, '以下哪些属于人工智能的主要研究领域', '{"A": "机器学习", "B": "自然语言处理", "C": "计算机视觉", "D": "操作系统管理"}', 'ABC', '机器学习、NLP、计算机视觉是AI的核心研究领域，操作系统管理属于系统软件范畴', 3.00, 1, 114),
(4737, 112, 2, '以下哪些是常用的激活函数', '{"A": "ReLU", "B": "Sigmoid", "C": "Tanh", "D": "Adam"}', 'ABC', 'ReLU、Sigmoid、Tanh都是常用激活函数，Adam是优化器不是激活函数', 3.00, 1, 114),
(4738, 112, 2, '机器学习按学习方式可分为', '{"A": "监督学习", "B": "无监督学习", "C": "强化学习", "D": "被动学习"}', 'ABC', '机器学习的三大类型是监督学习、无监督学习和强化学习', 3.00, 1, 114),
(4739, 112, 2, '以下哪些是深度学习常用的框架', '{"A": "TensorFlow", "B": "PyTorch", "C": "MySQL", "D": "Keras"}', 'ABD', 'TensorFlow、PyTorch、Keras是主流深度学习框架，MySQL是数据库', 3.00, 1, 114),
(4740, 112, 2, '卷积神经网络（CNN）通常包含哪些层', '{"A": "卷积层", "B": "池化层", "C": "全连接层", "D": "嵌入层"}', 'ABC', 'CNN的典型结构包括卷积层、池化层和全连接层，嵌入层主要用于NLP', 3.00, 2, 114),
(4741, 112, 2, '以下哪些方法可以防止过拟合', '{"A": "正则化", "B": "Dropout", "C": "增加训练数据", "D": "增加模型复杂度"}', 'ABC', '正则化、Dropout、数据增强都能防止过拟合，增加模型复杂度反而加重过拟合', 3.00, 2, 114),
(4742, 112, 2, '自然语言处理的应用包括', '{"A": "机器翻译", "B": "情感分析", "C": "文本摘要", "D": "图像分割"}', 'ABC', '机器翻译、情感分析、文本摘要都是NLP应用，图像分割属于计算机视觉', 3.00, 2, 114),
(4743, 112, 2, '以下哪些属于无监督学习算法', '{"A": "K-Means", "B": "DBSCAN", "C": "主成分分析", "D": "逻辑回归"}', 'ABC', 'K-Means、DBSCAN是聚类算法，PCA是降维算法，都属于无监督学习；逻辑回归是监督学习', 3.00, 2, 114),
(4744, 112, 2, '以下关于梯度下降的说法正确的是', '{"A": "学习率过大可能导致震荡", "B": "学习率过小会导致收敛缓慢", "C": "批量梯度下降使用全部样本计算梯度", "D": "随机梯度下降每次使用全部样本"}', 'ABC', 'SGD每次只用一个样本，不是全部样本', 3.00, 2, 114),
(4745, 112, 2, '以下哪些是循环神经网络（RNN）的变体', '{"A": "LSTM", "B": "GRU", "C": "ResNet", "D": "Bi-RNN"}', 'ABD', 'LSTM、GRU、双向RNN都是RNN的变体，ResNet是CNN的变体', 3.00, 2, 114),
(4746, 112, 2, '决策树算法中常用的特征选择准则包括', '{"A": "信息增益", "B": "基尼系数", "C": "均方误差", "D": "欧氏距离"}', 'ABC', '信息增益（ID3）、基尼系数（CART）、均方误差（回归树）都是决策树的划分准则', 3.00, 2, 114),
(4747, 112, 2, '以下关于Transformer的说法正确的是', '{"A": "采用自注意力机制", "B": "可以并行化训练", "C": "完全摒弃了循环结构", "D": "只能用于文本任务"}', 'ABC', 'Transformer采用自注意力、支持并行训练、无循环结构，但也可用于视觉等任务（如ViT）', 3.00, 2, 114),
(4748, 112, 2, '以下哪些属于强化学习的关键概念', '{"A": "状态", "B": "奖励", "C": "策略", "D": "标签"}', 'ABC', '状态（State）、奖励（Reward）、策略（Policy）是强化学习核心概念，标签属于监督学习', 3.00, 2, 114),
(4749, 112, 2, '以下哪些评估指标常用于分类任务', '{"A": "准确率", "B": "精确率", "C": "召回率", "D": "均方误差"}', 'ABC', '准确率、精确率、召回率用于分类评估，均方误差用于回归评估', 3.00, 2, 114),
(4750, 112, 2, '以下哪些技术用于处理序列数据', '{"A": "RNN", "B": "LSTM", "C": "Transformer", "D": "CNN"}', 'ABC', 'RNN、LSTM、Transformer都擅长处理序列数据，CNN主要处理空间数据（虽然1D-CNN也可处理序列）', 3.00, 2, 114),
(4751, 112, 2, '神经网络训练中常用的优化器包括', '{"A": "SGD", "B": "Adam", "C": "RMSProp", "D": "Softmax"}', 'ABC', 'SGD、Adam、RMSProp都是优化器，Softmax是激活函数', 3.00, 2, 114),
(4752, 112, 2, '以下哪些属于生成式AI的应用', '{"A": "文本生成", "B": "图像生成", "C": "语音合成", "D": "垃圾邮件分类"}', 'ABC', '文本生成、图像生成、语音合成都是生成式AI应用，垃圾邮件分类是判别式任务', 3.00, 2, 114),
(4753, 112, 2, '以下关于注意力机制的说法正确的是', '{"A": "Query、Key、Value是其核心组成", "B": "多头注意力可以关注不同子空间", "C": "自注意力计算复杂度与序列长度平方成正比", "D": "注意力机制只能用于NLP任务"}', 'ABC', 'QKV是注意力核心，多头注意力并行关注不同信息，复杂度O(n²)，但注意力也可用于CV等领域', 3.00, 3, 114),
(4754, 112, 2, '以下关于GAN（生成对抗网络）的说法正确的是', '{"A": "由生成器和判别器组成", "B": "训练过程是一个博弈过程", "C": "生成器试图生成逼真数据", "D": "判别器的目标是生成数据"}', 'ABC', 'GAN由生成器G和判别器D组成，G生成假数据、D判别真假，两者博弈训练', 3.00, 3, 114),
(4755, 112, 2, '以下关于正则化的说法正确的是', '{"A": "L1正则化可以产生稀疏解", "B": "L2正则化倾向于使权重接近零但不为零", "C": "Dropout在测试时也随机丢弃神经元", "D": "Early Stopping也是一种正则化方法"}', 'ABD', 'Dropout在测试时不丢弃神经元，而是使用所有神经元并缩放权重', 3.00, 3, 114),
(4756, 112, 3, '人工智能就是让机器完全模拟人类大脑', NULL, '错误', '人工智能不要求完全模拟人脑，而是让机器具备某些智能行为能力', 2.00, 1, 114),
(4757, 112, 3, '监督学习需要带标签的训练数据', NULL, '正确', '监督学习通过标注数据（输入-输出对）来训练模型', 2.00, 1, 114),
(4758, 112, 3, '深度学习中的''深度''指的是神经网络的层数多', NULL, '正确', '深度学习的''深度''指神经网络具有多个隐藏层', 2.00, 1, 114),
(4759, 112, 3, '机器学习模型一旦训练完成就不需要更新', NULL, '错误', '随着数据分布变化，模型可能需要定期重新训练或更新', 2.00, 1, 114),
(4760, 112, 3, '聚类算法属于无监督学习', NULL, '正确', '聚类是典型的无监督学习方法，不需要标签数据', 2.00, 1, 114),
(4761, 112, 3, 'ReLU激活函数的输出值范围是0到正无穷', NULL, '正确', 'ReLU(x) = max(0, x)，输出范围为[0, +∞)', 2.00, 1, 114),
(4762, 112, 3, '训练数据越多，模型性能一定越好', NULL, '错误', '数据质量比数量更重要，噪声数据过多反而会降低模型性能', 2.00, 1, 114),
(4763, 112, 3, '卷积神经网络（CNN）主要用于处理图像数据', NULL, '正确', 'CNN通过卷积操作提取空间特征，特别适合图像处理任务', 2.00, 1, 114),
(4764, 112, 3, 'Python是目前人工智能开发中最常用的编程语言', NULL, '正确', 'Python拥有丰富的AI库（TensorFlow、PyTorch等），是AI开发的首选语言', 2.00, 1, 114),
(4765, 112, 3, '强化学习中的奖励信号总是正数', NULL, '错误', '强化学习中的奖励可以是正数（奖励）也可以是负数（惩罚）', 2.00, 1, 114),
(4766, 112, 3, 'GPT是一种基于Transformer架构的语言模型', NULL, '正确', 'GPT（Generative Pre-trained Transformer）基于Transformer的解码器架构', 2.00, 1, 114),
(4767, 112, 3, '人工智能和机器学习是完全相同的概念', NULL, '错误', '机器学习是人工智能的一个子领域，AI的范围更广', 2.00, 1, 114),
(4768, 112, 3, '特征工程是机器学习中非常重要的步骤', NULL, '正确', '特征工程直接影响模型性能，好的特征往往比复杂的模型更重要', 2.00, 1, 114),
(4769, 112, 3, 'Batch Normalization可以加速神经网络的训练过程', NULL, '正确', 'BN通过标准化每层输入使训练更稳定，允许使用更大学习率从而加速训练', 2.00, 2, 114),
(4770, 112, 3, '在分类问题中，准确率越高模型一定越好', NULL, '错误', '在类别不平衡时，准确率可能具有误导性，需要结合精确率、召回率、F1等指标综合评估', 2.00, 2, 114),
(4771, 112, 3, '卷积操作中，步长越大输出特征图的尺寸越小', NULL, '正确', '步长（stride）增大会减少卷积滑动次数，导致输出特征图尺寸减小', 2.00, 2, 114),
(4772, 112, 3, 'Word2Vec可以将单词映射为固定维度的向量', NULL, '正确', 'Word2Vec通过CBOW或Skip-gram模型将每个单词映射为一个固定维度的密集向量', 2.00, 2, 114),
(4773, 112, 3, '梯度消失问题只会出现在深层神经网络中', NULL, '错误', '梯度消失也可能出现在较浅的网络中，特别是使用Sigmoid等饱和激活函数时', 2.00, 2, 114),
(4774, 112, 3, '迁移学习可以将一个任务上学到的知识应用到另一个任务', NULL, '正确', '迁移学习通过复用预训练模型的知识来加速新任务的学习', 2.00, 2, 114),
(4775, 112, 3, '交叉熵损失函数常用于回归任务', NULL, '错误', '交叉熵损失函数常用于分类任务，回归任务通常使用均方误差等损失函数', 2.00, 2, 114),
(4776, 112, 4, '人工智能的英文全称是____', NULL, 'Artificial Intelligence', 'AI的全称是Artificial Intelligence（人工智能）', 2.00, 1, 114),
(4777, 112, 4, '机器学习的三大类型是监督学习、无监督学习和____', NULL, '强化学习', '机器学习三大类型：监督学习、无监督学习、强化学习', 2.00, 1, 114),
(4778, 112, 4, '神经网络中最基本的计算单元称为____', NULL, '神经元', '神经元（Neuron）是神经网络的基本计算单元', 3.00, 1, 114),
(4779, 112, 4, 'CNN的全称是____神经网络', NULL, '卷积', 'CNN = Convolutional Neural Network，即卷积神经网络', 3.00, 1, 114),
(4780, 112, 4, '深度学习中，通过____算法来更新网络权重', NULL, '反向传播', '反向传播（Backpropagation）是深度学习中更新权重的核心算法', 3.00, 1, 114),
(4781, 112, 4, 'RNN的全称是____神经网络', NULL, '循环', 'RNN = Recurrent Neural Network，即循环神经网络', 3.00, 1, 114),
(4782, 112, 4, '在神经网络中，____函数用于引入非线性变换', NULL, '激活', '激活函数（Activation Function）为神经网络引入非线性', 3.00, 1, 114),
(4783, 112, 4, 'K-Means算法中的K代表____的数量', NULL, '聚类中心', 'K-Means中K是预设的聚类簇数', 3.00, 1, 114),
(4784, 112, 4, '在模型评估中，F1分数是____和____的调和平均', NULL, '精确率和召回率', 'F1 = 2 × (Precision × Recall) / (Precision + Recall)', 3.00, 1, 114),
(4785, 112, 4, '防止神经网络过拟合的常用技术____会随机丢弃部分神经元', NULL, 'Dropout', 'Dropout在训练时随机将部分神经元置零，防止过拟合', 3.00, 1, 114),
(4786, 112, 4, 'GAN由生成器和____两部分组成', NULL, '判别器', 'GAN = 生成对抗网络，由生成器（Generator）和判别器（Discriminator）组成', 3.00, 1, 114),
(4787, 112, 4, '用于判断机器是否具有智能的经典测试方法称为____', NULL, '图灵测试', '图灵测试（Turing Test）是艾伦·图灵提出的判断机器智能的方法', 3.00, 1, 114),
(4788, 112, 4, '自然语言处理的英文缩写是____', NULL, 'NLP', 'NLP = Natural Language Processing', 3.00, 1, 114),
(4789, 112, 4, '在梯度下降中，控制每次参数更新幅度的超参数称为____', NULL, '学习率', '学习率（Learning Rate）决定了每次参数更新的步长', 3.00, 1, 114),
(4790, 112, 4, '将预训练模型应用到新任务上的方法称为____学习', NULL, '迁移', '迁移学习（Transfer Learning）复用预训练模型的知识', 3.00, 1, 114),
(4791, 112, 4, 'Transformer模型中的核心机制是____机制', NULL, '自注意力', 'Self-Attention（自注意力）是Transformer的核心创新', 3.00, 2, 114),
(4792, 112, 4, 'LSTM中用于控制信息流动的三个门是输入门、输出门和____', NULL, '遗忘门', 'LSTM的三个门：遗忘门（forget gate）、输入门（input gate）、输出门（output gate）', 3.00, 2, 114),
(4793, 112, 4, '在神经网络中，____问题是指梯度在反向传播过程中逐渐趋近于零', NULL, '梯度消失', '梯度消失（Vanishing Gradient）导致深层网络难以训练', 3.00, 2, 114),
(4794, 112, 4, 'Word2Vec的两种训练模式是CBOW和____', NULL, 'Skip-gram', 'Word2Vec有CBOW（连续词袋）和Skip-gram两种模型', 3.00, 2, 114),
(4795, 112, 4, '在目标检测任务中，IoU是指两个边界框的____', NULL, '交并比', 'IoU = Intersection over Union（交并比），衡量预测框与真实框的重叠程度', 3.00, 2, 114),
(4796, 112, 5, '请简述监督学习和无监督学习的区别', NULL, '监督学习：使用带标签的数据进行训练，目标是学习输入到输出的映射关系，常见任务包括分类和回归，如决策树、SVM等。无监督学习：使用无标签数据，目标是发现数据中的内在结构和模式，常见任务包括聚类和降维，如K-Means、PCA等。主要区别在于是否需要标注数据。', '应从数据标注、学习目标、典型任务和算法等方面进行对比', 5.00, 2, 114),
(4797, 112, 5, '请解释什么是过拟合，并列举至少三种防止过拟合的方法', NULL, '过拟合是指模型在训练数据上表现很好，但在新数据上表现较差的现象，即模型记住了训练数据中的噪声而非真正的规律。防止过拟合的方法：1. 正则化（L1/L2）：在损失函数中添加惩罚项限制模型复杂度；2. Dropout：训练时随机丢弃部分神经元；3. 增加训练数据或数据增强；4. Early Stopping：在验证集性能开始下降时停止训练；5. 交叉验证：更稳健地评估模型泛化能力。', '需要解释过拟合概念并列举具体防止方法', 5.00, 2, 114),
(4798, 112, 5, '请简述卷积神经网络（CNN）的基本结构及各层作用', NULL, 'CNN的基本结构包括：1. 输入层：接收原始图像数据；2. 卷积层：通过卷积核（滤波器）提取局部特征，如边缘、纹理等；3. 激活层：通常使用ReLU函数引入非线性；4. 池化层：通过下采样降低特征维度，减少计算量，常用最大池化和平均池化；5. 全连接层：将提取的特征映射到最终的输出类别；6. 输出层：使用Softmax等函数输出分类概率。CNN通过权值共享和局部连接大幅减少参数数量。', '应描述CNN的层次结构及每层的功能', 5.00, 2, 114),
(4799, 112, 5, '请解释梯度下降算法的基本原理', NULL, '梯度下降是一种迭代优化算法，用于最小化损失函数。基本原理：1. 初始化模型参数；2. 计算损失函数对每个参数的偏导数（梯度），梯度方向是函数值增大最快的方向；3. 沿梯度的反方向更新参数：θ = θ - α∇J(θ)，其中α是学习率；4. 重复上述过程直到收敛。常见变体：批量梯度下降（使用全部样本）、随机梯度下降SGD（使用单个样本）、小批量梯度下降（使用部分样本）。', '应说明梯度下降的原理、更新公式和常见变体', 5.00, 2, 114),
(4800, 112, 5, '请简述强化学习的基本框架和核心概念', NULL, '强化学习的基本框架：智能体（Agent）在环境（Environment）中通过执行动作（Action）、观察状态（State）和获取奖励（Reward）来学习最优策略（Policy）。核心概念：1. 状态（State）：环境的当前描述；2. 动作（Action）：智能体可执行的操作；3. 奖励（Reward）：环境对动作的反馈信号；4. 策略（Policy）：状态到动作的映射；5. 价值函数（Value Function）：评估状态或状态-动作对的长期收益。目标是找到使累计奖励最大化的最优策略。', '应描述强化学习框架和关键术语', 5.00, 2, 114),
(4801, 112, 5, '请解释什么是迁移学习及其优势', NULL, '迁移学习是将在一个任务（源任务）上训练好的模型知识，迁移到另一个相关任务（目标任务）上的方法。优势：1. 减少对大量标注数据的需求，在小数据集上也能取得好效果；2. 缩短训练时间，因为预训练模型已学到通用特征；3. 提升模型性能，利用大规模数据预训练的特征表示；4. 降低计算成本。常见做法：使用在ImageNet上预训练的CNN模型作为特征提取器，或在预训练模型基础上微调（Fine-tuning）适应新任务。', '应说明迁移学习的定义、优势和常见实践', 5.00, 2, 114),
(4802, 112, 5, '请说明精确率、召回率和F1分数的含义及计算方式', NULL, '精确率（Precision）= TP/(TP+FP)，表示预测为正类的样本中实际为正类的比例，衡量预测的准确性。召回率（Recall）= TP/(TP+FN)，表示实际正类样本中被正确预测的比例，衡量对正类的覆盖程度。F1分数 = 2×Precision×Recall/(Precision+Recall)，是精确率和召回率的调和平均，综合衡量模型性能。其中TP=真正例，FP=假正例，FN=假反例。在类别不平衡场景中，F1比准确率更有参考价值。', '需要给出三个指标的定义和计算公式', 5.00, 2, 114),
(4803, 112, 5, '请详细解释Transformer模型的自注意力机制的工作原理', NULL, '自注意力机制（Self-Attention）的工作原理：1. 对输入序列的每个位置生成三个向量：Query(Q)、Key(K)、Value(V)，通过线性变换得到；2. 计算注意力权重：将Q与所有K做点积，除以√d_k进行缩放，再通过Softmax归一化得到权重；3. 加权求和：用注意力权重对V进行加权求和，得到每个位置的输出。公式：Attention(Q,K,V) = Softmax(QK^T/√d_k)V。多头注意力（Multi-Head Attention）是将QKV分成多组并行计算注意力再拼接，使模型能关注不同位置和子空间的信息。优势：可以捕获任意距离的依赖关系，且支持并行计算。', '需要详细说明QKV的计算过程和注意力公式', 5.00, 3, 114),
(4804, 112, 5, '请比较GAN和VAE两种生成模型的原理及优缺点', NULL, 'GAN（生成对抗网络）：由生成器G和判别器D博弈训练，G生成假数据欺骗D，D判别真假数据。优点：生成质量高、图像清晰；缺点：训练不稳定、可能出现模式崩溃。VAE（变分自编码器）：基于概率模型，由编码器将数据映射到潜在空间分布，解码器从潜在空间采样重建数据，通过最大化变分下界（ELBO）训练。优点：训练稳定、可以学习有意义的潜在表示；缺点：生成图像可能较模糊。对比：GAN生成质量更高但训练更难，VAE理论更完善但生成质量稍差。两者也可结合使用（如VAE-GAN）。', '需要分别说明两种模型的原理并进行对比分析', 5.00, 3, 114),
(4805, 112, 5, '请解释LSTM如何解决普通RNN的梯度消失问题', NULL, '普通RNN在处理长序列时，梯度在反向传播过程中经过多次连乘会趋近于零（梯度消失）或无穷大（梯度爆炸），导致无法学习长距离依赖。LSTM通过引入门控机制解决该问题：1. 遗忘门（Forget Gate）：决定从细胞状态中丢弃哪些信息，f_t = σ(W_f·[h_{t-1},x_t] + b_f)；2. 输入门（Input Gate）：决定向细胞状态中添加哪些新信息，i_t = σ(W_i·[h_{t-1},x_t] + b_i)；3. 细胞状态更新：C_t = f_t⊙C_{t-1} + i_t⊙tanh(W_C·[h_{t-1},x_t] + b_C)；4. 输出门（Output Gate）：决定输出哪些信息。关键在于细胞状态的更新是加法操作而非乘法，梯度可以不衰减地流过多个时间步，从而有效缓解梯度消失问题。', '需要说明RNN梯度消失原因以及LSTM各门的工作机制', 5.00, 3, 114),
(4806, 112, 1, '人工智能(AI)的概念最早提出于', '{"A": "1956 年达特茅斯会议", "B": "1950 年图灵测试", "C": "1980 年专家系统", "D": "2012 年深度学习"}', 'A', '1956 达特茅斯会议', 2.00, 2, 114),
(4807, 112, 1, '图灵测试由谁提出', '{"A": "图灵", "B": "麦卡锡", "C": "明斯基", "D": "纽厄尔"}', 'A', '1950 年 Alan Turing 提出', 2.00, 2, 114),
(4808, 112, 1, '下列哪个是图灵测试的判断标准', '{"A": "机器能否欺骗人类", "B": "机器能否计算", "C": "机器能否记忆", "D": "机器能否搜索"}', 'A', '图灵测试看交互模仿能力', 2.00, 2, 114),
(4809, 112, 1, '下列哪个不是 AI 三大学派', '{"A": "符号主义", "B": "连接主义", "C": "行为主义", "D": "结构主义"}', 'D', 'AI 三大学派', 2.00, 3, 114),
(4810, 112, 1, '符号主义的核心是', '{"A": "逻辑推理", "B": "神经网络", "C": "进化", "D": "感知"}', 'A', '符号主义=逻辑', 2.00, 2, 114),
(4811, 112, 1, '连接主义的核心是', '{"A": "神经网络", "B": "逻辑", "C": "规则", "D": "知识"}', 'A', '连接主义=神经网络', 2.00, 2, 114),
(4812, 112, 1, '行为主义的核心是', '{"A": "感知-行动", "B": "逻辑", "C": "规则", "D": "知识"}', 'A', '行为主义=感知行动', 2.00, 3, 114),
(4813, 112, 1, '下列哪个是 AI 的弱定义', '{"A": "完成特定任务的智能", "B": "通用智能", "C": "拟人智能", "D": "数学智能"}', 'A', 'Weak AI = 特定任务', 2.00, 2, 114),
(4814, 112, 1, 'AGI 表示', '{"A": "通用人工智能", "B": "专用人工智能", "C": "弱人工智能", "D": "数据人工智能"}', 'A', 'AGI: Artificial General Intelligence', 2.00, 2, 114),
