(4997, 112, 5, '简述人工智能的定义', NULL, 'AI(Artificial Intelligence)是研究、开发用于模拟、延伸和扩展人智能的理论、方法、技术及应用系统的学科。AI 让机器具备认知能力,如学习、推理、感知、规划、决策、语言理解等。AI 分为弱 AI(完成特定任务)和强 AI/AGI(通用智能,接近人类水平)。AI 是计算机科学的一个分支,与机器学习、深度学习关系密切:DL ⊂ ML ⊂ AI。', 'AI 定义', 5.00, 2, 114),
(4998, 112, 5, '简述图灵测试', NULL, '图灵测试由 Alan Turing 在 1950 年论文 ''Computing Machinery and Intelligence'' 中提出。测试方式:让人类裁判与机器和另一个人通过文本对话,若裁判不能可靠区分对方是人还是机器,则机器通过测试,可认为具有智能。意义:1)首次给智能下了可操作的判断标准;2)开启了 AI 哲学的讨论;3)避免直接定义''思考''的难题。批评:只关注语言模仿,忽视感知/运动等智能形式。', '图灵测试', 5.00, 2, 114),
(4999, 112, 5, '简述 AI 三大学派', NULL, 'AI 三大学派:1)符号主义(Symbolism):基于物理符号系统假设,通过逻辑推理和符号操作实现智能,代表:专家系统、谓词逻辑、定理证明。2)连接主义(Connectionism):模拟人脑神经网络,通过大量神经元的连接和权重实现智能,代表:神经网络、深度学习。3)行为主义(Behaviorism):基于感知-行动循环,通过与环境交互实现智能,代表:进化算法、机器人学、强化学习。三派各有侧重,现代 AI 倾向融合。', 'AI 三大学派', 5.00, 2, 114),
(5000, 112, 5, '简述机器学习的三大类型', NULL, '1)监督学习(Supervised):有标签数据,学习输入到输出的映射,典型任务:分类(逻辑回归、SVM、决策树)、回归(线性回归);2)无监督学习(Unsupervised):无标签,发现数据结构,典型任务:聚类(K-Means、DBSCAN)、降维(PCA、t-SNE)、关联规则(Apriori);3)强化学习(Reinforcement):通过试错和奖励学习最优策略,典型算法:Q-Learning、DQN、Policy Gradient。半监督学习介于监督和无监督之间。', 'ML 类型', 5.00, 2, 114),
(5001, 112, 5, '简述监督学习的工作流程', NULL, '监督学习流程:1)数据收集:获取有标签数据集;2)数据预处理:清洗、缺失值填充、归一化、特征工程;3)划分数据:训练集/验证集/测试集(常 8:1:1);4)选择模型:根据任务选(分类:逻辑回归/SVM/树;回归:线性/树/NN);5)训练模型:用训练集学习参数,用损失函数衡量误差;6)调参:用验证集调超参;7)评估:用测试集评估指标(准确率、F1、AUC、MSE);8)部署:上线服务。', '监督学习流程', 5.00, 2, 114),
(5002, 112, 5, '简述决策树算法及其划分标准', NULL, '决策树通过递归地把样本按特征划分到子集,构造一棵树进行分类/回归。三种经典算法:1)ID3:用信息增益(熵)选最优属性,但偏向多值属性;2)C4.5:用信息增益率,克服 ID3 偏置,支持连续属性;3)CART:用基尼系数(分类)或方差(回归),生成二叉树。优点:可解释性强、不需归一化、能处理混合类型。缺点:易过拟合(用剪枝/集成解决)。', '决策树', 5.00, 3, 114),
(5003, 112, 5, '简述集成学习的三大方法', NULL, '集成学习通过组合多个弱学习器获得更强模型:1)Bagging(并行):并行训练多个模型(在 Bootstrap 采样的子集上),最后投票/平均。代表:Random Forest。优点:降低方差。2)Boosting(串行):按顺序训练模型,后模型关注前模型的错误。代表:AdaBoost、GBDT、XGBoost、LightGBM。优点:降低偏差。3)Stacking:用多个不同模型的输出作为新特征,训练元模型。常在比赛中获胜方案。', '集成学习', 5.00, 3, 114),
(5004, 112, 5, '简述深度学习与传统机器学习的区别', NULL, '1)特征工程:传统 ML 需手工特征;DL 端到端自动学习特征;2)数据需求:DL 需大量数据(百万级);ML 数据少也能用;3)硬件:DL 需 GPU/TPU;ML CPU 即可;4)可解释性:ML(树/线性)强;DL 弱(黑箱);5)适用任务:DL 在 CV/NLP/语音上突破;ML 在结构化数据(表格)仍有优势;6)训练时间:DL 长;ML 短;7)调参:DL 复杂(网络结构、学习率等);ML 简单。', 'DL vs ML', 5.00, 2, 114),
(5005, 112, 5, '简述 CNN 的核心思想和典型结构', NULL, 'CNN(卷积神经网络)针对图像设计:1)核心思想:①局部感受野(Local Receptive Field):每个神经元只看局部;②权值共享(Weight Sharing):同一卷积核在不同位置共享参数,大幅减少参数;③池化(Pooling):降维并提供平移不变性。2)典型结构:输入→[卷积+ReLU+池化]×N→展平→全连接→Softmax 输出。3)经典模型:LeNet、AlexNet、VGG、GoogLeNet、ResNet(残差连接解决深度退化)。', 'CNN', 5.00, 3, 114),
(5006, 112, 5, '简述 RNN 及其变体', NULL, 'RNN(循环神经网络)处理序列数据,神经元有循环连接,记忆历史:h_t = f(W·x_t + U·h_{t-1})。问题:长序列梯度消失/爆炸。变体:1)LSTM(长短期记忆):用三个门(输入门、遗忘门、输出门)和细胞状态,有效缓解梯度消失,擅长长序列;2)GRU(门控循环单元):简化的 LSTM,只有更新门和重置门,参数少;3)BiRNN:双向 RNN,同时考虑前后文;4)Seq2Seq:编码器-解码器结构,用于机器翻译。现在被 Transformer 部分取代。', 'RNN 变体', 5.00, 3, 114),
(5007, 112, 5, '简述 Transformer 架构', NULL, 'Transformer 由 Vaswani 等于 2017 年提出 (''Attention is All You Need''),完全基于注意力机制。1)核心机制:自注意力(Self-Attention),Q/K/V 矩阵实现序列内任意位置的关联;2)结构:Encoder-Decoder,各 6 层。每层:多头注意力 + Add&Norm + 前馈网络 + Add&Norm;3)位置编码:用三角函数注入位置信息;4)优势:并行计算、长距离依赖;5)衍生:BERT(只用 Encoder)、GPT(只用 Decoder)、T5(Encoder-Decoder)。改变了 NLP 乃至 CV/语音格局。', 'Transformer', 5.00, 3, 114),
(5008, 112, 5, '简述 BERT 与 GPT 的区别', NULL, '1)架构:BERT 用 Transformer Encoder(双向);GPT 用 Decoder(单向自回归)。2)预训练任务:BERT 用 MLM(Masked Language Model)+ NSP;GPT 用自回归语言模型(预测下一词)。3)适用任务:BERT 适合理解任务(分类、问答、NER);GPT 适合生成任务(对话、写作)。4)规模:BERT 参数较小(110M-340M);GPT 系列从 117M 到 GPT-4 数千亿参数。5)使用方式:BERT fine-tune;GPT 大模型用 prompt。', 'BERT vs GPT', 5.00, 3, 114),
(5009, 112, 5, '简述深度学习的反向传播算法', NULL, '反向传播(Backpropagation,BP)是训练神经网络的核心算法。流程:1)前向传播:输入经过各层得到输出和损失;2)计算损失对输出的梯度;3)反向传播:从输出层逐层向输入层应用链式法则,计算每层参数对损失的梯度;4)参数更新:用梯度下降更新参数 w ← w - η·∂L/∂w。优势:利用计算图共享中间结果,效率高 O(网络规模)。框架(TensorFlow/PyTorch)用自动微分实现。', '反向传播', 5.00, 3, 114),
(5010, 112, 5, '简述梯度下降及其变种', NULL, '梯度下降:沿负梯度方向更新参数,θ ← θ - η·∇L(θ)。变种:1)BGD(批量):用全部数据计算梯度,精确但慢;2)SGD(随机):每次一个样本,快但震荡;3)Mini-batch GD:折中,常用,batch_size=32~256;4)动量法(Momentum):累积历史梯度方向,加速收敛;5)Adagrad:每个参数自适应学习率;6)RMSprop:Adagrad 改进,指数移动平均;7)Adam:综合动量和 RMSprop,最常用,默认 lr=0.001。', '梯度下降', 5.00, 3, 114),
(5011, 112, 5, '简述过拟合及其解决方法', NULL, '过拟合:模型在训练集表现好,在测试集表现差,记住了噪声而非规律。原因:模型复杂、数据少。解决方法:1)增加数据:数据增强(图像翻转/裁剪)、合成数据;2)正则化:L1(稀疏)、L2(权重衰减);3)Dropout:训练时随机失活神经元;4)Early Stopping:验证集 loss 不再下降时停止;5)简化模型:减少层数/神经元;6)集成学习:多模型平均;7)BatchNorm:稳定训练;8)交叉验证:充分利用数据。', '过拟合', 5.00, 3, 114),
(5012, 112, 5, '简述强化学习', NULL, '强化学习(RL)让 Agent 在环境中通过试错学习最优策略以最大化累积奖励。五要素:Agent、Environment、State、Action、Reward。马尔可夫决策过程(MDP)是其数学框架。算法分类:1)Value-based:Q-Learning、DQN(深度 Q 网络);2)Policy-based:Policy Gradient、REINFORCE;3)Actor-Critic:A2C、A3C、PPO 等。应用:AlphaGo(围棋)、Atari 游戏、机器人、自动驾驶、ChatGPT 的 RLHF。', '强化学习', 5.00, 3, 114),
(5013, 112, 5, '简述生成式 AI', NULL, '生成式 AI 通过学习训练数据分布,生成类似的新数据。1)文本生成:GPT 系列(ChatGPT)、LLaMA、Claude;2)图像生成:Stable Diffusion、DALL-E、Midjourney;3)语音生成:VITS、Tacotron;4)视频生成:Sora、Runway;5)代码生成:Copilot、Cursor。底层技术:Transformer(LLM)、扩散模型(图像)、GAN。生成式 AI 是 AI 的重要新方向,带来产业变革,也引发伦理(深度伪造、版权等)讨论。', '生成式 AI', 5.00, 2, 114),
(5014, 112, 5, '简述 NLP 的主要任务', NULL, 'NLP(自然语言处理)主要任务:1)分词/词性标注;2)命名实体识别(NER):识别人名、地名、组织;3)文本分类:情感分析、垃圾邮件检测;4)机器翻译:中英互译;5)问答系统:阅读理解、知识问答;6)文本摘要:抽取式/生成式;7)对话系统:聊天机器人、智能助手;8)语言模型:预测下一词,LLM 基础;9)文本生成:写作、续写。当前主流方法:基于 Transformer 的预训练大模型 + Fine-tune 或 Prompt。', 'NLP 任务', 5.00, 2, 114),
(5015, 112, 5, '简述 CV 的主要任务', NULL, 'CV(计算机视觉)主要任务:1)图像分类:识别图像类别;2)目标检测:定位+分类(YOLO、R-CNN);3)图像分割:像素级分类(语义分割、实例分割,U-Net、Mask R-CNN);4)人脸识别:身份验证;5)关键点检测:姿态估计;6)图像生成:GAN、Stable Diffusion;7)图像描述:Image Captioning;8)OCR:文字识别;9)视频分析:动作识别、视频理解;10)自动驾驶感知:车道线、目标、深度。主流模型:CNN(ResNet)、Vision Transformer(ViT)。', 'CV 任务', 5.00, 2, 114),
(5016, 112, 5, '简述 AI 伦理问题', NULL, 'AI 伦理涉及多方面问题:1)算法歧视/公平性:训练数据偏见导致歧视(性别、种族);2)隐私泄露:大模型可能记忆并泄露训练数据;3)可解释性:深度学习黑箱难以解释决策;4)责任归属:自动驾驶事故责任谁负;5)就业冲击:替代部分白领工作;6)虚假信息:深度伪造、AI 生成假新闻;7)军事化:AI 武器自主决策;8)版权:训练数据使用、生成内容归属。需要多方共治:技术、法律、伦理、监管协同。', 'AI 伦理', 5.00, 2, 114);
INSERT INTO exam_question (id, subject_id, question_type, content, options, answer, analysis, score, difficulty, creator_id) VALUES
(5017, 113, 1, '「私___学生です。」の___に入る正しい助詞は？', '{"A": "を", "B": "に", "C": "は", "D": "が"}', 'C', '「は」は主題を表す助詞、「私は学生です」(我是学生)', 2.00, 1, 106),
(5018, 113, 1, '「本___読みます。」の___に入る正しい助詞は？', '{"A": "が", "B": "を", "C": "に", "D": "へ"}', 'B', '「を」は他動詞の対象を示す目的格助詞', 2.00, 1, 106),
(5019, 113, 1, '「学校___行きます。」の___に入る適切な助詞は？', '{"A": "を", "B": "へ", "C": "が", "D": "も"}', 'B', '「へ」は方向を表す助詞；「に」も可だが「へ」が方向の典型', 2.00, 1, 106),
(5020, 113, 1, '「食べる」の過去形は？', '{"A": "食べた", "B": "食べました", "C": "食べて", "D": "食べない"}', 'A', '一段動詞「食べる」の普通形過去は「食べた」、丁寧形は「食べました」（A 是普通形）', 2.00, 1, 106),
(5021, 113, 1, '「先生___本___あげます。」の正しい助詞の組み合わせは？', '{"A": "を / に", "B": "に / を", "C": "へ / が", "D": "が / に"}', 'B', '「先生に本をあげます」(送给老师书)，対象は「に」、目的語は「を」', 2.00, 2, 106),
(5022, 113, 1, '「読まなければなりません」の意味は？', '{"A": "读了", "B": "必须读", "C": "不读", "D": "想读"}', 'B', '「～なければなりません」表示「必须」、義務を表す', 2.00, 2, 106),
(5023, 113, 1, '「もし雨が降ったら、家にいます。」の「降ったら」の文法形式は？', '{"A": "假定形", "B": "命令形", "C": "过去形", "D": "被动形"}', 'A', '「～たら」は假定条件形式', 2.00, 2, 106),
(5024, 113, 1, '「来る」の使役形は？', '{"A": "来られる", "B": "来させる", "C": "来らせる", "D": "来させられる"}', 'B', 'カ变动词「来る」的使役形为「来させる」（让……来）', 2.00, 3, 106),
(5025, 113, 1, '「お父さん」是 ___ 的尊敬称呼。', '{"A": "自己的父亲", "B": "别人的父亲", "C": "祖父", "D": "叔叔"}', 'B', '「お父さん」称呼他人的父亲；自己父亲对外说「父」', 2.00, 2, 106),
(5026, 113, 1, '「いただきます」を言う時間は？', '{"A": "食前", "B": "食後", "C": "朝起きた時", "D": "寝る時"}', 'A', '「いただきます」是饭前的礼貌用语，意为「我开动了」', 2.00, 1, 106),
(5027, 113, 1, '「漢字」の正しい読み方は？', '{"A": "かんじ", "B": "かんし", "C": "がんじ", "D": "ぎゃんじ"}', 'A', '「漢字（かんじ）」是汉字的标准读音', 2.00, 1, 106),
(5028, 113, 1, '「日本語が___です。」最适合填入的是？', '{"A": "上手", "B": "上手い", "C": "うまい", "D": "得意"}', 'A', 'な形容词「上手（じょうず）」做谓语接「です」表「擅长」', 2.00, 2, 106),
(5029, 113, 2, '日本語の動詞「五段活用」に属するのは？', '{"A": "書く", "B": "食べる", "C": "読む", "D": "見る"}', 'AC', '「書く」「読む」是五段动词；「食べる」「見る」是一段动词', 3.00, 2, 106),
(5030, 113, 2, '以下のうち、敬語に分類されるのは？', '{"A": "召し上がる", "B": "食べる", "C": "いただく", "D": "食う"}', 'AC', '召し上がる是尊敬语；いただく是谦让语；食べる是普通；食う是粗俗', 3.00, 3, 106),
(5031, 113, 2, '日本語の文末表現で疑問を表すのは？', '{"A": "～か", "B": "～です", "C": "～かな", "D": "～ね"}', 'AC', '「か」是直接疑问；「かな」是自言自语式疑问；「ね」是寻求确认', 3.00, 2, 106),
(5032, 113, 2, '日本語の漢字の音読みの起源として正しいのは？', '{"A": "呉音", "B": "漢音", "C": "唐音", "D": "訓読"}', 'ABC', '音読有呉音/漢音/唐音三种从中国传入的读法；訓読是日本固有的训读', 3.00, 3, 106),
(5033, 113, 3, '日本語の「ひらがな」と「カタカナ」は同じ音を表す異なる文字体系である。', NULL, '正确', '两者发音相同，用途不同（カタカナ常用于外来词）', 1.00, 1, 106),
(5034, 113, 3, '「です」は丁寧体の助動詞である。', NULL, '正确', '「です」是判断助动词「だ」的丁宁体', 1.00, 1, 106),
(5035, 113, 3, '日本語の文の基本語順は SOV（主語-目的語-動詞）である。', NULL, '正确', '日语典型语序是 SOV，与汉/英 SVO 不同', 1.00, 1, 106),
(5036, 113, 3, '「あなた」は親しい人に対しても普通に使われる二人称代名詞である。', NULL, '错误', '「あなた」对长辈/上司不礼貌；亲密关系通常直呼姓名+さん', 1.00, 2, 106),
(5037, 113, 3, '日本語の動詞は人称によって活用が変化する。', NULL, '错误', '与欧洲语言不同，日语动词不随主语人称变化', 1.00, 2, 106),
(5038, 113, 3, '「行きます」是「行く」的辞書形である。', NULL, '错误', '「行く」は辞書形；「行きます」是丁寧体ます形', 1.00, 2, 106),
(5039, 113, 4, '「学校___行きます」表示去学校时，最常用的助词是 ___ 或「に」。', NULL, 'へ', '「へ」表示方向；「に」表示到达点，两者在表方向时常通用', 2.00, 1, 106),
(5040, 113, 4, '「食べる」のて形は ___ である。', NULL, '食べて', '一段动词て形：去掉る + て', 2.00, 1, 106),
(5041, 113, 4, '日本語の数字「7」の読み方は「しち」または ___（另一种读法）。', NULL, 'なな', '「7」可读「しち」（汉音）或「なな」（训读），后者更常用避歧义', 2.00, 2, 106),
(5042, 113, 4, '「明日は雨が降る___しれません」（明天可能下雨）の___に入るのは ___。', NULL, 'かも', '「～かもしれません」表示「可能～」', 2.00, 2, 106),
(5043, 113, 5, '简述日语动词的三类分类，并各举一个例子。', NULL, '三类分类：(1) 五段动词（一类动词/u 段动词）：词尾为う段假名 (u/ku/su/tsu/nu/bu/mu/ru) 的动词。例：書く、読む。(2) 一段动词（二类动词/ru 动词）：词尾为「る」且る前为 i 段或 e 段。例：食べる、見る。(3) サ変・カ変（不规则动词）：只有「する」(做) 和「来る」(来) 两个', '日语动词分类是基础语法', 5.00, 2, 106),
(5044, 113, 5, '什么是日语敬语？日语敬语主要分为哪几类？请举例说明。', NULL, '敬语：通过特定语法形式表达对话者/话题人物的尊敬。三大类：(1) 尊敬语：抬高对方动作。例：いらっしゃる(行く/来る/いる的尊敬)、おっしゃる(言う);(2) 谦让语：谦称自己动作。例：参る(行く/来る)、申す(言う)、いただく(もらう/食べる);(3) 丁宁语：使用「です/ます」表达对听者的礼貌', '敬语是日语社交核心', 5.00, 3, 106),
(5045, 113, 5, '请把句子 “明天我和朋友一起去东京。” 翻译成日语，并说明使用的助词。', NULL, '译文：明日、私は友達と一緒に東京へ行きます。助词说明：「は」标主题(我)、「と」表示「与～一起」、「に」/「へ」表示方向(去东京)、「行きます」是「行く」的丁宁体', '翻译能综合考查助词、动词、语序', 5.00, 2, 106),
(5046, 113, 5, '日语中「は」与「が」作主格助词时有什么区别？请举例说明。', NULL, '区别：(1) 「は」标识主题（已知信息），引出谈话焦点；(2) 「が」标识主语（新信息），常表示客观陈述、强调主语本身、或在疑问词主语中使用。例：「私は学生です」(关于我，是学生 - 谈论我)；「私が学生です」(是我是学生 - 强调是我)。「誰が来ましたか」(疑问词主语必用が)；「明日は雨です」(主题预报)', 'は/が 是日语学习者最常见的难点', 5.00, 3, 106),
(5047, 113, 1, '「先生は私たちに本を読ませました」中「読ませました」是什么形式', '{"A": "可能态", "B": "使役态", "C": "被动态", "D": "意志形"}', 'B', '～させる是使役态，表示''让...做''。这里是老师让我们读书', 2.00, 2, 106),
(5048, 113, 1, '「東京に住んでいる」中「いる」表示', '{"A": "存在", "B": "进行/状态", "C": "意志", "D": "尝试"}', 'B', '～ている表示动作正在进行或状态持续，''住んでいる''表示居住的状态', 2.00, 1, 106),
(5049, 113, 1, '请选择「お疲れ様でした」最恰当的使用场合', '{"A": "见面时打招呼", "B": "下班/工作结束后", "C": "餐前", "D": "睡前"}', 'B', '「お疲れ様でした」常用于工作结束后慰劳他人，''辛苦了''', 2.00, 1, 106),
(5050, 113, 1, '「行く」的尊敬语是', '{"A": "おっしゃる", "B": "いらっしゃる", "C": "拝見する", "D": "申し上げる"}', 'B', '「行く/来る/いる」的尊敬语都是「いらっしゃる」', 2.00, 2, 106),
(5051, 113, 1, '「もし時間があったら、映画を見に行きます」中「あったら」表示', '{"A": "完成", "B": "假定", "C": "推量", "D": "并列"}', 'B', '～たら是假定形，表示''如果...的话''', 2.00, 1, 106),
(5052, 113, 1, '下列哪个动词是Ⅰ类动词（五段动词）', '{"A": "食べる", "B": "見る", "C": "書く", "D": "来る"}', 'C', '「書く」以う段假名「く」结尾，是五段动词。食べる/見る是一段，来る是不规则', 2.00, 2, 106),
(5053, 113, 1, '「お弁当を作ってもらいました」表示', '{"A": "我做了便当", "B": "我让别人做了便当（自己受益）", "C": "别人做了便当（与我无关）", "D": "我帮别人做了便当"}', 'B', '～てもらう表示''让/请...为我做''，主语受益', 2.00, 2, 106),
(5054, 113, 1, '「東京は大阪より人口が多い」中「より」表示', '{"A": "理由", "B": "比较的基准", "C": "起点", "D": "并列"}', 'B', '「AはBより～」表示''A 比 B 更...''，より是比较基准标记', 2.00, 1, 106),
(5055, 113, 1, '「読書」（どくしょ）的意思是', '{"A": "図書館", "B": "读书", "C": "书店", "D": "买书"}', 'B', '「読書」（どくしょ）= 读书；「図書館」是图书馆', 2.00, 1, 106),
(5056, 113, 1, '「日本語が話せます」中「話せます」是', '{"A": "意志形", "B": "可能形", "C": "被动形", "D": "使役形"}', 'B', '話す→話せる→話せます，是可能形的礼貌体', 2.00, 2, 106),
(5057, 113, 1, '「明日は雨が降る___です」中应填入', '{"A": "そう", "B": "らしい", "C": "みたい", "D": "以上都对"}', 'D', '三者都可表推测，但语气和依据略不同：そう（外观/传闻）、らしい（客观依据）、みたい（口语推测）', 3.00, 3, 106),
(5058, 113, 1, '「申し訳ありません」是哪类敬语', '{"A": "尊敬語", "B": "謙譲語", "C": "丁寧語", "D": "美化語"}', 'B', '「申し訳ない」是说话人谦逊地表达歉意，属謙譲表現', 2.00, 2, 106),
(5059, 113, 2, '下列哪些是日语的助词', '{"A": "が", "B": "を", "C": "に", "D": "です"}', 'ABC', 'が/を/に都是助词（格助词）；です是断定助动词', 3.00, 1, 106),
(5060, 113, 2, '下列哪些表达可用于自我介绍', '{"A": "はじめまして", "B": "よろしくお願いします", "C": "お疲れさまでした", "D": "私は～と申します"}', 'ABD', '「お疲れ様でした」用于工作结束慰劳，不适合自我介绍', 3.00, 1, 106),
(5061, 113, 2, '下列哪些动词是不规则动词（变格动词）', '{"A": "する", "B": "来る", "C": "行く", "D": "ある"}', 'AB', '「する」和「来る」是仅有的两个不规则动词；行く是五段，ある是五段', 3.00, 2, 106),
(5062, 113, 2, '下列哪些是日语敬语的种类', '{"A": "尊敬語", "B": "謙譲語", "C": "丁寧語", "D": "卑語"}', 'ABC', '日语敬语三大类：尊敬語、謙譲語、丁寧語；卑語不是敬语', 3.00, 2, 106),
(5063, 113, 3, '日语中名词修饰名词时，通常用助词「の」连接', NULL, '正确', '「私の本」「日本の文化」等，「の」用于名词修饰名词', 1.00, 1, 106),
(5064, 113, 3, '「ます形」是日语动词的礼貌体', NULL, '正确', '「ます」是动词礼貌体（丁寧語）的标志，对应敬体「です」', 1.00, 1, 106),
(5065, 113, 3, '「行きます」的辞书形（原形）是「行く」', NULL, '正确', '行く→行きます（五段动词的ます形变换）', 1.00, 1, 106),
(5066, 113, 3, '日语中的「は」和「が」用法完全相同', NULL, '错误', '「は」是主题助词、「が」是主格助词，用法和强调点不同', 1.00, 2, 106),
(5067, 113, 3, '「すみません」既可表道歉又可表感谢', NULL, '正确', '「すみません」可表道歉，也可在受人恩惠时表示感谢（''不好意思让你麻烦''）', 1.00, 2, 106),
(5068, 113, 3, '「お／ご + 动词连用形 + する」是尊敬语句型', NULL, '错误', '「お／ご～する」是謙譲語句型，表示自己谦逊；尊敬语句型是「お／ご～になる」', 1.00, 2, 106),
(5069, 113, 4, '翻译：私は学生です。 → 我是 ____', NULL, '学生', '「私は学生です」我是学生（最基础的自我介绍）', 2.00, 1, 106),
(5070, 113, 4, '日语中表示''去做某事''的句型是：动词ます形去ます + ____ + 行きます', NULL, 'に', '「～に行きます」表示''去做某事''，如「映画を見に行きます」', 2.00, 2, 106),
(5071, 113, 4, '「本を____ください」（请把书给我）填入合适的动词て形', NULL, '貸して', '「貸す」→「貸して」(借给我)，或填「ください」前的「～て」形', 2.00, 2, 106),
(5072, 113, 4, '「日本語_____勉強しています」中应填入助词 ____', NULL, 'を', '「日本語を勉強する」学习日语，を是宾格助词', 2.00, 1, 106),
(5073, 113, 5, '请说明日语的「は」和「が」的主要区别，各举一例', NULL, '「は」是主题助词，提示话题，强调后项信息；「が」是主格助词，强调主语本身或客观陈述。例：(1) 私は田中です。（提示话题：关于我，是田中）— 强调''田中''；(2) 田中が来ました。（强调主语：是田中来了）。''は''常用于已知信息，''が''常用于新信息或疑问句答语', 'は vs が 是日语学习的核心难点之一', 5.00, 3, 106),
(5074, 113, 5, '简述日语动词的三大类（变格分类），并举例', NULL, '日语动词分三类：(1) Ⅰ类（五段动词）：词尾在う段，如''書く・話す・買う''，活用涉及五段假名；(2) Ⅱ类（一段动词）：词尾为''える/いる''，如''食べる・見る・起きる''，去る加变化；(3) Ⅲ类（变格/不规则）：仅''する''和''来る''两个。三类动词的ます形、て形、た形、可能形等活用规则各异', '动词分类是日语语法基础', 5.00, 2, 106),
(5075, 113, 5, '请将下列中文翻译成日文：''明天我打算和朋友一起去图书馆学习''', NULL, '明日、友達と一緒に図書館へ勉強しに行くつもりです。 注：「～つもりです」表示''打算...'';「へ」表示移动方向（也可用に）；「友達と一緒に」与朋友一起；「勉強しに行く」去学习（する+に+行く）', '综合考查移动、目的、意志、伙伴等表达', 5.00, 2, 106),
(5076, 113, 5, '解释敬语中「尊敬語」「謙譲語」「丁寧語」的区别，各举一例', NULL, '(1) 尊敬語：尊敬对方/他人的行为或状态。例：先生がいらっしゃる（老师来了，对''先生''表尊敬）；(2) 謙譲語：谦逊地表达自己/己方的动作，以抬高对方。例：私が参ります（我去，''参る''是''行く''的谦让语）；(3) 丁寧語：通过''です/ます''等表达礼貌，对所有人统一使用。例：今日は寒いです（今天很冷）。三者可叠加使用，是日语沟通的关键礼仪', '敬语三大类是日语高级语法的核心', 5.00, 3, 106),
