(5273, 113, 3, '日语的「あなた」相当于你', NULL, '正确', 'あなた=你', 1.00, 1, 106),
(5274, 113, 3, '日语的「これ」表示这个', NULL, '正确', 'これ=这个', 1.00, 1, 106),
(5275, 113, 4, '「私____学生です」(主题助词)', NULL, 'は', 'は 主题', 2.00, 2, 106),
(5276, 113, 4, '「本____読みます」(宾格)', NULL, 'を', 'を 宾格', 2.00, 2, 106),
(5277, 113, 4, '「学校____行きます」(方向)', NULL, 'へ', 'へ 方向', 2.00, 2, 106),
(5278, 113, 4, '「私____本」(属格)', NULL, 'の', 'の=的', 2.00, 2, 106),
(5279, 113, 4, '「友達____食べます」(共同)', NULL, 'と', 'と 共同', 2.00, 2, 106),
(5280, 113, 4, '「日本語____話します」(手段)', NULL, 'で', 'で 手段', 2.00, 2, 106),
(5281, 113, 4, '「東京____住んでいます」(存在)', NULL, 'に', 'に 存在', 2.00, 2, 106),
(5282, 113, 4, '「学生です____」(疑问)', NULL, 'か', 'か 疑问', 2.00, 2, 106),
(5283, 113, 4, '「行く」的ます形是 ____', NULL, '行きます', '行く ます', 2.00, 3, 106),
(5284, 113, 4, '「食べる」的ます形是 ____', NULL, '食べます', '食べる ます', 2.00, 3, 106),
(5285, 113, 4, '「行く」的て形是 ____', NULL, '行って', '行く て', 2.00, 3, 106),
(5286, 113, 4, '「読む」的て形是 ____', NULL, '読んで', 'む→んで', 2.00, 3, 106),
(5287, 113, 4, '「食べる」的过去式是 ____', NULL, '食べた', '食べる 过去', 2.00, 3, 106),
(5288, 113, 4, '「行く」的否定形是 ____', NULL, '行かない', '行く ない', 2.00, 3, 106),
(5289, 113, 4, '「する」的可能形是 ____', NULL, 'できる', 'する→できる', 2.00, 3, 106),
(5290, 113, 4, '「来る」的可能形是 ____', NULL, '来られる(こられる)', '来る→こられる', 2.00, 3, 106),
(5291, 113, 4, '「行く」的尊敬语是 ____', NULL, 'いらっしゃる', '行く 尊敬', 2.00, 3, 106),
(5292, 113, 4, '「食べる」的尊敬语是 ____', NULL, '召し上がる', '食べる 尊敬', 2.00, 3, 106),
(5293, 113, 4, '「言う」的谦让语是 ____', NULL, '申す', '言う 谦让', 2.00, 3, 106),
(5294, 113, 4, '「美しい」的过去式是 ____', NULL, '美しかった', 'い形 过去', 2.00, 3, 106),
(5295, 113, 4, '「綺麗だ」的过去式是 ____', NULL, '綺麗だった', 'な形 过去', 2.00, 3, 106),
(5296, 113, 4, '表示我想做(用动词ます形) ____', NULL, '~たい', '~たい', 2.00, 2, 106),
(5297, 113, 4, '表示必须 ____ ならない', NULL, 'なければ', '必须', 2.00, 3, 106),
(5298, 113, 4, '表示禁止 ____ はいけない', NULL, 'て', '禁止', 2.00, 3, 106),
(5299, 113, 4, '表示推测(也许) ____ ない', NULL, 'かもしれ', '推测', 2.00, 3, 106),
(5300, 113, 4, '「桜」的读音是 ____', NULL, 'さくら', '桜=さくら', 2.00, 2, 106),
(5301, 113, 4, '「学生」的读音是 ____', NULL, 'がくせい', '学生=がくせい', 2.00, 2, 106),
(5302, 113, 4, '「先生」的读音是 ____', NULL, 'せんせい', '先生=せんせい', 2.00, 2, 106),
(5303, 113, 4, '「日本」的读音是 ____', NULL, 'にほん', '日本=にほん', 2.00, 2, 106),
(5304, 113, 4, '「中国」的读音是 ____', NULL, 'ちゅうごく', '中国=ちゅうごく', 2.00, 2, 106),
(5305, 113, 4, 'JLPT 全称是 ____', NULL, '日本语能力测试', 'JLPT', 2.00, 2, 106),
(5306, 113, 4, '日语句子结构是 ____ 顺序', NULL, 'SOV', 'SOV', 2.00, 3, 106),
(5307, 113, 4, '「~たら」表示 ____ 条件', NULL, '假设', '条件句', 2.00, 3, 106),
(5308, 113, 4, '「より」用于 ____', NULL, '比较', '比较', 2.00, 2, 106),
(5309, 113, 4, '「~ために」表示 ____', NULL, '目的', '目的', 2.00, 3, 106),
(5310, 113, 5, '简述日语的文字体系', NULL, '日语有三套文字:1)平假名(ひらがな):46 个清音,源自汉字草书,用于本土词、助词、动词变形等;2)片假名(カタカナ):46 个清音,源自汉字偏旁,主要用于外来语、拟声词、强调;3)汉字(漢字):从中国传入,有音读(中国发音演变)和训读(日本本土发音)两种读法。此外还有罗马字(ローマ字),用拉丁字母表示发音。一句日语常混用三种文字。', '日语文字', 5.00, 2, 106),
(5311, 113, 5, '简述五十音图的结构', NULL, '五十音图由 10 行 5 列构成,实际有 46 个清音(部分位置空缺)。1)行:あ、か、さ、た、な、は、ま、や、ら、わ;2)段:あ、い、う、え、お。例:か行 = か(ka)、き(ki)、く(ku)、け(ke)、こ(ko)。变化音:1)浊音(が、ざ、だ、ば 行,加浊点);2)半浊音(ぱ 行,加半浊点);3)拗音(い段假名+小ゃゅょ);4)促音(っ,延一拍);5)长音。每个假名都有平假名、片假名两种写法。', '五十音图', 5.00, 2, 106),
(5312, 113, 5, '简述日语动词的分类', NULL, '日语动词分三类:1)一类动词(五段动词):词尾在 う段(う、く、ぐ、す、つ、ぬ、ぶ、む、る)的动词中,变化时词尾在五段间变化。例:書く、読む、行く、買う。2)二类动词(一段动词):词尾是「いる/える+る」。又分上一段(い段+る,如:見る、起きる)和下一段(え段+る,如:食べる、寝る)。3)三类动词(不规则,サ变、カ变):サ变只有「する」及「~する」复合动词;カ变只有「来る」。判断要看词尾和具体词形。', '动词分类', 5.00, 3, 106),
(5313, 113, 5, '简述动词变形的常见类型', NULL, '日语动词常见变形:1)ます形(敬体现在):一类 い段+ます(行きます),二类 去る+ます(食べます),三类 します/来ます。2)て形:用于连接句子、请求(~てください)。一类:く→いて(行く特殊→って),ぐ→いで,む/ぬ/ぶ→んで,す→して,う/つ/る→って。二类:去る+て。三类:して/来て。3)ない形(否定):一类 う段→あ段+ない,二类 去る+ない,三类 しない/来ない。4)た形(过去):同て形,て→た。5)可能形、被动形、使役形等。', '动词变形', 5.00, 3, 106),
(5314, 113, 5, '简述「て形」的用法', NULL, '「~て形」是日语连接句子的核心形式:1)连接动作:食べて、寝ます(吃完睡);2)请求:~てください(请);3)许可:~てもいい;4)禁止:~てはいけない;5)正在进行:~ている(正在/状态);6)经验:~たことがある;7)尝试:~てみる;8)给予:~てあげる/~てくれる/~てもらう;9)进行/逐渐:~ていく/~てくる;10)完成:~てしまう。一类动词て形变化规则需牢记。', 'て形用法', 5.00, 3, 106),
(5315, 113, 5, '简述助词「は」「が」的区别', NULL, '两者都接在体言后,但功能不同:1)「は」(主题助词,读 wa):提示主题、对比;新信息后接 が,旧信息(主题)后接 は;一般用于句子前半或主题。例:象は鼻が長い(大象鼻子长)。2)「が」(主格助词):指出主语、强调;疑问代词的回答用 が;描述存在/感觉/能力的主语;新信息。例:誰が来た?(谁来了);誰がリンゴを食べたの?。规则:1)文脉中已知的主题用 は;2)疑问代词作主语必用 が;3)感觉/存在 が;4)对比 は。', 'は と が', 5.00, 3, 106),
(5316, 113, 5, '简述日语的助词体系', NULL, '日语主要助词分类:1)格助词(标示句子成分):が(主格)、を(宾格)、に(对象/时间/地点)、で(地点/手段)、と(共同)、から(起点)、まで(终点)、の(属格);2)主题助词:は;3)接续助词:と、ば、なら、たら、ても、けれども、のに、から、ので、し;4)副助词:も、だけ、ばかり、しか、まで、こそ、さえ、でも、なんか;5)终助词:か、ね、よ、な、わ、ぞ。助词决定词与词的语法关系,掌握助词是日语学习的重点。', '助词体系', 5.00, 3, 106),
(5317, 113, 5, '简述日语的形容词类型', NULL, '日语形容词分两类:1)い形容词(形容词):词尾为「い」,如:美しい、高い、寒い。可独立作谓语。变形:1)过去:~かった;2)否定:~くない;3)中顿连用:~くて;4)修饰名词:い+名词。例外:いい→よかった、よくない、よくて。2)な形容词(形容动词):词尾本无固定,但接名词时加「な」,如:綺麗、便利、有名。变形:用「だ」充当连体形(綺麗だ);1)过去:~だった;2)否定:~ではない/~じゃない;3)中顿:~で;4)修饰名词:な+名词。', '形容词类型', 5.00, 3, 106),
(5318, 113, 5, '简述日语的敬语体系', NULL, '日语敬语分三类:1)尊敬语:抬高对方/话题人物。常用:「お/ご+动词ます形+になる」(おかきになる);特殊词:いらっしゃる、おっしゃる、召し上がる、ご覧になる、なさる。2)谦让语:贬低自己/己方。常用:「お/ご+动词ます形+する」;特殊词:参る、申す、いただく、拝見する、いたす、おる。3)郑重语(丁宁语):用 ですます体保持礼貌。「ございます」(ある的郑重)。规则:对长辈、客户、初见用敬语;对家人、同事可省。商务日语中敬语尤为重要。', '敬语体系', 5.00, 3, 106),
(5319, 113, 5, '简述日语句子的语序', NULL, '日语是 SOV(主-宾-谓)语序,谓语放在最后。1)基本结构:主语 + 宾语 + 谓语。例:私はリンゴを食べる(我吃苹果)。2)修饰语在被修饰语之前:形容词/动词修饰名词都放前;3)助词决定成分:位置可较灵活,但谓语必在末尾;4)疑问句不变语序,加か即可;5)与英语 SVO 不同,与汉语 SVO 不同;6)从句:修饰名词放前,「~とき、~ところ、~人」。', '日语语序', 5.00, 3, 106),
(5320, 113, 5, '简述日语的时态', NULL, '日语时态主要分现在(非过去)和过去两大类,无单独的未来时:1)现在/未来时:动词原形/ます形,表示现在习惯、将来、规律。例:毎日勉強する。2)过去时:动词た形/ました形。例:昨日勉強した。3)进行/状态:~ている。例:今勉強している。4)完成:~てしまう、~た。5)体貌(aspect):~ところ表示即将/正在/刚刚。日语用动词变形而非时态变化表示时态,时态系统比英语简单但比汉语丰富(动词需变形)。', '日语时态', 5.00, 3, 106),
(5321, 113, 5, '简述「~たい」「~ほしい」的区别', NULL, '两者都表示愿望,但主语不同:1)「~たい」(我想做):说话人想做的事,主语是说话人。前接动词ます形(去 ます)。例:行きたい(我想去)、食べたい(我想吃)。第三人称用「~たがる」(他/她想~)。2)「~ほしい」(我想要):说话人想要某物或希望对方做某事。形式:~がほしい(想要某物);~てほしい(希望对方做)。例:お金がほしい(我想要钱);手伝ってほしい(希望(你)帮忙)。区别:たい 自己做,ほしい 自己得 或 他人做。', '愿望表达', 5.00, 3, 106),
(5322, 113, 5, '简述日语的条件句', NULL, '日语有 4 种条件句:1)~たら:最常用,后接结果。例:雨が降ったら、行きません;表示假设/前提,主从句时间关系灵活。2)~ば:接 a 段后接ば(动词)或+ければ(形容词);表示假设、并列条件。例:時間があれば、行く。3)~なら:对方提出话题后回应。例:日本語を勉強するなら、辞書を買ってください;表示话题相关的建议。4)~と:必然结果、自然规律、习惯。例:春になると、桜が咲く。区别在于:たら 时间先后明显;ば 一般假设;なら 话题假设;と 必然性。', '条件句', 5.00, 3, 106),
(5323, 113, 5, '简述日语的被动态', NULL, '日语被动态分两种:1)直接被动:主语承受动作,与英语类似。形式:一类动词词尾 う段→あ段+れる(読まれる);二类动词去る+られる(食べられる);三类:される/来られる。例:私は先生に叱られた(我被老师骂)。2)间接被动(迷惑被动):主语受到不快的影响,即使是间接的。例:雨に降られた(被雨淋了);妻に死なれた(妻子离世给我带来痛苦)。被动态常带「に」标示动作者。日语被动用得比英语更广泛,反映受影响的视角。', '被动态', 5.00, 3, 106),
(5324, 113, 5, '简述日语的使役态', NULL, '日语使役态表示让/使某人做某事:1)形式:一类 う段→あ段+せる(書かせる、読ませる);二类 去る+させる(食べさせる);三类 させる/来させる。2)用法:1)指令:先生は学生に本を読ませた(老师让学生读书);2)允许:子供に遊ばせる(让孩子玩);3)情感:心配させる(让人担心)。3)使役被动:~される/~させられる,表示被迫做某事。例:無理にお酒を飲まされた(被迫喝酒)。助词:被使役者用「に」(自他动词)或「を」(自动词)。', '使役态', 5.00, 3, 106),
(5325, 113, 5, '简述日语的可能态', NULL, '日语可能态表示能够做某事,有两种形式:1)动词的可能形:一类 う段→え段+る(書く→書ける、読む→読める),二类 去る+られる(食べる→食べられる),三类 する→できる、来る→来られる。2)~ことができる:动词原形+ことができる(食べることができる)。区别:可能形更口语化,~ことができる更书面/正式。注意:1)被动形和可能形对二类动词形式相同,需根据上下文区分;2)感觉/情感动词的可能形较少使用;3)可能态的助词常用「が」而非「を」(本を読める→本が読める)。', '可能态', 5.00, 3, 106),
(5326, 113, 5, '简述日语的授受动词', NULL, '授受动词表示给予/接受,体现日本人的内外、上下关系:1)あげる/差し上げる(我或我方给他人):上向。例:友達に本をあげる。2)くれる/くださる(他人给我或我方):下向、感谢。例:友達が本をくれる。3)もらう/いただく(我或我方从他人处得):いただく更敬。例:友達に本をもらう。4)~てあげる/~てくれる/~てもらう:表示授受恩惠。授受关系决定句子的方向感和情感色彩。', '授受动词', 5.00, 3, 106),
(5327, 113, 5, '简述日语的疑问表达', NULL, '日语疑问表达:1)是非问句:加か。例:学生ですか?2)疑问词问句:何(什么)、誰(谁)、いつ(何时)、どこ(哪里)、どう(如何)、どれ/どの(哪个)、なぜ/どうして(为什么)、いくつ(几个)、いくら(多少钱)。例:何を食べますか?3)反问句:のではないか。4)选择问:AかBか。5)语气词:か(疑问)、ね(确认/委婉)、よ(强调)。日语疑问句一般不变语序,只加疑问词或か即可。语调:女性多用ね,男性多用ぞ/ぜ。', '疑问表达', 5.00, 3, 106),
(5328, 113, 5, '简述日语的指示词体系', NULL, '日语指示词分四组:1)指物:これ(这个)、それ(那个,听话人附近)、あれ(那个,远)、どれ(哪个);2)指人/物的修饰:この、その、あの、どの+名词;3)指方向:こちら、そちら、あちら、どちら(也用作敬语指人);4)指方位:ここ、そこ、あそこ、どこ。「こ」「そ」「あ」「ど」体系称为「コソアド」。1)こ:说话人附近;2)そ:听话人附近;3)あ:双方都远;4)ど:疑问。指示词在日语会话中频繁使用,需特别注意距离感。', '指示词', 5.00, 3, 106),
(5329, 113, 5, '简述日语的拟声拟态词', NULL, '拟声拟态词(オノマトペ)在日语中极为丰富,分:1)拟声词(擬声語):模拟声音。例:わんわん(汪汪)、にゃーにゃー(喵喵)、ガタガタ(咯哒咯哒);2)拟态词(擬態語):描述状态、感觉。例:キラキラ(闪闪)、ふわふわ(蓬松)、ペラペラ(流利);3)拟情词:描述情感。例:ドキドキ(心跳)、わくわく(兴奋)。特点:1)多用片假名书写;2)叠词或 ABAB 结构;3)使语言生动形象,常用于会话、漫画、广告;4)与 と 连用作副词。', '拟声拟态词', 5.00, 3, 106),
(5330, 113, 5, '简述日本的语言文化特点', NULL, '日本语言文化特点:1)敬语体系发达:体现上下关系、内外区分;2)模糊表达:多用「~と思います」「~かもしれない」回避绝对断言,体现谦虚;3)省略主语:从语境判断主语,以体察对方为美;4)间接表达:不直接拒绝,常用「ちょっと…」「考えておきます」;5)男女用语差异:男性用語(僕、ぞ),女性用語(わ、わよ);6)男女敬语差异;7)读空气(空気を読む):理解话外之意;8)外来语丰富:用片假名记录,反映文化吸收;9)成语谚语丰富:四字熟语等。', '语言文化', 5.00, 2, 106),
(5331, 113, 5, '简述日本传统文化', NULL, '日本传统文化丰富多元:1)茶道(さどう):点茶、侍奉、礼仪精神;2)花道(かどう):插花艺术;3)柔道、剣道、合気道、空手道:武道精神;4)和服(着物):传统服饰,女性振袖、留袖,男性紋付袴;5)和食(寿司、刺身、天ぷら、ラーメン):2013 年入选 UNESCO 非遗;6)节日:お正月(新年)、お盆(盂兰盆)、桜祭り(赏樱)、七夕、お祭り;7)神道、佛教融合;8)艺术:能、歌舞伎、文楽(人偶剧)、浮世絵;9)俳句、和歌;10)武士道精神:誠、義、勇、礼、仁、忠、名誉。', '日本传统文化', 5.00, 2, 106),
(5332, 113, 5, '简述 JLPT 考试', NULL, 'JLPT(日本語能力試験):由国际交流基金会和日本国际教育支援协会主办的全球性日语能力测试。1)级别:N1(最高)~N5(最低)5 个级别;2)内容:文字词汇、语法、阅读、听力(N1、N2 不含口语和写作);3)级别要求:N5 简单日常会话;N4 基础会话;N3 一般日常生活;N2 较广泛领域;N1 高级、商务、新闻;4)题型:多选+填空;5)合格:每部分 ≥ 该级别基准分;6)证书:终身有效;7)国际通用,留学、工作、移民必备。每年 7 月、12 月各一次,在中国大陆 30+ 城市设考点。', 'JLPT', 5.00, 2, 106),
(5333, 113, 5, '简述日语学习的方法和资源', NULL, '日语学习方法:1)五十音入门:平假名、片假名都背熟;2)系统学语法:推荐《大家的日本语》、《新版标准日本语》;3)单词积累:JLPT 词汇表、Anki 卡片、每天 20-30 词;4)听力:NHK Easy News、动漫、JLPT 听力;5)口语:语言交换 HelloTalk、Tandem;输出练习;6)阅读:从儿童读物、小说到新闻;7)考级:JLPT N5→N1 阶梯式;8)沉浸式:看动漫、日剧、学唱日文歌、留学/工作;9)资源:NHK World、Duolingo、 Bunpro、JapanesePod101、ANCHIN、Imabi。坚持 2-3 年达 N1。', '日语学习', 5.00, 2, 106),
(5334, 113, 5, '简述日语外来语', NULL, '外来语(外来語/カタカナ語):从外国引入的词,主要用片假名书写。1)来源:英语最多,其他还有法语、德语、葡萄牙语、汉语等;2)类型:1)普通名词:コンピューター(computer)、テレビ(television);2)专有名词:アメリカ(America);3)和制英语:サラリーマン(salaryman);4)缩略词:エアコン(air conditioner);3)发音规则:遵循日语音节,长音用「ー」;4)使用场景:外来概念、科技、品牌、流行语。日语外来语数量持续增长,反映文化交流。但传统主义者担忧汉字/日语词汇衰退。', '外来语', 5.00, 3, 106),
(5335, 113, 5, '简述日语动词中自他动词', NULL, '自他动词:1)自动词(intransitive):不需要直接宾语,主语自身的动作或状态。例:ドアが開く(门开了)、水が止まる。常用助词「が」。2)他动词(transitive):需要直接宾语,动作及于他物。例:ドアを開ける(打开门)、水を止める。常用助词「を」。3)对应关系:许多动词成对出现,如 開く/開ける、出る/出す、上がる/上げる、入る/入れる。规律:他动词多以える/す结尾。区别:1)自动词:被影响者作主语;2)他动词:动作者作主语,被影响者作宾语。汉语对应不严格,需特别记忆。', '自他动词', 5.00, 3, 106),
(5336, 113, 5, '简述日语阅读理解技巧', NULL, '日语阅读理解技巧:1)抓住主题:文首文末常含主旨;2)注意接续词:しかし(然而)、つまり(就是说)、したがって(因此);3)定位关键词:疑问代词、限定词;4)语法分析:特别注意修饰关系、动词时态、敬语层级;5)汉字优势:汉字词义可推测;6)分段阅读:将长文分段,逐段理解;7)上下文推测生词;8)文化背景:理解时事、习俗、典故;9)训练:从简到难,先读 NHK Easy → 报刊 → 文学。备考 JLPT N1 阅读量需达标。', '阅读理解', 5.00, 3, 106),
(5337, 113, 5, '简述日语写作要点', NULL, '日语写作要点:1)文体一致:全文用敬体(です/ます)或简体(だ/である),不可混用;2)句子结构:谓语在句末,修饰语前置;3)助词正确使用:决定语法关系;4)使用合适的接续词:逻辑清晰;5)使用敬语:正式场合、商务邮件;6)汉字与假名比例:适当用汉字提升正式度,过多则艰深;7)标点:主要用「、」「。」、引用「」、对话「」「」;8)纵书横书:小说常纵书,商务横书;9)文法多样化:不重复同一句型;10)避免汉字误用:同音异字易错。', '日语写作', 5.00, 3, 106),
(5338, 113, 5, '简述日语在国际化中的作用', NULL, '日语的国际地位:1)使用人口:约 1.25 亿,主要在日本本土;2)动漫、漫画、游戏:日本流行文化推动日语全球热;3)经济地位:日本是世界第三大经济体,日企遍布全球;4)旅游:疫情前每年 3000+ 万游客赴日;5)JLPT:全球 80+ 国家可考,留学/工作必备;6)海外学习者:全球约 400 万,中国占 1/4;7)技术文档:工程、汽车、半导体;8)文化输出:文学(村上春树等)、诺贝尔奖、设计、建筑;9)未来:作为亚洲文化纽带,继续推动东亚文化交流和软实力。', '日语国际化', 5.00, 2, 106),
