(5344, 113, 4, '「あなた」是日语的 ____ 人称', NULL, '第二', '第二人称', 2.00, 1, 106),
(5345, 113, 4, '「私」是日语的 ____ 人称', NULL, '第一', '第一人称', 2.00, 1, 106),
(5346, 113, 4, '日语的标点符号「、」相当于中文 ____', NULL, '逗号', '、=逗号', 2.00, 2, 106),
(5347, 113, 4, '日语的标点符号「。」相当于中文 ____', NULL, '句号', '。=句号', 2.00, 2, 106),
